import React, { createContext, useContext, useEffect, useState } from 'react';

export interface ApiItem {
    index: string;
    name: string;
    url: string;
    desc?: string[];
    rarity?: { name: string };
    equipment_category?: { name: string };
    cost?: { quantity: number, unit: string };
    is_magic?: boolean;
}

interface ItemContextType {
    items: ApiItem[];
    loading: boolean;
    loadingProgress: string;
}

const ItemContext = createContext<ItemContextType>({
    items: [],
    loading: false,
    loadingProgress: '',
});

export const useItems = () => useContext(ItemContext);

const CACHE_KEY = 'dnd_items_cache_v2';
const API_BASE = 'https://www.dnd5eapi.co';

export const ItemProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const [items, setItems] = useState<ApiItem[]>([]);
    const [loading, setLoading] = useState(false);
    const [loadingProgress, setLoadingProgress] = useState('');

    useEffect(() => {
        const loadItems = async () => {
            // 1. Check Cache
            const cached = localStorage.getItem(CACHE_KEY);
            if (cached) {
                try {
                    const parsed = JSON.parse(cached);
                    if (Array.isArray(parsed) && parsed.length > 0) {
                        setItems(parsed);
                        return;
                    }
                } catch (e) {
                    console.error("Cache parse error", e);
                }
            }

            setLoading(true);
            try {
                // 2. Fetch Indexes
                setLoadingProgress("Fetching item indexes...");
                const [magicRes, equipRes] = await Promise.all([
                    fetch(`${API_BASE}/api/magic-items`),
                    fetch(`${API_BASE}/api/equipment`)
                ]);

                const magicData = await magicRes.json();
                const equipData = await equipRes.json();

                // 3. Process & Waterfall
                const allMagic: ApiItem[] = magicData.results.map((i: any) => ({ ...i, is_magic: true }));
                const allEquip: ApiItem[] = equipData.results.map((i: any) => ({ ...i, is_magic: false }));

                // We prioritize fetching details for magic items as they are more complex
                // Equipment details can often be inferred or are simpler, but we'll fetch them all for searchability

                const combined = [...allMagic, ...allEquip];
                const enrichedItems: ApiItem[] = [];
                const batchSize = 10; // Request in small batches

                for (let i = 0; i < combined.length; i += batchSize) {
                    const batch = combined.slice(i, i + batchSize);
                    setLoadingProgress(`Loading item details: ${i} / ${combined.length}`);

                    const details = await Promise.all(
                        batch.map(async (item) => {
                            try {
                                const res = await fetch(`${API_BASE}${item.url}`);
                                const data = await res.json();
                                return {
                                    index: item.index,
                                    name: item.name,
                                    url: item.url,
                                    desc: data.desc,
                                    rarity: data.rarity,
                                    equipment_category: data.equipment_category,
                                    cost: data.cost,
                                    is_magic: item.is_magic
                                };
                            } catch (e) {
                                console.warn(`Failed to fetch details for ${item.name}`, e);
                                return item;
                            }
                        })
                    );
                    enrichedItems.push(...details);
                    // Small delay to be nice to the API
                    await new Promise(r => setTimeout(r, 50));
                }

                setItems(enrichedItems);
                localStorage.setItem(CACHE_KEY, JSON.stringify(enrichedItems));
            } catch (err) {
                console.error("Failed to load items", err);
            } finally {
                setLoading(false);
                setLoadingProgress('');
            }
        };

        loadItems();
    }, []);

    return (
        <ItemContext.Provider value={{ items, loading, loadingProgress }}>
            {children}
        </ItemContext.Provider>
    );
};

import React, { useState, useEffect, createContext, useContext, useCallback } from 'react';
import { Session, User } from '@supabase/supabase-js';
import { supabase } from './services/supabase';
import { AppUser, UserProfile } from './types';
import AuthScreen from './components/AuthScreen';
import Dashboard from './components/Dashboard';
import { Icon } from './components/Icons';
import { ItemProvider } from './components/ItemProvider';

type AuthContextType = {
  session: Session | null;
  user: AppUser | null;
  loading: boolean;
  signOut: () => Promise<void>;
};

const AuthContext = createContext<AuthContextType>({
  session: null,
  user: null,
  loading: true,
  signOut: async () => {},
});

export const useAuth = () => useContext(AuthContext);

/**
 * Creates a user profile in the database. This is typically called for new sign-ups.
 * @param authUser The user object from Supabase auth.
 * @returns An object with the new profile or an error message.
 */
const createAndFetchUserProfile = async (authUser: User): Promise<{ profile: UserProfile | null, error: string | null }> => {
    console.log('New user detected. Fetching fresh user data to ensure metadata is present.');

    const { data, error: getUserError } = await supabase.auth.getUser();

    if (getUserError || !data.user) {
        console.error("Critical: Could not fetch fresh user details after sign in.", getUserError);
        return { profile: null, error: "Could not verify your new account. Please try again." };
    }
    const freshUser = data.user;

    const usernameToInsert = freshUser.user_metadata.username || freshUser.email?.split('@')[0] || `user_${Date.now()}`;
    const roleToInsert = freshUser.user_metadata.role || 'Player';

    const { data: profile, error: insertError } = await supabase
      .from('users')
      .insert({
        id: freshUser.id,
        username: usernameToInsert,
        role: roleToInsert,
      })
      .select()
      .single();

    if (insertError) {
      if (insertError.code === '23505') { // unique violation, profile likely exists
        const { data: existingProfile, error: fetchError } = await supabase.from('users').select('*').eq('id', freshUser.id).single();
        if (existingProfile) return { profile: existingProfile, error: null };
        if(fetchError) console.error("Error re-fetching profile after insert failed:", fetchError);
      } else {
        console.error("Error creating user profile:", insertError);
      }
      return { profile: null, error: "There was a problem setting up your profile." };
    }

    return { profile, error: null };
};

const App: React.FC = () => {
  const [session, setSession] = useState<Session | null>(null);
  const [user, setUser] = useState<AppUser | null>(null);
  const [loading, setLoading] = useState(true);
  const [authError, setAuthError] = useState<string | null>(null);

  const signOut = useCallback(async () => {
    await supabase.auth.signOut();
  }, []);

  const handleAuthAttempt = useCallback(() => {
    setAuthError(null);
  }, []);

  useEffect(() => {
    setLoading(true);

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      try {
        setSession(session);
        setAuthError(null);

        if (!session?.user) {
          setUser(null);
          return;
        }

        const { data: profile, error } = await supabase
          .from('users')
          .select('*')
          .eq('id', session.user.id)
          .single();

        if (profile) {
          setUser({ ...session.user, profile });
        } else if (error && error.code !== 'PGRST116') {
          console.error("Auth listener profile fetch error:", error);
          setAuthError("Could not load your profile. Please try again.");
          setUser(null);
        } else {
          // Profile not found, let's try to create it.
          // This handles both new sign-ups and existing auth users without a profile.
          const { profile: newProfile, error: createError } = await createAndFetchUserProfile(session.user);
          if (newProfile) {
            setUser({ ...session.user, profile: newProfile });
          } else {
            setAuthError(createError);
            setUser(null);
            // Sign out to clear the bad state
            await supabase.auth.signOut();
          }
        }
      } catch (e) {
        console.error("Unhandled error in onAuthStateChange:", e);
        setAuthError("An unexpected error occurred.");
        setUser(null);
      } finally {
        setLoading(false);
      }
    });

    return () => {
      subscription?.unsubscribe();
    };
  }, []);

  if (loading) {
    return (
      <div className="flex h-screen w-full items-center justify-center bg-stone-950">
        <Icon name="spinner" className="h-12 w-12 animate-spin text-amber-500" />
      </div>
    );
  }

  return (
    <AuthContext.Provider value={{ session, user, loading: false, signOut }}>
      <ItemProvider>
        {user && session ? <Dashboard /> : <AuthScreen authError={authError} onAuthAttempt={handleAuthAttempt} />}
      </ItemProvider>
    </AuthContext.Provider>
  );
};

export default App;

