import Sidebar from './Sidebar';
import MapViewer from './MapViewer';
import PinDetails from './PinDetails';
import Wiki from './Wiki';
import { MapManagerModal, PinEditorModal, PinTypeManagerModal } from './Modals';
import { Icon } from './Icons';

type AppContextType = {
    maps: MapType[];
    pinTypes: PinType[];
    pins: Pin[];
    isPlayerView: boolean;
    refreshData: () => Promise<void>;
    setIsPlayerView: React.Dispatch<React.SetStateAction<boolean>>;
};

const AppContext = createContext<AppContextType | null>(null);
export const useAppContext = () => {
    const context = useContext(AppContext);
    if (!context) throw new Error('useAppContext must be used within an AppContextProvider');
    return context;
};

const Dashboard: React.FC = () => {
    const { user } = useAuth();
    const [maps, setMaps] = useState<MapType[]>([]);
    const [pinTypes, setPinTypes] = useState<PinType[]>([]);
    const [pins, setPins] = useState<Pin[]>([]);

    // View State
    const [currentView, setCurrentView] = useState<'map' | 'wiki'>('map');
    const [selectedMap, setSelectedMap] = useState<MapType | null>(null);
    const [selectedPin, setSelectedPin] = useState<Pin | null>(null);

    // Highlight State (for locating pins from Wiki)
    const [highlightedPinId, setHighlightedPinId] = useState<string | null>(null);

    const [isPlayerView, setIsPlayerView] = useState(user?.profile.role === 'Player');
    const [loading, setLoading] = useState(true);

    // Modal states
    const [isMapManagerOpen, setMapManagerOpen] = useState(false);
    const [isPinTypeManagerOpen, setPinTypeManagerOpen] = useState(false);
    const [editingPin, setEditingPin] = useState<Partial<Pin> | null>(null);

    useEffect(() => {
        if (user) {
            setIsPlayerView(user.profile.role === 'Player');
        }
    }, [user?.id]);

    const refreshData = useCallback(async () => {
        if (!user) return;
        setLoading(true);

        const fetchMaps = supabase.from('maps').select('*');
        const { data: mapsData, error: mapsError } = await (user.profile.role === 'DM' ? fetchMaps : fetchMaps.eq('is_visible', true));

        const { data: pinTypesData, error: pinTypesError } = await supabase.from('pin_types').select('*');

        if (mapsData) setMaps(mapsData);
        if (pinTypesData) setPinTypes(pinTypesData);
        if (mapsError) console.error("Error fetching maps", mapsError);
        if (pinTypesError) console.error("Error fetching pin types", pinTypesError);

        // Fetch ALL pins for the wiki search, but map viewer filters by selected map
        const fetchPins = supabase.from('pins').select('*, pin_types(*)');
        const { data: pinsData, error: pinsError } = await (user.profile.role === 'DM' && !isPlayerView ? fetchPins : fetchPins.eq('is_visible', true));
        if (pinsData) setPins(pinsData as Pin[]);

        setLoading(false);
    }, [user, isPlayerView]);

    useEffect(() => {
        refreshData();
    }, [refreshData]);

    const handleSelectMap = (map: MapType | null) => {
        setSelectedMap(map);
        setSelectedPin(null);
        setHighlightedPinId(null);
        setCurrentView('map'); // Switch to map view when selecting from sidebar
    };

    const handlePinSave = async () => {
        setEditingPin(null);
        await refreshData();
    };

    if (loading) {
        return <div className="flex h-screen w-full items-center justify-center bg-stone-950"><Icon name="spinner" className="h-10 w-10 animate-spin text-amber-500" /></div>;
    }

    return (
        <AppContext.Provider value={{ maps, pinTypes, pins, isPlayerView, refreshData, setIsPlayerView }}>
            <div className="flex h-screen w-full flex-col md:flex-row overflow-hidden bg-stone-950 text-stone-200">
                <Sidebar
                    selectedMap={selectedMap}
                    onSelectMap={handleSelectMap}
                    currentView={currentView}
                    onViewChange={setCurrentView}
                    onMapManagerOpen={() => setMapManagerOpen(true)}
                    onPinTypeManagerOpen={() => setPinTypeManagerOpen(true)}
                />
                <main className="relative flex-1 bg-stone-950 overflow-hidden">
                    {currentView === 'map' ? (
                        <>
                            {selectedMap ? (
                                <MapViewer
                                    map={selectedMap}
                                    onSelectPin={(pin) => {
                                        setSelectedPin(pin);
                                        setHighlightedPinId(null); // Clear highlight on user interaction
                                    }}
                                    onAddPin={(coords) => {
                                        if (user?.profile.role === 'DM' && !isPlayerView) {
                                            setEditingPin({ ...coords, map_id: selectedMap.id });
                                            setHighlightedPinId(null);
                                        }
                                    }}
                                    highlightedPinId={highlightedPinId}
                                />
                            ) : (
                                <div className="flex h-full w-full items-center justify-center text-stone-500">
                                    <div className="text-center">
                                        <Icon name="map" className="mx-auto h-16 w-16 opacity-30 mb-4" />
                                        <p className="text-lg font-medieval">Select a map to begin</p>
                                    </div>
                                </div>
                            )}
                            <PinDetails 
                                pin={selectedPin} 
                                onClose={() => setSelectedPin(null)} 
                                onEdit={(pin) => setEditingPin(pin)}
                                mapId={selectedMap?.id}
                            />
                        </>
                    ) : (
                        <Wiki 
                            onSelectMap={(map) => handleSelectMap(map)}
                            onLocatePin={(pin) => {
                                const map = maps.find(m => m.id === pin.map_id);
                                if(map) {
                                    setSelectedMap(map);
                                    setHighlightedPinId(pin.id); // Set the highlight
                                    setSelectedPin(null); // Ensure detail view is closed
                                    setCurrentView('map');
                                }
                            }}
                        />
                    )}

                    {isMapManagerOpen && <MapManagerModal isOpen={isMapManagerOpen} onClose={() => setMapManagerOpen(false)} />}
                    {isPinTypeManagerOpen && <PinTypeManagerModal isOpen={isPinTypeManagerOpen} onClose={() => setPinTypeManagerOpen(false)} />}
                    {editingPin && (
                        <PinEditorModal 
                            pinData={editingPin} 
                            onClose={() => setEditingPin(null)} 
                            onSave={handlePinSave} 
                        />
                    )}
                </main>
            </div>
        </AppContext.Provider>
    );
};

export default Dashboard;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Map as MapType, Pin } from '../types';
import { useAppContext } from './Dashboard';
import { useAuth } from '../App';
import { Icon } from './Icons';

interface MapViewerProps {
    map: MapType;
    onSelectPin: (pin: Pin) => void;
    onAddPin: (coords: { x: number; y: number }) => void;
    highlightedPinId?: string | null;
}

type InteractionMode = 'pan' | 'pin';

const MapViewer: React.FC<MapViewerProps> = ({ map, onSelectPin, onAddPin, highlightedPinId }) => {
    const { pins, pinTypes, isPlayerView } = useAppContext();
    const { user } = useAuth();
    const containerRef = useRef<HTMLDivElement>(null);
    const mapRef = useRef<HTMLDivElement>(null);

    const [viewState, setViewState] = useState({ scale: 1, x: 0, y: 0 });
    const [isPanning, setIsPanning] = useState(false);
    const [panStart, setPanStart] = useState({ x: 0, y: 0 });
    const [imgDimensions, setImgDimensions] = useState({ width: 0, height: 0 });

    // Default to 'pan' mode. Only DMs can switch to 'pin'.
    const [interactionMode, setInteractionMode] = useState<InteractionMode>('pan');

    // Defaults if map config is missing
    const gridSize = map.grid_size || 50;
    const pinSize = map.pin_scale || 50;
    const showGrid = map.is_grid_visible || false;

    const isDM = user?.profile.role === 'DM';
    const canEdit = isDM && !isPlayerView;

    const getPinType = (pinTypeId: string) => pinTypes.find(pt => pt.id === pinTypeId);

    const resetView = useCallback(() => {
        if (!containerRef.current || !imgDimensions.width) return;
        const container = containerRef.current;
        const { width: cWidth, height: cHeight } = container.getBoundingClientRect();
        const { width: iWidth, height: iHeight } = imgDimensions;

        const scaleX = cWidth / iWidth;
        const scaleY = cHeight / iHeight;
        const scale = Math.min(scaleX, scaleY, 1);

        const x = (cWidth - iWidth * scale) / 2;
        const y = (cHeight - iHeight * scale) / 2;

        setViewState({ scale, x, y });
    }, [imgDimensions]);

    // Ensure players are always in pan mode
    useEffect(() => {
        if (!canEdit) {
            setInteractionMode('pan');
        }
    }, [canEdit]);

    useEffect(() => {
        const img = new Image();
        img.src = map.image_url;
        img.onload = () => {
            setImgDimensions({ width: img.width, height: img.height });
        };
    }, [map.image_url]);

    // Auto-center on highlighted pin when ID changes
    useEffect(() => {
        if (highlightedPinId && imgDimensions.width > 0 && containerRef.current) {
            const pin = pins.find(p => p.id === highlightedPinId);
            if (pin && pin.map_id === map.id) {
                const container = containerRef.current.getBoundingClientRect();
                const targetScale = Math.max(viewState.scale, 1); // Ensure we are zoomed in at least 1x

                const pinXPx = pin.x_coord * imgDimensions.width;
                const pinYPx = pin.y_coord * imgDimensions.height;

                // Center logic: (ContainerCenter) - (PinPos * Scale)
                const newX = (container.width / 2) - (pinXPx * targetScale);
                const newY = (container.height / 2) - (pinYPx * targetScale);

                setViewState({ scale: targetScale, x: newX, y: newY });
            }
        } else if (!highlightedPinId && imgDimensions.width > 0) {
            // Only reset view on initial load, not when highlight is cleared manually
            if (viewState.scale === 1 && viewState.x === 0) resetView();
        }
    }, [highlightedPinId, imgDimensions, pins, map.id]); // Removed resetView dep to avoid loop, handled implicitly

    // Initial reset view on image load
    useEffect(() => {
        if (imgDimensions.width > 0 && !highlightedPinId) {
            resetView();
        }
    }, [imgDimensions, resetView]);

    // Zoom Helpers
    const zoomIn = () => {
        setViewState(prev => ({ ...prev, scale: Math.min(prev.scale * 1.2, 5) }));
    };

    const zoomOut = () => {
        setViewState(prev => ({ ...prev, scale: Math.max(prev.scale / 1.2, 0.1) }));
    };

    const handleWheel = (e: React.WheelEvent) => {
        e.preventDefault();
        const { deltaY, clientX, clientY } = e;
        const scaleAmount = -deltaY * 0.001;
        const newScale = Math.min(Math.max(0.1, viewState.scale + scaleAmount), 5);

        const rect = containerRef.current!.getBoundingClientRect();
        const mouseX = clientX - rect.left;
        const mouseY = clientY - rect.top;

        const newX = mouseX - (mouseX - viewState.x) * (newScale / viewState.scale);
        const newY = mouseY - (mouseY - viewState.y) * (newScale / viewState.scale);

        setViewState({ scale: newScale, x: newX, y: newY });
    };

    const handleMouseDown = (e: React.MouseEvent) => {
        if (interactionMode === 'pan' || e.button === 1 || e.button === 2) {
            setIsPanning(true);
            setPanStart({ x: e.clientX - viewState.x, y: e.clientY - viewState.y });
        }
    };

    const handleMouseUp = (e: React.MouseEvent) => {
        setIsPanning(false);
    };

    const handleMouseMove = (e: React.MouseEvent) => {
        if (!isPanning) return;
        setViewState(prev => ({ ...prev, x: e.clientX - panStart.x, y: e.clientY - panStart.y }));
    };

    const handleMapClick = (e: React.MouseEvent) => {
        if (!canEdit || isPanning || interactionMode !== 'pin') return;

        if (e.target !== mapRef.current && e.target !== (mapRef.current?.querySelector('img') as HTMLElement) && e.target !== (mapRef.current?.querySelector('.grid-overlay') as HTMLElement)) return;

        const rect = mapRef.current!.getBoundingClientRect();

        let x = (e.clientX - rect.left) / rect.width;
        let y = (e.clientY - rect.top) / rect.height;

        if (showGrid && gridSize > 0 && imgDimensions.width > 0 && imgDimensions.height > 0) {
            const originalX = x * imgDimensions.width;
            const originalY = y * imgDimensions.height;
            const col = Math.floor(originalX / gridSize);
            const row = Math.floor(originalY / gridSize);
            const centerX = (col * gridSize) + (gridSize / 2);
            const centerY = (row * gridSize) + (gridSize / 2);
            x = centerX / imgDimensions.width;
            y = centerY / imgDimensions.height;
        }

        onAddPin({ x, y });
    };

    let cursorStyle = 'default';
    if (isPanning) {
        cursorStyle = 'grabbing';
    } else if (interactionMode === 'pan') {
        cursorStyle = 'grab';
    } else if (interactionMode === 'pin' && canEdit) {
        cursorStyle = 'crosshair';
    }

    return (
        <div 
            ref={containerRef}
            className="h-full w-full overflow-hidden bg-stone-950 relative"
            style={{ cursor: cursorStyle }}
            onWheel={handleWheel}
            onMouseDown={handleMouseDown}
            onMouseUp={handleMouseUp}
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseUp}
        >
            <div
                ref={mapRef}
                className="relative origin-top-left"
                style={{
                    transform: `translate(${viewState.x}px, ${viewState.y}px) scale(${viewState.scale})`,
                    width: `${imgDimensions.width}px`,
                    height: `${imgDimensions.height}px`,
                }}
                onClick={handleMapClick}
            >
                <img src={map.image_url} alt={map.name} className="pointer-events-none w-full h-full absolute top-0 left-0" />

                {showGrid && (
                    <div 
                        className="grid-overlay absolute inset-0 pointer-events-none opacity-30"
                        style={{
                            backgroundSize: `${gridSize}px ${gridSize}px`,
                            backgroundImage: `
                                linear-gradient(to right, rgba(255, 255, 255, 0.5) 1px, transparent 1px),
                                linear-gradient(to bottom, rgba(255, 255, 255, 0.5) 1px, transparent 1px)
                            `
                        }}
                    />
                )}

                {/* Pins */}
                {pins.map(pin => {
                    if (pin.map_id !== map.id) return null;
                    const pinType = getPinType(pin.pin_type_id);
                    const isHighlighted = pin.id === highlightedPinId;

                    return (
                        <button
                            key={pin.id}
                            onClick={(e) => { e.stopPropagation(); onSelectPin(pin); }}
                            className={`absolute transform -translate-x-1/2 -translate-y-1/2 flex items-center justify-center rounded-full transition-all focus:outline-none shadow-lg shadow-black/50 ${isHighlighted ? 'ring-4 ring-amber-500 ring-offset-2 ring-offset-black z-50 scale-125 animate-pulse' : 'hover:brightness-110 focus:ring-2 focus:ring-white hover:z-50'}`}
                            style={{ 
                                left: `${pin.x_coord * 100}%`, 
                                top: `${pin.y_coord * 100}%`,
                                backgroundColor: pinType?.color || '#3B82F6',
                                width: `${pinSize}px`,
                                height: `${pinSize}px`,
                                fontSize: `${pinSize * 0.6}px`, 
                                cursor: 'pointer'
                            }}
                            title={pin.title}
                        >
                            <span className="drop-shadow-md leading-none select-none">
                                {pinType?.emoji || '📍'}
                            </span>
                        </button>
                    );
                })}
            </div>

            {/* Controls */}
             <div className="absolute bottom-6 right-6 flex flex-col gap-4 z-10">
                {canEdit && (
                    <div className="flex flex-col gap-1 p-1 rounded-xl bg-stone-900/80 backdrop-blur-lg border border-stone-700/50 shadow-xl">
                        <button 
                            onClick={() => setInteractionMode('pan')} 
                            className={`p-2 rounded-lg transition-colors ${interactionMode === 'pan' ? 'bg-amber-600 text-white' : 'text-stone-400 hover:text-stone-200 hover:bg-stone-800'}`}
                            title="Pan Mode"
                        >
                            <Icon name="hand" className="w-5 h-5"/>
                        </button>
                        <button 
                            onClick={() => setInteractionMode('pin')} 
                            className={`p-2 rounded-lg transition-colors ${interactionMode === 'pin' ? 'bg-amber-600 text-white' : 'text-stone-400 hover:text-stone-200 hover:bg-stone-800'}`}
                            title="Add Pin Mode"
                        >
                            <Icon name="pin" className="w-5 h-5"/>
                        </button>
                    </div>
                )}

                <div className="flex flex-col gap-1 p-1 rounded-xl bg-stone-900/80 backdrop-blur-lg border border-stone-700/50 shadow-xl">
                    <button onClick={zoomIn} className="p-2 rounded-lg text-stone-300 hover:text-amber-500 hover:bg-stone-800 transition-colors" title="Zoom In">
                        <Icon name="plus" className="w-5 h-5"/>
                    </button>
                    <button onClick={resetView} className="p-2 rounded-lg text-stone-300 hover:text-amber-500 hover:bg-stone-800 transition-colors" title="Center View">
                        <Icon name="center" className="w-5 h-5"/>
                    </button>
                    <button onClick={zoomOut} className="p-2 rounded-lg text-stone-300 hover:text-amber-500 hover:bg-stone-800 transition-colors" title="Zoom Out">
                        <Icon name="minus" className="w-5 h-5"/>
                    </button>
                </div>
             </div>
        </div>
    );
};

export default MapViewer;

import React, { useState, useMemo } from 'react';
import { useAppContext } from './Dashboard';
import { useAuth } from '../App';
import { Map as MapType, Pin, PinSection } from '../types';
import { Icon } from './Icons';

interface WikiProps {
    onSelectMap: (map: MapType) => void;
    onLocatePin: (pin: Pin) => void;
}

const Wiki: React.FC<WikiProps> = ({ onSelectMap, onLocatePin }) => {
    const { maps, pins, pinTypes, isPlayerView } = useAppContext();
    const { user } = useAuth();
    const isDM = user?.profile.role === 'DM';
    const canSeeSecrets = isDM && !isPlayerView;

    const [searchQuery, setSearchQuery] = useState('');
    const [selectedMapId, setSelectedMapId] = useState<string | null>(null);
    const [selectedPinId, setSelectedPinId] = useState<string | null>(null);

    // Filter logic
    const filteredContent = useMemo(() => {
        const lowerQ = searchQuery.toLowerCase();

        return maps.map(map => {
            const mapPins = pins.filter(p => p.map_id === map.id);

            // If searching, check if map matches OR any of its pins match
            let matchesMap = !searchQuery || map.name.toLowerCase().includes(lowerQ);

            const matchingPins = mapPins.filter(pin => {
                if (!searchQuery) return true;

                // Search Pin Title
                if (pin.title.toLowerCase().includes(lowerQ)) return true;
                // Search Pin Description
                if (pin.data.description?.toLowerCase().includes(lowerQ)) return true;
                // Search Sections
                return pin.data.sections?.some(s => 
                    s.title.toLowerCase().includes(lowerQ) || 
                    s.content.toLowerCase().includes(lowerQ) ||
                    (s.type === 'list' && s.list_items?.some(i => i.toLowerCase().includes(lowerQ))) ||
                    (s.type === 'inventory' && s.items?.some(i => i.name.toLowerCase().includes(lowerQ)))
                );
            });

            // If query exists, only show map if it matches or has matching pins
            if (searchQuery && !matchesMap && matchingPins.length === 0) return null;

            return {
                map,
                pins: matchingPins
            };
        }).filter(Boolean) as { map: MapType, pins: Pin[] }[];

    }, [maps, pins, searchQuery]);

    const activeMapData = selectedMapId ? filteredContent.find(c => c.map.id === selectedMapId) : null;
    const activePin = selectedPinId ? pins.find(p => p.id === selectedPinId) : null;
    const activePinMap = activePin ? maps.find(m => m.id === activePin.map_id) : null;

    // --- Renderers ---

    const renderPinContent = (pin: Pin) => {
        const type = pinTypes.find(t => t.id === pin.pin_type_id);

        return (
            <div className="space-y-8 animate-modal-in max-w-4xl mx-auto pb-20">
                {/* Header */}
                <div className="border-b border-stone-700/50 pb-6">
                    <div className="flex items-center gap-4 mb-4">
                        <div className="flex items-center justify-center w-16 h-16 rounded-2xl shadow-xl text-3xl ring-2 ring-stone-700/50" style={{ backgroundColor: type?.color || '#555' }}>
                            {type?.emoji || '📍'}
                        </div>
                        <div>
                            <h1 className="text-4xl font-medieval font-bold text-stone-100">{pin.title}</h1>
                            <div className="flex items-center gap-2 mt-1">
                                <span className="bg-stone-800/50 px-2 py-0.5 rounded text-xs text-stone-400 border border-stone-700 uppercase tracking-wider">{type?.name || 'Unknown'}</span>
                                {activePinMap && <span className="text-stone-500 text-sm flex items-center gap-1"><Icon name="map" className="w-3 h-3"/> {activePinMap.name}</span>}
                            </div>
                        </div>
                        <button 
                            onClick={() => onLocatePin(pin)}
                            className="ml-auto flex items-center gap-2 bg-stone-800 hover:bg-amber-700/20 hover:text-amber-500 border border-stone-700 px-4 py-2 rounded-xl transition-all text-sm font-medium group"
                        >
                            <Icon name="compass" className="w-4 h-4 group-hover:rotate-45 transition-transform"/>
                            Locate on Map
                        </button>
                    </div>

                    {pin.data.description && (
                         <div className="prose prose-invert max-w-none text-stone-300 text-lg leading-relaxed bg-stone-900/20 p-6 rounded-2xl border border-stone-800/50">
                            {pin.data.description}
                         </div>
                    )}
                </div>

                {/* Sections */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {pin.data.sections?.map((section, idx) => {
                        if (section.type === 'secret' && !canSeeSecrets) return null;

                        const isFullWidth = section.type === 'text' || section.type === 'list' || section.type === 'inventory';

                        return (
                            <div key={idx} className={`bg-stone-800/20 rounded-2xl border border-stone-700/30 overflow-hidden ${isFullWidth ? 'md:col-span-2' : ''} ${section.type === 'secret' ? 'border-red-900/50 bg-red-950/10' : ''}`}>
                                <div className={`px-5 py-3 border-b border-stone-700/30 flex items-center justify-between ${section.type === 'secret' ? 'bg-red-950/30' : 'bg-stone-800/40'}`}>
                                    <h3 className={`font-medieval text-xl ${section.type === 'secret' ? 'text-red-400' : 'text-stone-200'}`}>
                                        {section.type === 'secret' && <Icon name="lock" className="w-4 h-4 inline mr-2" />}
                                        {section.title}
                                    </h3>
                                    <span className="text-xs uppercase text-stone-600 font-bold tracking-wider">{section.type}</span>
                                </div>

                                <div className="p-5">
                                    {section.type === 'text' && <p className="whitespace-pre-wrap text-stone-300 leading-relaxed">{section.content}</p>}
                                    {section.type === 'secret' && <p className="whitespace-pre-wrap text-red-200/80 leading-relaxed font-mono text-sm">{section.content}</p>}

                                    {section.type === 'list' && (
                                        <>
                                            {section.content && <p className="mb-4 text-stone-400 italic">{section.content}</p>}
                                            <ul className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                                                {section.list_items?.map((item, i) => (
                                                    <li key={i} className="flex items-start gap-2 text-stone-300 bg-stone-900/30 p-2 rounded">
                                                        <span className="text-amber-500 mt-1">✦</span>
                                                        <span>{item}</span>
                                                    </li>
                                                ))}
                                            </ul>
                                        </>
                                    )}

                                    {section.type === 'statblock' && (
                                        <>
                                            {section.content && <p className="mb-4 text-stone-400 italic">{section.content}</p>}
                                            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                                                {section.stats?.map((stat, i) => (
                                                    <div key={i} className="bg-stone-900/50 p-3 rounded-lg border border-stone-800 flex flex-col items-center text-center">
                                                        <span className="text-xs uppercase tracking-wider text-amber-600 font-bold mb-1">{stat.label}</span>
                                                        <span className="font-medieval text-xl text-stone-200">{stat.value}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </>
                                    )}

                                    {section.type === 'image' && (
                                        <div className="space-y-2">
                                            {section.image_url ? (
                                                <img src={section.image_url} alt={section.title} className="w-full h-auto rounded-lg shadow-lg" />
                                            ) : <div className="h-32 bg-stone-900/50 rounded flex items-center justify-center text-stone-600">No Image</div>}
                                            {section.content && <p className="text-sm text-stone-400 text-center italic">{section.content}</p>}
                                        </div>
                                    )}

                                    {section.type === 'inventory' && (
                                        <div className="overflow-x-auto">
                                            <table className="w-full text-left text-sm">
                                                <thead className="text-stone-500 uppercase text-xs border-b border-stone-700/50">
                                                    <tr>
                                                        <th className="pb-2 pl-2">Item</th>
                                                        <th className="pb-2">Rarity</th>
                                                        <th className="pb-2 text-right pr-2">Qty</th>
                                                    </tr>
                                                </thead>
                                                <tbody className="divide-y divide-stone-700/30">
                                                    {section.items?.map((item, i) => (
                                                        <tr key={i} className="hover:bg-stone-700/20">
                                                            <td className="py-2 pl-2">
                                                                <span className={`font-medium ${item.is_magic ? 'text-amber-400' : 'text-stone-300'}`}>{item.name}</span>
                                                                {item.desc && <p className="text-xs text-stone-500 line-clamp-1">{item.desc}</p>}
                                                            </td>
                                                            <td className="py-2 text-purple-400 text-xs">{item.rarity || '-'}</td>
                                                            <td className="py-2 text-right pr-2 font-mono text-stone-400">{item.count}</td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>
                                    )}
                                </div>
