import React, { useState, useEffect, useMemo } from 'react';
import { supabase, supabaseUrl, supabaseAnonKey } from '../services/supabase';
import { createClient } from '@supabase/supabase-js';
import { useAuth } from '../App';
import { useAppContext } from './Dashboard';
import { useItems, ApiItem } from './ItemProvider';
import { Map as MapType, Pin, PinData, PinType, PinSectionType, PinSection, InventoryItem, Character } from '../types';
import { Icon } from './Icons';

// Helper to convert file to Base64
const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => resolve(reader.result as string);
        reader.onerror = error => reject(error);
    });
};

// Reusable Modal Wrapper
interface ModalProps {
    isOpen: boolean;
    onClose: () => void;
    title: string;
    children: React.ReactNode;
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children }) => {
    useEffect(() => {
        const handleEscape = (event: KeyboardEvent) => {
            if (event.key === 'Escape') {
                onClose();
            }
        };
        document.addEventListener('keydown', handleEscape);
        return () => {
            document.removeEventListener('keydown', handleEscape);
        };
    }, [onClose]);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={onClose} role="dialog" aria-modal="true">
            <div className="w-full max-w-2xl rounded-3xl bg-stone-900/95 backdrop-blur-2xl border border-stone-700/50 p-6 shadow-2xl animate-modal-in flex flex-col max-h-[90vh]" onClick={(e) => e.stopPropagation()}>
                <div className="flex items-center justify-between border-b border-stone-700/50 pb-4 mb-4 flex-shrink-0">
                    <h2 className="text-2xl font-medieval font-bold text-amber-500">{title}</h2>
                    <button onClick={onClose} className="rounded-full p-2 text-stone-500 transition-colors hover:bg-stone-800 hover:text-stone-300">
                        <Icon name="close" className="h-6 w-6" />
                    </button>
                </div>
                <div className="overflow-y-auto pr-2 custom-scrollbar flex-1">{children}</div>
            </div>
        </div>
    );
};

// --- PLAYER MANAGER MODAL ---
interface PlayerManagerModalProps { isOpen: boolean; onClose: () => void; }
export const PlayerManagerModal: React.FC<PlayerManagerModalProps> = ({ isOpen, onClose }) => {
    const [username, setUsername] = useState('');
    const [role, setRole] = useState<'Player' | 'DM'>('Player');
    const [loading, setLoading] = useState(false);
    const [status, setStatus] = useState<{ type: 'success' | 'error', msg: string } | null>(null);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setStatus(null);

        const trimmedUsername = username.trim();
        if (!trimmedUsername) {
            setStatus({ type: 'error', msg: 'Username is required.' });
            setLoading(false);
            return;
        }

        const usernameRegex = /^[a-zA-Z0-9_-]+$/;
        if (!usernameRegex.test(trimmedUsername)) {
            setStatus({ type: 'error', msg: 'Username can only contain letters, numbers, hyphens, and underscores.' });
            setLoading(false);
            return;
        }

        // Generate dummy credentials based on app pattern
        const lowerCaseUsername = trimmedUsername.toLowerCase();
        const dummyEmail = `${lowerCaseUsername}@dnd-map-login.local`;
        const dummyPassword = `DUMMY_PASSWORD_FOR_${lowerCaseUsername}`;

        // CRITICAL: We use a separate Supabase client to create the user.
        // If we used the main `supabase` instance, calling signUp would log out the current DM.
        const tempClient = createClient(supabaseUrl, supabaseAnonKey, {
            auth: {
                persistSession: false, // Don't save this session to localStorage
                autoRefreshToken: false,
                detectSessionInUrl: false,
                storageKey: 'temp-auth-client' // Use distinct key to reduce warnings
            }
        });

        const { data: authData, error: signUpError } = await tempClient.auth.signUp({
            email: dummyEmail,
            password: dummyPassword,
            options: {
                data: { username: trimmedUsername, role: role }
            }
        });

        if (signUpError) {
            setStatus({ type: 'error', msg: signUpError.message });
            setLoading(false);
            return;
        }

        if (authData.user) {
            // Manually insert into public.users to ensure profile exists immediately
            // This is redundant if the trigger works, but safe to ensure immediate consistency
            const { error: profileError } = await supabase.from('users').insert({
                id: authData.user.id,
                username: trimmedUsername,
                role: role,
                password_hash: 'managed_by_supabase_auth' // Required by DB constraint
            });

            if (profileError && profileError.code !== '23505') { // Ignore unique constraint if trigger beat us to it
                 console.error("Profile creation warning:", profileError);
            }

            setStatus({ type: 'success', msg: `User '${trimmedUsername}' created successfully!` });
            setUsername('');
        }

        setLoading(false);
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Add New User">
            <form onSubmit={handleSubmit} className="space-y-6">
                <div className="bg-stone-800/40 p-4 rounded-xl border border-stone-700/50 mb-4">
                    <p className="text-sm text-stone-300">
                        Create a new account for your players. They will log in using only the username provided below.
                    </p>
                </div>

                <div>
                    <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Username</label>
                    <input 
                        type="text" 
                        value={username} 
                        onChange={e => setUsername(e.target.value)} 
                        className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none focus:ring-1 focus:ring-amber-500" 
                        placeholder="e.g. Aragorn" 
                    />
                </div>

                <div>
                    <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Role</label>
                    <div className="flex gap-4">
                        <label className={`flex-1 cursor-pointer rounded-xl border px-4 py-3 text-center transition-all ${role === 'Player' ? 'bg-amber-900/30 border-amber-500 text-amber-500' : 'bg-stone-800/40 border-stone-700 text-stone-400 hover:bg-stone-800'}`}>
                            <input type="radio" className="hidden" checked={role === 'Player'} onChange={() => setRole('Player')} />
                            <span className="font-bold">Player</span>
                        </label>
                        <label className={`flex-1 cursor-pointer rounded-xl border px-4 py-3 text-center transition-all ${role === 'DM' ? 'bg-amber-900/30 border-amber-500 text-amber-500' : 'bg-stone-800/40 border-stone-700 text-stone-400 hover:bg-stone-800'}`}>
                            <input type="radio" className="hidden" checked={role === 'DM'} onChange={() => setRole('DM')} />
                            <span className="font-bold">Dungeon Master</span>
                        </label>
                    </div>
                </div>

                {status && (
                    <div className={`p-4 rounded-xl border text-sm ${status.type === 'success' ? 'bg-green-900/20 border-green-800/50 text-green-300' : 'bg-red-900/20 border-red-800/50 text-red-300'}`}>
                        {status.msg}
                    </div>
                )}

                <button 
                    type="submit" 
                    disabled={loading}
                    className="w-full bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg hover:shadow-amber-900/20 transition-all hover:scale-[1.02] active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    {loading ? <Icon name="spinner" className="h-5 w-5 animate-spin mx-auto"/> : 'Create User'}
                </button>
            </form>
        </Modal>
    );
};

// --- CHARACTER MANAGER MODAL ---
interface CharacterManagerModalProps { isOpen: boolean; onClose: () => void; }
export const CharacterManagerModal: React.FC<CharacterManagerModalProps> = ({ isOpen, onClose }) => {
    const { user } = useAuth();
    const { characters, refreshData } = useAppContext();
    const [editingChar, setEditingChar] = useState<Partial<Character> | null>(null);
    const [isEditing, setIsEditing] = useState(false);

    // Form State
    const [name, setName] = useState('');
    const [race, setRace] = useState('');
    const [charClass, setCharClass] = useState('');
    const [level, setLevel] = useState(1);
    const [alignment, setAlignment] = useState('');
    const [backstory, setBackstory] = useState('');
    const [gmNotes, setGmNotes] = useState('');
    const [isNpc, setIsNpc] = useState(true);
    const [imageFile, setImageFile] = useState<File | null>(null);
    const [imageUrl, setImageUrl] = useState('');
    const [submitting, setSubmitting] = useState(false);

    const resetForm = () => {
        setName(''); setRace(''); setCharClass(''); setLevel(1); setAlignment('');
        setBackstory(''); setGmNotes(''); setIsNpc(true); setImageFile(null); setImageUrl('');
        setEditingChar(null);
        setIsEditing(false);
    };

    const handleEdit = (char: Character) => {
        setEditingChar(char);
        setName(char.name);
        setRace(char.role_details?.race || '');
        setCharClass(char.role_details?.class || '');
        setLevel(char.role_details?.level || 1);
        setAlignment(char.role_details?.alignment || '');
        setBackstory(char.backstory || '');
        setGmNotes(char.gm_notes || '');
        setIsNpc(char.is_npc);
        setImageUrl(char.image_url || '');
        setIsEditing(true);
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user || !name) return;
        setSubmitting(true);

        let finalImageUrl = imageUrl;
        if (imageFile) {
             finalImageUrl = await fileToBase64(imageFile);
        }

        const payload = {
            name,
            role_details: { race, class: charClass, level, alignment },
            backstory,
            gm_notes: gmNotes,
            image_url: finalImageUrl,
            is_npc: isNpc,
            created_by: user.id
        };

        let result;
        if (editingChar && editingChar.id) {
            result = await supabase.from('characters').update(payload).eq('id', editingChar.id);
        } else {
            result = await supabase.from('characters').insert(payload);
        }

        if (result.error) {
            console.error("Error saving character:", result.error);
            alert("Error saving character. Ensure the database table 'characters' exists.");
        } else {
            await refreshData(true);
            resetForm();
        }
        setSubmitting(false);
    };

    const handleDelete = async (char: Character) => {
        if(!window.confirm(`Delete ${char.name}?`)) return;
        const { error } = await supabase.from('characters').delete().eq('id', char.id);
        if(!error) await refreshData(true);
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title={isEditing ? (editingChar ? "Edit Character" : "New Character") : "Manage Characters"}>
            {!isEditing ? (
                <div className="space-y-6">
                    <button onClick={() => setIsEditing(true)} className="w-full flex items-center justify-center space-x-2 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-4 rounded-xl shadow-lg transition-all">
                        <Icon name="plus" className="h-5 w-5" />
                        <span>Create New Character</span>
                    </button>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {characters.map(char => (
                             <div key={char.id} className="relative group bg-stone-800/40 border border-stone-700/50 rounded-xl p-4 flex gap-4 hover:bg-stone-800/60 transition-colors">
                                <div className="w-16 h-16 rounded-full bg-stone-900 overflow-hidden flex-shrink-0 border-2 border-stone-600 group-hover:border-amber-500 transition-colors">
                                    {char.image_url ? <img src={char.image_url} alt={char.name} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-stone-600 text-xs">No Img</div>}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <h3 className="font-medieval text-lg text-stone-200 truncate">{char.name}</h3>
                                    <p className="text-xs text-stone-500 uppercase tracking-wider font-bold mb-1">{char.is_npc ? 'NPC' : 'Player Character'}</p>
                                    <p className="text-xs text-stone-400 truncate">{char.role_details?.race} {char.role_details?.class} (Lvl {char.role_details?.level})</p>
                                </div>
                                <div className="flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity absolute right-2 top-2">
                                     <button onClick={() => handleEdit(char)} className="p-1.5 rounded-lg bg-stone-900 text-stone-400 hover:text-amber-500"><Icon name="pencil" className="w-4 h-4" /></button>
                                     <button onClick={() => handleDelete(char)} className="p-1.5 rounded-lg bg-stone-900 text-stone-400 hover:text-red-500"><Icon name="trash" className="w-4 h-4" /></button>
                                </div>
                             </div>
                        ))}
                        {characters.length === 0 && <p className="col-span-2 text-center text-stone-500 italic py-8">No characters found.</p>}
                    </div>
                </div>
            ) : (
                <form onSubmit={handleSave} className="space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="md:col-span-2 flex items-center gap-4 bg-stone-800/30 p-4 rounded-xl border border-stone-700/30">
                            <label className="w-20 h-20 rounded-full bg-stone-900 border-2 border-dashed border-stone-600 flex items-center justify-center cursor-pointer hover:border-amber-500 overflow-hidden relative">
                                {imageUrl || (imageFile && URL.createObjectURL(imageFile)) ? (
                                    <img src={imageUrl || (imageFile ? URL.createObjectURL(imageFile) : '')} className="w-full h-full object-cover" />
                                ) : (
                                    <span className="text-xs text-stone-500 text-center">Upload<br/>Avatar</span>
                                )}
                                <input type="file" className="hidden" accept="image/*" onChange={e => {
                                    if(e.target.files?.[0]) { setImageFile(e.target.files[0]); setImageUrl(''); }
                                }} />
                            </label>
                            <div className="flex-1 space-y-2">
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input type="checkbox" checked={isNpc} onChange={e => setIsNpc(e.target.checked)} className="rounded border-stone-600 bg-stone-800 text-amber-600 focus:ring-amber-500" />
                                    <span className="text-sm font-bold text-stone-300">Is NPC?</span>
                                </label>
                                <input type="text" placeholder="Image URL (optional)" value={imageUrl} onChange={e => { setImageUrl(e.target.value); setImageFile(null); }} className="w-full rounded-lg border border-stone-600/50 bg-stone-900/40 px-3 py-2 text-sm text-stone-200" />
                            </div>
                        </div>

                        <input type="text" placeholder="Name" value={name} onChange={e => setName(e.target.value)} required className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 placeholder-stone-500 focus:border-amber-500 focus:outline-none" />
                        <input type="text" placeholder="Race" value={race} onChange={e => setRace(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 placeholder-stone-500 focus:border-amber-500 focus:outline-none" />
                        <input type="text" placeholder="Class" value={charClass} onChange={e => setCharClass(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 placeholder-stone-500 focus:border-amber-500 focus:outline-none" />

                        <div className="flex gap-2">
                            <input type="number" placeholder="Level" min="1" max="20" value={level} onChange={e => setLevel(parseInt(e.target.value))} className="w-24 rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 placeholder-stone-500 focus:border-amber-500 focus:outline-none" />
                            <input type="text" placeholder="Alignment" value={alignment} onChange={e => setAlignment(e.target.value)} className="flex-1 rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 placeholder-stone-500 focus:border-amber-500 focus:outline-none" />
                        </div>
                    </div>

                    <textarea placeholder="Backstory / Bio" value={backstory} onChange={e => setBackstory(e.target.value)} rows={4} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 placeholder-stone-500 focus:border-amber-500 focus:outline-none" />
                    <textarea placeholder="GM Notes (Secret)" value={gmNotes} onChange={e => setGmNotes(e.target.value)} rows={2} className="w-full rounded-xl border border-red-900/30 bg-red-950/10 px-4 py-3 text-stone-200 placeholder-red-400/50 focus:border-red-500 focus:outline-none" />

                    <div className="flex gap-3 pt-4 border-t border-stone-700/50">
                        <button type="button" onClick={resetForm} className="flex-1 bg-stone-700 hover:bg-stone-600 text-stone-200 font-bold py-3 px-6 rounded-xl transition-all">Cancel</button>
                        <button type="submit" disabled={submitting} className="flex-1 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all">{submitting ? "Saving..." : "Save Character"}</button>
                    </div>
                </form>
            )}
        </Modal>
    );
};

// --- DEDICATED MAP EDITOR MODAL ---
interface MapEditorModalProps {
    isOpen: boolean;
    onClose: () => void;
    mapToEdit: MapType | null; // null = Create Mode
}

export const MapEditorModal: React.FC<MapEditorModalProps> = ({ isOpen, onClose, mapToEdit }) => {
    const { user } = useAuth();
    const { maps, refreshData } = useAppContext();
    const [step, setStep] = useState<'details' | 'calibration'>('details');

    const [mapName, setMapName] = useState('');
    const [mapUrl, setMapUrl] = useState('');
    const [mapFile, setMapFile] = useState<File | null>(null);
    const [parentMapId, setParentMapId] = useState<string | null>(null);
    const [isVisible, setIsVisible] = useState(false);

    const [gridSize, setGridSize] = useState(50);
    const [pinScale, setPinScale] = useState(50);
    const [isGridVisible, setIsGridVisible] = useState(false);

    const [submitting, setSubmitting] = useState(false);
    const [error, setError] = useState('');

    useEffect(() => {
        if (isOpen) {
            setStep('details');
            setError('');
            if (mapToEdit) {
                setMapName(mapToEdit.name);
                setMapUrl(mapToEdit.image_url);
                setMapFile(null);
                setParentMapId(mapToEdit.parent_map_id);
                setIsVisible(mapToEdit.is_visible);
                setGridSize(mapToEdit.grid_size || 50);
                setPinScale(mapToEdit.pin_scale || 50);
                setIsGridVisible(mapToEdit.is_grid_visible || false);
            } else {
                setMapName('');
                setMapUrl('');
                setMapFile(null);
                setParentMapId(null);
                setIsVisible(false);
                setGridSize(50);
                setPinScale(50);
                setIsGridVisible(false);
            }
        }
    }, [isOpen, mapToEdit]);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files[0]) {
            setMapFile(e.target.files[0]);
            setMapUrl('');
        }
    };

    const handleNext = async () => {
        if (!mapName) {
            setError('Please provide a map name.');
            return;
        }
        if (!mapUrl && !mapFile && !mapToEdit) {
            setError('Please provide an image URL or upload a file.');
            return;
        }

        if (mapFile) {
            try {
                const base64 = await fileToBase64(mapFile);
                setMapUrl(base64);
            } catch (e) {
                setError("Error processing image file.");
                return;
            }
        } else if (!mapUrl && mapToEdit) {
            setMapUrl(mapToEdit.image_url);
        }

        setError('');
        setStep('calibration');
    };

    const handleSubmit = async () => {
        if (!user) return;
        setSubmitting(true);
        setError('');

        const payload = {
            name: mapName,
            image_url: mapUrl,
            parent_map_id: parentMapId || null,
            grid_size: gridSize,
            pin_scale: pinScale,
            is_grid_visible: isGridVisible,
            is_visible: isVisible
        };

        let result;
        const attemptSave = async (data: any) => {
            if (mapToEdit) {
                return await supabase.from('maps').update(data).eq('id', mapToEdit.id);
            } else {
                return await supabase.from('maps').insert({ ...data, created_by: user.id });
            }
        };

        result = await attemptSave(payload);

        if (result.error && result.error.code === 'PGRST204') {
            console.warn("Extended columns missing, saving basic info.");
            const basicPayload = { name: mapName, image_url: mapUrl };
            result = await attemptSave(basicPayload);
            if (!result.error) {
                alert("Map saved. Note: Calibration or Parent settings could not be stored due to database schema version.");
            }
        }

        if (result.error) {
            console.error("Database error:", result.error);
            setError(`Error: ${result.error.message}`);
        } else {
            await refreshData(true);
            onClose();
        }
        setSubmitting(false);
    };

    const getDescendants = (mapId: string): Set<string> => {
        const descendants = new Set<string>();
        const stack = [mapId];
        while (stack.length > 0) {
            const currentId = stack.pop()!;
            const children = maps.filter(m => m.parent_map_id === currentId);
            children.forEach(child => {
                if (!descendants.has(child.id)) {
                    descendants.add(child.id);
                    stack.push(child.id);
                }
            });
        }
        return descendants;
    };

    const forbiddenParentIds = mapToEdit ? getDescendants(mapToEdit.id) : new Set();
    if (mapToEdit) forbiddenParentIds.add(mapToEdit.id);

    return (
        <Modal isOpen={isOpen} onClose={onClose} title={step === 'details' ? (mapToEdit ? "Edit Map" : "New Map") : "Calibration"}>
            {step === 'details' ? (
                <div className="space-y-6">
                    <div className="space-y-4">
                        <div>
                            <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Map Name</label>
                            <input type="text" value={mapName} onChange={e => setMapName(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none focus:ring-1 focus:ring-amber-500" placeholder="e.g. The Blue Tavern" />
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Upload Image</label>
                                <label className="flex w-full cursor-pointer flex-col items-center justify-center rounded-xl border-2 border-dashed border-stone-600/50 bg-stone-800/40 p-4 hover:bg-stone-800/60 transition-colors">
                                    <Icon name="upload" className="mb-2 h-6 w-6 text-stone-400" />
                                    <span className="text-xs text-stone-400">{mapFile ? mapFile.name : "Select File"}</span>
                                    <input type="file" className="hidden" accept="image/*" onChange={handleFileChange} />
                                </label>
                            </div>
                            <div>
                                <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Or Image URL</label>
                                <input type="url" value={mapUrl && mapUrl.length < 100 ? mapUrl : ''} onChange={e => { setMapUrl(e.target.value); setMapFile(null); }} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none focus:ring-1 focus:ring-amber-500" placeholder="https://..." disabled={!!mapFile} />
                            </div>
                        </div>

                        <div>
                            <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Parent Map</label>
                            <select
                                value={parentMapId || ''}
                                onChange={e => setParentMapId(e.target.value || null)}
                                className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none focus:ring-1 focus:ring-amber-500"
                            >
                                <option value="" className="bg-stone-800">None (Top Level)</option>
                                {maps
                                    .filter(m => !forbiddenParentIds.has(m.id))
                                    .sort((a, b) => a.name.localeCompare(b.name))
                                    .map(m => (
                                        <option key={m.id} value={m.id} className="bg-stone-800">{m.name}</option>
                                    ))}
                            </select>
                            <p className="text-xs text-stone-600 mt-1">Select a parent to nest this map inside another.</p>
                        </div>

                         <label className="flex cursor-pointer items-center justify-between rounded-xl bg-stone-800/40 border border-stone-700/30 p-4">
                            <div className="flex flex-col">
                                <span className="font-medium text-stone-300">Visible to Players</span>
                                <span className="text-xs text-stone-500">If unchecked, this map will be hidden from players sidebar.</span>
                            </div>
                            <button
                                type="button"
                                onClick={() => setIsVisible(!isVisible)}
                                className={`relative inline-flex h-6 w-11 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none focus:ring-2 focus:ring-amber-500 focus:ring-offset-2 focus:ring-offset-stone-900 ${isVisible ? 'bg-amber-600' : 'bg-stone-700'}`}
                                >
                                <span className={`inline-block h-5 w-5 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${isVisible ? 'translate-x-5' : 'translate-x-0'}`} />
                            </button>
                        </label>
                    </div>

                    {error && <p className="text-sm text-red-400 bg-red-900/20 p-3 rounded-xl border border-red-900/50">{error}</p>}

                    <div className="flex gap-3 pt-4 border-t border-stone-800">
                        <button onClick={onClose} className="bg-stone-700 hover:bg-stone-600 text-stone-300 font-bold py-3 px-6 rounded-xl transition-all">Cancel</button>
                        <button onClick={handleNext} className="flex-1 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all">Next: Calibration</button>
                    </div>
                </div>
            ) : (
                <div className="space-y-6 h-full flex flex-col">
                    {/* Calibration Content */}
                    <p className="text-stone-400 text-sm">Align the grid and set pin size.</p>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="bg-stone-800/40 p-4 rounded-xl border border-stone-700/30 space-y-4">
                             <div>
                                <label className="flex justify-between text-xs font-bold uppercase text-stone-500 mb-2">
                                    <span>Grid Size (px)</span>
                                    <span className="text-amber-500">{gridSize}px</span>
                                </label>
                                <input type="range" min="20" max="200" value={gridSize} onChange={e => setGridSize(Number(e.target.value))} className="w-full h-2 bg-stone-700 rounded-lg appearance-none cursor-pointer accent-amber-600" />
                            </div>

                            <div>
                                <label className="flex justify-between text-xs font-bold uppercase text-stone-500 mb-2">
                                    <span>Pin Size (px)</span>
                                    <span className="text-amber-500">{pinScale}px</span>
                                </label>
                                <input type="range" min="10" max="200" value={pinScale} onChange={e => setPinScale(Number(e.target.value))} className="w-full h-2 bg-stone-700 rounded-lg appearance-none cursor-pointer accent-amber-600" />
                            </div>

                            <label className="flex cursor-pointer items-center justify-between pt-2">
                                <span className="font-medium text-stone-300 text-sm">Show Grid Overlay</span>
                                <button
                                    type="button"
                                    onClick={() => setIsGridVisible(!isGridVisible)}
                                    className={`relative inline-flex h-6 w-11 flex-shrink-0 cursor-pointer rounded-full border-2 border-transparent transition-colors duration-200 ease-in-out focus:outline-none focus:ring-2 focus:ring-amber-500 focus:ring-offset-2 focus:ring-offset-stone-900 ${isGridVisible ? 'bg-amber-600' : 'bg-stone-700'}`}
                                    >
                                    <span className={`inline-block h-5 w-5 transform rounded-full bg-white shadow ring-0 transition duration-200 ease-in-out ${isGridVisible ? 'translate-x-5' : 'translate-x-0'}`} />
                                </button>
                            </label>
                        </div>

                        <div className="bg-stone-950 rounded-xl border border-stone-700/50 overflow-auto h-64 relative shadow-inner custom-scrollbar">
                            <div className="relative min-w-max min-h-max">
                                {mapUrl ? (
                                     <img src={mapUrl} alt="Preview" className="max-w-none opacity-80" />
                                ) : (
                                    <div className="flex items-center justify-center h-full w-full p-10 text-stone-600">No Image</div>
                                )}
                                <div 
                                    className="absolute inset-0 pointer-events-none opacity-50"
                                    style={{
                                        backgroundSize: `${gridSize}px ${gridSize}px`,
                                        backgroundImage: `linear-gradient(to right, rgba(255, 255, 255, 0.5) 1px, transparent 1px), linear-gradient(to bottom, rgba(255, 255, 255, 0.5) 1px, transparent 1px)`
                                    }}
                                />
                                <div 
                                    className="absolute flex items-center justify-center rounded-full bg-amber-500 shadow-lg shadow-black/50 ring-2 ring-white"
                                    style={{
                                        top: `${gridSize}px`,
                                        left: `${gridSize}px`,
                                        width: `${pinScale}px`,
                                        height: `${pinScale}px`,
                                        fontSize: `${pinScale * 0.6}px`
                                    }}
                                >
                                    📍
                                </div>
                            </div>
                        </div>
                    </div>

                    <div className="flex gap-3 pt-4 border-t border-stone-700/50 mt-auto">
                        <button onClick={() => setStep('details')} className="flex-1 bg-stone-700 hover:bg-stone-600 text-stone-200 font-bold py-3 px-6 rounded-xl transition-all">Back</button>
                        <button onClick={handleSubmit} disabled={submitting} className="flex-1 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all">
                            {submitting ? <Icon name="spinner" className="h-5 w-5 animate-spin mx-auto"/> : 'Save Map'}
                        </button>
                    </div>
                </div>
            )}
        </Modal>
    );
};


// --- MAP MANAGER MODAL (List View) ---
interface MapManagerModalProps { isOpen: boolean; onClose: () => void; }
export const MapManagerModal: React.FC<MapManagerModalProps> = ({ isOpen, onClose }) => {
    const { maps, refreshData } = useAppContext();
    const [isEditorOpen, setIsEditorOpen] = useState(false);
    const [mapToEdit, setMapToEdit] = useState<MapType | null>(null);
    const [error, setError] = useState('');

    const handleCreate = () => {
        setMapToEdit(null);
        setIsEditorOpen(true);
    };

    const handleEdit = (map: MapType) => {
        setMapToEdit(map);
        setIsEditorOpen(true);
    };

    const handleDelete = async (map: MapType) => {
        if (!window.confirm(`Are you sure you want to delete "${map.name}"? This cannot be undone.`)) return;
        setError('');

        await supabase.from('pins').update({ linked_map_id: null }).eq('linked_map_id', map.id);
        await supabase.from('maps').update({ parent_map_id: null }).eq('parent_map_id', map.id);

        const { data: mapPins } = await supabase.from('pins').select('id').eq('map_id', map.id);
        if (mapPins && mapPins.length > 0) {
            const pinIds = mapPins.map(p => p.id);
            await supabase.from('comments').delete().in('pin_id', pinIds);
            await supabase.from('pins').delete().in('id', pinIds);
        }

        const { error: deleteError } = await supabase.from('maps').delete().eq('id', map.id);

        if (deleteError) {
            setError(`Error deleting map: ${deleteError.message}`);
        } else {
            await refreshData(true);
        }
    };

    return (
        <>
            <Modal isOpen={isOpen && !isEditorOpen} onClose={onClose} title="Manage Maps">
                <div className="space-y-6">
                    <button onClick={handleCreate} className="w-full flex items-center justify-center space-x-2 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-4 rounded-xl shadow-lg transition-all">
                        <Icon name="upload" className="h-5 w-5" />
                        <span>Add New Map</span>
                    </button>

                    {error && <p className="text-sm text-red-400 bg-red-900/20 p-3 rounded-xl border border-red-900/50">{error}</p>}

                    <div className="space-y-3">
                        <h3 className="text-xs font-bold uppercase text-stone-500">Existing Maps</h3>
                        {maps.length > 0 ? maps.sort((a,b) => a.name.localeCompare(b.name)).map(map => (
                            <div key={map.id} className="flex items-center justify-between rounded-xl p-3 border border-stone-700/30 bg-stone-800/40">
                                <div>
                                    <div className="flex items-center gap-2">
                                        <span className="font-medium text-stone-300 block">{map.name}</span>
                                        {!map.is_visible && <Icon name="eye-off" className="w-4 h-4 text-stone-600" title="Hidden from players" />}
                                    </div>
                                    {map.parent_map_id && <span className="text-xs text-stone-500">↳ Child map</span>}
                                </div>
                                <div className="flex gap-2">
                                     <button onClick={() => handleEdit(map)} className="rounded-full p-2 text-stone-500 transition-colors hover:bg-stone-700 hover:text-amber-500" title="Edit Map">
                                        <Icon name="pencil" className="h-5 w-5" />
                                    </button>
                                    <button onClick={() => handleDelete(map)} className="rounded-full p-2 text-stone-500 transition-colors hover:bg-red-900/20 hover:text-red-400" title="Delete Map">
                                        <Icon name="trash" className="h-5 w-5" />
                                    </button>
                                </div>
                            </div>
                        )) : (
                            <p className="text-sm text-stone-600 italic">No maps yet.</p>
                        )}
                    </div>
                </div>
            </Modal>

            {isEditorOpen && (
                <MapEditorModal 
                    isOpen={isEditorOpen} 
                    onClose={() => setIsEditorOpen(false)} 
                    mapToEdit={mapToEdit} 
                />
            )}
        </>
    );
};

// PinTypeManagerModal
interface PinTypeManagerProps { isOpen: boolean; onClose: () => void; }
export const PinTypeManagerModal: React.FC<PinTypeManagerProps> = ({ isOpen, onClose }) => {
    const { user } = useAuth();
    const { pinTypes, refreshData } = useAppContext();
    const [name, setName] = useState('');
    const [emoji, setEmoji] = useState('');
    const [color, setColor] = useState('#f59e0b');
    const [editingId, setEditingId] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);

    const resetForm = () => {
        setName('');
        setEmoji('');
        setColor('#f59e0b');
        setEditingId(null);
        setError(null);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!name || !user) return;
        setError(null);

        let result;

        if (editingId) {
            result = await supabase.from('pin_types').update({ name, emoji, color }).eq('id', editingId);
        } else {
            result = await supabase.from('pin_types').insert({ name, emoji, color, created_by: user.id });
        }

        if (result.error) {
            console.error("Error saving pin type:", result.error);
            setError(result.error.message);
            return;
        }

        resetForm();
        await refreshData(true);
    };

    const handleEdit = (pt: PinType) => {
        setName(pt.name);
        setEmoji(pt.emoji || '');
        setColor(pt.color);
        setEditingId(pt.id);
        setError(null);
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm('Delete this pin type?')) return;
        setError(null);
        const { error } = await supabase.from('pin_types').delete().eq('id', id);
        if (error) {
            console.error("Error deleting pin type:", error);
            setError(error.message);
            return;
        }

        if (editingId === id) resetForm();
        await refreshData(true);
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title={editingId ? "Edit Pin Type" : "Manage Pin Types"}>
            <form onSubmit={handleSubmit} className="space-y-4">
                <div className="grid grid-cols-1 gap-4 sm:grid-cols-3">
                    <input type="text" placeholder="Name" value={name} onChange={e => setName(e.target.value)} required className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 placeholder-stone-500 transition-colors focus:border-amber-500 focus:outline-none focus:ring-1 focus:ring-amber-500 sm:col-span-2" />
                    <input type="text" placeholder="Emoji" value={emoji} onChange={e => setEmoji(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-center text-xl text-stone-200 placeholder-stone-500 transition-colors focus:border-amber-500 focus:outline-none focus:ring-1 focus:ring-amber-500" />
                </div>
                <div className="relative">
                    <label className="mb-2 block text-xs font-bold uppercase text-stone-500">Pin Color</label>
                    <input type="color" value={color} onChange={e => setColor(e.target.value)} className="absolute h-12 w-full cursor-pointer opacity-0" />
                    <div className="pointer-events-none flex h-12 w-full items-center justify-between rounded-xl px-4 border border-stone-600/50" style={{ backgroundColor: color }}>
                        <span className="font-mono text-lg text-white mix-blend-difference">{color.toUpperCase()}</span>
                        <Icon name="brush" className="h-5 w-5 text-white mix-blend-difference" />
                    </div>
                </div>
                {error && <div className="p-3 bg-red-900/20 border border-red-800/50 rounded-xl text-red-300 text-sm">{error}</div>}
                <div className="flex gap-3">
                    {editingId && (
                        <button type="button" onClick={resetForm} className="flex-1 bg-stone-700 hover:bg-stone-600 text-stone-200 font-bold py-3 px-6 rounded-xl transition-all">
                            Cancel
                        </button>
                    )}
                    <button type="submit" className="flex-1 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg hover:shadow-amber-900/20 transition-all hover:scale-[1.02] active:scale-[0.98]">
                        {editingId ? 'Update Pin Type' : 'Add New Pin Type'}
                    </button>
                </div>
            </form>
            <div className="mt-8 space-y-3">
                 <h3 className="text-xs font-bold uppercase text-stone-500">Existing Types</h3>
                {pinTypes.map(pt => (
                    <div key={pt.id} className="flex items-center justify-between rounded-xl bg-stone-800/40 border border-stone-700/30 p-3">
                        <div className="flex items-center gap-3">
                            <span className="flex h-8 w-8 items-center justify-center rounded-full text-xl shadow-sm" style={{ backgroundColor: pt.color }}>{pt.emoji}</span>
                            <span className="font-semibold text-stone-300">{pt.name}</span>
                        </div>
                        <div className="flex gap-2">
                            <button onClick={() => handleEdit(pt)} className="rounded-full p-2 text-stone-500 transition-colors hover:bg-stone-700 hover:text-amber-500">
                                <Icon name="pencil" className="h-5 w-5" />
                            </button>
                            <button onClick={() => handleDelete(pt.id)} className="rounded-full p-2 text-stone-500 transition-colors hover:bg-red-900/20 hover:text-red-400">
                                <Icon name="trash" className="h-5 w-5" />
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        </Modal>
    );
};

// --- PIN EDITOR MODAL ---
interface PinEditorModalProps {
    pinData: Partial<Pin>;
    onClose: () => void;
    onSave: () => void;
}

export const PinEditorModal: React.FC<PinEditorModalProps> = ({ pinData, onClose, onSave }) => {
    const { user } = useAuth();
    const { maps, pinTypes } = useAppContext();

    // Safety check for coordinates if they came from a malformed upstream
    const xCoord = pinData.x_coord !== undefined ? pinData.x_coord : (pinData as any).x;
    const yCoord = pinData.y_coord !== undefined ? pinData.y_coord : (pinData as any).y;

    const [title, setTitle] = useState(pinData.title || '');
    const [typeId, setTypeId] = useState(pinData.pin_type_id || (pinTypes.length > 0 ? pinTypes[0].id : ''));
    const [desc, setDesc] = useState(pinData.data?.description || '');
    const [linkedMapId, setLinkedMapId] = useState(pinData.linked_map_id || '');
    const [isVisible, setIsVisible] = useState(pinData.is_visible !== false);

    // Preserve sections.
    const sections = pinData.data?.sections || [];
    const images = pinData.data?.images || [];
    const encounterFile = pinData.data?.encounter_file || null;

    const [submitting, setSubmitting] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user || !pinData.map_id) return;
        setSubmitting(true);

        const payload = {
            map_id: pinData.map_id,
            pin_type_id: typeId,
            x_coord: xCoord,
            y_coord: yCoord,
            title,
            data: {
                description: desc,
                images,
                sections,
                encounter_file: encounterFile
            },
            linked_map_id: linkedMapId || null,
            is_visible: isVisible,
            created_by: pinData.created_by || user.id
        };

        let result;
        if (pinData.id) {
             result = await supabase.from('pins').update(payload).eq('id', pinData.id);
        } else {
             result = await supabase.from('pins').insert(payload);
        }

        if (result.error) {
            console.error(result.error);
            alert(`Error: ${result.error.message}`);
        } else {
            onSave();
        }
        setSubmitting(false);
    };

    const handleDelete = async () => {
        if(!pinData.id || !window.confirm("Delete this pin?")) return;
        const { error } = await supabase.from('pins').delete().eq('id', pinData.id);
        if(!error) onSave();
    };

    return (
        <Modal isOpen={true} onClose={onClose} title={pinData.id ? "Edit Pin" : "New Pin"}>
            <form onSubmit={handleSubmit} className="space-y-4">
                <div className="flex gap-4">
                    <div className="flex-1">
                        <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Title</label>
                        <input autoFocus type="text" value={title} onChange={e => setTitle(e.target.value)} required className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                    </div>
                    <div>
                         <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Type</label>
                         <select value={typeId} onChange={e => setTypeId(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none appearance-none">
                             {pinTypes.map(pt => (
                                 <option key={pt.id} value={pt.id}>{pt.emoji} {pt.name}</option>
                             ))}
                         </select>
                    </div>
                </div>

                <div>
                    <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Description</label>
                    <textarea value={desc} onChange={e => setDesc(e.target.value)} rows={4} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                         <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Link to Map (Optional)</label>
                         <select value={linkedMapId} onChange={e => setLinkedMapId(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none">
                             <option value="">None</option>
                             {maps.filter(m => m.id !== pinData.map_id).map(m => (
                                 <option key={m.id} value={m.id}>{m.name}</option>
                             ))}
                         </select>
                    </div>
                    <div className="flex items-center pt-6">
                        <label className="flex items-center gap-2 cursor-pointer select-none">
                            <input type="checkbox" checked={isVisible} onChange={e => setIsVisible(e.target.checked)} className="rounded border-stone-600 bg-stone-800 text-amber-600 focus:ring-amber-500" />
                            <span className="text-stone-300 font-medium">Visible to Players</span>
                        </label>
                    </div>
                </div>

                <div className="flex gap-3 pt-4 border-t border-stone-800">
                    {pinData.id && (
                         <button type="button" onClick={handleDelete} className="bg-red-900/20 hover:bg-red-900/40 text-red-400 font-bold py-3 px-4 rounded-xl transition-all">
                             <Icon name="trash" className="h-5 w-5" />
                         </button>
                    )}
                    <div className="flex-1 flex gap-3">
                        <button type="button" onClick={onClose} className="flex-1 bg-stone-700 hover:bg-stone-600 text-stone-300 font-bold py-3 px-6 rounded-xl transition-all">Cancel</button>
                        <button type="submit" disabled={submitting} className="flex-1 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all">
                            {submitting ? <Icon name="spinner" className="h-5 w-5 animate-spin mx-auto"/> : 'Save Pin'}
                        </button>
                    </div>
                </div>
            </form>
        </Modal>
    );
};

import React, { useState, useEffect, createContext, useContext, useCallback } from 'react';
import { useAuth } from '../App';
import { Map as MapType, Pin, PinType, Character } from '../types';
import { supabase } from '../services/supabase';
import Sidebar from './Sidebar';
import MapViewer from './MapViewer';
import PinDetails from './PinDetails';
import Wiki from './Wiki';
import { MapManagerModal, PinEditorModal, PinTypeManagerModal, PlayerManagerModal, CharacterManagerModal } from './Modals';
import { Icon } from './Icons';

type AppContextType = {
    maps: MapType[];
    pinTypes: PinType[];
    pins: Pin[];
    characters: Character[];
    isPlayerView: boolean;
    refreshData: (silent?: boolean) => Promise<void>;
    setIsPlayerView: React.Dispatch<React.SetStateAction<boolean>>;
};

const AppContext = createContext<AppContextType | null>(null);
export const useAppContext = () => {
    const context = useContext(AppContext);
    if (!context) throw new Error('useAppContext must be used within an AppContextProvider');
    return context;
};

const Dashboard: React.FC = () => {
    const { user } = useAuth();
    const [maps, setMaps] = useState<MapType[]>([]);
    const [pinTypes, setPinTypes] = useState<PinType[]>([]);
    const [pins, setPins] = useState<Pin[]>([]);
    const [characters, setCharacters] = useState<Character[]>([]);

    // View State
    const [currentView, setCurrentView] = useState<'map' | 'wiki'>('map');
    const [selectedMap, setSelectedMap] = useState<MapType | null>(null);
    const [selectedPin, setSelectedPin] = useState<Pin | null>(null);

    // Highlight State (for locating pins from Wiki)
    const [highlightedPinId, setHighlightedPinId] = useState<string | null>(null);

    const [isPlayerView, setIsPlayerView] = useState(user?.profile.role === 'Player');
    const [loading, setLoading] = useState(true);

    // Modal states
    const [isMapManagerOpen, setMapManagerOpen] = useState(false);
    const [isPinTypeManagerOpen, setPinTypeManagerOpen] = useState(false);
    const [isPlayerManagerOpen, setPlayerManagerOpen] = useState(false);
    const [isCharacterManagerOpen, setCharacterManagerOpen] = useState(false);
    const [editingPin, setEditingPin] = useState<Partial<Pin> | null>(null);

    useEffect(() => {
        if (user) {
            setIsPlayerView(user.profile.role === 'Player');
        }
    }, [user?.id]);

    const refreshData = useCallback(async (silent = false) => {
        if (!user) return;
        if (!silent) setLoading(true);

        const fetchMaps = supabase.from('maps').select('*');
        const { data: mapsData, error: mapsError } = await (user.profile.role === 'DM' ? fetchMaps : fetchMaps.eq('is_visible', true));

        const { data: pinTypesData, error: pinTypesError } = await supabase.from('pin_types').select('*');

        if (mapsData) setMaps(mapsData);
        if (pinTypesData) setPinTypes(pinTypesData);
        if (mapsError) console.error("Error fetching maps", mapsError);
        if (pinTypesError) console.error("Error fetching pin types", pinTypesError);

        // Fetch ALL pins for the wiki search, but map viewer filters by selected map
        const fetchPins = supabase.from('pins').select('*, pin_types(*)');
        const { data: pinsData, error: pinsError } = await (user.profile.role === 'DM' && !isPlayerView ? fetchPins : fetchPins.eq('is_visible', true));
        if (pinsData) setPins(pinsData as Pin[]);

        // Fetch Characters
        const { data: charData, error: charError } = await supabase.from('characters').select('*');
        if (charData) setCharacters(charData as Character[]);
        if (charError) {
             // Swallow error if table doesn't exist yet to prevent app crash on older DBs
             if(charError.code !== '42P01') console.error("Error fetching characters", charError);
        }

        if (!silent) setLoading(false);
    }, [user, isPlayerView]);

    useEffect(() => {
        refreshData();
    }, [refreshData]);

    const handleSelectMap = (map: MapType | null) => {
        setSelectedMap(map);
        setSelectedPin(null);
        setHighlightedPinId(null);
        setCurrentView('map'); // Switch to map view when selecting from sidebar
    };

    const handlePinSave = async () => {
        setEditingPin(null);
        await refreshData(true);
    };

    if (loading) {
        return <div className="flex h-screen w-full items-center justify-center bg-stone-950"><Icon name="spinner" className="h-10 w-10 animate-spin text-amber-500" /></div>;
    }

    return (
        <AppContext.Provider value={{ maps, pinTypes, pins, characters, isPlayerView, refreshData, setIsPlayerView }}>
            <div className="flex h-screen w-full flex-col md:flex-row overflow-hidden bg-stone-950 text-stone-200">
                <Sidebar
                    selectedMap={selectedMap}
                    onSelectMap={handleSelectMap}
                    currentView={currentView}
                    onViewChange={setCurrentView}
                    onMapManagerOpen={() => setMapManagerOpen(true)}
                    onPinTypeManagerOpen={() => setPinTypeManagerOpen(true)}
                    onPlayerManagerOpen={() => setPlayerManagerOpen(true)}
                    onCharacterManagerOpen={() => setCharacterManagerOpen(true)}
                />
                <main className="relative flex-1 bg-stone-950 overflow-hidden">
                    {currentView === 'map' ? (
                        <>
                            {selectedMap ? (
                                <MapViewer
                                    map={selectedMap}
                                    onSelectPin={(pin) => {
                                        setSelectedPin(pin);
                                        setHighlightedPinId(null); // Clear highlight on user interaction
                                    }}
                                    onAddPin={(coords) => {
                                        if (user?.profile.role === 'DM' && !isPlayerView) {
                                            setEditingPin({ x_coord: coords.x, y_coord: coords.y, map_id: selectedMap.id });
                                            setHighlightedPinId(null);
                                        }
                                    }}
                                    highlightedPinId={highlightedPinId}
                                />
                            ) : (
                                <div className="flex h-full w-full items-center justify-center text-stone-500">
                                    <div className="text-center">
                                        <Icon name="map" className="mx-auto h-16 w-16 opacity-30 mb-4" />
                                        <p className="text-lg font-medieval">Select a map to begin</p>
                                    </div>
                                </div>
                            )}
                            <PinDetails 
                                pin={selectedPin} 
                                onClose={() => setSelectedPin(null)} 
                                onEdit={(pin) => setEditingPin(pin)}
                                mapId={selectedMap?.id}
                            />
                        </>
                    ) : (
                        <Wiki 
                            onSelectMap={(map) => handleSelectMap(map)}
                            onLocatePin={(pin) => {
                                const map = maps.find(m => m.id === pin.map_id);
                                if(map) {
                                    setSelectedMap(map);
                                    setHighlightedPinId(pin.id); // Set the highlight
                                    setSelectedPin(null); // Ensure detail view is closed
                                    setCurrentView('map');
                                }
                            }}
                        />
                    )}

                    {isMapManagerOpen && <MapManagerModal isOpen={isMapManagerOpen} onClose={() => setMapManagerOpen(false)} />}
                    {isPinTypeManagerOpen && <PinTypeManagerModal isOpen={isPinTypeManagerOpen} onClose={() => setPinTypeManagerOpen(false)} />}
                    {isPlayerManagerOpen && <PlayerManagerModal isOpen={isPlayerManagerOpen} onClose={() => setPlayerManagerOpen(false)} />}
                    {isCharacterManagerOpen && <CharacterManagerModal isOpen={isCharacterManagerOpen} onClose={() => setCharacterManagerOpen(false)} />}
                    {editingPin && (
                        <PinEditorModal 
                            pinData={editingPin} 
                            onClose={() => setEditingPin(null)} 
                            onSave={handlePinSave} 
                        />
                    )}
                </main>
            </div>
        </AppContext.Provider>
    );
};

