// Helper to convert file to Base64
const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => resolve(reader.result as string);
        reader.onerror = error => reject(error);
    });
};

// Reusable Modal Wrapper
interface ModalProps {
    isOpen: boolean;
    onClose: () => void;
    title: string;
    children: React.ReactNode;
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children }) => {
    useEffect(() => {
        const handleEscape = (event: KeyboardEvent) => {
            if (event.key === 'Escape') {
                onClose();
            }
        };
        document.addEventListener('keydown', handleEscape);
        return () => {
            document.removeEventListener('keydown', handleEscape);
        };
    }, [onClose]);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={onClose} role="dialog" aria-modal="true">
            <div className="w-full max-w-2xl rounded-3xl bg-stone-900/95 backdrop-blur-2xl border border-stone-700/50 p-6 shadow-2xl animate-modal-in flex flex-col max-h-[90vh]" onClick={(e) => e.stopPropagation()}>
                <div className="flex items-center justify-between border-b border-stone-700/50 pb-4 mb-4 flex-shrink-0">
                    <h2 className="text-2xl font-medieval font-bold text-amber-500">{title}</h2>
                    <button onClick={onClose} className="rounded-full p-2 text-stone-500 transition-colors hover:bg-stone-800 hover:text-stone-300">
                        <Icon name="close" className="h-6 w-6" />
                    </button>
                </div>
                <div className="overflow-y-auto pr-2 custom-scrollbar flex-1">{children}</div>
            </div>
        </div>
    );
};

// --- PLAYER MANAGER MODAL ---
interface PlayerManagerModalProps { isOpen: boolean; onClose: () => void; }
export const PlayerManagerModal: React.FC<PlayerManagerModalProps> = ({ isOpen, onClose }) => {
    const [username, setUsername] = useState('');
    const [role, setRole] = useState<'Player' | 'DM'>('Player');
    const [loading, setLoading] = useState(false);
    const [status, setStatus] = useState<{ type: 'success' | 'error', msg: string } | null>(null);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setStatus(null);

        const trimmedUsername = username.trim();
        if (!trimmedUsername) {
            setStatus({ type: 'error', msg: 'Username is required.' });
            setLoading(false);
            return;
        }

        const usernameRegex = /^[a-zA-Z0-9_-]+$/;
        if (!usernameRegex.test(trimmedUsername)) {
            setStatus({ type: 'error', msg: 'Username can only contain letters, numbers, hyphens, and underscores.' });
            setLoading(false);
            return;
        }

        // Generate dummy credentials based on app pattern
        const lowerCaseUsername = trimmedUsername.toLowerCase();
        const dummyEmail = `${lowerCaseUsername}@dnd-map-login.local`;
        const dummyPassword = `DUMMY_PASSWORD_FOR_${lowerCaseUsername}`;

        // CRITICAL: We use a separate Supabase client to create the user.
        // If we used the main `supabase` instance, calling signUp would log out the current DM.
        const tempClient = createClient(supabaseUrl, supabaseAnonKey, {
            auth: {
                persistSession: false, // Don't save this session to localStorage
                autoRefreshToken: false,
                detectSessionInUrl: false,
                storageKey: 'temp-auth-client' // Use distinct key to reduce warnings
            }
        });

        const { data: authData, error: signUpError } = await tempClient.auth.signUp({
            email: dummyEmail,
            password: dummyPassword,
            options: {
                data: { username: trimmedUsername, role: role }
            }
        });

        if (signUpError) {
            setStatus({ type: 'error', msg: signUpError.message });
            setLoading(false);
            return;
        }

        if (authData.user) {
            // Manually insert into public.users to ensure profile exists immediately
            // This is redundant if the trigger works, but safe to ensure immediate consistency
            const { error: profileError } = await supabase.from('users').insert({
                id: authData.user.id,
                username: trimmedUsername,
                role: role,
                password_hash: 'managed_by_supabase_auth' // Required by DB constraint
            });

            if (profileError && profileError.code !== '23505') { // Ignore unique constraint if trigger beat us to it
                 console.error("Profile creation warning:", profileError);
            }

            setStatus({ type: 'success', msg: `User '${trimmedUsername}' created successfully!` });
            setUsername('');
        }

        setLoading(false);
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Add New User">
            <form onSubmit={handleSubmit} className="space-y-6">
                <div className="bg-stone-800/40 p-4 rounded-xl border border-stone-700/50 mb-4">
                    <p className="text-sm text-stone-300">
                        Create a new account for your players. They will log in using only the username provided below.
                    </p>
                </div>

                <div>
                    <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Username</label>
                    <input 
                        type="text" 
                        value={username} 
                        onChange={e => setUsername(e.target.value)} 
                        className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none focus:ring-1 focus:ring-amber-500" 
                        placeholder="e.g. Aragorn" 
                    />
                </div>

                <div>
                    <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Role</label>
                    <div className="flex gap-4">
                        <label className={`flex-1 cursor-pointer rounded-xl border px-4 py-3 text-center transition-all ${role === 'Player' ? 'bg-amber-900/30 border-amber-500 text-amber-500' : 'bg-stone-800/40 border-stone-700 text-stone-400 hover:bg-stone-800'}`}>
                            <input type="radio" className="hidden" checked={role === 'Player'} onChange={() => setRole('Player')} />
                            <span className="font-bold">Player</span>
                        </label>
                        <label className={`flex-1 cursor-pointer rounded-xl border px-4 py-3 text-center transition-all ${role === 'DM' ? 'bg-amber-900/30 border-amber-500 text-amber-500' : 'bg-stone-800/40 border-stone-700 text-stone-400 hover:bg-stone-800'}`}>
                            <input type="radio" className="hidden" checked={role === 'DM'} onChange={() => setRole('DM')} />
                            <span className="font-bold">Dungeon Master</span>
                        </label>
                    </div>
                </div>

                {status && (
                    <div className={`p-4 rounded-xl border text-sm ${status.type === 'success' ? 'bg-green-900/20 border-green-800/50 text-green-300' : 'bg-red-900/20 border-red-800/50 text-red-300'}`}>
                        {status.msg}
                    </div>
                )}

                <button 
                    type="submit" 
                    disabled={loading}
                    className="w-full bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg hover:shadow-amber-900/20 transition-all hover:scale-[1.02] active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    {loading ? <Icon name="spinner" className="h-5 w-5 animate-spin mx-auto"/> : 'Create User'}
                </button>
            </form>
        </Modal>
    );
};

// --- CHARACTER MANAGER MODAL ---
interface CharacterManagerModalProps { isOpen: boolean; onClose: () => void; }
export const CharacterManagerModal: React.FC<CharacterManagerModalProps> = ({ isOpen, onClose }) => {
    const { user } = useAuth();
    const { characters, maps, pins, refreshData } = useAppContext();
    const [editingChar, setEditingChar] = useState<Partial<Character> | null>(null);
    const [isEditing, setIsEditing] = useState(false);

    // Form State
    const [name, setName] = useState('');
    const [race, setRace] = useState('');
    const [charClass, setCharClass] = useState('');
    const [level, setLevel] = useState(1);
    const [alignment, setAlignment] = useState('');
    const [backstory, setBackstory] = useState('');
    const [gmNotes, setGmNotes] = useState('');
    const [isNpc, setIsNpc] = useState(true);
    const [imageFile, setImageFile] = useState<File | null>(null);
    const [imageUrl, setImageUrl] = useState('');

    // Relationship & Location State
    const [relationships, setRelationships] = useState<CharacterRelationship[]>([]);
    const [currentPinId, setCurrentPinId] = useState<string | null>(null);
    const [selectedMapId, setSelectedMapId] = useState<string>(''); // For location picker UI only

    const [submitting, setSubmitting] = useState(false);

    // Filtered pins for location picker
    const mapPins = useMemo(() => {
        if (!selectedMapId) return [];
        return pins.filter(p => p.map_id === selectedMapId);
    }, [selectedMapId, pins]);

    const resetForm = () => {
        setName(''); setRace(''); setCharClass(''); setLevel(1); setAlignment('');
        setBackstory(''); setGmNotes(''); setIsNpc(true); setImageFile(null); setImageUrl('');
        setRelationships([]); setCurrentPinId(null); setSelectedMapId('');
        setEditingChar(null);
        setIsEditing(false);
    };

    const handleEdit = (char: Character) => {
        setEditingChar(char);
        setName(char.name);
        setRace(char.role_details?.race || '');
        setCharClass(char.role_details?.class || '');
        setLevel(char.role_details?.level || 1);
        setAlignment(char.role_details?.alignment || '');
        setBackstory(char.backstory || '');
        setGmNotes(char.gm_notes || '');
        setIsNpc(char.is_npc);
        setImageUrl(char.image_url || '');
        setRelationships(char.relationships || []);
        setCurrentPinId(char.current_pin_id || null);

        // Try to pre-fill map selector
        if (char.current_pin_id) {
            const pin = pins.find(p => p.id === char.current_pin_id);
            if (pin) setSelectedMapId(pin.map_id);
        } else {
            setSelectedMapId('');
        }

        setIsEditing(true);
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user || !name) return;
        setSubmitting(true);

        let finalImageUrl = imageUrl;
        if (imageFile) {
             finalImageUrl = await fileToBase64(imageFile);
        }

        const payload = {
            name,
            role_details: { race, class: charClass, level, alignment },
            backstory,
            gm_notes: gmNotes,
            image_url: finalImageUrl,
            is_npc: isNpc,
            relationships,
            current_pin_id: currentPinId,
            created_by: user.id
        };

        let result;
        if (editingChar && editingChar.id) {
            result = await supabase.from('characters').update(payload).eq('id', editingChar.id);
        } else {
            result = await supabase.from('characters').insert(payload);
        }

        if (result.error) {
            console.error("Error saving character:", result.error);
            alert("Error saving character. Ensure the database table 'characters' exists.");
        } else {
            await refreshData(true);
            resetForm();
        }
        setSubmitting(false);
    };

    const handleDelete = async (char: Character) => {
        if(!window.confirm(`Delete ${char.name}?`)) return;
        const { error } = await supabase.from('characters').delete().eq('id', char.id);
        if(!error) await refreshData(true);
    };

    // Relationship Helpers
    const addRelationship = () => {
        setRelationships([...relationships, { targetId: '', type: '', notes: '' }]);
    };

    const updateRelationship = (index: number, field: keyof CharacterRelationship, value: string) => {
        const newRels = [...relationships];
        newRels[index] = { ...newRels[index], [field]: value };
        setRelationships(newRels);
    };

    const removeRelationship = (index: number) => {
        setRelationships(relationships.filter((_, i) => i !== index));
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title={isEditing ? (editingChar ? "Edit Character" : "New Character") : "Manage Characters"}>
            {!isEditing ? (
                <div className="space-y-6">
                    <button onClick={() => setIsEditing(true)} className="w-full flex items-center justify-center space-x-2 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-4 rounded-xl shadow-lg transition-all">
                        <Icon name="plus" className="h-5 w-5" />
                        <span>Create New Character</span>
                    </button>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {characters.map(char => (
                             <div key={char.id} className="relative group bg-stone-800/40 border border-stone-700/50 rounded-xl p-4 flex gap-4 hover:bg-stone-800/60 transition-colors">
                                <div className="w-16 h-16 rounded-full bg-stone-900 overflow-hidden flex-shrink-0 border-2 border-stone-600 group-hover:border-amber-500 transition-colors">
                                    {char.image_url ? <img src={char.image_url} alt={char.name} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-stone-600 text-xs">No Img</div>}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <h3 className="font-medieval text-lg text-stone-200 truncate">{char.name}</h3>
                                    <p className="text-xs text-stone-500 uppercase tracking-wider font-bold mb-1">{char.is_npc ? 'NPC' : 'Player Character'}</p>
                                    <p className="text-xs text-stone-400 truncate">{char.role_details?.race} {char.role_details?.class} (Lvl {char.role_details?.level})</p>
                                    {char.current_pin_id && <p className="text-[10px] text-amber-500/80 mt-1 flex items-center gap-1"><Icon name="pin" className="w-3 h-3" /> Located on map</p>}
                                </div>
                                <div className="flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity absolute right-2 top-2">
                                     <button onClick={() => handleEdit(char)} className="p-1.5 rounded-lg bg-stone-900 text-stone-400 hover:text-amber-500"><Icon name="pencil" className="w-4 h-4" /></button>
                                     <button onClick={() => handleDelete(char)} className="p-1.5 rounded-lg bg-stone-900 text-stone-400 hover:text-red-500"><Icon name="trash" className="w-4 h-4" /></button>
                                </div>
                             </div>
                        ))}
                        {characters.length === 0 && <p className="col-span-2 text-center text-stone-500 italic py-8">No characters found.</p>}
                    </div>
                </div>
            ) : (
                <form onSubmit={handleSave} className="space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div className="md:col-span-2 flex items-center gap-4 bg-stone-800/30 p-4 rounded-xl border border-stone-700/30">
                            <label className="w-20 h-20 rounded-full bg-stone-900 border-2 border-dashed border-stone-600 flex items-center justify-center cursor-pointer hover:border-amber-500 overflow-hidden relative">
                                {imageUrl || (imageFile && URL.createObjectURL(imageFile)) ? (
                                    <img src={imageUrl || (imageFile ? URL.createObjectURL(imageFile) : '')} className="w-full h-full object-cover" />
                                ) : (
                                    <span className="text-xs text-stone-500 text-center">Upload<br/>Avatar</span>
                                )}
                                <input type="file" className="hidden" accept="image/*" onChange={e => {
                                    if(e.target.files?.[0]) { setImageFile(e.target.files[0]); setImageUrl(''); }
                                }} />
                            </label>
                            <div className="flex-1 space-y-2">
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input type="checkbox" checked={isNpc} onChange={e => setIsNpc(e.target.checked)} className="rounded border-stone-600 bg-stone-800 text-amber-600 focus:ring-amber-500" />
                                    <span className="text-sm font-bold text-stone-300">Is NPC?</span>
                                </label>
                                <input type="text" placeholder="Image URL (optional)" value={imageUrl} onChange={e => { setImageUrl(e.target.value); setImageFile(null); }} className="w-full rounded-lg border border-stone-600/50 bg-stone-900/40 px-3 py-2 text-sm text-stone-200" />
                            </div>
                        </div>

                        <input type="text" placeholder="Name" value={name} onChange={e => setName(e.target.value)} required className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 placeholder-stone-500 focus:border-amber-500 focus:outline-none" />
                        <input type="text" placeholder="Race" value={race} onChange={e => setRace(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 placeholder-stone-500 focus:border-amber-500 focus:outline-none" />
                        <input type="text" placeholder="Class" value={charClass} onChange={e => setCharClass(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 placeholder-stone-500 focus:border-amber-500 focus:outline-none" />

                        <div className="flex gap-2">
                            <input type="number" placeholder="Level" min="1" max="20" value={level} onChange={e => setLevel(parseInt(e.target.value))} className="w-24 rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 placeholder-stone-500 focus:border-amber-500 focus:outline-none" />
                            <input type="text" placeholder="Alignment" value={alignment} onChange={e => setAlignment(e.target.value)} className="flex-1 rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 placeholder-stone-500 focus:border-amber-500 focus:outline-none" />
                        </div>
                    </div>

                    <textarea placeholder="Backstory / Bio" value={backstory} onChange={e => setBackstory(e.target.value)} rows={4} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 placeholder-stone-500 focus:border-amber-500 focus:outline-none" />

                    {/* Location Picker */}
                    <div className="bg-stone-800/30 p-4 rounded-xl border border-stone-700/30 space-y-3">
                        <h4 className="text-sm font-bold uppercase text-stone-400 flex items-center gap-2"><Icon name="map" className="w-4 h-4" /> Current Location</h4>
                        <div className="grid grid-cols-2 gap-3">
                            <select value={selectedMapId} onChange={e => { setSelectedMapId(e.target.value); setCurrentPinId(null); }} className="rounded-lg border border-stone-600/50 bg-stone-900/40 px-3 py-2 text-sm text-stone-200 focus:outline-none">
                                <option value="">(Select Map)</option>
                                {maps.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                            </select>
                            <select 
                                value={currentPinId || ''} 
                                onChange={e => setCurrentPinId(e.target.value || null)} 
                                disabled={!selectedMapId}
                                className="rounded-lg border border-stone-600/50 bg-stone-900/40 px-3 py-2 text-sm text-stone-200 focus:outline-none disabled:opacity-50"
                            >
                                <option value="">(No Location / Hidden)</option>
                                {mapPins.map(p => <option key={p.id} value={p.id}>{p.title}</option>)}
                            </select>
                        </div>
                    </div>

                    {/* Relationships Editor */}
                    <div className="bg-stone-800/30 p-4 rounded-xl border border-stone-700/30 space-y-3">
                        <div className="flex justify-between items-center">
                            <h4 className="text-sm font-bold uppercase text-stone-400 flex items-center gap-2"><Icon name="user" className="w-4 h-4" /> Relationships</h4>
                            <button type="button" onClick={addRelationship} className="text-xs text-amber-500 hover:underline">+ Add</button>
                        </div>
                        {relationships.map((rel, idx) => (
                            <div key={idx} className="flex flex-col gap-2 p-2 bg-stone-900/40 rounded border border-stone-800">
                                <div className="flex gap-2">
                                    <select 
                                        value={rel.targetId} 
                                        onChange={e => updateRelationship(idx, 'targetId', e.target.value)} 
                                        className="flex-1 rounded border border-stone-600/50 bg-stone-800 text-xs text-stone-200 p-1"
                                    >
                                        <option value="">Select Character...</option>
                                        {characters.filter(c => c.id !== editingChar?.id).map(c => (
                                            <option key={c.id} value={c.id}>{c.name}</option>
                                        ))}
                                    </select>
                                    <input 
                                        type="text" 
                                        placeholder="Type (e.g. Rival)" 
                                        value={rel.type} 
                                        onChange={e => updateRelationship(idx, 'type', e.target.value)} 
                                        className="w-1/3 rounded border border-stone-600/50 bg-stone-800 text-xs text-stone-200 p-1"
                                    />
                                    <button type="button" onClick={() => removeRelationship(idx)} className="text-stone-500 hover:text-red-500 px-1"><Icon name="trash" className="w-3 h-3" /></button>
                                </div>
                                <input 
                                    type="text" 
                                    placeholder="Notes..." 
                                    value={rel.notes || ''} 
                                    onChange={e => updateRelationship(idx, 'notes', e.target.value)} 
                                    className="w-full rounded border border-stone-600/30 bg-stone-800 text-xs text-stone-400 p-1"
                                />
                            </div>
                        ))}
                        {relationships.length === 0 && <p className="text-xs text-stone-600 italic text-center">No relationships defined.</p>}
                    </div>

                    <textarea placeholder="GM Notes (Secret)" value={gmNotes} onChange={e => setGmNotes(e.target.value)} rows={2} className="w-full rounded-xl border border-red-900/30 bg-red-950/10 px-4 py-3 text-stone-200 placeholder-red-400/50 focus:border-red-500 focus:outline-none" />

                    <div className="flex gap-3 pt-4 border-t border-stone-700/50">
                        <button type="button" onClick={resetForm} className="flex-1 bg-stone-700 hover:bg-stone-600 text-stone-200 font-bold py-3 px-6 rounded-xl transition-all">Cancel</button>
                        <button type="submit" disabled={submitting} className="flex-1 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all">{submitting ? "Saving..." : "Save Character"}</button>
                    </div>
                </form>
            )}
        </Modal>
    );
};

import React, { useState, useEffect } from 'react';
import { Pin, Comment, PinSection, Character } from '../types';
import { useAuth } from '../App';
import { useAppContext } from './Dashboard';
import { supabase } from '../services/supabase';
import { Icon } from './Icons';

interface PinDetailsProps {
    pin: Pin | null;
    onClose: () => void;
    onEdit: (pin: Pin) => void;
    mapId: string | undefined;
}

const PinDetails: React.FC<PinDetailsProps> = ({ pin, onClose, onEdit, mapId }) => {
    const { user } = useAuth();
    const { isPlayerView, maps, characters, refreshData } = useAppContext();
    const [comments, setComments] = useState<Comment[]>([]);
    const [newComment, setNewComment] = useState('');
    const [isPrivateComment, setIsPrivateComment] = useState(false);

    // For expanding inventory items to show description
    const [expandedItem, setExpandedItem] = useState<string | null>(null);

    // Character summoning state
    const [isSummoning, setIsSummoning] = useState(false);
    const [viewingCharacter, setViewingCharacter] = useState<Character | null>(null);

    // Derived: Characters present at this pin
    const presentCharacters = pin ? characters.filter(c => c.current_pin_id === pin.id) : [];

    useEffect(() => {
        const fetchComments = async () => {
            if (pin) {
                const { data, error } = await supabase
                    .from('comments')
                    .select('*, users(username)')
                    .eq('pin_id', pin.id)
                    .order('created_at', { ascending: true });
                if (data) setComments(data as any);
                if (error) console.error("Error fetching comments", error);
            } else {
                setComments([]);
            }
        };
        fetchComments();
    }, [pin]);

    const handleAddComment = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newComment.trim() || !pin || !user) return;

        const { data, error } = await supabase
            .from('comments')
            .insert({
                pin_id: pin.id,
                user_id: user.id,
                text: newComment,
                is_private: isPrivateComment
            })
            .select('*, users(username)')
            .single();

        if (data) setComments([...comments, data as any]);
        if (error) console.error("Error adding comment", error);

        setNewComment('');
        setIsPrivateComment(false);
    };

    const handleMoveCharacter = async (charId: string, targetPinId: string | null) => {
        const { error } = await supabase.from('characters').update({ current_pin_id: targetPinId }).eq('id', charId);
        if(!error) {
            await refreshData(true);
            setIsSummoning(false);
        }
    };

    const handleDownloadEncounter = () => {
        if (!pin?.data.encounter_file) return;
        const blob = new Blob([pin.data.encounter_file.content], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = pin.data.encounter_file.name;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const getCharacterName = (id: string) => characters.find(c => c.id === id)?.name || "Unknown";

    const renderSection = (section: PinSection, index: number) => {
        // Render based on type
        switch (section.type) {
            case 'inventory':
                 return (
                    <div key={section.id || index} className="bg-stone-800/40 rounded-xl overflow-hidden border border-amber-900/30 shadow-md">
                        <h3 className="bg-amber-900/20 font-medieval text-lg text-amber-500 px-4 py-2 border-b border-amber-900/30 flex items-center justify-between">
                            {section.title || "Inventory"}
                            <Icon name="chest" className="w-5 h-5 opacity-70" />
                        </h3>
                        <div className="p-2 space-y-1">
                            {section.items && section.items.length > 0 ? section.items.map(item => (
                                <div key={item.id} className="rounded-lg bg-stone-900/40 border border-stone-800/50 overflow-hidden">
                                    <div 
                                        onClick={() => setExpandedItem(expandedItem === item.id ? null : item.id)}
                                        className="flex items-center justify-between p-3 cursor-pointer hover:bg-stone-800/50 transition-colors"
                                    >
                                        <div className="flex items-center gap-3">
                                            <span className="bg-stone-800 text-stone-400 text-xs font-mono px-2 py-0.5 rounded border border-stone-700">{item.count}x</span>
                                            <div>
                                                <p className={`font-medium text-sm ${item.is_magic ? 'text-amber-400' : 'text-stone-300'}`}>{item.name}</p>
                                                <div className="flex gap-2 text-[10px] text-stone-500 leading-none mt-0.5">
                                                    {item.rarity && <span className="text-purple-400/80">{item.rarity}</span>}
                                                    {item.category && <span>{item.category}</span>}
                                                </div>
                                            </div>
                                        </div>
                                        <Icon name={expandedItem === item.id ? 'chevron-down' : 'chevron-right'} className="w-4 h-4 text-stone-600" />
                                    </div>
                                    {expandedItem === item.id && item.desc && (
                                        <div className="px-3 pb-3 pt-0 text-xs text-stone-400 border-t border-stone-800/50 mt-1">
                                            <div className="py-2 prose prose-invert prose-p:my-1 max-w-none">
                                                {item.desc.split('\n').map((line, i) => <p key={i}>{line}</p>)}
                                            </div>
                                            {item.cost && <p className="text-amber-600 font-mono mt-2">Value: {item.cost}</p>}
                                        </div>
                                    )}
                                </div>
                            )) : (
                                <p className="text-center text-sm text-stone-600 py-4 italic">Empty.</p>
                            )}
                        </div>
                    </div>
                 );
            case 'image':
                return (
                    <div key={section.id || index} className="bg-stone-800/30 rounded-xl p-2 border border-stone-700/30 overflow-hidden">
                        {section.title && <h3 className="font-medieval text-lg text-stone-200 mb-2 px-2">{section.title}</h3>}
                        {section.image_url ? (
                            <img src={section.image_url} alt={section.title || 'Pin Image'} className="w-full h-auto rounded-lg shadow-md border border-stone-900/50" />
                        ) : (
                            <div className="w-full h-40 flex items-center justify-center bg-stone-900/50 rounded-lg text-stone-600 italic">No image provided</div>
                        )}
                        {section.content && <p className="text-sm text-stone-400 mt-2 px-2 pb-2 italic">{section.content}</p>}
                    </div>
                );
            case 'statblock':
                return (
                    <div key={section.id || index} className="bg-stone-800/40 rounded-xl overflow-hidden border border-amber-900/30 shadow-md">
                        <h3 className="bg-amber-900/20 font-medieval text-lg text-amber-500 px-4 py-2 border-b border-amber-900/30 flex items-center justify-between">
                            {section.title}
                            <Icon name="shield" className="w-4 h-4 opacity-70" />
                        </h3>
                        <div className="p-4">
                            {section.content && <p className="text-sm text-stone-400 mb-3 italic">{section.content}</p>}
                            <div className="grid grid-cols-2 gap-2">
                                {section.stats?.map((stat, i) => (
                                    <div key={i} className="flex flex-col bg-stone-900/50 p-2 rounded border border-stone-800">
                                        <span className="text-xs uppercase tracking-wider text-amber-600/80 font-bold">{stat.label}</span>
                                        <span className="text-stone-200 font-medieval text-lg">{stat.value}</span>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                );
            case 'list':
                return (
                    <div key={section.id || index} className="bg-stone-800/30 rounded-xl p-4 border border-stone-700/30">
                        <h3 className="font-medieval text-lg text-stone-200 mb-2 pb-1 border-b border-stone-700/50">{section.title}</h3>
                        {section.content && <p className="text-sm text-stone-400 mb-3">{section.content}</p>}
                        <ul className="space-y-2">
                            {section.list_items?.map((item, i) => (
                                <li key={i} className="flex items-start gap-2 text-sm text-stone-300">
                                    <span className="text-amber-500 mt-1">✦</span>
                                    <span>{item}</span>
                                </li>
                            ))}
                        </ul>
                    </div>
                );
            case 'secret':
                 if (isPlayerView && !isDM) return null; // Double safety, though usually parent hides it
                 return (
                    <div key={section.id || index} className="bg-red-950/20 rounded-xl p-4 border border-red-900/40 relative overflow-hidden group">
                        <div className="absolute top-0 right-0 p-2 opacity-20 group-hover:opacity-40 transition-opacity">
                            <Icon name="lock" className="w-12 h-12 text-red-800" />
                        </div>
                        <h3 className="font-medieval text-lg text-red-400 mb-2 flex items-center gap-2">
                            <Icon name="lock" className="w-4 h-4" />
                            {section.title}
                        </h3>
                        <p className="text-sm text-red-200/80 whitespace-pre-wrap leading-relaxed relative z-10">{section.content}</p>
                    </div>
                 );
            default: // 'text'
                return (
                    <div key={section.id || index} className="bg-stone-800/30 rounded-xl p-4 border border-stone-700/30">
                        <h3 className="font-medieval text-lg text-stone-200 mb-2 border-b border-stone-700/50 pb-1">{section.title}</h3>
                        <p className="text-sm text-stone-400 whitespace-pre-wrap leading-relaxed">{section.content}</p>
                    </div>
                );
        }
    };

    if (!pin) return null;

    const isDM = user?.profile.role === 'DM';
    const linkedMap = maps.find(m => m.id === pin.linked_map_id);

    return (
        <aside className={`absolute top-0 right-0 h-full w-full max-w-md transform bg-stone-900/95 backdrop-blur-2xl border-l border-stone-700/50 p-6 shadow-2xl transition-transform duration-300 ease-in-out z-30 ${pin ? 'translate-x-0' : 'translate-x-full'}`}>
            <div className="flex h-full flex-col">
                <div className="flex items-start justify-between border-b border-stone-800 pb-4">
                    <div>
                        <div className="flex items-center gap-3">
                            <span style={{ backgroundColor: pin.pin_types?.color || '#718096' }} className="flex h-10 w-10 items-center justify-center rounded-full text-xl shadow-lg ring-2 ring-stone-800">
                                {pin.pin_types?.emoji || '❓'}
                            </span>
                            <div>
                                <h2 className="text-2xl font-bold font-medieval text-stone-100">{pin.title}</h2>
                                <p className="text-xs text-stone-500 uppercase tracking-widest">{pin.pin_types?.name || 'Unknown Type'}</p>
                            </div>
                        </div>
                    </div>
                    <button onClick={onClose} className="rounded-full p-2 text-stone-500 hover:bg-stone-800 hover:text-stone-300 transition-colors">
                        <Icon name="close" className="h-6 w-6" />
                    </button>
                </div>

                {/* Character & Edit Controls */}
                <div className="mt-4 flex flex-col gap-4">
                    {/* Character Presence Section */}
                    {(presentCharacters.length > 0 || (isDM && !isPlayerView)) && (
                        <div className="bg-stone-800/30 rounded-xl p-3 border border-stone-700/30">
                            <div className="flex items-center justify-between mb-2">
                                <h3 className="text-xs font-bold uppercase text-stone-400 flex items-center gap-2">
                                    <Icon name="user" className="w-3 h-3"/> Characters Present
                                </h3>
                                {isDM && !isPlayerView && !isSummoning && (
                                    <button onClick={() => setIsSummoning(true)} className="text-xs text-amber-500 hover:text-amber-400">+ Summon</button>
                                )}
                            </div>

                            {isSummoning && (
                                <div className="mb-3 bg-stone-900 rounded-lg border border-amber-500/30 p-2 animate-modal-in">
                                    <input autoFocus type="text" placeholder="Search characters..." className="w-full bg-transparent text-sm border-b border-stone-700 pb-1 mb-2 focus:outline-none focus:border-amber-500" />
                                    <div className="max-h-32 overflow-y-auto custom-scrollbar space-y-1">
                                        {characters.filter(c => c.current_pin_id !== pin.id).map(c => (
                                            <button 
                                                key={c.id} 
                                                onClick={() => handleMoveCharacter(c.id, pin.id)}
                                                className="w-full text-left flex items-center gap-2 px-2 py-1 hover:bg-stone-800 rounded text-sm text-stone-300"
                                            >
                                                <div className="w-4 h-4 rounded-full bg-stone-700 overflow-hidden">{c.image_url && <img src={c.image_url} className="w-full h-full object-cover"/>}</div>
                                                {c.name}
                                            </button>
                                        ))}
                                    </div>
                                    <button onClick={() => setIsSummoning(false)} className="w-full text-center text-xs text-stone-500 mt-2 hover:text-stone-300">Cancel</button>
                                </div>
                            )}

                            <div className="flex flex-wrap gap-2">
                                {presentCharacters.map(char => (
                                    <div key={char.id} className="relative group">
                                        <button 
                                            onClick={() => setViewingCharacter(char)}
                                            className="w-10 h-10 rounded-full bg-stone-700 border-2 border-stone-600 hover:border-amber-500 overflow-hidden transition-all relative z-10"
                                            title={char.name}
                                        >
                                            {char.image_url ? (
                                                <img src={char.image_url} alt={char.name} className="w-full h-full object-cover" />
                                            ) : (
                                                <div className="flex items-center justify-center w-full h-full text-xs font-bold">{char.name.charAt(0)}</div>
                                            )}
                                        </button>
                                        {isDM && !isPlayerView && (
                                            <button 
                                                onClick={() => handleMoveCharacter(char.id, null)}
                                                className="absolute -top-1 -right-1 z-20 bg-stone-900 text-stone-500 hover:text-red-500 rounded-full w-4 h-4 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
                                                title="Remove from location"
                                            >
                                                &times;
                                            </button>
                                        )}
                                    </div>
                                ))}
                                {presentCharacters.length === 0 && !isSummoning && <span className="text-xs text-stone-600 italic">No one is here.</span>}
                            </div>
                        </div>
                    )}

                    {/* View Character Mini-Modal (Overlay inside Sidebar) */}
                    {viewingCharacter && (
                        <div className="bg-stone-800 border border-amber-900/30 rounded-xl p-4 animate-modal-in relative">
                            <button onClick={() => setViewingCharacter(null)} className="absolute top-2 right-2 text-stone-500 hover:text-stone-300"><Icon name="close" className="w-4 h-4"/></button>
                            <div className="flex gap-3 mb-3">
                                <div className="w-16 h-16 rounded-lg bg-stone-900 overflow-hidden border border-stone-600 flex-shrink-0">
                                    {viewingCharacter.image_url && <img src={viewingCharacter.image_url} className="w-full h-full object-cover"/>}
                                </div>
                                <div>
                                    <h3 className="font-medieval text-lg text-amber-500">{viewingCharacter.name}</h3>
                                    <p className="text-xs text-stone-400">{viewingCharacter.role_details?.race} {viewingCharacter.role_details?.class}</p>
                                    <p className="text-xs text-stone-500">Level {viewingCharacter.role_details?.level} • {viewingCharacter.role_details?.alignment}</p>
                                </div>
                            </div>

                            <div className="text-sm text-stone-300 max-h-32 overflow-y-auto custom-scrollbar whitespace-pre-wrap mb-2">
                                {viewingCharacter.backstory || "No backstory."}
                            </div>

                            {/* Relationships Section in Mini Sheet */}
                            {viewingCharacter.relationships && viewingCharacter.relationships.length > 0 && (
                                <div className="mt-2 pt-2 border-t border-stone-700/50">
                                    <p className="text-xs text-stone-500 font-bold mb-1 uppercase">Connections</p>
                                    <div className="space-y-1">
                                        {viewingCharacter.relationships.map((rel, i) => (
                                            <div key={i} className="text-xs flex items-start gap-1">
                                                <span className="text-amber-500 font-bold">•</span>
                                                <span className="text-stone-300">
                                                    <span className="font-medium text-stone-200">{getCharacterName(rel.targetId)}</span>
                                                    <span className="text-stone-500"> ({rel.type})</span>
                                                    {rel.notes && <span className="text-stone-500 block pl-2 italic">"{rel.notes}"</span>}
