                                    >
                                        <option value="">Select Character...</option>
                                        {characters.filter(c => c.id !== editingChar?.id).map(c => (
                                            <option key={c.id} value={c.id}>{c.name}</option>
                                        ))}
                                    </select>
                                    <input 
                                        type="text" 
                                        placeholder="Type (e.g. Rival)" 
                                        value={rel.type} 
                                        onChange={e => updateRelationship(idx, 'type', e.target.value)} 
                                        className="w-1/3 rounded border border-stone-600/50 bg-stone-800 text-xs text-stone-200 p-1"
                                    />
                                    <button type="button" onClick={() => removeRelationship(idx)} className="text-stone-500 hover:text-red-500 px-1"><Icon name="trash" className="w-3 h-3" /></button>
                                </div>
                                <input 
                                    type="text" 
                                    placeholder="Notes..." 
                                    value={rel.notes || ''} 
                                    onChange={e => updateRelationship(idx, 'notes', e.target.value)} 
                                    className="w-full rounded border border-stone-600/30 bg-stone-800 text-xs text-stone-400 p-1"
                                />
                            </div>
                        ))}
                        {relationships.length === 0 && <p className="text-xs text-stone-600 italic text-center">No relationships defined.</p>}
                    </div>

                    <textarea placeholder="GM Notes (Secret)" value={gmNotes} onChange={e => setGmNotes(e.target.value)} rows={2} className="w-full rounded-xl border border-red-900/30 bg-red-950/10 px-4 py-3 text-stone-200 placeholder-red-400/50 focus:border-red-500 focus:outline-none" />

                    <div className="flex gap-3 pt-4 border-t border-stone-700/50">
                        <button type="button" onClick={resetForm} className="flex-1 bg-stone-700 hover:bg-stone-600 text-stone-200 font-bold py-3 px-6 rounded-xl transition-all">Cancel</button>
                        <button type="submit" disabled={submitting} className="flex-1 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all">{submitting ? "Saving..." : "Save Character"}</button>
                    </div>
                </form>
            )}
        </Modal>
    );
};

// --- PIN TYPE MANAGER MODAL ---
interface PinTypeManagerModalProps { isOpen: boolean; onClose: () => void; }
export const PinTypeManagerModal: React.FC<PinTypeManagerModalProps> = ({ isOpen, onClose }) => {
    const { pinTypes, refreshData } = useAppContext();
    const [name, setName] = useState('');
    const [emoji, setEmoji] = useState('📍');
    const [color, setColor] = useState('#3b82f6');
    const [loading, setLoading] = useState(false);

    const handleAdd = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        if (!name) return;

        await supabase.from('pin_types').insert({ name, emoji, color });
        await refreshData(true);

        setName('');
