                         </div>
                         <input type="text" placeholder="Emoji" value={emoji} onChange={e => setEmoji(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/50 px-3 py-2 text-center text-stone-200 focus:border-amber-500 focus:outline-none" />
                         <input type="color" value={color} onChange={e => setColor(e.target.value)} className="w-full h-10 rounded-xl bg-transparent cursor-pointer" />
