// --- MAP MANAGER MODAL ---
interface MapManagerModalProps { isOpen: boolean; onClose: () => void; }
export const MapManagerModal: React.FC<MapManagerModalProps> = ({ isOpen, onClose }) => {
    const { user } = useAuth();
    const { maps, refreshData } = useAppContext();
    const [name, setName] = useState('');
    const [imageUrl, setImageUrl] = useState('');
    const [imageFile, setImageFile] = useState<File | null>(null);
    const [parentMapId, setParentMapId] = useState<string>('');
    const [isVisible, setIsVisible] = useState(true);
    const [loading, setLoading] = useState(false);
    const [isEditing, setIsEditing] = useState<string | null>(null); // Map ID if editing config

    // Config fields
    const [gridSize, setGridSize] = useState(50);
    const [pinScale, setPinScale] = useState(50);
    const [showGrid, setShowGrid] = useState(false);

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user) return;
        setLoading(true);

        let finalUrl = imageUrl;
        if (imageFile) {
            finalUrl = await fileToBase64(imageFile);
        }

        if (isEditing) {
             // Update existing config
             await supabase.from('maps').update({ 
                 name, 
                 parent_map_id: parentMapId || null, 
                 is_visible: isVisible,
                 grid_size: gridSize,
                 pin_scale: pinScale,
                 is_grid_visible: showGrid,
                 ...(finalUrl ? { image_url: finalUrl } : {})
             }).eq('id', isEditing);
        } else {
             // Insert new
             await supabase.from('maps').insert({
                 name,
                 image_url: finalUrl,
                 parent_map_id: parentMapId || null,
                 is_visible: isVisible,
                 created_by: user.id,
                 grid_size: gridSize,
                 pin_scale: pinScale,
                 is_grid_visible: showGrid
             });
        }

        await refreshData(true);
        resetForm();
        setLoading(false);
    };

    const resetForm = () => {
        setName(''); setImageUrl(''); setImageFile(null); setParentMapId(''); setIsVisible(true);
        setGridSize(50); setPinScale(50); setShowGrid(false); setIsEditing(null);
    };

    const handleEdit = (map: MapType) => {
        setIsEditing(map.id);
        setName(map.name);
        setImageUrl(map.image_url);
        setParentMapId(map.parent_map_id || '');
        setIsVisible(map.is_visible);
        setGridSize(map.grid_size || 50);
        setPinScale(map.pin_scale || 50);
        setShowGrid(map.is_grid_visible || false);
    };

    const handleDelete = async (id: string) => {
        if(!window.confirm("Delete map? This will cascade to pins!")) return;
        await supabase.from('maps').delete().eq('id', id);
        await refreshData(true);
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Map Manager">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {/* List Column */}
                <div className="md:col-span-1 border-r border-stone-700/50 pr-4 space-y-3">
                    <button onClick={resetForm} className="w-full flex items-center gap-2 bg-stone-800 hover:bg-stone-700 p-3 rounded-xl transition-colors border border-stone-700">
                        <Icon name="plus" className="w-4 h-4 text-amber-500"/>
                        <span className="font-bold text-stone-300">Add New Map</span>
                    </button>
                    <div className="space-y-2 max-h-[60vh] overflow-y-auto custom-scrollbar">
                        {maps.map(m => (
                            <div key={m.id} className={`p-3 rounded-xl border cursor-pointer transition-all flex justify-between items-center ${isEditing === m.id ? 'bg-amber-900/20 border-amber-500/50' : 'bg-stone-900/40 border-stone-800 hover:border-stone-600'}`} onClick={() => handleEdit(m)}>
                                <span className="text-sm font-medium text-stone-300 truncate">{m.name}</span>
                                <div className="flex gap-1">
                                    {!m.is_visible && <Icon name="eye-off" className="w-3 h-3 text-stone-500" />}
                                    <button onClick={(e) => {e.stopPropagation(); handleDelete(m.id);}} className="text-stone-600 hover:text-red-500"><Icon name="trash" className="w-3 h-3"/></button>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Form Column */}
                <form onSubmit={handleSave} className="md:col-span-2 space-y-4">
                    <h3 className="font-medieval text-xl text-amber-500 border-b border-stone-700/50 pb-2 mb-4">
                        {isEditing ? `Edit: ${name}` : "New Map Details"}
                    </h3>

                    <div className="space-y-3">
                         <input type="text" placeholder="Map Name" value={name} onChange={e => setName(e.target.value)} required className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />

                         <div className="flex items-center gap-4 bg-stone-800/30 p-4 rounded-xl border border-stone-700/30">
                            <label className="w-20 h-20 rounded-lg bg-stone-900 border-2 border-dashed border-stone-600 flex items-center justify-center cursor-pointer hover:border-amber-500 overflow-hidden relative flex-shrink-0">
                                {imageUrl || (imageFile && URL.createObjectURL(imageFile)) ? (
                                    <img src={imageUrl || (imageFile ? URL.createObjectURL(imageFile) : '')} className="w-full h-full object-cover" />
                                ) : (
                                    <Icon name="image" className="w-8 h-8 text-stone-600" />
                                )}
                                <input type="file" className="hidden" accept="image/*" onChange={e => {
                                    if(e.target.files?.[0]) { setImageFile(e.target.files[0]); setImageUrl(''); }
                                }} />
                            </label>
                            <div className="flex-1">
                                <label className="text-xs font-bold uppercase text-stone-500 mb-1 block">Image Source</label>
                                <input type="text" placeholder="Or paste Image URL..." value={imageUrl} onChange={e => { setImageUrl(e.target.value); setImageFile(null); }} className="w-full rounded-lg border border-stone-600/50 bg-stone-900/40 px-3 py-2 text-sm text-stone-200" />
                            </div>
                         </div>

                         <div className="grid grid-cols-2 gap-4">
                             <div>
                                <label className="text-xs font-bold uppercase text-stone-500 mb-1 block">Parent Map</label>
                                <select value={parentMapId} onChange={e => setParentMapId(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-3 py-3 text-stone-200 focus:outline-none">
                                    <option value="">(None - Top Level)</option>
                                    {maps.filter(m => m.id !== isEditing).map(m => (
                                        <option key={m.id} value={m.id}>{m.name}</option>
                                    ))}
                                </select>
                             </div>
                             <div className="flex items-center px-4 bg-stone-800/40 rounded-xl border border-stone-700/50">
                                <label className="flex items-center gap-3 cursor-pointer w-full">
                                    <input type="checkbox" checked={isVisible} onChange={e => setIsVisible(e.target.checked)} className="rounded border-stone-600 bg-stone-800 text-amber-600 focus:ring-amber-500" />
                                    <span className="font-bold text-stone-300">Player Visible?</span>
                                </label>
                             </div>
                         </div>

                         {/* Advanced Config */}
                         <div className="bg-stone-800/30 p-4 rounded-xl border border-stone-700/30 space-y-3">
                             <div className="flex justify-between items-center">
                                <h4 className="text-xs font-bold uppercase text-stone-500">Map Configuration</h4>
                                <label className="flex items-center gap-2 text-xs text-stone-400 cursor-pointer">
                                    <input type="checkbox" checked={showGrid} onChange={e => setShowGrid(e.target.checked)} />
                                    Show Grid Overlay
                                </label>
                             </div>
                             <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="text-[10px] text-stone-500 uppercase block mb-1">Grid Size (px)</label>
                                    <input type="number" value={gridSize} onChange={e => setGridSize(parseInt(e.target.value))} className="w-full bg-stone-900 rounded border border-stone-700 px-2 py-1 text-sm text-stone-200" />
                                </div>
                                <div>
                                    <label className="text-[10px] text-stone-500 uppercase block mb-1">Pin Scale (px)</label>
                                    <input type="number" value={pinScale} onChange={e => setPinScale(parseInt(e.target.value))} className="w-full bg-stone-900 rounded border border-stone-700 px-2 py-1 text-sm text-stone-200" />
                                </div>
                             </div>
                         </div>
                    </div>

                    <div className="pt-4 border-t border-stone-700/50 flex gap-3">
                         <button type="submit" disabled={loading} className="flex-1 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all">{loading ? 'Saving...' : 'Save Map'}</button>
                    </div>
                </form>
            </div>
        </Modal>
    );
};

// --- PIN EDITOR MODAL ---
interface PinEditorModalProps {
    pinData: Partial<Pin>;
    onClose: () => void;
    onSave: () => void;
}
export const PinEditorModal: React.FC<PinEditorModalProps> = ({ pinData, onClose, onSave }) => {
    const { user } = useAuth();
    const { maps, pinTypes, refreshData } = useAppContext();
    const { items } = useItems(); // For inventory search

    const [title, setTitle] = useState(pinData.title || '');
    const [pinTypeId, setPinTypeId] = useState(pinData.pin_type_id || (pinTypes[0]?.id || ''));
    const [isVisible, setIsVisible] = useState(pinData.is_visible !== undefined ? pinData.is_visible : true);
    const [linkedMapId, setLinkedMapId] = useState(pinData.linked_map_id || '');
    const [description, setDescription] = useState(pinData.data?.description || '');
    const [sections, setSections] = useState<PinSection[]>(pinData.data?.sections || []);
    const [encounterFile, setEncounterFile] = useState<{name: string, content: string} | null>(pinData.data?.encounter_file || null);

    const [loading, setLoading] = useState(false);
    const [newItemType, setNewItemType] = useState<PinSectionType>('text');

    // Section Helpers
    const addSection = () => {
        const newSection: PinSection = {
            id: `sec_${Date.now()}`,
            type: newItemType,
            title: '',
            content: '',
            list_items: [],
            stats: [],
            items: []
        };
        setSections([...sections, newSection]);
    };

    const updateSection = (id: string, updates: Partial<PinSection>) => {
        setSections(sections.map(s => s.id === id ? { ...s, ...updates } : s));
    };

    const removeSection = (id: string) => {
        setSections(sections.filter(s => s.id !== id));
    };

    const moveSection = (index: number, direction: 'up' | 'down') => {
        const newSecs = [...sections];
        if (direction === 'up' && index > 0) {
            [newSecs[index], newSecs[index-1]] = [newSecs[index-1], newSecs[index]];
        } else if (direction === 'down' && index < newSecs.length - 1) {
            [newSecs[index], newSecs[index+1]] = [newSecs[index+1], newSecs[index]];
        }
        setSections(newSecs);
    };

    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const text = await file.text();
        setEncounterFile({ name: file.name, content: text });
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user || !title || !pinTypeId) return;
        setLoading(true);

        const dataPayload: PinData = {
            description,
            images: [], // Deprecated/Not used heavily in favor of sections
            sections,
            encounter_file: encounterFile
        };

        const dbPayload = {
            map_id: pinData.map_id,
            x_coord: pinData.x_coord,
            y_coord: pinData.y_coord,
            title,
            pin_type_id: pinTypeId,
            is_visible: isVisible,
            linked_map_id: linkedMapId || null,
            data: dataPayload,
            created_by: pinData.created_by || user.id
        };

        if (pinData.id) {
            await supabase.from('pins').update(dbPayload).eq('id', pinData.id);
        } else {
            await supabase.from('pins').insert(dbPayload);
        }

        await onSave(); // Triggers refresh
        setLoading(false);
    };

    // --- Sub-components for Section Editors ---
    const renderSectionEditor = (section: PinSection, index: number) => {
        return (
            <div key={section.id} className="bg-stone-800/40 border border-stone-700/50 rounded-xl p-3 mb-3 animate-modal-in">
                <div className="flex items-center justify-between mb-3 border-b border-stone-700/50 pb-2">
                    <div className="flex items-center gap-2">
                        <span className="text-xs uppercase font-bold text-stone-500 bg-stone-900 px-2 py-0.5 rounded">{section.type}</span>
                        <input 
                            type="text" 
                            placeholder="Section Title" 
                            value={section.title} 
                            onChange={e => updateSection(section.id, { title: e.target.value })} 
                            className="bg-transparent text-sm font-bold text-stone-200 focus:outline-none border-b border-transparent focus:border-amber-500 w-48"
                        />
                    </div>
                    <div className="flex items-center gap-1">
                        <button type="button" onClick={() => moveSection(index, 'up')} disabled={index === 0} className="p-1 text-stone-500 hover:text-stone-300 disabled:opacity-30"><Icon name="chevron-down" className="rotate-180 w-4 h-4"/></button>
                        <button type="button" onClick={() => moveSection(index, 'down')} disabled={index === sections.length - 1} className="p-1 text-stone-500 hover:text-stone-300 disabled:opacity-30"><Icon name="chevron-down" className="w-4 h-4"/></button>
                        <button type="button" onClick={() => removeSection(section.id)} className="p-1 text-stone-500 hover:text-red-500 ml-2"><Icon name="trash" className="w-4 h-4"/></button>
                    </div>
                </div>

                <div className="space-y-2">
                    {/* Content Input based on Type */}
                    {(section.type === 'text' || section.type === 'secret') && (
                        <textarea 
                            placeholder="Content..." 
                            value={section.content} 
                            onChange={e => updateSection(section.id, { content: e.target.value })} 
                            rows={3} 
                            className="w-full bg-stone-900/50 rounded border border-stone-700/50 p-2 text-sm text-stone-300 focus:border-amber-500 focus:outline-none"
                        />
                    )}

                    {section.type === 'image' && (
                        <div className="flex gap-2">
                            <input 
                                type="text" 
                                placeholder="Image URL" 
                                value={section.image_url || ''} 
                                onChange={e => updateSection(section.id, { image_url: e.target.value })} 
                                className="flex-1 bg-stone-900/50 rounded border border-stone-700/50 p-2 text-sm text-stone-300"
                            />
                            {/* Could add file upload for section images here too */}
                        </div>
                    )}

                    {section.type === 'list' && (
                        <div>
                             <textarea 
                                placeholder="Description (optional)" 
                                value={section.content} 
                                onChange={e => updateSection(section.id, { content: e.target.value })} 
                                rows={1}
                                className="w-full bg-stone-900/50 rounded border border-stone-700/50 p-2 text-sm text-stone-300 mb-2"
                            />
                            <div className="space-y-1">
                                {section.list_items?.map((item, i) => (
                                    <div key={i} className="flex gap-2">
                                        <input 
                                            value={item} 
                                            onChange={e => {
                                                const newList = [...(section.list_items || [])];
                                                newList[i] = e.target.value;
                                                updateSection(section.id, { list_items: newList });
                                            }}
                                            className="flex-1 bg-stone-900/30 rounded border border-stone-700/30 px-2 py-1 text-sm text-stone-300"
                                        />
                                        <button type="button" onClick={() => {
                                            const newList = section.list_items?.filter((_, idx) => idx !== i);
                                            updateSection(section.id, { list_items: newList });
                                        }} className="text-red-500 hover:text-red-400">&times;</button>
                                    </div>
                                ))}
                                <button type="button" onClick={() => updateSection(section.id, { list_items: [...(section.list_items || []), ''] })} className="text-xs text-amber-500 hover:underline">+ Add Item</button>
                            </div>
                        </div>
                    )}

                    {section.type === 'statblock' && (
                        <div>
                             <textarea 
                                placeholder="Description (optional)" 
                                value={section.content} 
                                onChange={e => updateSection(section.id, { content: e.target.value })} 
                                rows={1}
                                className="w-full bg-stone-900/50 rounded border border-stone-700/50 p-2 text-sm text-stone-300 mb-2"
                            />
                             <div className="grid grid-cols-2 gap-2">
                                {section.stats?.map((stat, i) => (
                                    <div key={i} className="flex gap-1 bg-stone-900/30 p-1 rounded border border-stone-800">
                                        <input placeholder="Label" value={stat.label} onChange={e => {
                                            const newStats = [...(section.stats || [])];
                                            newStats[i].label = e.target.value;
                                            updateSection(section.id, { stats: newStats });
                                        }} className="w-1/2 bg-transparent text-xs text-amber-500 font-bold uppercase focus:outline-none" />
                                        <input placeholder="Value" value={stat.value} onChange={e => {
                                            const newStats = [...(section.stats || [])];
                                            newStats[i].value = e.target.value;
                                            updateSection(section.id, { stats: newStats });
                                        }} className="w-1/2 bg-transparent text-sm text-stone-200 text-right focus:outline-none" />
                                        <button type="button" onClick={() => {
                                            const newStats = section.stats?.filter((_, idx) => idx !== i);
                                            updateSection(section.id, { stats: newStats });
                                        }} className="text-red-500 px-1">&times;</button>
                                    </div>
                                ))}
                             </div>
                             <button type="button" onClick={() => updateSection(section.id, { stats: [...(section.stats || []), { label: 'STAT', value: '10' }] })} className="text-xs text-amber-500 hover:underline mt-1">+ Add Stat</button>
                        </div>
                    )}

                    {section.type === 'inventory' && (
                        <div>
                            {/* Item Search */}
                            <input 
                                type="text" 
                                placeholder="Search 5e items to add..." 
                                onChange={e => {
                                    // Basic fuzzy search logic here or just rely on manual entry for custom items
                                    // For now, implementing a manual add + search dropdown logic is complex for this modal size.
                                    // We will stick to simple adding for custom items + rudimentary search
                                }}
                                list={`datalist-${section.id}`}
                                className="w-full bg-stone-900/50 rounded border border-stone-700/50 p-2 text-sm text-stone-300 mb-2 focus:border-amber-500 focus:outline-none"
                                onKeyDown={(e) => {
                                    if (e.key === 'Enter') {
                                        e.preventDefault();
                                        const val = e.currentTarget.value;
                                        if(!val) return;

                                        // Check if it matches a known item
                                        const knownItem = items.find(i => i.name.toLowerCase() === val.toLowerCase());
                                        const newItem: InventoryItem = {
                                            id: `item_${Date.now()}`,
                                            name: knownItem ? knownItem.name : val,
                                            count: 1,
                                            is_magic: knownItem?.is_magic,
                                            // We could fetch details here if we had them in context fully
                                            desc: knownItem?.desc ? knownItem.desc.join('\n') : undefined
                                        };

                                        updateSection(section.id, { items: [...(section.items || []), newItem] });
                                        e.currentTarget.value = '';
                                    }
