                </div>

                <div className="border-t border-stone-700/50 pt-4">
                     <label className="flex items-center justify-between bg-stone-800/30 p-3 rounded-xl border border-stone-700/30 cursor-pointer hover:bg-stone-800/50 transition-colors">
