                </div>
            </form>
        </Modal>
    );
};

import React, { useState, useEffect, useMemo } from 'react';
import { supabase, supabaseUrl, supabaseAnonKey } from '../services/supabase';
import { createClient } from '@supabase/supabase-js';
import { useAuth } from '../App';
import { useAppContext } from './Dashboard';
import { useItems, ApiItem } from './ItemProvider';
import { Map as MapType, Pin, PinData, PinType, PinSectionType, PinSection, InventoryItem, Character, CharacterRelationship } from '../types';
import { Icon } from './Icons';
import MapViewer from './MapViewer';

// Helper to convert file to Base64
const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => resolve(reader.result as string);
        reader.onerror = error => reject(error);
    });
};

// Reusable Modal Wrapper
interface ModalProps {
    isOpen: boolean;
    onClose: () => void;
    title: string;
    children: React.ReactNode;
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children }) => {
    useEffect(() => {
        const handleEscape = (event: KeyboardEvent) => {
            if (event.key === 'Escape') {
                onClose();
            }
        };
        document.addEventListener('keydown', handleEscape);
        return () => {
            document.removeEventListener('keydown', handleEscape);
        };
    }, [onClose]);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={onClose} role="dialog" aria-modal="true">
            <div className="w-full max-w-2xl rounded-3xl bg-stone-900/95 backdrop-blur-2xl border border-stone-700/50 p-6 shadow-2xl animate-modal-in flex flex-col max-h-[90vh]" onClick={(e) => e.stopPropagation()}>
                <div className="flex items-center justify-between border-b border-stone-700/50 pb-4 mb-4 flex-shrink-0">
                    <h2 className="text-2xl font-medieval font-bold text-amber-500">{title}</h2>
                    <button onClick={onClose} className="rounded-full p-2 text-stone-500 transition-colors hover:bg-stone-800 hover:text-stone-300">
                        <Icon name="close" className="h-6 w-6" />
                    </button>
                </div>
                <div className="overflow-y-auto pr-2 custom-scrollbar flex-1">{children}</div>
            </div>
        </div>
    );
};

// --- PLAYER MANAGER MODAL ---
interface PlayerManagerModalProps { isOpen: boolean; onClose: () => void; }
export const PlayerManagerModal: React.FC<PlayerManagerModalProps> = ({ isOpen, onClose }) => {
    const [username, setUsername] = useState('');
    const [role, setRole] = useState<'Player' | 'DM'>('Player');
    const [loading, setLoading] = useState(false);
    const [status, setStatus] = useState<{ type: 'success' | 'error', msg: string } | null>(null);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setStatus(null);

        const trimmedUsername = username.trim();
        if (!trimmedUsername) {
            setStatus({ type: 'error', msg: 'Username is required.' });
            setLoading(false);
            return;
        }

        const usernameRegex = /^[a-zA-Z0-9_-]+$/;
        if (!usernameRegex.test(trimmedUsername)) {
            setStatus({ type: 'error', msg: 'Username can only contain letters, numbers, hyphens, and underscores.' });
            setLoading(false);
            return;
        }

        // Generate dummy credentials based on app pattern
        const lowerCaseUsername = trimmedUsername.toLowerCase();
        const dummyEmail = `${lowerCaseUsername}@dnd-map-login.local`;
        const dummyPassword = `DUMMY_PASSWORD_FOR_${lowerCaseUsername}`;

        // CRITICAL: We use a separate Supabase client to create the user.
        // If we used the main `supabase` instance, calling signUp would log out the current DM.
        const tempClient = createClient(supabaseUrl, supabaseAnonKey, {
            auth: {
                persistSession: false, // Don't save this session to localStorage
                autoRefreshToken: false,
                detectSessionInUrl: false,
                storageKey: 'temp-auth-client' // Use distinct key to reduce warnings
            }
        });

        const { data: authData, error: signUpError } = await tempClient.auth.signUp({
            email: dummyEmail,
            password: dummyPassword,
            options: {
                data: { username: trimmedUsername, role: role }
            }
        });

        if (signUpError) {
            setStatus({ type: 'error', msg: signUpError.message });
            setLoading(false);
            return;
        }

        if (authData.user) {
            // Manually insert into public.users to ensure profile exists immediately
            // This is redundant if the trigger works, but safe to ensure immediate consistency
            const { error: profileError } = await supabase.from('users').insert({
                id: authData.user.id,
                username: trimmedUsername,
                role: role,
                password_hash: 'managed_by_supabase_auth' // Required by DB constraint
            });

            if (profileError && profileError.code !== '23505') { // Ignore unique constraint if trigger beat us to it
                 console.error("Profile creation warning:", profileError);
            }

            setStatus({ type: 'success', msg: `User '${trimmedUsername}' created successfully!` });
            setUsername('');
        }

        setLoading(false);
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Add New User">
            <form onSubmit={handleSubmit} className="space-y-6">
                <div className="bg-stone-800/40 p-4 rounded-xl border border-stone-700/50 mb-4">
                    <p className="text-sm text-stone-300">
                        Create a new account for your players. They will log in using only the username provided below.
                    </p>
                </div>

                <div>
                    <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Username</label>
                    <input 
                        type="text" 
                        value={username} 
                        onChange={e => setUsername(e.target.value)} 
                        className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none focus:ring-1 focus:ring-amber-500" 
                        placeholder="e.g. Aragorn" 
                    />
                </div>

                <div>
                    <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Role</label>
                    <div className="flex gap-4">
                        <label className={`flex-1 cursor-pointer rounded-xl border px-4 py-3 text-center transition-all ${role === 'Player' ? 'bg-amber-900/30 border-amber-500 text-amber-500' : 'bg-stone-800/40 border-stone-700 text-stone-400 hover:bg-stone-800'}`}>
                            <input type="radio" className="hidden" checked={role === 'Player'} onChange={() => setRole('Player')} />
                            <span className="font-bold">Player</span>
                        </label>
                        <label className={`flex-1 cursor-pointer rounded-xl border px-4 py-3 text-center transition-all ${role === 'DM' ? 'bg-amber-900/30 border-amber-500 text-amber-500' : 'bg-stone-800/40 border-stone-700 text-stone-400 hover:bg-stone-800'}`}>
                            <input type="radio" className="hidden" checked={role === 'DM'} onChange={() => setRole('DM')} />
                            <span className="font-bold">Dungeon Master</span>
                        </label>
                    </div>
                </div>

                {status && (
                    <div className={`p-4 rounded-xl border text-sm ${status.type === 'success' ? 'bg-green-900/20 border-green-800/50 text-green-300' : 'bg-red-900/20 border-red-800/50 text-red-300'}`}>
                        {status.msg}
                    </div>
                )}

                <button 
                    type="submit" 
                    disabled={loading}
                    className="w-full bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg hover:shadow-amber-900/20 transition-all hover:scale-[1.02] active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed"
                >
                    {loading ? <Icon name="spinner" className="h-5 w-5 animate-spin mx-auto"/> : 'Create User'}
                </button>
            </form>
        </Modal>
    );
};

// --- CHARACTER MANAGER MODAL ---
interface CharacterManagerModalProps { isOpen: boolean; onClose: () => void; }
export const CharacterManagerModal: React.FC<CharacterManagerModalProps> = ({ isOpen, onClose }) => {
    const { user } = useAuth();
    const { characters, maps, pins, refreshData } = useAppContext();
    const [editingChar, setEditingChar] = useState<Partial<Character> | null>(null);
    const [isEditing, setIsEditing] = useState(false);

    // Form State
    const [name, setName] = useState('');
    const [race, setRace] = useState('');
    const [charClass, setCharClass] = useState('');
    const [level, setLevel] = useState(1);
    const [alignment, setAlignment] = useState('');
    const [backstory, setBackstory] = useState('');
    const [gmNotes, setGmNotes] = useState('');
    const [isNpc, setIsNpc] = useState(true);
    const [imageFile, setImageFile] = useState<File | null>(null);
    const [imageUrl, setImageUrl] = useState('');

    // Relationship & Location State
    const [relationships, setRelationships] = useState<CharacterRelationship[]>([]);
    const [currentPinId, setCurrentPinId] = useState<string | null>(null);
    const [selectedMapId, setSelectedMapId] = useState<string>(''); 

    const [submitting, setSubmitting] = useState(false);

    // Derived map for picker
    const selectedMap = useMemo(() => maps.find(m => m.id === selectedMapId), [selectedMapId, maps]);

    const resetForm = () => {
        setName(''); setRace(''); setCharClass(''); setLevel(1); setAlignment('');
        setBackstory(''); setGmNotes(''); setIsNpc(true); setImageFile(null); setImageUrl('');
        setRelationships([]); setCurrentPinId(null); setSelectedMapId('');
        setEditingChar(null);
        setIsEditing(false);
    };

    const handleEdit = (char: Character) => {
        setEditingChar(char);
        setName(char.name);
        setRace(char.role_details?.race || '');
        setCharClass(char.role_details?.class || '');
        setLevel(char.role_details?.level || 1);
        setAlignment(char.role_details?.alignment || '');
        setBackstory(char.backstory || '');
        setGmNotes(char.gm_notes || '');
        setIsNpc(char.is_npc);
        setImageUrl(char.image_url || '');
        setRelationships(char.relationships || []);
        setCurrentPinId(char.current_pin_id || null);

        // Try to pre-fill map selector
        if (char.current_pin_id) {
            const pin = pins.find(p => p.id === char.current_pin_id);
            if (pin) setSelectedMapId(pin.map_id);
        } else {
            setSelectedMapId('');
        }

        setIsEditing(true);
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user || !name) return;
        setSubmitting(true);

        try {
            let finalImageUrl = imageUrl;
            if (imageFile) {
                 finalImageUrl = await fileToBase64(imageFile);
            }

            const payload = {
                name,
                role_details: { race, class: charClass, level, alignment },
                backstory,
                gm_notes: gmNotes,
                image_url: finalImageUrl,
                is_npc: isNpc,
                relationships: relationships || [],
                current_pin_id: currentPinId || null,
                created_by: user.id
            };

            let result;
            if (editingChar && editingChar.id) {
                result = await supabase.from('characters').update(payload).eq('id', editingChar.id);
            } else {
                result = await supabase.from('characters').insert(payload);
            }

            if (result.error) throw result.error;

            await refreshData(true);
            resetForm();
        } catch (error: any) {
            console.error("Error saving character:", error);
            alert(`Error saving character: ${error.message || "Unknown error"}. Check if 'characters' table exists.`);
        } finally {
            setSubmitting(false);
        }
    };

    const handleDelete = async (char: Character) => {
        if(!window.confirm(`Delete ${char.name}?`)) return;
        const { error } = await supabase.from('characters').delete().eq('id', char.id);
        if(!error) await refreshData(true);
    };

    // Relationship Helpers
    const addRelationship = () => {
        setRelationships([...relationships, { targetId: '', type: '', notes: '' }]);
    };

    const updateRelationship = (index: number, field: keyof CharacterRelationship, value: string) => {
        const newRels = [...relationships];
        newRels[index] = { ...newRels[index], [field]: value };
        setRelationships(newRels);
    };

    const removeRelationship = (index: number) => {
        setRelationships(relationships.filter((_, i) => i !== index));
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title={isEditing ? (editingChar ? "Edit Character" : "New Character") : "Manage Characters"}>
            {!isEditing ? (
                <div className="space-y-6">
                    <button onClick={() => setIsEditing(true)} className="w-full flex items-center justify-center space-x-2 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-4 rounded-xl shadow-lg transition-all">
                        <Icon name="plus" className="h-5 w-5" />
                        <span>Create New Character</span>
                    </button>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {characters.map(char => (
                             <div key={char.id} className="relative group bg-stone-800/40 border border-stone-700/50 rounded-xl p-4 flex gap-4 hover:bg-stone-800/60 transition-colors">
                                <div className="w-16 h-16 rounded-full bg-stone-900 overflow-hidden flex-shrink-0 border-2 border-stone-600 group-hover:border-amber-500 transition-colors">
                                    {char.image_url ? <img src={char.image_url} alt={char.name} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-stone-600 text-xs">No Img</div>}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <h3 className="font-medieval text-lg text-stone-200 truncate">{char.name}</h3>
                                    <p className="text-xs text-stone-500 uppercase tracking-wider font-bold mb-1">{char.is_npc ? 'NPC' : 'Player Character'}</p>
                                    <p className="text-xs text-stone-400 truncate">{char.role_details?.race} {char.role_details?.class} (Lvl {char.role_details?.level})</p>
                                    {char.current_pin_id && <p className="text-[10px] text-amber-500/80 mt-1 flex items-center gap-1"><Icon name="pin" className="w-3 h-3" /> Located on map</p>}
                                </div>
                                <div className="flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity absolute right-2 top-2">
                                     <button onClick={() => handleEdit(char)} className="p-1.5 rounded-lg bg-stone-900 text-stone-400 hover:text-amber-500"><Icon name="pencil" className="w-4 h-4" /></button>
                                     <button onClick={() => handleDelete(char)} className="p-1.5 rounded-lg bg-stone-900 text-stone-400 hover:text-red-500"><Icon name="trash" className="w-4 h-4" /></button>
                                </div>
                             </div>
                        ))}
                        {characters.length === 0 && <p className="col-span-2 text-center text-stone-500 italic py-8">No characters found.</p>}
                    </div>
