// Helper to convert file to Base64
const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => resolve(reader.result as string);
        reader.onerror = error => reject(error);
    });
};

// Reusable Modal Wrapper
interface ModalProps {
    isOpen: boolean;
    onClose: () => void;
    title: string;
    children: React.ReactNode;
    maxWidthClass?: string;
}

const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children, maxWidthClass = 'max-w-2xl' }) => {
    useEffect(() => {
        const handleEscape = (event: KeyboardEvent) => {
            if (event.key === 'Escape') {
                onClose();
            }
        };
        document.addEventListener('keydown', handleEscape);
        return () => {
            document.removeEventListener('keydown', handleEscape);
        };
    }, [onClose]);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4" onClick={onClose} role="dialog" aria-modal="true">
            <div className={`w-full ${maxWidthClass} rounded-3xl bg-stone-900/95 backdrop-blur-2xl border border-stone-700/50 p-6 shadow-2xl animate-modal-in flex flex-col max-h-[95vh]`} onClick={(e) => e.stopPropagation()}>
                <div className="flex items-center justify-between border-b border-stone-700/50 pb-4 mb-4 flex-shrink-0">
                    <h2 className="text-2xl font-medieval font-bold text-amber-500">{title}</h2>
                    <button onClick={onClose} className="rounded-full p-2 text-stone-500 transition-colors hover:bg-stone-800 hover:text-stone-300">
                        <Icon name="close" className="h-6 w-6" />
                    </button>
                </div>
                <div className="overflow-y-auto pr-2 custom-scrollbar flex-1">{children}</div>
            </div>
        </div>
    );
};

// --- PLAYER MANAGER MODAL ---
interface PlayerManagerModalProps { isOpen: boolean; onClose: () => void; }
export const PlayerManagerModal: React.FC<PlayerManagerModalProps> = ({ isOpen, onClose }) => {
    const [username, setUsername] = useState('');
    const [role, setRole] = useState<'Player' | 'DM'>('Player');
    const [loading, setLoading] = useState(false);
    const [status, setStatus] = useState<{ type: 'success' | 'error', msg: string } | null>(null);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setStatus(null);

        try {
            const trimmedUsername = username.trim();
            if (!trimmedUsername) throw new Error('Username is required.');

            const usernameRegex = /^[a-zA-Z0-9_-]+$/;
            if (!usernameRegex.test(trimmedUsername)) throw new Error('Username can only contain letters, numbers, hyphens, and underscores.');

            // Generate dummy credentials
            const lowerCaseUsername = trimmedUsername.toLowerCase();
            const dummyEmail = `${lowerCaseUsername}@dnd-map-login.local`;
            const dummyPassword = `DUMMY_PASSWORD_FOR_${lowerCaseUsername}`;

            const tempClient = createClient(supabaseUrl, supabaseAnonKey, {
                auth: { persistSession: false, autoRefreshToken: false, detectSessionInUrl: false, storageKey: 'temp-auth-client' }
            });

            const { data: authData, error: signUpError } = await tempClient.auth.signUp({
                email: dummyEmail,
                password: dummyPassword,
                options: { data: { username: trimmedUsername, role: role } }
            });

            if (signUpError) throw signUpError;

            if (authData.user) {
                const { error: profileError } = await supabase.from('users').insert({
                    id: authData.user.id,
                    username: trimmedUsername,
                    role: role,
                    password_hash: 'managed_by_supabase_auth'
                });
                if (profileError && profileError.code !== '23505') console.error("Profile creation warning:", profileError);
                setStatus({ type: 'success', msg: `User '${trimmedUsername}' created successfully!` });
                setUsername('');
            }
        } catch (error: any) {
            setStatus({ type: 'error', msg: error.message || "Unknown error occurred" });
        } finally {
            setLoading(false);
        }
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Add New User">
            <form onSubmit={handleSubmit} className="space-y-6">
                <div className="bg-stone-800/40 p-4 rounded-xl border border-stone-700/50 mb-4">
                    <p className="text-sm text-stone-300">
                        Create a new account for your players. They will log in using only the username provided below.
                    </p>
                </div>

                <div>
                    <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Username</label>
                    <input 
                        type="text" 
                        value={username} 
                        onChange={e => setUsername(e.target.value)} 
                        className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none focus:ring-1 focus:ring-amber-500" 
                        placeholder="e.g. Aragorn" 
                    />
                </div>

                <div>
                    <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Role</label>
                    <div className="flex gap-4">
                        <label className={`flex-1 cursor-pointer rounded-xl border px-4 py-3 text-center transition-all ${role === 'Player' ? 'bg-amber-900/30 border-amber-500 text-amber-500' : 'bg-stone-800/40 border-stone-700 text-stone-400 hover:bg-stone-800'}`}>
                            <input type="radio" className="hidden" checked={role === 'Player'} onChange={() => setRole('Player')} />
                            <span className="font-bold">Player</span>
                        </label>
                        <label className={`flex-1 cursor-pointer rounded-xl border px-4 py-3 text-center transition-all ${role === 'DM' ? 'bg-amber-900/30 border-amber-500 text-amber-500' : 'bg-stone-800/40 border-stone-700 text-stone-400 hover:bg-stone-800'}`}>
                            <input type="radio" className="hidden" checked={role === 'DM'} onChange={() => setRole('DM')} />
                            <span className="font-bold">Dungeon Master</span>
                        </label>
                    </div>
                </div>

                {status && (
                    <div className={`p-4 rounded-xl border text-sm ${status.type === 'success' ? 'bg-green-900/20 border-green-800/50 text-green-300' : 'bg-red-900/20 border-red-800/50 text-red-300'}`}>
                        {status.msg}
                    </div>
                )}

                <button type="submit" disabled={loading} className="w-full bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all disabled:opacity-50">
                    {loading ? <Icon name="spinner" className="h-5 w-5 animate-spin mx-auto"/> : 'Create User'}
                </button>
            </form>
        </Modal>
    );
};

// --- CHARACTER MANAGER MODAL ---
interface CharacterManagerModalProps { isOpen: boolean; onClose: () => void; }
export const CharacterManagerModal: React.FC<CharacterManagerModalProps> = ({ isOpen, onClose }) => {
    const { user } = useAuth();
    const { characters, maps, pins, refreshData } = useAppContext();
    const [editingChar, setEditingChar] = useState<Partial<Character> | null>(null);
    const [isEditing, setIsEditing] = useState(false);

    // Form State
    const [name, setName] = useState('');
    const [race, setRace] = useState('');
    const [charClass, setCharClass] = useState('');
    const [level, setLevel] = useState(1);
    const [alignment, setAlignment] = useState('');
    const [backstory, setBackstory] = useState('');
    const [gmNotes, setGmNotes] = useState('');
    const [isNpc, setIsNpc] = useState(true);
    const [imageFile, setImageFile] = useState<File | null>(null);
    const [imageUrl, setImageUrl] = useState('');

    // New Features
    const [sheetUrl, setSheetUrl] = useState('');
    const [charJson, setCharJson] = useState<any>(null);
    const [jsonFileName, setJsonFileName] = useState('');

    // Relationship & Location State
    const [relationships, setRelationships] = useState<CharacterRelationship[]>([]);
    const [currentPinId, setCurrentPinId] = useState<string | null>(null);
    const [selectedMapId, setSelectedMapId] = useState<string>(''); 

    const [submitting, setSubmitting] = useState(false);

    // Derived map for picker
    const selectedMap = useMemo(() => maps.find(m => m.id === selectedMapId), [selectedMapId, maps]);

    const resetForm = () => {
        setName(''); setRace(''); setCharClass(''); setLevel(1); setAlignment('');
        setBackstory(''); setGmNotes(''); setIsNpc(true); setImageFile(null); setImageUrl('');
        setRelationships([]); setCurrentPinId(null); setSelectedMapId('');
        setSheetUrl(''); setCharJson(null); setJsonFileName('');
        setEditingChar(null);
        setIsEditing(false);
    };

    const handleEdit = (char: Character) => {
        setEditingChar(char);
        setName(char.name);
        setRace(char.role_details?.race || '');
        setCharClass(char.role_details?.class || '');
        setLevel(char.role_details?.level || 1);
        setAlignment(char.role_details?.alignment || '');
        setBackstory(char.backstory || '');
        setGmNotes(char.gm_notes || '');
        setIsNpc(char.is_npc);
        setImageUrl(char.image_url || '');
        setRelationships(char.relationships || []);
        setCurrentPinId(char.current_pin_id || null);
        setSheetUrl(char.sheet_url || '');
        setCharJson(char.character_json || null);
        setJsonFileName(char.character_json ? 'Existing File Loaded' : '');

        if (char.current_pin_id) {
            const pin = pins.find(p => p.id === char.current_pin_id);
            if (pin) setSelectedMapId(pin.map_id);
        } else {
            setSelectedMapId('');
        }

        setIsEditing(true);
    };

    const handleJsonUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        try {
            const text = await file.text();
            const json = JSON.parse(text);
            setCharJson(json);
            setJsonFileName(file.name);
        } catch (error) {
            alert("Invalid JSON file");
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user || !name) return;
        setSubmitting(true);

        try {
            let finalImageUrl = imageUrl;
            if (imageFile) {
                 finalImageUrl = await fileToBase64(imageFile);
            }

            const payload = {
                name,
                role_details: { race, class: charClass, level, alignment },
                backstory,
                gm_notes: gmNotes,
                image_url: finalImageUrl,
                is_npc: isNpc,
                relationships: relationships || [],
                current_pin_id: currentPinId || null,
                sheet_url: sheetUrl,
                character_json: charJson,
                created_by: user.id
            };

            let result;
            if (editingChar && editingChar.id) {
                result = await supabase.from('characters').update(payload).eq('id', editingChar.id);
            } else {
                result = await supabase.from('characters').insert(payload);
            }

            if (result.error) throw result.error;

            await refreshData(true);
            resetForm();
        } catch (error: any) {
            console.error("Error saving character:", error);
            alert(`Error saving character: ${error.message || "Unknown error"}. Check if 'characters' table exists.`);
        } finally {
            setSubmitting(false); // CRITICAL: Always reset loading state
        }
    };

    const handleDelete = async (char: Character) => {
        if(!window.confirm(`Delete ${char.name}?`)) return;
        const { error } = await supabase.from('characters').delete().eq('id', char.id);
        if(!error) await refreshData(true);
    };

    const addRelationship = () => setRelationships([...relationships, { targetId: '', type: '', notes: '' }]);
    const updateRelationship = (index: number, field: keyof CharacterRelationship, value: string) => {
        const newRels = [...relationships];
        newRels[index] = { ...newRels[index], [field]: value };
        setRelationships(newRels);
    };
    const removeRelationship = (index: number) => setRelationships(relationships.filter((_, i) => i !== index));

    return (
        <Modal isOpen={isOpen} onClose={onClose} title={isEditing ? (editingChar ? "Edit Character" : "New Character") : "Manage Characters"} maxWidthClass="max-w-4xl">
            {!isEditing ? (
                <div className="space-y-6">
                    <button onClick={() => setIsEditing(true)} className="w-full flex items-center justify-center space-x-2 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-4 rounded-xl shadow-lg transition-all">
                        <Icon name="plus" className="h-5 w-5" />
                        <span>Create New Character</span>
                    </button>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {characters.map(char => (
                             <div key={char.id} className="relative group bg-stone-800/40 border border-stone-700/50 rounded-xl p-4 flex gap-4 hover:bg-stone-800/60 transition-colors">
                                <div className="w-16 h-16 rounded-full bg-stone-900 overflow-hidden flex-shrink-0 border-2 border-stone-600 group-hover:border-amber-500 transition-colors">
                                    {char.image_url ? <img src={char.image_url} alt={char.name} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-stone-600 text-xs">No Img</div>}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <h3 className="font-medieval text-lg text-stone-200 truncate">{char.name}</h3>
                                    <p className="text-xs text-stone-500 uppercase tracking-wider font-bold mb-1">{char.is_npc ? 'NPC' : 'PC'}</p>
                                    <p className="text-xs text-stone-400 truncate">{char.role_details?.race} {char.role_details?.class}</p>
                                    {char.current_pin_id && <p className="text-[10px] text-amber-500/80 mt-1 flex items-center gap-1"><Icon name="pin" className="w-3 h-3" /> On Map</p>}
                                </div>
                                <div className="flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity absolute right-2 top-2">
                                     <button onClick={() => handleEdit(char)} className="p-1.5 rounded-lg bg-stone-900 text-stone-400 hover:text-amber-500"><Icon name="pencil" className="w-4 h-4" /></button>
                                     <button onClick={() => handleDelete(char)} className="p-1.5 rounded-lg bg-stone-900 text-stone-400 hover:text-red-500"><Icon name="trash" className="w-4 h-4" /></button>
                                </div>
                             </div>
                        ))}
                        {characters.length === 0 && <p className="col-span-full text-center text-stone-500 italic py-8">No characters found.</p>}
                    </div>
                </div>
            ) : (
                <form onSubmit={handleSave} className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    {/* Left Column: Stats & Basic Info */}
                    <div className="space-y-4">
                        <div className="flex items-center gap-4 bg-stone-800/30 p-4 rounded-xl border border-stone-700/30">
                            <label className="w-20 h-20 rounded-full bg-stone-900 border-2 border-dashed border-stone-600 flex items-center justify-center cursor-pointer hover:border-amber-500 overflow-hidden relative">
                                {imageUrl || (imageFile && URL.createObjectURL(imageFile)) ? (
                                    <img src={imageUrl || (imageFile ? URL.createObjectURL(imageFile) : '')} className="w-full h-full object-cover" />
                                ) : <span className="text-xs text-stone-500 text-center">Avatar</span>}
                                <input type="file" className="hidden" accept="image/*" onChange={e => {
                                    if(e.target.files?.[0]) { setImageFile(e.target.files[0]); setImageUrl(''); }
                                }} />
                            </label>
                            <div className="flex-1 space-y-2">
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input type="checkbox" checked={isNpc} onChange={e => setIsNpc(e.target.checked)} className="rounded border-stone-600 bg-stone-800 text-amber-600 focus:ring-amber-500" />
                                    <span className="text-sm font-bold text-stone-300">Is NPC?</span>
                                </label>
                                <input type="text" placeholder="Image URL (optional)" value={imageUrl} onChange={e => { setImageUrl(e.target.value); setImageFile(null); }} className="w-full rounded-lg border border-stone-600/50 bg-stone-900/40 px-3 py-2 text-sm text-stone-200" />
                            </div>
                        </div>

                        <input type="text" placeholder="Name" value={name} onChange={e => setName(e.target.value)} required className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                        <div className="grid grid-cols-2 gap-2">
                             <input type="text" placeholder="Race" value={race} onChange={e => setRace(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                             <input type="text" placeholder="Class" value={charClass} onChange={e => setCharClass(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                        </div>
                        <div className="flex gap-2">
                            <input type="number" placeholder="Level" min="1" max="20" value={level} onChange={e => setLevel(parseInt(e.target.value))} className="w-24 rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                            <input type="text" placeholder="Alignment" value={alignment} onChange={e => setAlignment(e.target.value)} className="flex-1 rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                        </div>

                         {/* Extra Links */}
                         <div className="space-y-2 bg-stone-800/30 p-4 rounded-xl border border-stone-700/30">
                            <h4 className="text-xs font-bold uppercase text-stone-500 mb-2">Integrations</h4>
                            <div className="flex items-center gap-2">
                                <Icon name="external" className="w-4 h-4 text-stone-500" />
                                <input type="text" placeholder="Link to Character Sheet (URL)" value={sheetUrl} onChange={e => setSheetUrl(e.target.value)} className="flex-1 bg-stone-900/50 rounded border border-stone-700/50 px-3 py-2 text-sm text-stone-200" />
                            </div>
                            <label className="flex items-center gap-2 cursor-pointer bg-stone-900/50 rounded border border-stone-700/50 px-3 py-2 text-sm hover:bg-stone-800/50 transition-colors">
                                <Icon name="upload" className="w-4 h-4 text-stone-500" />
                                <span className="text-stone-300 flex-1 truncate">{jsonFileName || "Upload Tracker JSON (for encounter tools)"}</span>
                                <input type="file" accept=".json" onChange={handleJsonUpload} className="hidden" />
                            </label>
                         </div>

                        <textarea placeholder="Backstory / Bio" value={backstory} onChange={e => setBackstory(e.target.value)} rows={5} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                    </div>

                    {/* Right Column: Location & Relationships */}
                    <div className="space-y-4">
                        <div className="bg-stone-800/30 p-4 rounded-xl border border-stone-700/30 space-y-3">
                            <div className="flex justify-between items-center border-b border-stone-700/50 pb-2">
                                <h4 className="text-sm font-bold uppercase text-stone-400 flex items-center gap-2"><Icon name="map" className="w-4 h-4" /> Location</h4>
                                <div className="text-xs text-stone-500 italic">
                                    {currentPinId ? "Pin selected" : "Select a map, then click a pin"}
                                </div>
                            </div>

                            <select 
                                value={selectedMapId} 
                                onChange={e => { setSelectedMapId(e.target.value); setCurrentPinId(null); }} 
                                className="w-full rounded-lg border border-stone-600/50 bg-stone-900/40 px-3 py-2 text-sm text-stone-200 focus:outline-none"
                            >
                                <option value="">(Select Map to Locate Character)</option>
                                {maps.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                            </select>

                            {selectedMap ? (
                                <div className="relative h-64 w-full rounded-xl overflow-hidden border border-stone-700/50 shadow-inner bg-stone-950 group">
                                    <MapViewer 
                                        map={selectedMap}
                                        onSelectPin={(pin) => setCurrentPinId(pin.id)}
                                        onAddPin={() => {}} 
                                        highlightedPinId={currentPinId}
                                    />
                                    {!currentPinId && <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-black/60 px-3 py-1 rounded-full text-xs text-amber-500 pointer-events-none backdrop-blur-sm border border-amber-900/30">Click a pin to place character</div>}
                                    {currentPinId && <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-amber-600/90 px-3 py-1 rounded-full text-xs text-white pointer-events-none shadow-lg">Location Set</div>}
                                </div>
                            ) : (
                                <div className="h-64 flex items-center justify-center bg-stone-900/20 rounded-xl border border-dashed border-stone-700/50 text-stone-600 text-sm italic">
                                    Map preview will appear here
                                </div>
                            )}

                            <div className="flex items-center justify-between text-xs">
                                <span className="text-stone-500">Current ID: <span className="font-mono text-stone-400">{currentPinId ? pins.find(p => p.id === currentPinId)?.title || 'Unknown Pin' : 'None'}</span></span>
                                {currentPinId && <button type="button" onClick={() => setCurrentPinId(null)} className="text-red-500 hover:underline">Clear Location</button>}
                            </div>
                        </div>

                        {/* Relationships */}
                        <div className="bg-stone-800/30 p-4 rounded-xl border border-stone-700/30 space-y-3">
                            <div className="flex justify-between items-center">
                                <h4 className="text-sm font-bold uppercase text-stone-400 flex items-center gap-2"><Icon name="user" className="w-4 h-4" /> Relationships</h4>
                                <button type="button" onClick={addRelationship} className="text-xs text-amber-500 hover:underline">+ Add</button>
                            </div>
                            <div className="space-y-2 max-h-40 overflow-y-auto custom-scrollbar">
                                {relationships.map((rel, idx) => (
                                    <div key={idx} className="flex flex-col gap-2 p-2 bg-stone-900/40 rounded border border-stone-800">
                                        <div className="flex gap-2">
                                            <select 
                                                value={rel.targetId} 
                                                onChange={e => updateRelationship(idx, 'targetId', e.target.value)} 
                                                className="flex-1 rounded border border-stone-600/50 bg-stone-800 text-xs text-stone-200 p-1"
                                            >
                                                <option value="">Select Character...</option>
                                                {characters.filter(c => c.id !== editingChar?.id).map(c => (
                                                    <option key={c.id} value={c.id}>{c.name}</option>
                                                ))}
                                            </select>
                                            <input 
                                                type="text" 
                                                placeholder="Type (e.g. Rival)" 
                                                value={rel.type} 
                                                onChange={e => updateRelationship(idx, 'type', e.target.value)} 
                                                className="w-1/3 rounded border border-stone-600/50 bg-stone-800 text-xs text-stone-200 p-1"
                                            />
                                            <button type="button" onClick={() => removeRelationship(idx)} className="text-stone-500 hover:text-red-500 px-1"><Icon name="trash" className="w-3 h-3" /></button>
                                        </div>
                                        <input 
                                            type="text" 
                                            placeholder="Notes..." 
                                            value={rel.notes || ''} 
                                            onChange={e => updateRelationship(idx, 'notes', e.target.value)} 
                                            className="w-full rounded border border-stone-600/30 bg-stone-800 text-xs text-stone-400 p-1"
                                        />
                                    </div>
                                ))}
                                {relationships.length === 0 && <p className="text-xs text-stone-600 italic text-center">No relationships defined.</p>}
                            </div>
                        </div>

                         <textarea placeholder="GM Notes (Secret)" value={gmNotes} onChange={e => setGmNotes(e.target.value)} rows={2} className="w-full rounded-xl border border-red-900/30 bg-red-950/10 px-4 py-3 text-stone-200 placeholder-red-400/50 focus:border-red-500 focus:outline-none" />
                    </div>

                    <div className="lg:col-span-2 flex gap-3 pt-4 border-t border-stone-700/50">
                        <button type="button" onClick={resetForm} className="flex-1 bg-stone-700 hover:bg-stone-600 text-stone-200 font-bold py-3 px-6 rounded-xl transition-all">Cancel</button>
                        <button type="submit" disabled={submitting} className="flex-1 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all">
                            {submitting ? <Icon name="spinner" className="h-5 w-5 animate-spin mx-auto"/> : "Save Character"}
                        </button>
                    </div>
                </form>
            )}
        </Modal>
    );
};

// --- MAP MANAGER MODAL ---
interface MapManagerModalProps { isOpen: boolean; onClose: () => void; }
export const MapManagerModal: React.FC<MapManagerModalProps> = ({ isOpen, onClose }) => {
    const { user } = useAuth();
    const { maps, refreshData } = useAppContext();
    const [name, setName] = useState('');
    const [imageUrl, setImageUrl] = useState('');
    const [imageFile, setImageFile] = useState<File | null>(null);
    const [parentMapId, setParentMapId] = useState<string>('');
    const [isVisible, setIsVisible] = useState(true);
    const [loading, setLoading] = useState(false);
    const [isEditing, setIsEditing] = useState<string | null>(null);

    // Config fields
    const [gridSize, setGridSize] = useState(50);
    const [pinScale, setPinScale] = useState(50);
    const [showGrid, setShowGrid] = useState(false);

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user) return;
        setLoading(true);

        try {
            let finalUrl = imageUrl;
            if (imageFile) {
                finalUrl = await fileToBase64(imageFile);
            }

            const payload = {
                name,
                parent_map_id: parentMapId || null,
                is_visible: isVisible,
                grid_size: gridSize,
                pin_scale: pinScale,
                is_grid_visible: showGrid,
                ...(finalUrl ? { image_url: finalUrl } : {})
            };

            let result;
            if (isEditing) {
                 result = await supabase.from('maps').update(payload).eq('id', isEditing);
            } else {
                 result = await supabase.from('maps').insert({ ...payload, image_url: finalUrl || '', created_by: user.id });
            }

            if (result.error) throw result.error;

            await refreshData(true);
            resetForm();
        } catch (error: any) {
            console.error("Map save failed", error);
            alert("Error saving map: " + error.message);
        } finally {
            setLoading(false);
        }
    };

    const resetForm = () => {
        setName(''); setImageUrl(''); setImageFile(null); setParentMapId(''); setIsVisible(true);
        setGridSize(50); setPinScale(50); setShowGrid(false); setIsEditing(null);
    };

    const handleEdit = (map: MapType) => {
        setIsEditing(map.id);
        setName(map.name);
        setImageUrl(map.image_url);
        setParentMapId(map.parent_map_id || '');
        setIsVisible(map.is_visible);
        setGridSize(map.grid_size || 50);
        setPinScale(map.pin_scale || 50);
        setShowGrid(map.is_grid_visible || false);
    };

    const handleDelete = async (id: string) => {
        if(!window.confirm("Delete map? This will cascade to pins!")) return;
        await supabase.from('maps').delete().eq('id', id);
        await refreshData(true);
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Map Manager" maxWidthClass="max-w-6xl">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 h-full min-h-[500px]">
                {/* List Column (Left) */}
                <div className="lg:col-span-3 border-r border-stone-700/50 pr-4 space-y-3 flex flex-col">
                    <button onClick={resetForm} className="w-full flex items-center gap-2 bg-stone-800 hover:bg-stone-700 p-3 rounded-xl transition-colors border border-stone-700">
                        <Icon name="plus" className="w-4 h-4 text-amber-500"/>
                        <span className="font-bold text-stone-300">Add New Map</span>
                    </button>
                    <div className="space-y-2 overflow-y-auto custom-scrollbar flex-1">
                        {maps.map(m => (
                            <div key={m.id} className={`p-3 rounded-xl border cursor-pointer transition-all flex justify-between items-center ${isEditing === m.id ? 'bg-amber-900/20 border-amber-500/50' : 'bg-stone-900/40 border-stone-800 hover:border-stone-600'}`} onClick={() => handleEdit(m)}>
                                <span className="text-sm font-medium text-stone-300 truncate">{m.name}</span>
                                <div className="flex gap-1">
                                    {!m.is_visible && <Icon name="eye-off" className="w-3 h-3 text-stone-500" />}
                                    <button onClick={(e) => {e.stopPropagation(); handleDelete(m.id);}} className="text-stone-600 hover:text-red-500"><Icon name="trash" className="w-3 h-3"/></button>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>

                {/* Form Column (Right) */}
                <form onSubmit={handleSave} className="lg:col-span-9 flex flex-col h-full overflow-hidden">
                    <div className="flex items-center justify-between border-b border-stone-700/50 pb-4 mb-4">
                         <h3 className="font-medieval text-xl text-amber-500">{isEditing ? `Edit: ${name}` : "New Map Details"}</h3>
                         <div className="flex gap-3">
                            <button type="button" onClick={onClose} className="px-4 py-2 text-stone-400 hover:text-stone-200">Cancel</button>
                            <button type="submit" disabled={loading} className="bg-amber-600 hover:bg-amber-500 text-white font-bold py-2 px-6 rounded-xl shadow-lg transition-all disabled:opacity-50 min-w-[120px]">
                                {loading ? <Icon name="spinner" className="h-5 w-5 animate-spin mx-auto"/> : 'Save Map'}
                            </button>
                         </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 overflow-y-auto custom-scrollbar flex-1 pr-2">
                        {/* Config Inputs */}
                        <div className="space-y-4">
                             <input type="text" placeholder="Map Name" value={name} onChange={e => setName(e.target.value)} required className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />

                             <div className="flex items-center gap-4 bg-stone-800/30 p-4 rounded-xl border border-stone-700/30">
                                <label className="w-20 h-20 rounded-lg bg-stone-900 border-2 border-dashed border-stone-600 flex items-center justify-center cursor-pointer hover:border-amber-500 overflow-hidden relative flex-shrink-0">
                                    {imageUrl || (imageFile && URL.createObjectURL(imageFile)) ? (
                                        <img src={imageUrl || (imageFile ? URL.createObjectURL(imageFile) : '')} className="w-full h-full object-cover" />
                                    ) : (
                                        <Icon name="image" className="w-8 h-8 text-stone-600" />
                                    )}
                                    <input type="file" className="hidden" accept="image/*" onChange={e => {
                                        if(e.target.files?.[0]) { setImageFile(e.target.files[0]); setImageUrl(''); }
                                    }} />
                                </label>
                                <div className="flex-1">
                                    <label className="text-xs font-bold uppercase text-stone-500 mb-1 block">Image Source</label>
                                    <input type="text" placeholder="Or paste Image URL..." value={imageUrl} onChange={e => { setImageUrl(e.target.value); setImageFile(null); }} className="w-full rounded-lg border border-stone-600/50 bg-stone-900/40 px-3 py-2 text-sm text-stone-200" />
                                </div>
                             </div>

                             <div className="grid grid-cols-2 gap-4">
                                 <div>
                                    <label className="text-xs font-bold uppercase text-stone-500 mb-1 block">Parent Map</label>
                                    <select value={parentMapId} onChange={e => setParentMapId(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-3 py-3 text-stone-200 focus:outline-none">
                                        <option value="">(None - Top Level)</option>
                                        {maps.filter(m => m.id !== isEditing).map(m => (
                                            <option key={m.id} value={m.id}>{m.name}</option>
                                        ))}
                                    </select>
                                 </div>
                                 <div className="flex items-center px-4 bg-stone-800/40 rounded-xl border border-stone-700/50">
                                    <label className="flex items-center gap-3 cursor-pointer w-full">
                                        <input type="checkbox" checked={isVisible} onChange={e => setIsVisible(e.target.checked)} className="rounded border-stone-600 bg-stone-800 text-amber-600 focus:ring-amber-500" />
                                        <span className="font-bold text-stone-300">Player Visible?</span>
                                    </label>
                                 </div>
                             </div>

                             <div className="bg-stone-800/30 p-4 rounded-xl border border-stone-700/30 space-y-4">
                                 <div className="flex justify-between items-center">
                                    <h4 className="text-xs font-bold uppercase text-stone-500">Calibration</h4>
                                    <label className="flex items-center gap-2 text-xs text-stone-400 cursor-pointer">
                                        <input type="checkbox" checked={showGrid} onChange={e => setShowGrid(e.target.checked)} className="rounded text-amber-600 focus:ring-amber-500 bg-stone-900 border-stone-700" />
                                        Show Grid Overlay
                                    </label>
                                 </div>
                                 <div className="space-y-4">
                                    <div>
                                        <label className="flex justify-between text-[10px] text-stone-500 uppercase mb-1">
                                            <span>Grid Size</span>
                                            <span className="text-stone-300">{gridSize}px</span>
                                        </label>
                                        <input type="range" min="10" max="200" value={gridSize} onChange={e => setGridSize(parseInt(e.target.value))} className="w-full accent-amber-600 bg-stone-700 h-2 rounded-lg appearance-none cursor-pointer" />
                                    </div>
                                    <div>
                                        <label className="flex justify-between text-[10px] text-stone-500 uppercase mb-1">
                                            <span>Pin Scale</span>
                                            <span className="text-stone-300">{pinScale}px</span>
                                        </label>
                                        <input type="range" min="10" max="150" value={pinScale} onChange={e => setPinScale(parseInt(e.target.value))} className="w-full accent-amber-600 bg-stone-700 h-2 rounded-lg appearance-none cursor-pointer" />
                                    </div>
                                 </div>
                             </div>
                        </div>

                        {/* Visual Preview */}
                        <div className="relative bg-stone-950 rounded-xl border border-stone-700/50 overflow-hidden shadow-inner flex items-center justify-center min-h-[300px]">
                            {imageUrl || imageFile ? (
                                <div className="relative w-full h-full overflow-auto custom-scrollbar flex items-center justify-center p-4">
                                    <div className="relative shadow-2xl">
                                        <img src={imageUrl || (imageFile ? URL.createObjectURL(imageFile) : '')} className="max-w-none opacity-80" style={{ transform: 'scale(1)' }} alt="Preview" />

                                        {/* Grid Overlay */}
                                        <div 
                                            className="absolute inset-0 pointer-events-none opacity-40"
                                            style={{
                                                backgroundSize: `${gridSize}px ${gridSize}px`,
                                                backgroundImage: `linear-gradient(to right, rgba(255, 255, 255, 0.5) 1px, transparent 1px), linear-gradient(to bottom, rgba(255, 255, 255, 0.5) 1px, transparent 1px)`
                                            }}
                                        />

                                        {/* Pin Preview */}
                                        <div 
                                            className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-amber-500 rounded-full flex items-center justify-center shadow-lg ring-2 ring-white"
                                            style={{ width: `${pinScale}px`, height: `${pinScale}px`, fontSize: `${pinScale * 0.6}px` }}
                                        >
                                            📍
                                        </div>
                                    </div>
                                </div>
                            ) : (
                                <div className="text-stone-600 text-sm flex flex-col items-center">
                                    <Icon name="image" className="w-12 h-12 mb-2 opacity-20"/>
                                    Select an image to calibrate
                                </div>
                            )}
                        </div>
                    </div>
                </form>
            </div>
        </Modal>
    );
};

// --- PIN TYPE MANAGER MODAL ---
interface PinTypeManagerModalProps { isOpen: boolean; onClose: () => void; }
export const PinTypeManagerModal: React.FC<PinTypeManagerModalProps> = ({ isOpen, onClose }) => {
    const { pinTypes, refreshData } = useAppContext();
    const [name, setName] = useState('');
    const [emoji, setEmoji] = useState('📍');
    const [color, setColor] = useState('#3b82f6');
    const [loading, setLoading] = useState(false);

    const handleAdd = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        try {
            if (!name) return;
            await supabase.from('pin_types').insert({ name, emoji, color });
            await refreshData(true);
            setName('');
        } catch (error) {
            console.error("Error adding pin type", error);
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async (id: string) => {
        if (!window.confirm("Delete this pin type? This might affect existing pins.")) return;
        await supabase.from('pin_types').delete().eq('id', id);
        await refreshData(true);
    };

    return (
        <Modal isOpen={isOpen} onClose={onClose} title="Manage Pin Types">
            {/* Same content as before */}
             <div className="space-y-6">
                <form onSubmit={handleAdd} className="bg-stone-800/40 p-4 rounded-xl border border-stone-700/50 space-y-4">
                    <h3 className="font-bold text-stone-400 uppercase text-xs">Create New Type</h3>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                         <div className="col-span-2">
                            <input type="text" placeholder="Type Name (e.g. City)" value={name} onChange={e => setName(e.target.value)} required className="w-full rounded-xl border border-stone-600/50 bg-stone-800/50 px-3 py-2 text-stone-200 focus:border-amber-500 focus:outline-none" />
                         </div>
                         <input type="text" placeholder="Emoji" value={emoji} onChange={e => setEmoji(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/50 px-3 py-2 text-center text-stone-200 focus:border-amber-500 focus:outline-none" />
                         <input type="color" value={color} onChange={e => setColor(e.target.value)} className="w-full h-10 rounded-xl bg-transparent cursor-pointer" />
                    </div>
                    <button type="submit" disabled={loading} className="w-full bg-amber-600 hover:bg-amber-500 text-white font-bold py-2 rounded-xl transition-all disabled:opacity-50">
                        {loading ? 'Adding...' : 'Add Type'}
                    </button>
                </form>

                <div className="space-y-2">
                    {pinTypes.map(pt => (
                        <div key={pt.id} className="flex items-center justify-between p-3 bg-stone-800/30 rounded-xl border border-stone-700/30">
                            <div className="flex items-center gap-3">
                                <div className="w-8 h-8 rounded-full flex items-center justify-center shadow-lg" style={{ backgroundColor: pt.color }}>{pt.emoji}</div>
                                <span className="font-medium text-stone-200">{pt.name}</span>
                            </div>
                            <button onClick={() => handleDelete(pt.id)} className="text-stone-500 hover:text-red-500 p-2"><Icon name="trash" className="w-4 h-4"/></button>
                        </div>
                    ))}
                    {pinTypes.length === 0 && <p className="text-center text-stone-500 text-sm">No pin types defined.</p>}
                </div>
            </div>
        </Modal>
    );
};

// --- PIN EDITOR MODAL ---
interface PinEditorModalProps {
    pinData: Partial<Pin>;
    onClose: () => void;
    onSave: () => void;
}
export const PinEditorModal: React.FC<PinEditorModalProps> = ({ pinData, onClose, onSave }) => {
    const { user } = useAuth();
    const { maps, pinTypes, refreshData } = useAppContext();
    const { items } = useItems(); // For inventory search

    const [title, setTitle] = useState(pinData.title || '');
    const [pinTypeId, setPinTypeId] = useState(pinData.pin_type_id || (pinTypes[0]?.id || ''));
    const [isVisible, setIsVisible] = useState(pinData.is_visible !== undefined ? pinData.is_visible : true);
    const [linkedMapId, setLinkedMapId] = useState(pinData.linked_map_id || '');
    const [description, setDescription] = useState(pinData.data?.description || '');
    const [sections, setSections] = useState<PinSection[]>(pinData.data?.sections || []);
    const [encounterFile, setEncounterFile] = useState<{name: string, content: string} | null>(pinData.data?.encounter_file || null);

    const [loading, setLoading] = useState(false);
    const [newItemType, setNewItemType] = useState<PinSectionType>('text');

    // Section Helpers
    const addSection = () => {
        const newSection: PinSection = {
            id: `sec_${Date.now()}`,
            type: newItemType,
            title: '',
            content: '',
            list_items: [],
            stats: [],
            items: []
        };
        setSections([...sections, newSection]);
    };

    const updateSection = (id: string, updates: Partial<PinSection>) => {
        setSections(sections.map(s => s.id === id ? { ...s, ...updates } : s));
    };

    const removeSection = (id: string) => {
        setSections(sections.filter(s => s.id !== id));
    };

    const moveSection = (index: number, direction: 'up' | 'down') => {
        const newSecs = [...sections];
        if (direction === 'up' && index > 0) {
            [newSecs[index], newSecs[index-1]] = [newSecs[index-1], newSecs[index]];
        } else if (direction === 'down' && index < newSecs.length - 1) {
            [newSecs[index], newSecs[index+1]] = [newSecs[index+1], newSecs[index]];
        }
        setSections(newSecs);
    };

    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        const text = await file.text();
        setEncounterFile({ name: file.name, content: text });
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user || !title || !pinTypeId) return;
        setLoading(true);

        try {
            const dataPayload: PinData = {
                description,
                images: [], 
                sections,
                encounter_file: encounterFile
            };

            const dbPayload = {
                map_id: pinData.map_id,
                x_coord: pinData.x_coord,
                y_coord: pinData.y_coord,
                title,
                pin_type_id: pinTypeId,
                is_visible: isVisible,
                linked_map_id: linkedMapId || null,
                data: dataPayload,
                created_by: pinData.created_by || user.id
            };

            if (pinData.id) {
                await supabase.from('pins').update(dbPayload).eq('id', pinData.id);
            } else {
                await supabase.from('pins').insert(dbPayload);
            }

            await onSave();
        } catch (error: any) {
            console.error("Error saving pin:", error);
            alert("Error saving pin: " + error.message);
        } finally {
            setLoading(false);
        }
    };

    // --- Sub-components for Section Editors ---
    const renderSectionEditor = (section: PinSection, index: number) => {
        return (
            <div key={section.id} className="bg-stone-800/40 border border-stone-700/50 rounded-xl p-3 mb-3 animate-modal-in">
                <div className="flex items-center justify-between mb-3 border-b border-stone-700/50 pb-2">
                    <div className="flex items-center gap-2">
                        <span className="text-xs uppercase font-bold text-stone-500 bg-stone-900 px-2 py-0.5 rounded">{section.type}</span>
                        <input 
                            type="text" 
                            placeholder="Section Title" 
                            value={section.title} 
                            onChange={e => updateSection(section.id, { title: e.target.value })} 
                            className="bg-transparent text-sm font-bold text-stone-200 focus:outline-none border-b border-transparent focus:border-amber-500 w-48"
                        />
                    </div>
                    <div className="flex items-center gap-1">
                        <button type="button" onClick={() => moveSection(index, 'up')} disabled={index === 0} className="p-1 text-stone-500 hover:text-stone-300 disabled:opacity-30"><Icon name="chevron-down" className="rotate-180 w-4 h-4"/></button>
                        <button type="button" onClick={() => moveSection(index, 'down')} disabled={index === sections.length - 1} className="p-1 text-stone-500 hover:text-stone-300 disabled:opacity-30"><Icon name="chevron-down" className="w-4 h-4"/></button>
                        <button type="button" onClick={() => removeSection(section.id)} className="p-1 text-stone-500 hover:text-red-500 ml-2"><Icon name="trash" className="w-4 h-4"/></button>
                    </div>
                </div>

                <div className="space-y-2">
                    {(section.type === 'text' || section.type === 'secret') && (
                        <textarea 
                            placeholder="Content..." 
                            value={section.content} 
                            onChange={e => updateSection(section.id, { content: e.target.value })} 
                            rows={3} 
                            className="w-full bg-stone-900/50 rounded border border-stone-700/50 p-2 text-sm text-stone-300 focus:border-amber-500 focus:outline-none"
                        />
                    )}

                    {section.type === 'image' && (
                        <div className="flex gap-2">
                            <input 
                                type="text" 
                                placeholder="Image URL" 
                                value={section.image_url || ''} 
                                onChange={e => updateSection(section.id, { image_url: e.target.value })} 
                                className="flex-1 bg-stone-900/50 rounded border border-stone-700/50 p-2 text-sm text-stone-300"
                            />
                        </div>
                    )}

                    {section.type === 'list' && (
                        <div>
                             <textarea 
                                placeholder="Description (optional)" 
                                value={section.content} 
                                onChange={e => updateSection(section.id, { content: e.target.value })} 
                                rows={1}
                                className="w-full bg-stone-900/50 rounded border border-stone-700/50 p-2 text-sm text-stone-300 mb-2"
                            />
                            <div className="space-y-1">
                                {section.list_items?.map((item, i) => (
                                    <div key={i} className="flex gap-2">
                                        <input 
                                            value={item} 
                                            onChange={e => {
                                                const newList = [...(section.list_items || [])];
                                                newList[i] = e.target.value;
                                                updateSection(section.id, { list_items: newList });
                                            }}
                                            className="flex-1 bg-stone-900/30 rounded border border-stone-700/30 px-2 py-1 text-sm text-stone-300"
                                        />
                                        <button type="button" onClick={() => {
                                            const newList = section.list_items?.filter((_, idx) => idx !== i);
                                            updateSection(section.id, { list_items: newList });
                                        }} className="text-red-500 hover:text-red-400">&times;</button>
                                    </div>
                                ))}
                                <button type="button" onClick={() => updateSection(section.id, { list_items: [...(section.list_items || []), ''] })} className="text-xs text-amber-500 hover:underline">+ Add Item</button>
                            </div>
                        </div>
                    )}

                    {section.type === 'statblock' && (
                        <div>
                             <textarea 
                                placeholder="Description (optional)" 
                                value={section.content} 
                                onChange={e => updateSection(section.id, { content: e.target.value })} 
                                rows={1}
                                className="w-full bg-stone-900/50 rounded border border-stone-700/50 p-2 text-sm text-stone-300 mb-2"
                            />
                             <div className="grid grid-cols-2 gap-2">
                                {section.stats?.map((stat, i) => (
                                    <div key={i} className="flex gap-1 bg-stone-900/30 p-1 rounded border border-stone-800">
                                        <input placeholder="Label" value={stat.label} onChange={e => {
                                            const newStats = [...(section.stats || [])];
                                            newStats[i].label = e.target.value;
                                            updateSection(section.id, { stats: newStats });
                                        }} className="w-1/2 bg-transparent text-xs text-amber-500 font-bold uppercase focus:outline-none" />
                                        <input placeholder="Value" value={stat.value} onChange={e => {
                                            const newStats = [...(section.stats || [])];
                                            newStats[i].value = e.target.value;
                                            updateSection(section.id, { stats: newStats });
                                        }} className="w-1/2 bg-transparent text-sm text-stone-200 text-right focus:outline-none" />
                                        <button type="button" onClick={() => {
                                            const newStats = section.stats?.filter((_, idx) => idx !== i);
                                            updateSection(section.id, { stats: newStats });
                                        }} className="text-red-500 px-1">&times;</button>
                                    </div>
                                ))}
                             </div>
                             <button type="button" onClick={() => updateSection(section.id, { stats: [...(section.stats || []), { label: 'STAT', value: '10' }] })} className="text-xs text-amber-500 hover:underline mt-1">+ Add Stat</button>
                        </div>
                    )}

                    {section.type === 'inventory' && (
                        <div>
                            {/* Item Search */}
                            <input 
                                type="text" 
                                placeholder="Search 5e items to add..." 
                                onChange={e => {
                                    // Basic fuzzy search logic here or just rely on manual entry for custom items
                                }}
                                list={`datalist-${section.id}`}
                                className="w-full bg-stone-900/50 rounded border border-stone-700/50 p-2 text-sm text-stone-300 mb-2 focus:border-amber-500 focus:outline-none"
                                onKeyDown={(e) => {
                                    if (e.key === 'Enter') {
                                        e.preventDefault();
                                        const val = e.currentTarget.value;
                                        if(!val) return;

                                        const knownItem = items.find(i => i.name.toLowerCase() === val.toLowerCase());
                                        const newItem: InventoryItem = {
                                            id: `item_${Date.now()}`,
                                            name: knownItem ? knownItem.name : val,
                                            count: 1,
                                            is_magic: knownItem?.is_magic,
                                            desc: knownItem?.desc ? knownItem.desc.join('\n') : undefined
                                        };

                                        updateSection(section.id, { items: [...(section.items || []), newItem] });
                                        e.currentTarget.value = '';
                                    }
                                }}
                            />
                            <datalist id={`datalist-${section.id}`}>
                                {items.slice(0, 100).map(i => <option key={i.index} value={i.name} />)}
                            </datalist>

                            <div className="space-y-1 max-h-40 overflow-y-auto custom-scrollbar">
                                {section.items?.map((item, i) => (
                                    <div key={item.id} className="flex items-center gap-2 bg-stone-900/30 p-1 rounded">
                                        <input 
                                            type="number" 
                                            value={item.count} 
                                            onChange={e => {
                                                const newItems = [...(section.items || [])];
                                                newItems[i].count = parseInt(e.target.value);
                                                updateSection(section.id, { items: newItems });
                                            }}
                                            className="w-10 bg-transparent text-center border-b border-stone-700 text-stone-400 text-xs"
                                        />
                                        <span className={`flex-1 text-sm ${item.is_magic ? 'text-amber-500' : 'text-stone-300'}`}>{item.name}</span>
                                        <button type="button" onClick={() => {
                                            const newItems = section.items?.filter((_, idx) => idx !== i);
                                            updateSection(section.id, { items: newItems });
                                        }} className="text-red-500 hover:text-red-400 px-2">&times;</button>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            </div>
        );
    };

    return (
        <Modal isOpen={true} onClose={onClose} title={pinData.id ? "Edit Pin" : "New Pin"}>
            <form onSubmit={handleSave} className="space-y-6">
                <div className="space-y-3">
                    <input type="text" placeholder="Pin Title" value={title} onChange={e => setTitle(e.target.value)} required className="w-full text-lg font-bold rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-100 focus:border-amber-500 focus:outline-none" />

                    <div className="grid grid-cols-2 gap-4">
                        <select value={pinTypeId} onChange={e => setPinTypeId(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-3 py-3 text-stone-200 focus:outline-none">
                            {pinTypes.map(pt => (
                                <option key={pt.id} value={pt.id}>{pt.emoji} {pt.name}</option>
                            ))}
                        </select>
                        <select value={linkedMapId} onChange={e => setLinkedMapId(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-3 py-3 text-stone-200 focus:outline-none">
                            <option value="">(No Linked Map)</option>
                            {maps.filter(m => m.id !== pinData.map_id).map(m => (
                                <option key={m.id} value={m.id}>Link to: {m.name}</option>
                            ))}
                        </select>
                    </div>

                    <label className="flex items-center gap-3 cursor-pointer bg-stone-800/40 p-3 rounded-xl border border-stone-700/50 w-full">
                        <input type="checkbox" checked={isVisible} onChange={e => setIsVisible(e.target.checked)} className="rounded border-stone-600 bg-stone-800 text-amber-600 focus:ring-amber-500" />
                        <span className="font-bold text-stone-300">Visible to Players?</span>
                    </label>

                    <textarea placeholder="Main Description" value={description} onChange={e => setDescription(e.target.value)} rows={3} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                </div>

                <div className="border-t border-stone-700/50 pt-4">
                    <div className="flex items-center justify-between mb-4">
                        <h3 className="font-medieval text-lg text-stone-400">Sections</h3>
                        <div className="flex gap-2">
                             <select value={newItemType} onChange={e => setNewItemType(e.target.value as PinSectionType)} className="bg-stone-900 border border-stone-700 text-stone-300 text-xs rounded px-2">
                                <option value="text">Text</option>
                                <option value="list">List</option>
                                <option value="statblock">Statblock</option>
                                <option value="image">Image</option>
                                <option value="inventory">Inventory</option>
                                <option value="secret">Secret (DM Only)</option>
                             </select>
                             <button type="button" onClick={addSection} className="bg-amber-700 hover:bg-amber-600 text-white text-xs px-3 py-1 rounded shadow">+ Add</button>
                        </div>
                    </div>

                    <div className="space-y-3">
                        {sections.map((section, index) => renderSectionEditor(section, index))}
                        {sections.length === 0 && <p className="text-center text-stone-600 italic text-sm py-4 border border-dashed border-stone-800 rounded-xl">No sections added.</p>}
                    </div>
                </div>

                <div className="border-t border-stone-700/50 pt-4">
                     <label className="flex items-center justify-between bg-stone-800/30 p-3 rounded-xl border border-stone-700/30 cursor-pointer hover:bg-stone-800/50 transition-colors">
                        <div className="flex items-center gap-3">
                            <Icon name="scroll" className="w-5 h-5 text-stone-500" />
                            <div className="text-sm">
                                <p className="font-bold text-stone-300">Encounter File (JSON)</p>
                                <p className="text-xs text-stone-500">{encounterFile ? encounterFile.name : 'No file selected'}</p>
                            </div>
                        </div>
                        <input type="file" accept=".json" onChange={handleFileUpload} className="hidden" />
                        <span className="text-xs text-amber-500 hover:underline">Upload</span>
                     </label>
                </div>

                <div className="flex gap-3 pt-4">
                     <button type="button" onClick={onClose} className="flex-1 bg-stone-700 hover:bg-stone-600 text-stone-200 font-bold py-3 px-6 rounded-xl transition-all">Cancel</button>
                     <button type="submit" disabled={loading} className="flex-1 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all">{loading ? 'Saving...' : 'Save Pin'}</button>
                </div>
            </form>
        </Modal>
    );
};

import React, { useState, useEffect } from 'react';
import { Pin, Comment, PinSection, Character } from '../types';
import { useAuth } from '../App';
import { useAppContext } from './Dashboard';
import { supabase } from '../services/supabase';
import { Icon } from './Icons';

interface PinDetailsProps {
    pin: Pin | null;
    onClose: () => void;
    onEdit: (pin: Pin) => void;
    mapId: string | undefined;
}

const PinDetails: React.FC<PinDetailsProps> = ({ pin, onClose, onEdit, mapId }) => {
    const { user } = useAuth();
    const { isPlayerView, maps, characters, refreshData } = useAppContext();
    const [comments, setComments] = useState<Comment[]>([]);
    const [newComment, setNewComment] = useState('');
    const [isPrivateComment, setIsPrivateComment] = useState(false);

    // For expanding inventory items to show description
    const [expandedItem, setExpandedItem] = useState<string | null>(null);

    // Character summoning state
    const [isSummoning, setIsSummoning] = useState(false);
    const [viewingCharacter, setViewingCharacter] = useState<Character | null>(null);

    // Derived: Characters present at this pin
    const presentCharacters = pin ? characters.filter(c => c.current_pin_id === pin.id) : [];

    useEffect(() => {
        const fetchComments = async () => {
            if (pin) {
                const { data, error } = await supabase
                    .from('comments')
                    .select('*, users(username)')
                    .eq('pin_id', pin.id)
                    .order('created_at', { ascending: true });
                if (data) setComments(data as any);
                if (error) console.error("Error fetching comments", error);
            } else {
                setComments([]);
            }
        };
        fetchComments();
    }, [pin]);

    const handleAddComment = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newComment.trim() || !pin || !user) return;

        const { data, error } = await supabase
            .from('comments')
            .insert({
                pin_id: pin.id,
                user_id: user.id,
                text: newComment,
                is_private: isPrivateComment
            })
            .select('*, users(username)')
            .single();

        if (data) setComments([...comments, data as any]);
        if (error) console.error("Error adding comment", error);

        setNewComment('');
        setIsPrivateComment(false);
    };

    const handleMoveCharacter = async (charId: string, targetPinId: string | null) => {
        const { error } = await supabase.from('characters').update({ current_pin_id: targetPinId }).eq('id', charId);
        if(!error) {
            await refreshData(true);
            setIsSummoning(false);
        }
    };

    const handleDownloadEncounter = () => {
        if (!pin?.data.encounter_file) return;
        const blob = new Blob([pin.data.encounter_file.content], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = pin.data.encounter_file.name;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const handleDownloadCharJson = (char: Character) => {
        if (!char.character_json) return;
        const blob = new Blob([JSON.stringify(char.character_json, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${char.name.replace(/\s+/g, '_').toLowerCase()}.json`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const getCharacterName = (id: string) => characters.find(c => c.id === id)?.name || "Unknown";

    const renderSection = (section: PinSection, index: number) => {
        // Render based on type
        switch (section.type) {
            case 'inventory':
                 return (
                    <div key={section.id || index} className="bg-stone-800/40 rounded-xl overflow-hidden border border-amber-900/30 shadow-md">
                        <h3 className="bg-amber-900/20 font-medieval text-lg text-amber-500 px-4 py-2 border-b border-amber-900/30 flex items-center justify-between">
                            {section.title || "Inventory"}
                            <Icon name="chest" className="w-5 h-5 opacity-70" />
                        </h3>
                        <div className="p-2 space-y-1">
                            {section.items && section.items.length > 0 ? section.items.map(item => (
                                <div key={item.id} className="rounded-lg bg-stone-900/40 border border-stone-800/50 overflow-hidden">
                                    <div 
                                        onClick={() => setExpandedItem(expandedItem === item.id ? null : item.id)}
                                        className="flex items-center justify-between p-3 cursor-pointer hover:bg-stone-800/50 transition-colors"
                                    >
                                        <div className="flex items-center gap-3">
                                            <span className="bg-stone-800 text-stone-400 text-xs font-mono px-2 py-0.5 rounded border border-stone-700">{item.count}x</span>
                                            <div>
                                                <p className={`font-medium text-sm ${item.is_magic ? 'text-amber-400' : 'text-stone-300'}`}>{item.name}</p>
                                                <div className="flex gap-2 text-[10px] text-stone-500 leading-none mt-0.5">
                                                    {item.rarity && <span className="text-purple-400/80">{item.rarity}</span>}
                                                    {item.category && <span>{item.category}</span>}
                                                </div>
                                            </div>
                                        </div>
                                        <Icon name={expandedItem === item.id ? 'chevron-down' : 'chevron-right'} className="w-4 h-4 text-stone-600" />
                                    </div>
                                    {expandedItem === item.id && item.desc && (
                                        <div className="px-3 pb-3 pt-0 text-xs text-stone-400 border-t border-stone-800/50 mt-1">
                                            <div className="py-2 prose prose-invert prose-p:my-1 max-w-none">
                                                {item.desc.split('\n').map((line, i) => <p key={i}>{line}</p>)}
                                            </div>
                                            {item.cost && <p className="text-amber-600 font-mono mt-2">Value: {item.cost}</p>}
