                        <div className="flex-1">
                             <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Color</label>
                             <input type="color" value={color} onChange={e => setColor(e.target.value)} className="w-full h-[50px] rounded-xl border border-stone-600/50 bg-stone-800/40 cursor-pointer" />
                        </div>
                    </div>
                    <button type="submit" disabled={loading} className="w-full bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all disabled:opacity-50">
                        {loading ? <Icon name="spinner" className="h-5 w-5 animate-spin mx-auto"/> : 'Save Type'}
                    </button>
                </form>
            </div>
        </Modal>
    );
};

// --- PIN EDITOR MODAL ---
interface PinEditorModalProps { 
    pinData: Partial<Pin>; 
    onClose: () => void; 
    onSave: () => Promise<void>; 
}

export const PinEditorModal: React.FC<PinEditorModalProps> = ({ pinData, onClose, onSave }) => {
    const { user } = useAuth();
    const { maps, pinTypes } = useAppContext();
    const { items: apiItems } = useItems(); // For inventory search

    const [title, setTitle] = useState(pinData.title || '');
    const [pinTypeId, setPinTypeId] = useState(pinData.pin_type_id || (pinTypes[0]?.id || ''));
    const [linkedMapId, setLinkedMapId] = useState(pinData.linked_map_id || '');
    const [isVisible, setIsVisible] = useState(pinData.is_visible ?? true);
    const [description, setDescription] = useState(pinData.data?.description || '');
    const [sections, setSections] = useState<PinSection[]>(pinData.data?.sections || []);
    const [encounterFile, setEncounterFile] = useState<{name: string, content: string} | null>(pinData.data?.encounter_file || null);

    const [loading, setLoading] = useState(false);

    // Section editing state
    const addSection = (type: PinSectionType) => {
        setSections([...sections, {
            id: Date.now().toString(),
            type,
            title: type.charAt(0).toUpperCase() + type.slice(1),
            content: '',
            list_items: [],
            stats: [],
            items: []
        }]);
    };

    const removeSection = (index: number) => {
        const newSections = [...sections];
        newSections.splice(index, 1);
        setSections(newSections);
    };

    const updateSection = (index: number, field: keyof PinSection, value: any) => {
        const newSections = [...sections];
        newSections[index] = { ...newSections[index], [field]: value };
        setSections(newSections);
    };

    // Inventory Helper for Sections
    const InventoryEditor: React.FC<{ sectionIndex: number, currentItems: InventoryItem[] }> = ({ sectionIndex, currentItems }) => {
        const [search, setSearch] = useState('');
        const [matches, setMatches] = useState<ApiItem[]>([]);

        useEffect(() => {
            if (!search) { setMatches([]); return; }
            setMatches(apiItems.filter(i => i.name.toLowerCase().includes(search.toLowerCase())).slice(0, 5));
        }, [search, apiItems]);

        const addItem = (apiItem: ApiItem) => {
            const newItem: InventoryItem = {
                id: Date.now().toString(),
                name: apiItem.name,
                count: 1,
                is_magic: apiItem.is_magic
            };
            // Fetch basic details if possible from local cache or allow edit later
            updateSection(sectionIndex, 'items', [...(currentItems || []), newItem]);
            setSearch('');
        };

        const updateItem = (itemId: string, field: keyof InventoryItem, val: any) => {
            const newItems = currentItems.map(i => i.id === itemId ? { ...i, [field]: val } : i);
            updateSection(sectionIndex, 'items', newItems);
        };

        const removeItem = (itemId: string) => {
            updateSection(sectionIndex, 'items', currentItems.filter(i => i.id !== itemId));
        };

        return (
            <div className="space-y-3">
                <div className="relative">
                    <input type="text" placeholder="Search 5e items..." value={search} onChange={e => setSearch(e.target.value)} className="w-full bg-stone-900 border border-stone-700 rounded p-2 text-sm text-stone-300"/>
                    {matches.length > 0 && (
                        <div className="absolute top-full left-0 w-full bg-stone-800 border border-stone-700 z-50 max-h-40 overflow-y-auto">
                            {matches.map(m => (
                                <button key={m.index} onClick={() => addItem(m)} type="button" className="w-full text-left p-2 hover:bg-stone-700 text-sm text-stone-300">
                                    {m.name}
                                </button>
                            ))}
                        </div>
                    )}
                </div>
                <div className="space-y-1">
                    {currentItems?.map(item => (
                        <div key={item.id} className="flex items-center gap-2 bg-stone-900/50 p-2 rounded">
                            <input type="number" value={item.count} onChange={e => updateItem(item.id, 'count', parseInt(e.target.value))} className="w-12 bg-stone-800 border border-stone-700 rounded text-center text-sm" />
                            <span className={`flex-1 text-sm ${item.is_magic ? 'text-amber-400' : 'text-stone-300'}`}>{item.name}</span>
                            <button type="button" onClick={() => removeItem(item.id)} className="text-stone-500 hover:text-red-500"><Icon name="trash" className="w-4 h-4"/></button>
                        </div>
                    ))}
                </div>
            </div>
        );
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        const dataPayload: PinData = {
            description,
            images: [], // Deprecated in favor of sections
            sections,
            encounter_file: encounterFile
        };

        const dbPayload = {
            map_id: pinData.map_id,
            x_coord: pinData.x_coord,
            y_coord: pinData.y_coord,
            title,
            pin_type_id: pinTypeId,
            linked_map_id: linkedMapId || null,
            is_visible: isVisible,
            data: dataPayload as any, // jsonb casting
            created_by: pinData.created_by || user?.id
        };

        try {
            if (pinData.id) {
                await supabase.from('pins').update(dbPayload).eq('id', pinData.id);
            } else {
                await supabase.from('pins').insert(dbPayload);
            }
            await onSave();
        } catch (error) {
            console.error(error);
            alert("Failed to save pin.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <Modal isOpen={true} onClose={onClose} title={pinData.id ? "Edit Pin" : "New Pin"} maxWidthClass="max-w-4xl">
            <form onSubmit={handleSave} className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="space-y-4">
                     <div className="bg-stone-800/40 p-4 rounded-xl border border-stone-700/50 space-y-3">
                        <h3 className="text-xs font-bold uppercase text-stone-500">Core Info</h3>
                        <input type="text" placeholder="Pin Title" value={title} onChange={e => setTitle(e.target.value)} required className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                        <div className="flex gap-4">
                            <div className="flex-1">
                                <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Type</label>
                                <select value={pinTypeId} onChange={e => setPinTypeId(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-3 py-2 text-stone-300">
                                    {pinTypes.map(pt => <option key={pt.id} value={pt.id}>{pt.emoji} {pt.name}</option>)}
                                </select>
                            </div>
                            <div className="flex-1">
                                <label className="block text-xs font-bold uppercase text-stone-500 mb-1">Linked Map</label>
                                <select value={linkedMapId} onChange={e => setLinkedMapId(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-3 py-2 text-stone-300">
                                    <option value="">(None)</option>
                                    {maps.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                                </select>
                            </div>
                        </div>
                        <label className="flex items-center gap-2 cursor-pointer pt-2">
                             <input type="checkbox" checked={isVisible} onChange={e => setIsVisible(e.target.checked)} className="rounded bg-stone-800 border-stone-600 text-amber-600" />
                             <span className="text-sm text-stone-300 font-bold">Visible to Players</span>
                        </label>
                     </div>

                     <div className="bg-stone-800/40 p-4 rounded-xl border border-stone-700/50 space-y-3">
                         <h3 className="text-xs font-bold uppercase text-stone-500">Main Description</h3>
                         <textarea value={description} onChange={e => setDescription(e.target.value)} rows={4} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" placeholder="General description seen by everyone..." />
                     </div>

                     <div className="bg-stone-800/40 p-4 rounded-xl border border-stone-700/50 space-y-3">
                         <h3 className="text-xs font-bold uppercase text-stone-500">Encounter Data</h3>
                         <label className="block w-full cursor-pointer bg-stone-900/50 border border-dashed border-stone-600 rounded-xl p-4 text-center hover:border-amber-500 transition-colors">
                             <span className="text-sm text-stone-400">{encounterFile ? `File Loaded: ${encounterFile.name}` : "Upload .json Encounter File"}</span>
                             <input type="file" accept=".json" className="hidden" onChange={async (e) => {
                                 const f = e.target.files?.[0];
                                 if (f) {
                                     const text = await f.text();
                                     setEncounterFile({ name: f.name, content: text });
                                 }
                             }}/>
                         </label>
                         {encounterFile && <button type="button" onClick={() => setEncounterFile(null)} className="text-xs text-red-400 hover:underline">Clear File</button>}
                     </div>
                </div>

                {/* Right Column: Sections */}
                <div className="flex flex-col h-full bg-stone-800/20 rounded-xl border border-stone-700/30 overflow-hidden">
                    <div className="bg-stone-800/80 p-3 border-b border-stone-700/50 flex justify-between items-center">
                        <span className="font-medieval text-stone-300">Content Sections</span>
                        <div className="flex gap-1">
                            {['text', 'secret', 'list', 'statblock', 'image', 'inventory'].map(t => (
                                <button key={t} type="button" onClick={() => addSection(t as PinSectionType)} className="p-1.5 bg-stone-700 hover:bg-amber-600 rounded text-stone-200 text-xs uppercase" title={`Add ${t}`}>
                                    <Icon name={t === 'secret' ? 'lock' : t === 'image' ? 'image' : t === 'inventory' ? 'backpack' : t === 'list' ? 'scroll' : t === 'statblock' ? 'shield' : 'book'} className="w-4 h-4" />
                                </button>
                            ))}
                        </div>
                    </div>
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-3 space-y-4">
                        {sections.map((section, idx) => (
                            <div key={idx} className={`relative bg-stone-900/40 rounded-xl border p-3 ${section.type === 'secret' ? 'border-red-900/30' : 'border-stone-700/50'}`}>
                                <div className="flex justify-between items-center mb-2">
                                    <input type="text" value={section.title} onChange={e => updateSection(idx, 'title', e.target.value)} className="bg-transparent border-b border-stone-700 text-sm font-bold text-stone-300 focus:border-amber-500 focus:outline-none w-1/2" />
                                    <div className="flex items-center gap-2">
                                        <span className="text-[10px] uppercase text-stone-600 font-bold">{section.type}</span>
                                        <button type="button" onClick={() => removeSection(idx)} className="text-stone-600 hover:text-red-500"><Icon name="close" className="w-4 h-4"/></button>
                                    </div>
                                </div>

                                {section.type === 'text' && <textarea value={section.content} onChange={e => updateSection(idx, 'content', e.target.value)} rows={3} className="w-full bg-stone-800/50 border border-stone-700 rounded p-2 text-sm text-stone-300"/>}
                                {section.type === 'secret' && <textarea value={section.content} onChange={e => updateSection(idx, 'content', e.target.value)} rows={3} className="w-full bg-red-950/20 border border-red-900/30 rounded p-2 text-sm text-red-200"/>}
                                {section.type === 'image' && (
                                    <div className="space-y-2">
                                        <div className="flex gap-2">
                                            <input type="text" placeholder="Image URL" value={section.image_url || ''} onChange={e => updateSection(idx, 'image_url', e.target.value)} className="flex-1 bg-stone-800 border border-stone-700 rounded p-1 text-xs text-stone-300"/>
                                            <label className="cursor-pointer bg-stone-700 px-2 py-1 rounded text-xs text-stone-200 hover:bg-stone-600">
                                                Upload
                                                <input type="file" className="hidden" accept="image/*" onChange={async (e) => {
                                                    if(e.target.files?.[0]) updateSection(idx, 'image_url', await fileToBase64(e.target.files[0]));
                                                }}/>
                                            </label>
                                        </div>
                                        {section.image_url && <img src={section.image_url} className="h-20 rounded border border-stone-700" />}
                                    </div>
                                )}
                                {section.type === 'list' && (
                                    <div>
                                        <div className="flex gap-2 mb-2">
                                            <input type="text" placeholder="Add item..." onKeyPress={e => {
                                                if(e.key === 'Enter') { 
                                                    e.preventDefault(); 
                                                    const target = e.target as HTMLInputElement; 
                                                    if(target.value) { 
                                                        updateSection(idx, 'list_items', [...(section.list_items || []), target.value]); 
                                                        target.value = ''; 
                                                    } 
                                                }
                                            }} className="flex-1 bg-stone-800 border border-stone-700 rounded p-1 text-xs text-stone-300"/>
                                        </div>
                                        <ul className="space-y-1">
                                            {section.list_items?.map((li, liIdx) => (
                                                <li key={liIdx} className="flex justify-between text-xs text-stone-400 bg-stone-800/50 px-2 py-1 rounded">
                                                    <span>{li}</span>
                                                    <button type="button" onClick={() => updateSection(idx, 'list_items', section.list_items?.filter((_, i) => i !== liIdx))} className="text-stone-600 hover:text-red-500">&times;</button>
                                                </li>
                                            ))}
                                        </ul>
                                    </div>
                                )}
                                {section.type === 'statblock' && (
                                    <div className="space-y-2">
                                        <button type="button" onClick={() => updateSection(idx, 'stats', [...(section.stats || []), {label: 'New Stat', value: '10'}])} className="text-xs text-amber-500 hover:underline">+ Add Stat</button>
                                        <div className="grid grid-cols-2 gap-2">
                                            {section.stats?.map((stat, sIdx) => (
                                                <div key={sIdx} className="bg-stone-800 p-1 rounded border border-stone-700 flex flex-col gap-1">
                                                    <input type="text" value={stat.label} onChange={e => {
                                                        const newStats = [...(section.stats || [])]; newStats[sIdx].label = e.target.value; updateSection(idx, 'stats', newStats);
                                                    }} className="bg-transparent text-[10px] text-amber-500 font-bold uppercase w-full"/>
                                                    <div className="flex justify-between">
                                                        <input type="text" value={stat.value} onChange={e => {
                                                            const newStats = [...(section.stats || [])]; newStats[sIdx].value = e.target.value; updateSection(idx, 'stats', newStats);
                                                        }} className="bg-transparent text-sm text-stone-200 w-full"/>
                                                        <button type="button" onClick={() => updateSection(idx, 'stats', section.stats?.filter((_, i) => i !== sIdx))} className="text-stone-600 hover:text-red-500 px-1">&times;</button>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )}
                                {section.type === 'inventory' && <InventoryEditor sectionIndex={idx} currentItems={section.items || []} />}
                            </div>
                        ))}
                        {sections.length === 0 && <p className="text-center text-stone-600 text-sm italic py-4">No content sections added.</p>}
                    </div>
                </div>

                <div className="lg:col-span-2 flex justify-end gap-3 border-t border-stone-700/50 pt-4">
                    <button type="button" onClick={onClose} className="bg-stone-700 hover:bg-stone-600 text-stone-200 font-bold py-3 px-6 rounded-xl transition-all">Cancel</button>
                    <button type="submit" disabled={loading} className="bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all disabled:opacity-50">
                        {loading ? <Icon name="spinner" className="h-5 w-5 animate-spin mx-auto"/> : 'Save Pin'}
                    </button>
                </div>
            </form>
        </Modal>
    );
};

// --- CHARACTER MANAGER MODAL ---
interface CharacterManagerModalProps { isOpen: boolean; onClose: () => void; }
export const CharacterManagerModal: React.FC<CharacterManagerModalProps> = ({ isOpen, onClose }) => {
    const { user } = useAuth();
    const { characters, maps, pins, refreshData } = useAppContext();
    const [editingChar, setEditingChar] = useState<Partial<Character> | null>(null);
    const [isEditing, setIsEditing] = useState(false);

    // Form State
    const [name, setName] = useState('');
    const [race, setRace] = useState('');
    const [charClass, setCharClass] = useState('');
    const [level, setLevel] = useState(1);
    const [alignment, setAlignment] = useState('');
    const [backstory, setBackstory] = useState('');
    const [gmNotes, setGmNotes] = useState('');
    const [isNpc, setIsNpc] = useState(true);
    const [isVisible, setIsVisible] = useState(false);
    const [imageFile, setImageFile] = useState<File | null>(null);
    const [imageUrl, setImageUrl] = useState('');

    // New Features
    const [sheetUrl, setSheetUrl] = useState('');
    const [charJson, setCharJson] = useState<any>(null);
    const [jsonFileName, setJsonFileName] = useState('');

    // Relationship & Location State
    const [relationships, setRelationships] = useState<CharacterRelationship[]>([]);
    const [currentPinId, setCurrentPinId] = useState<string | null>(null);
    const [selectedMapId, setSelectedMapId] = useState<string>(''); 

    const [submitting, setSubmitting] = useState(false);

    // Derived map for picker
    const selectedMap = useMemo(() => maps.find(m => m.id === selectedMapId), [selectedMapId, maps]);

    const resetForm = () => {
        setName(''); setRace(''); setCharClass(''); setLevel(1); setAlignment('');
        setBackstory(''); setGmNotes(''); setIsNpc(true); setIsVisible(false); setImageFile(null); setImageUrl('');
        setRelationships([]); setCurrentPinId(null); setSelectedMapId('');
        setSheetUrl(''); setCharJson(null); setJsonFileName('');
        setEditingChar(null);
        setIsEditing(false);
    };

    const handleEdit = (char: Character) => {
        setEditingChar(char);
        setName(char.name);
        setRace(char.role_details?.race || '');
        setCharClass(char.role_details?.class || '');
        setLevel(char.role_details?.level || 1);
        setAlignment(char.role_details?.alignment || '');
        setBackstory(char.backstory || '');
        setGmNotes(char.gm_notes || '');
        setIsNpc(char.is_npc);
        setIsVisible(char.is_visible);
        setImageUrl(char.image_url || '');
        setRelationships(char.relationships || []);
        setCurrentPinId(char.current_pin_id || null);
        setSheetUrl(char.sheet_url || '');
        setCharJson(char.character_json || null);
        setJsonFileName(char.character_json ? 'Existing File Loaded' : '');

        if (char.current_pin_id) {
            const pin = pins.find(p => p.id === char.current_pin_id);
            if (pin) setSelectedMapId(pin.map_id);
        } else {
            setSelectedMapId('');
        }

        setIsEditing(true);
    };

    const handleJsonUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        try {
            const text = await file.text();
            const json = JSON.parse(text);
            setCharJson(json);
            setJsonFileName(file.name);
        } catch (error) {
            alert("Invalid JSON file");
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user || !name) return;
        setSubmitting(true);

        try {
            let finalImageUrl = imageUrl;
            if (imageFile) {
                 finalImageUrl = await fileToBase64(imageFile);
            }

            const payload = {
                name,
                role_details: { race, class: charClass, level, alignment },
                backstory,
                gm_notes: gmNotes,
                image_url: finalImageUrl,
                is_npc: isNpc,
                is_visible: isVisible,
                relationships: relationships || [],
                current_pin_id: currentPinId || null,
                sheet_url: sheetUrl,
                character_json: charJson,
                created_by: user.id
            };

            let result;
            if (editingChar && editingChar.id) {
                result = await supabase.from('characters').update(payload).eq('id', editingChar.id);
            } else {
                result = await supabase.from('characters').insert(payload);
            }

            if (result.error) throw result.error;

            await refreshData(true);
            resetForm();
        } catch (error: any) {
            console.error("Error saving character:", error);
            alert(`Error saving character: ${error.message || "Unknown error"}. Check if 'characters' table exists.`);
        } finally {
            setSubmitting(false); // CRITICAL: Always reset loading state
        }
    };

    const handleDelete = async (char: Character) => {
        if(!window.confirm(`Delete ${char.name}?`)) return;
        const { error } = await supabase.from('characters').delete().eq('id', char.id);
        if(!error) await refreshData(true);
    };

    const addRelationship = () => setRelationships([...relationships, { targetId: '', type: '', notes: '' }]);
    const updateRelationship = (index: number, field: keyof CharacterRelationship, value: string) => {
        const newRels = [...relationships];
        newRels[index] = { ...newRels[index], [field]: value };
        setRelationships(newRels);
    };
    const removeRelationship = (index: number) => setRelationships(relationships.filter((_, i) => i !== index));

    return (
        <Modal isOpen={isOpen} onClose={onClose} title={isEditing ? (editingChar ? "Edit Character" : "New Character") : "Manage Characters"} maxWidthClass="max-w-4xl">
            {!isEditing ? (
                <div className="space-y-6">
                    <button onClick={() => setIsEditing(true)} className="w-full flex items-center justify-center space-x-2 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-4 rounded-xl shadow-lg transition-all">
                        <Icon name="plus" className="h-5 w-5" />
                        <span>Create New Character</span>
                    </button>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {characters.map(char => (
                             <div key={char.id} className="relative group bg-stone-800/40 border border-stone-700/50 rounded-xl p-4 flex gap-4 hover:bg-stone-800/60 transition-colors">
                                <div className="w-16 h-16 rounded-full bg-stone-900 overflow-hidden flex-shrink-0 border-2 border-stone-600 group-hover:border-amber-500 transition-colors">
                                    {char.image_url ? <img src={char.image_url} alt={char.name} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-stone-600 text-xs">No Img</div>}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <h3 className="font-medieval text-lg text-stone-200 truncate">{char.name}</h3>
                                    <p className="text-xs text-stone-500 uppercase tracking-wider font-bold mb-1">{char.is_npc ? 'NPC' : 'PC'}</p>
                                    <p className="text-xs text-stone-400 truncate">{char.role_details?.race} {char.role_details?.class}</p>
                                    <div className="flex items-center gap-2 mt-1">
                                        {char.current_pin_id && <p className="text-[10px] text-amber-500/80 flex items-center gap-1"><Icon name="pin" className="w-3 h-3" /> On Map</p>}
                                        {!char.is_visible && <p className="text-[10px] text-stone-500 flex items-center gap-1"><Icon name="eye-off" className="w-3 h-3" /> Hidden</p>}
                                    </div>
                                </div>
                                <div className="flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity absolute right-2 top-2">
                                     <button onClick={() => handleEdit(char)} className="p-1.5 rounded-lg bg-stone-900 text-stone-400 hover:text-amber-500"><Icon name="pencil" className="w-4 h-4" /></button>
                                     <button onClick={() => handleDelete(char)} className="p-1.5 rounded-lg bg-stone-900 text-stone-400 hover:text-red-500"><Icon name="trash" className="w-4 h-4" /></button>
                                </div>
                             </div>
                        ))}
                        {characters.length === 0 && <p className="col-span-full text-center text-stone-500 italic py-8">No characters found.</p>}
                    </div>
                </div>
            ) : (
                <form onSubmit={handleSave} className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    {/* Left Column: Stats & Basic Info */}
                    <div className="space-y-4">
                        <div className="flex items-center gap-4 bg-stone-800/30 p-4 rounded-xl border border-stone-700/30">
                            <label className="w-20 h-20 rounded-full bg-stone-900 border-2 border-dashed border-stone-600 flex items-center justify-center cursor-pointer hover:border-amber-500 overflow-hidden relative">
                                {imageUrl || (imageFile && URL.createObjectURL(imageFile)) ? (
                                    <img src={imageUrl || (imageFile ? URL.createObjectURL(imageFile) : '')} className="w-full h-full object-cover" />
                                ) : <span className="text-xs text-stone-500 text-center">Avatar</span>}
                                <input type="file" className="hidden" accept="image/*" onChange={e => {
                                    if(e.target.files?.[0]) { setImageFile(e.target.files[0]); setImageUrl(''); }
                                }} />
                            </label>
                            <div className="flex-1 space-y-2">
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input type="checkbox" checked={isNpc} onChange={e => setIsNpc(e.target.checked)} className="rounded border-stone-600 bg-stone-800 text-amber-600 focus:ring-amber-500" />
                                    <span className="text-sm font-bold text-stone-300">Is NPC?</span>
                                </label>
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input type="checkbox" checked={isVisible} onChange={e => setIsVisible(e.target.checked)} className="rounded border-stone-600 bg-stone-800 text-amber-600 focus:ring-amber-500" />
                                    <span className="text-sm font-bold text-stone-300">Visible to Players?</span>
                                </label>
                                <input type="text" placeholder="Image URL (optional)" value={imageUrl} onChange={e => { setImageUrl(e.target.value); setImageFile(null); }} className="w-full rounded-lg border border-stone-600/50 bg-stone-900/40 px-3 py-2 text-sm text-stone-200" />
                            </div>
                        </div>

                        <input type="text" placeholder="Name" value={name} onChange={e => setName(e.target.value)} required className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                        <div className="grid grid-cols-2 gap-2">
                             <input type="text" placeholder="Race" value={race} onChange={e => setRace(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                             <input type="text" placeholder="Class" value={charClass} onChange={e => setCharClass(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                        </div>
                        <div className="flex gap-2">
                            <input type="number" placeholder="Level" min="1" max="20" value={level} onChange={e => setLevel(parseInt(e.target.value))} className="w-24 rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                            <input type="text" placeholder="Alignment" value={alignment} onChange={e => setAlignment(e.target.value)} className="flex-1 rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                        </div>

                         {/* Extra Links */}
                         <div className="space-y-2 bg-stone-800/30 p-4 rounded-xl border border-stone-700/30">
                            <h4 className="text-xs font-bold uppercase text-stone-500 mb-2">Integrations</h4>
                            <div className="flex items-center gap-2">
                                <Icon name="external" className="w-4 h-4 text-stone-500" />
                                <input type="text" placeholder="Link to Character Sheet (URL)" value={sheetUrl} onChange={e => setSheetUrl(e.target.value)} className="flex-1 bg-stone-900/50 rounded border border-stone-700/50 px-3 py-2 text-sm text-stone-200" />
                            </div>
                            <label className="flex items-center gap-2 cursor-pointer bg-stone-900/50 rounded border border-stone-700/50 px-3 py-2 text-sm hover:bg-stone-800/50 transition-colors">
                                <Icon name="upload" className="w-4 h-4 text-stone-500" />
                                <span className="text-stone-300 flex-1 truncate">{jsonFileName || "Upload Tracker JSON (for encounter tools)"}</span>
                                <input type="file" accept=".json" onChange={handleJsonUpload} className="hidden" />
                            </label>
                         </div>

                        <textarea placeholder="Backstory / Bio" value={backstory} onChange={e => setBackstory(e.target.value)} rows={5} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                    </div>

                    {/* Right Column: Location & Relationships */}
                    <div className="space-y-4">
                        <div className="bg-stone-800/30 p-4 rounded-xl border border-stone-700/30 space-y-3">
                            <div className="flex justify-between items-center border-b border-stone-700/50 pb-2">
                                <h4 className="text-sm font-bold uppercase text-stone-400 flex items-center gap-2"><Icon name="map" className="w-4 h-4" /> Location</h4>
                                <div className="text-xs text-stone-500 italic">
                                    {currentPinId ? "Pin selected" : "Select a map, then click a pin"}
                                </div>
                            </div>

                            <select 
                                value={selectedMapId} 
                                onChange={e => { setSelectedMapId(e.target.value); setCurrentPinId(null); }} 
                                className="w-full rounded-lg border border-stone-600/50 bg-stone-900/40 px-3 py-2 text-sm text-stone-200 focus:outline-none"
                            >
                                <option value="">(Select Map to Locate Character)</option>
                                {maps.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                            </select>

                            {selectedMap ? (
                                <div className="relative h-64 w-full rounded-xl overflow-hidden border border-stone-700/50 shadow-inner bg-stone-950 group">
                                    <MapViewer 
                                        map={selectedMap}
                                        onSelectPin={(pin) => setCurrentPinId(pin.id)}
                                        onAddPin={() => {}} 
                                        highlightedPinId={currentPinId}
                                    />
                                    {!currentPinId && <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-black/60 px-3 py-1 rounded-full text-xs text-amber-500 pointer-events-none backdrop-blur-sm border border-amber-900/30">Click a pin to place character</div>}
                                    {currentPinId && <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-amber-600/90 px-3 py-1 rounded-full text-xs text-white pointer-events-none shadow-lg">Location Set</div>}
                                </div>
                            ) : (
                                <div className="h-64 flex items-center justify-center bg-stone-900/20 rounded-xl border border-dashed border-stone-700/50 text-stone-600 text-sm italic">
                                    Map preview will appear here
                                </div>
                            )}

                            <div className="flex items-center justify-between text-xs">
                                <span className="text-stone-500">Current ID: <span className="font-mono text-stone-400">{currentPinId ? pins.find(p => p.id === currentPinId)?.title || 'Unknown Pin' : 'None'}</span></span>
                                {currentPinId && <button type="button" onClick={() => setCurrentPinId(null)} className="text-red-500 hover:underline">Clear Location</button>}
                            </div>
                        </div>

                        {/* Relationships */}
                        <div className="bg-stone-800/30 p-4 rounded-xl border border-stone-700/30 space-y-3">
                            <div className="flex justify-between items-center">
                                <h4 className="text-sm font-bold uppercase text-stone-400 flex items-center gap-2"><Icon name="user" className="w-4 h-4" /> Relationships</h4>
                                <button type="button" onClick={addRelationship} className="text-xs text-amber-500 hover:underline">+ Add</button>
                            </div>
                            <div className="space-y-2 max-h-40 overflow-y-auto custom-scrollbar">
                                {relationships.map((rel, idx) => (
                                    <div key={idx} className="flex flex-col gap-2 p-2 bg-stone-900/40 rounded border border-stone-800">
                                        <div className="flex gap-2">
                                            <select 
                                                value={rel.targetId} 
                                                onChange={e => updateRelationship(idx, 'targetId', e.target.value)} 
                                                className="flex-1 rounded border border-stone-600/50 bg-stone-800 text-xs text-stone-200 p-1"
                                            >
                                                <option value="">Select Character...</option>
                                                {characters.filter(c => c.id !== editingChar?.id).map(c => (
                                                    <option key={c.id} value={c.id}>{c.name}</option>
                                                ))}
                                            </select>
                                            <input 
                                                type="text" 
                                                placeholder="Type (e.g. Rival)" 
                                                value={rel.type} 
                                                onChange={e => updateRelationship(idx, 'type', e.target.value)} 
                                                className="w-1/3 rounded border border-stone-600/50 bg-stone-800 text-xs text-stone-200 p-1"
                                            />
                                            <button type="button" onClick={() => removeRelationship(idx)} className="text-stone-500 hover:text-red-500 px-1"><Icon name="trash" className="w-3 h-3" /></button>
                                        </div>
                                        <input 
                                            type="text" 
                                            placeholder="Notes..." 
                                            value={rel.notes || ''} 
                                            onChange={e => updateRelationship(idx, 'notes', e.target.value)} 
                                            className="w-full rounded border border-stone-600/30 bg-stone-800 text-xs text-stone-400 p-1"
                                        />
                                    </div>
                                ))}
                                {relationships.length === 0 && <p className="text-xs text-stone-600 italic text-center">No relationships defined.</p>}
                            </div>
                        </div>

                         <textarea placeholder="GM Notes (Secret)" value={gmNotes} onChange={e => setGmNotes(e.target.value)} rows={2} className="w-full rounded-xl border border-red-900/30 bg-red-950/10 px-4 py-3 text-stone-200 placeholder-red-400/50 focus:border-red-500 focus:outline-none" />
                    </div>

                    <div className="lg:col-span-2 flex gap-3 pt-4 border-t border-stone-700/50">
                        <button type="button" onClick={resetForm} className="flex-1 bg-stone-700 hover:bg-stone-600 text-stone-200 font-bold py-3 px-6 rounded-xl transition-all">Cancel</button>
                        <button type="submit" disabled={submitting} className="flex-1 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all">
                            {submitting ? <Icon name="spinner" className="h-5 w-5 animate-spin mx-auto"/> : "Save Character"}
                        </button>
                    </div>
                </form>
            )}
        </Modal>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { useAppContext } from './Dashboard';
import { useAuth } from '../App';
import { Map as MapType, Pin, Character, Comment } from '../types';
import { Icon } from './Icons';
import { supabase } from '../services/supabase';

interface WikiProps {
    onSelectMap: (map: MapType) => void;
    onLocatePin: (pin: Pin) => void;
}

const Wiki: React.FC<WikiProps> = ({ onSelectMap, onLocatePin }) => {
    const { maps, pins, pinTypes, characters, isPlayerView } = useAppContext();
    const { user } = useAuth();
    const isDM = user?.profile.role === 'DM';
    const canSeeSecrets = isDM && !isPlayerView;

    const [searchQuery, setSearchQuery] = useState('');
    const [selectedMapId, setSelectedMapId] = useState<string | null>(null);
    const [selectedPinId, setSelectedPinId] = useState<string | null>(null);
    const [selectedCharacterId, setSelectedCharacterId] = useState<string | null>(null);
    const [viewMode, setViewMode] = useState<'maps' | 'characters'>('maps'); // Toggle sidebar view

    // Comments State for Characters
    const [characterComments, setCharacterComments] = useState<Comment[]>([]);
    const [newComment, setNewComment] = useState('');
    const [isPrivateComment, setIsPrivateComment] = useState(false);

    // Fetch character comments when a character is selected
    useEffect(() => {
        if (selectedCharacterId) {
            const fetchComments = async () => {
                const { data, error } = await supabase
                    .from('comments')
                    .select('*, users(username)')
                    .eq('character_id', selectedCharacterId)
                    .order('created_at', { ascending: true });
                if (data) setCharacterComments(data as any);
            };
            fetchComments();
        } else {
            setCharacterComments([]);
        }
    }, [selectedCharacterId]);

    const handleAddCharacterComment = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newComment.trim() || !selectedCharacterId || !user) return;

        const { data, error } = await supabase
            .from('comments')
            .insert({
                character_id: selectedCharacterId,
                user_id: user.id,
                text: newComment,
                is_private: isPrivateComment
            })
            .select('*, users(username)')
            .single();

        if (data) setCharacterComments([...characterComments, data as any]);
        setNewComment('');
        setIsPrivateComment(false);
    };

    // Filter Logic for Maps
    const filteredMaps = useMemo(() => {
        const lowerQ = searchQuery.toLowerCase();

        return maps.map(map => {
            const mapPins = pins.filter(p => p.map_id === map.id);
            let matchesMap = !searchQuery || map.name.toLowerCase().includes(lowerQ);

            const matchingPins = mapPins.filter(pin => {
                if (!searchQuery) return true;
                if (pin.title.toLowerCase().includes(lowerQ)) return true;
                if (pin.data.description?.toLowerCase().includes(lowerQ)) return true;
                return pin.data.sections?.some(s => 
                    s.title.toLowerCase().includes(lowerQ) || 
                    s.content.toLowerCase().includes(lowerQ) ||
                    (s.type === 'list' && s.list_items?.some(i => i.toLowerCase().includes(lowerQ)))
                );
            });

            if (searchQuery && !matchesMap && matchingPins.length === 0) return null;

            return {
                map,
                pins: matchingPins
            };
        }).filter(Boolean) as { map: MapType, pins: Pin[] }[];

    }, [maps, pins, searchQuery]);

    // Filter Logic for Characters
    const filteredCharacters = useMemo(() => {
        const lowerQ = searchQuery.toLowerCase();
        // Determine visibility based on Role and isPlayerView toggle
        const availableChars = (isDM && !isPlayerView) 
            ? characters 
            : characters.filter(c => c.is_visible); // Only show unlocked chars to players

        return availableChars.filter(c => 
            !searchQuery || 
            c.name.toLowerCase().includes(lowerQ) || 
            c.role_details?.race.toLowerCase().includes(lowerQ) ||
            c.role_details?.class.toLowerCase().includes(lowerQ)
        );
    }, [characters, searchQuery, isDM, isPlayerView]);

    const activeMapData = selectedMapId ? filteredMaps.find(c => c.map.id === selectedMapId) : null;
    const activePin = selectedPinId ? pins.find(p => p.id === selectedPinId) : null;
    const activePinMap = activePin ? maps.find(m => m.id === activePin.map_id) : null;
    const activeCharacter = selectedCharacterId ? characters.find(c => c.id === selectedCharacterId) : null;

    // Helper to get character relationships
    const getCharacterName = (id: string) => characters.find(c => c.id === id)?.name || "Unknown";

    // --- Renderers ---

    const renderPinContent = (pin: Pin) => {
        const type = pinTypes.find(t => t.id === pin.pin_type_id);

        return (
            <div className="space-y-8 animate-modal-in max-w-4xl mx-auto pb-20">
                {/* Header */}
                <div className="border-b border-stone-700/50 pb-6">
                    <div className="flex items-center gap-4 mb-4">
                        <div className="flex items-center justify-center w-16 h-16 rounded-2xl shadow-xl text-3xl ring-2 ring-stone-700/50" style={{ backgroundColor: type?.color || '#555' }}>
                            {type?.emoji || '📍'}
                        </div>
                        <div>
                            <h1 className="text-4xl font-medieval font-bold text-stone-100">{pin.title}</h1>
                            <div className="flex items-center gap-2 mt-1">
                                <span className="bg-stone-800/50 px-2 py-0.5 rounded text-xs text-stone-400 border border-stone-700 uppercase tracking-wider">{type?.name || 'Unknown'}</span>
                                {activePinMap && <span className="text-stone-500 text-sm flex items-center gap-1"><Icon name="map" className="w-3 h-3"/> {activePinMap.name}</span>}
                            </div>
                        </div>
                        <button 
                            onClick={() => onLocatePin(pin)}
                            className="ml-auto flex items-center gap-2 bg-stone-800 hover:bg-amber-700/20 hover:text-amber-500 border border-stone-700 px-4 py-2 rounded-xl transition-all text-sm font-medium group"
                        >
                            <Icon name="compass" className="w-4 h-4 group-hover:rotate-45 transition-transform"/>
                            Locate on Map
                        </button>
                    </div>

                    {pin.data.description && (
                         <div className="prose prose-invert max-w-none text-stone-300 text-lg leading-relaxed bg-stone-900/20 p-6 rounded-2xl border border-stone-800/50">
                            {pin.data.description}
                         </div>
                    )}
                </div>

                {/* Sections */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {pin.data.sections?.map((section, idx) => {
                        if (section.type === 'secret' && !canSeeSecrets) return null;

                        const isFullWidth = section.type === 'text' || section.type === 'list' || section.type === 'inventory';

                        return (
                            <div key={idx} className={`bg-stone-800/20 rounded-2xl border border-stone-700/30 overflow-hidden ${isFullWidth ? 'md:col-span-2' : ''} ${section.type === 'secret' ? 'border-red-900/50 bg-red-950/10' : ''}`}>
                                <div className={`px-5 py-3 border-b border-stone-700/30 flex items-center justify-between ${section.type === 'secret' ? 'bg-red-950/30' : 'bg-stone-800/40'}`}>
                                    <h3 className={`font-medieval text-xl ${section.type === 'secret' ? 'text-red-400' : 'text-stone-200'}`}>
                                        {section.type === 'secret' && <Icon name="lock" className="w-4 h-4 inline mr-2" />}
                                        {section.title}
                                    </h3>
                                    <span className="text-xs uppercase text-stone-600 font-bold tracking-wider">{section.type}</span>
                                </div>

                                <div className="p-5">
                                    {section.type === 'text' && <p className="whitespace-pre-wrap text-stone-300 leading-relaxed">{section.content}</p>}
                                    {section.type === 'secret' && <p className="whitespace-pre-wrap text-red-200/80 leading-relaxed font-mono text-sm">{section.content}</p>}
                                    {/* ... other sections ... */}
                                    {section.type === 'list' && (
                                        <>
                                            {section.content && <p className="mb-4 text-stone-400 italic">{section.content}</p>}
                                            <ul className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                                                {section.list_items?.map((item, i) => (
                                                    <li key={i} className="flex items-start gap-2 text-stone-300 bg-stone-900/30 p-2 rounded">
                                                        <span className="text-amber-500 mt-1">✦</span>
                                                        <span>{item}</span>
                                                    </li>
                                                ))}
                                            </ul>
                                        </>
                                    )}
                                    {section.type === 'statblock' && (
                                        <>
                                            {section.content && <p className="mb-4 text-stone-400 italic">{section.content}</p>}
                                            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                                                {section.stats?.map((stat, i) => (
                                                    <div key={i} className="bg-stone-900/50 p-3 rounded-lg border border-stone-800 flex flex-col items-center text-center">
                                                        <span className="text-xs uppercase tracking-wider text-amber-600 font-bold mb-1">{stat.label}</span>
                                                        <span className="font-medieval text-xl text-stone-200">{stat.value}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </>
                                    )}
                                    {section.type === 'image' && section.image_url && (
                                        <img src={section.image_url} alt={section.title} className="w-full h-auto rounded-lg shadow-lg" />
                                    )}
                                    {section.type === 'inventory' && (
                                        <div className="overflow-x-auto">
                                            <table className="w-full text-left text-sm">
                                                <thead className="text-stone-500 uppercase text-xs border-b border-stone-700/50">
                                                    <tr>
                                                        <th className="pb-2 pl-2">Item</th>
                                                        <th className="pb-2">Rarity</th>
                                                        <th className="pb-2 text-right pr-2">Qty</th>
                                                    </tr>
                                                </thead>
                                                <tbody className="divide-y divide-stone-700/30">
                                                    {section.items?.map((item, i) => (
                                                        <tr key={i} className="hover:bg-stone-700/20">
                                                            <td className="py-2 pl-2">
                                                                <span className={`font-medium ${item.is_magic ? 'text-amber-400' : 'text-stone-300'}`}>{item.name}</span>
                                                            </td>
                                                            <td className="py-2 text-purple-400 text-xs">{item.rarity || '-'}</td>
                                                            <td className="py-2 text-right pr-2 font-mono text-stone-400">{item.count}</td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        );
    };

    const renderCharacterContent = (char: Character) => {
        return (
            <div className="space-y-8 animate-modal-in max-w-4xl mx-auto pb-20">
                <div className="flex flex-col md:flex-row gap-8 border-b border-stone-700/50 pb-8">
                    <div className="w-48 h-48 rounded-3xl overflow-hidden ring-4 ring-stone-800 shadow-2xl bg-stone-900 flex-shrink-0 mx-auto md:mx-0">
                        {char.image_url ? (
                            <img src={char.image_url} alt={char.name} className="w-full h-full object-cover" />
                        ) : (
                            <div className="w-full h-full flex items-center justify-center text-stone-600 bg-stone-800"><Icon name="user" className="w-16 h-16"/></div>
                        )}
                    </div>
                    <div className="flex-1 text-center md:text-left">
                        <h1 className="text-5xl font-medieval font-bold text-amber-500 mb-2">{char.name}</h1>
                        <div className="flex flex-wrap items-center justify-center md:justify-start gap-3 text-sm text-stone-400 mb-4">
                            <span className="bg-stone-800 px-3 py-1 rounded-full border border-stone-700">{char.role_details?.race}</span>
                            <span className="bg-stone-800 px-3 py-1 rounded-full border border-stone-700">{char.role_details?.class}</span>
                            <span className="bg-amber-900/30 px-3 py-1 rounded-full border border-amber-800/30 text-amber-500">Lvl {char.role_details?.level}</span>
                            <span className="text-stone-500">{char.role_details?.alignment}</span>
                        </div>
                        {char.current_pin_id && (() => {
                            const currentPin = pins.find(p => p.id === char.current_pin_id);
                            const currentMap = currentPin ? maps.find(m => m.id === currentPin.map_id) : null;

                            if (!currentPin || !currentMap) return null;

                            return (
                                <button 
                                    onClick={() => onLocatePin(currentPin)}
                                    className="inline-flex items-center gap-2 text-amber-500 bg-amber-900/10 hover:bg-amber-900/20 px-3 py-1.5 rounded-lg border border-amber-900/30 hover:border-amber-500/50 mb-4 transition-all cursor-pointer group"
                                >
                                    <Icon name="map" className="w-4 h-4 group-hover:scale-110 transition-transform"/>
                                    <span>Currently in <span className="font-bold border-b border-transparent group-hover:border-amber-500 transition-colors">{currentMap.name}</span></span>
                                    <Icon name="chevron-right" className="w-3 h-3 opacity-0 group-hover:opacity-100 transition-opacity -ml-1" />
                                </button>
                            );
                        })()}
                        <div className="flex gap-2 justify-center md:justify-start">
                            {char.sheet_url && (
                                <a href={char.sheet_url} target="_blank" rel="noopener noreferrer" className="flex items-center gap-2 bg-stone-800 hover:bg-stone-700 px-4 py-2 rounded-xl text-sm font-medium transition-colors">
                                    <Icon name="external" className="w-4 h-4"/> Character Sheet
                                </a>
                            )}
                        </div>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    <div className="md:col-span-2 space-y-6">
                        <div className="bg-stone-800/20 p-6 rounded-2xl border border-stone-700/30">
                            <h3 className="font-medieval text-xl text-stone-300 mb-4 border-b border-stone-700/50 pb-2">Biography</h3>
                            <p className="whitespace-pre-wrap text-stone-400 leading-relaxed">{char.backstory || "No biography available."}</p>
                        </div>

                        {/* Comments Section */}
                        <div className="bg-stone-800/20 p-6 rounded-2xl border border-stone-700/30">
                            <h3 className="font-medieval text-xl text-stone-300 mb-4 border-b border-stone-700/50 pb-2">Journal & Notes</h3>
                            <div className="space-y-4 mb-6">
                                {characterComments.length === 0 && <p className="text-stone-600 italic text-sm">No notes yet.</p>}
                                {characterComments.map(comment => (
                                    <div key={comment.id} className="bg-stone-900/40 p-4 rounded-xl border border-stone-800">
                                        <div className="flex justify-between items-start mb-2">
                                            <span className="font-bold text-amber-600 text-sm">{comment.users.username}</span>
                                            <span className="text-xs text-stone-600">{new Date(comment.created_at).toLocaleDateString()}</span>
                                        </div>
                                        <p className="text-stone-300 text-sm">{comment.text}</p>
                                    </div>
                                ))}
                            </div>
                            <form onSubmit={handleAddCharacterComment} className="space-y-3">
                                <textarea 
                                    value={newComment} 
                                    onChange={e => setNewComment(e.target.value)} 
                                    placeholder="Add a note..." 
                                    className="w-full bg-stone-900/50 border border-stone-700/50 rounded-xl p-3 text-sm text-stone-200 focus:outline-none focus:border-amber-500"
                                    rows={2}
                                />
                                <div className="flex justify-end">
                                    <button type="submit" className="bg-amber-600 hover:bg-amber-500 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-lg transition-all">Post Note</button>
                                </div>
                            </form>
                        </div>
                    </div>

                    <div className="space-y-6">
                        {canSeeSecrets && char.gm_notes && (
                            <div className="bg-red-950/20 p-5 rounded-2xl border border-red-900/40">
                                <h3 className="font-medieval text-lg text-red-400 mb-2 flex items-center gap-2"><Icon name="lock" className="w-4 h-4"/> GM Notes</h3>
                                <p className="text-sm text-red-300/70 whitespace-pre-wrap">{char.gm_notes}</p>
                            </div>
                        )}

                        <div className="bg-stone-800/20 p-5 rounded-2xl border border-stone-700/30">
                            <h3 className="font-medieval text-lg text-stone-300 mb-3">Relationships</h3>
                            {char.relationships.length > 0 ? (
                                <ul className="space-y-3">
                                    {char.relationships.map((rel, i) => (
                                        <li key={i} className="text-sm">
                                            <div className="font-bold text-stone-200">{getCharacterName(rel.targetId)}</div>
                                            <div className="text-amber-600 text-xs uppercase tracking-wide font-bold">{rel.type}</div>
                                            {rel.notes && <div className="text-stone-500 italic mt-1">"{rel.notes}"</div>}
                                        </li>
                                    ))}
                                </ul>
                            ) : <p className="text-stone-600 italic text-sm">No known connections.</p>}
                        </div>
                    </div>
                </div>
            </div>
        );
    };

    // --- Main Layout ---
    return (
        <div className="flex h-full w-full bg-stone-950 text-stone-200">
            {/* Left Sidebar: Index */}
            <div className="w-80 border-r border-stone-700/50 flex flex-col bg-stone-900/30 backdrop-blur-sm">
                <div className="p-4 border-b border-stone-700/50">
                    <h2 className="text-amber-500 font-medieval text-xl mb-3 flex items-center gap-2">
                        <Icon name="book" className="w-5 h-5"/>
                        Wiki & Codex
                    </h2>
                    <div className="relative mb-4">
                        <Icon name="search" className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-stone-500" />
                        <input 
                            type="text" 
                            placeholder="Search..." 
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full bg-stone-900/50 border border-stone-700 rounded-lg pl-9 pr-3 py-2 text-sm text-stone-200 focus:border-amber-500 focus:outline-none placeholder-stone-600"
                        />
                    </div>
                    <div className="flex p-1 bg-stone-800 rounded-lg">
                        <button onClick={() => setViewMode('maps')} className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${viewMode === 'maps' ? 'bg-stone-600 text-white shadow' : 'text-stone-400 hover:text-stone-300'}`}>Locations</button>
                        <button onClick={() => setViewMode('characters')} className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${viewMode === 'characters' ? 'bg-stone-600 text-white shadow' : 'text-stone-400 hover:text-stone-300'}`}>Character Book</button>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-2">
                    {viewMode === 'maps' && (
                        <>
                            {filteredMaps.map(({ map, pins }) => (
                                <div key={map.id} className="rounded-xl overflow-hidden border border-transparent">
                                    <button 
                                        onClick={() => { setSelectedMapId(map.id); setSelectedPinId(null); setSelectedCharacterId(null); }}
                                        className={`w-full flex items-center gap-3 px-3 py-2 text-left transition-colors ${selectedMapId === map.id && !selectedPinId ? 'bg-amber-900/20 text-amber-400 border-amber-500/30' : 'hover:bg-stone-800/50 text-stone-300'}`}
                                    >
                                        <Icon name="map" className="w-4 h-4 opacity-70"/>
                                        <span className="font-medium truncate">{map.name}</span>
                                    </button>

                                    {(selectedMapId === map.id || searchQuery) && (
                                        <div className="pl-4 border-l border-stone-800 ml-4 mt-1 space-y-0.5">
                                            {pins.map(pin => (
                                                <button 
                                                    key={pin.id}
                                                    onClick={() => { setSelectedMapId(map.id); setSelectedPinId(pin.id); setSelectedCharacterId(null); }}
                                                    className={`w-full flex items-center gap-2 px-3 py-1.5 text-left text-sm rounded-lg transition-colors ${selectedPinId === pin.id ? 'bg-stone-800 text-white' : 'text-stone-500 hover:text-stone-300 hover:bg-stone-800/30'}`}
                                                >
                                                    <span className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: pinTypes.find(t => t.id === pin.pin_type_id)?.color }}></span>
                                                    <span className="truncate">{pin.title}</span>
                                                </button>
                                            ))}
                                            {pins.length === 0 && <p className="px-3 py-1 text-xs text-stone-600 italic">No pins found</p>}
                                        </div>
                                    )}
                                </div>
                            ))}
                            {filteredMaps.length === 0 && <p className="text-center text-stone-600 text-sm py-4">No locations found.</p>}
                        </>
                    )}

                    {viewMode === 'characters' && (
                        <>
                            {filteredCharacters.map(char => (
                                <button
                                    key={char.id}
                                    onClick={() => { setSelectedCharacterId(char.id); setSelectedMapId(null); setSelectedPinId(null); }}
                                    className={`w-full flex items-center gap-3 px-3 py-2 rounded-xl text-left transition-colors ${selectedCharacterId === char.id ? 'bg-amber-900/20 text-amber-400 border border-amber-500/30' : 'hover:bg-stone-800/50 text-stone-300 border border-transparent'}`}
                                >
                                    <div className="w-8 h-8 rounded-full bg-stone-800 overflow-hidden flex-shrink-0">
                                        {char.image_url ? <img src={char.image_url} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center"><Icon name="user" className="w-4 h-4"/></div>}
                                    </div>
                                    <div className="min-w-0">
                                        <div className="font-medium truncate text-sm">{char.name}</div>
                                        <div className="text-[10px] text-stone-500 truncate">{char.role_details?.race} {char.role_details?.class}</div>
                                    </div>
                                </button>
                            ))}
                            {filteredCharacters.length === 0 && <p className="text-center text-stone-600 text-sm py-4">No characters found.</p>}
                        </>
                    )}
                </div>
            </div>

            {/* Right Pane: Content */}
            <div className="flex-1 overflow-y-auto custom-scrollbar bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')]">
                <div className="p-8 md:p-12 min-h-full">
                    {selectedPinId && activePin ? (
                        renderPinContent(activePin)
                    ) : selectedCharacterId && activeCharacter ? (
                        renderCharacterContent(activeCharacter)
                    ) : selectedMapId && activeMapData ? (
                        <div className="max-w-4xl mx-auto space-y-8 animate-modal-in">
                            <div className="flex items-center gap-4 border-b border-stone-700/50 pb-6">
                                <div className="w-20 h-20 rounded-2xl overflow-hidden ring-2 ring-stone-700 shadow-2xl bg-stone-900">
                                    <img src={activeMapData.map.image_url} className="w-full h-full object-cover" alt={activeMapData.map.name} />
                                </div>
                                <div>
                                    <h1 className="text-5xl font-medieval font-bold text-amber-500">{activeMapData.map.name}</h1>
                                    <p className="text-stone-500 mt-1 uppercase tracking-widest text-sm font-bold">Region Map</p>
                                </div>
                                <button 
                                    onClick={() => onSelectMap(activeMapData.map)}
                                    className="ml-auto flex items-center gap-2 bg-amber-600 hover:bg-amber-500 text-white px-6 py-3 rounded-xl shadow-lg transition-all font-bold"
                                >
                                    <Icon name="map" className="w-5 h-5"/>
                                    Open Map
                                </button>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                {activeMapData.pins.map(pin => {
                                    const type = pinTypes.find(t => t.id === pin.pin_type_id);
                                    return (
                                        <button 
                                            key={pin.id}
                                            onClick={() => setSelectedPinId(pin.id)}
                                            className="bg-stone-800/40 hover:bg-stone-800 border border-stone-700/30 hover:border-amber-500/50 p-4 rounded-xl text-left transition-all group flex flex-col gap-3"
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className="w-10 h-10 rounded-full flex items-center justify-center text-lg shadow-lg ring-1 ring-white/10" style={{ backgroundColor: type?.color }}>
                                                    {type?.emoji}
                                                </div>
                                                <div className="min-w-0">
                                                    <h3 className="font-bold text-stone-200 truncate group-hover:text-amber-400">{pin.title}</h3>
                                                    <p className="text-xs text-stone-500">{type?.name}</p>
                                                </div>
                                            </div>
                                            {pin.data.description && (
                                                <p className="text-sm text-stone-500 line-clamp-2">{pin.data.description}</p>
                                            )}
                                        </button>
                                    );
                                })}
                            </div>
                        </div>
                    ) : (
                        <div className="h-full flex flex-col items-center justify-center text-stone-600 space-y-6 opacity-50">
                            <Icon name="book" className="w-24 h-24"/>
                            <div className="text-center">
                                <h2 className="text-3xl font-medieval text-stone-400">The Archives</h2>
                                <p className="mt-2">Select a location or character from the left to begin reading.</p>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default Wiki;

import React, { useState, useMemo, useEffect } from 'react';
import { useAppContext } from './Dashboard';
import { useAuth } from '../App';
import { Map as MapType, Pin, Character, Comment } from '../types';
import { Icon } from './Icons';
import { supabase } from '../services/supabase';

interface WikiProps {
    onSelectMap: (map: MapType) => void;
    onLocatePin: (pin: Pin) => void;
}

const Wiki: React.FC<WikiProps> = ({ onSelectMap, onLocatePin }) => {
    const { maps, pins, pinTypes, characters, isPlayerView } = useAppContext();
    const { user } = useAuth();
    const isDM = user?.profile.role === 'DM';
    const canSeeSecrets = isDM && !isPlayerView;

    const [searchQuery, setSearchQuery] = useState('');
    const [selectedMapId, setSelectedMapId] = useState<string | null>(null);
    const [selectedPinId, setSelectedPinId] = useState<string | null>(null);
    const [selectedCharacterId, setSelectedCharacterId] = useState<string | null>(null);
    const [viewMode, setViewMode] = useState<'maps' | 'characters'>('maps'); // Toggle sidebar view

    // Comments State for Characters
    const [characterComments, setCharacterComments] = useState<Comment[]>([]);
    const [newComment, setNewComment] = useState('');
    const [isPrivateComment, setIsPrivateComment] = useState(false);

    // Fetch character comments when a character is selected
    useEffect(() => {
        if (selectedCharacterId) {
            const fetchComments = async () => {
                const { data, error } = await supabase
                    .from('comments')
                    .select('*, users(username)')
                    .eq('character_id', selectedCharacterId)
                    .order('created_at', { ascending: true });
                if (data) setCharacterComments(data as any);
            };
            fetchComments();
        } else {
            setCharacterComments([]);
        }
    }, [selectedCharacterId]);

    const handleAddCharacterComment = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newComment.trim() || !selectedCharacterId || !user) return;

        const { data, error } = await supabase
            .from('comments')
            .insert({
                character_id: selectedCharacterId,
                user_id: user.id,
                text: newComment,
                is_private: isPrivateComment
            })
            .select('*, users(username)')
            .single();

        if (data) setCharacterComments([...characterComments, data as any]);
        setNewComment('');
        setIsPrivateComment(false);
    };

    const handleNavigateToCharacter = (charId: string) => {
        setViewMode('characters');
        setSelectedCharacterId(charId);
        setSelectedMapId(null);
        setSelectedPinId(null);
    };

    // Filter Logic for Maps
    const filteredMaps = useMemo(() => {
        const lowerQ = searchQuery.toLowerCase();

        return maps.map(map => {
            const mapPins = pins.filter(p => p.map_id === map.id);
            let matchesMap = !searchQuery || map.name.toLowerCase().includes(lowerQ);

            const matchingPins = mapPins.filter(pin => {
                if (!searchQuery) return true;
                if (pin.title.toLowerCase().includes(lowerQ)) return true;
                if (pin.data.description?.toLowerCase().includes(lowerQ)) return true;
                return pin.data.sections?.some(s => 
                    s.title.toLowerCase().includes(lowerQ) || 
                    s.content.toLowerCase().includes(lowerQ) ||
                    (s.type === 'list' && s.list_items?.some(i => i.toLowerCase().includes(lowerQ)))
                );
            });

            if (searchQuery && !matchesMap && matchingPins.length === 0) return null;

            return {
                map,
                pins: matchingPins
            };
        }).filter(Boolean) as { map: MapType, pins: Pin[] }[];

    }, [maps, pins, searchQuery]);

    // Filter Logic for Characters
    const filteredCharacters = useMemo(() => {
        const lowerQ = searchQuery.toLowerCase();
        // Determine visibility based on Role and isPlayerView toggle
        const availableChars = (isDM && !isPlayerView) 
            ? characters 
            : characters.filter(c => c.is_visible); // Only show unlocked chars to players

        return availableChars.filter(c => 
            !searchQuery || 
            c.name.toLowerCase().includes(lowerQ) || 
            c.role_details?.race.toLowerCase().includes(lowerQ) ||
            c.role_details?.class.toLowerCase().includes(lowerQ)
        );
    }, [characters, searchQuery, isDM, isPlayerView]);

    const activeMapData = selectedMapId ? filteredMaps.find(c => c.map.id === selectedMapId) : null;
    const activePin = selectedPinId ? pins.find(p => p.id === selectedPinId) : null;
    const activePinMap = activePin ? maps.find(m => m.id === activePin.map_id) : null;
    const activeCharacter = selectedCharacterId ? characters.find(c => c.id === selectedCharacterId) : null;

    // Helper to get character relationships
    const getCharacterName = (id: string) => characters.find(c => c.id === id)?.name || "Unknown";

    // Helper to render a character list (used in Pin and Map views)
    const CharacterPresenceList: React.FC<{ chars: Character[], title: string }> = ({ chars, title }) => {
        if (chars.length === 0) return null;
        return (
            <div className="mb-8 bg-stone-900/40 p-5 rounded-2xl border border-stone-700/50">
                <h3 className="text-xs font-bold uppercase text-stone-500 mb-4 flex items-center gap-2">
                    <Icon name="user" className="w-4 h-4"/> {title}
                </h3>
                <div className="flex flex-wrap gap-4">
                    {chars.map(c => (
                        <button 
                            key={c.id} 
                            onClick={() => handleNavigateToCharacter(c.id)} 
                            className="flex items-center gap-3 bg-stone-800 hover:bg-stone-700 p-2 rounded-xl border border-stone-700 hover:border-amber-500/50 transition-all group min-w-[150px]"
                        >
                            <div className="w-10 h-10 rounded-full bg-stone-900 overflow-hidden ring-2 ring-stone-700 group-hover:ring-amber-500/50 transition-all">
                                {c.image_url ? <img src={c.image_url} className="w-full h-full object-cover" alt={c.name}/> : <div className="w-full h-full flex items-center justify-center text-stone-600"><Icon name="user" className="w-5 h-5"/></div>}
                            </div>
                            <div className="text-left">
                                <p className="text-sm font-bold text-stone-200 group-hover:text-amber-400 truncate max-w-[120px]">{c.name}</p>
                                <p className="text-[10px] text-stone-500 uppercase tracking-wider">{c.role_details?.race}</p>
                            </div>
                        </button>
                    ))}
                </div>
            </div>
        );
    };

    // --- Renderers ---

    const renderPinContent = (pin: Pin) => {
        const type = pinTypes.find(t => t.id === pin.pin_type_id);
        const charactersAtPin = characters.filter(c => c.current_pin_id === pin.id && ((isDM && !isPlayerView) || c.is_visible));

        return (
            <div className="space-y-8 animate-modal-in max-w-4xl mx-auto pb-20">
                {/* Header */}
                <div className="border-b border-stone-700/50 pb-6">
                    <div className="flex items-center gap-4 mb-4">
                        <div className="flex items-center justify-center w-16 h-16 rounded-2xl shadow-xl text-3xl ring-2 ring-stone-700/50" style={{ backgroundColor: type?.color || '#555' }}>
                            {type?.emoji || '📍'}
                        </div>
                        <div>
                            <h1 className="text-4xl font-medieval font-bold text-stone-100">{pin.title}</h1>
                            <div className="flex items-center gap-2 mt-1">
                                <span className="bg-stone-800/50 px-2 py-0.5 rounded text-xs text-stone-400 border border-stone-700 uppercase tracking-wider">{type?.name || 'Unknown'}</span>
                                {activePinMap && <span className="text-stone-500 text-sm flex items-center gap-1"><Icon name="map" className="w-3 h-3"/> {activePinMap.name}</span>}
                            </div>
                        </div>
                        <button 
                            onClick={() => onLocatePin(pin)}
                            className="ml-auto flex items-center gap-2 bg-stone-800 hover:bg-amber-700/20 hover:text-amber-500 border border-stone-700 px-4 py-2 rounded-xl transition-all text-sm font-medium group"
                        >
                            <Icon name="compass" className="w-4 h-4 group-hover:rotate-45 transition-transform"/>
                            Locate on Map
                        </button>
                    </div>

                    {pin.data.description && (
                         <div className="prose prose-invert max-w-none text-stone-300 text-lg leading-relaxed bg-stone-900/20 p-6 rounded-2xl border border-stone-800/50">
                            {pin.data.description}
                         </div>
                    )}
                </div>

                <CharacterPresenceList chars={charactersAtPin} title="Present Here" />

                {/* Sections */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {pin.data.sections?.map((section, idx) => {
                        if (section.type === 'secret' && !canSeeSecrets) return null;

                        const isFullWidth = section.type === 'text' || section.type === 'list' || section.type === 'inventory';

                        return (
                            <div key={idx} className={`bg-stone-800/20 rounded-2xl border border-stone-700/30 overflow-hidden ${isFullWidth ? 'md:col-span-2' : ''} ${section.type === 'secret' ? 'border-red-900/50 bg-red-950/10' : ''}`}>
                                <div className={`px-5 py-3 border-b border-stone-700/30 flex items-center justify-between ${section.type === 'secret' ? 'bg-red-950/30' : 'bg-stone-800/40'}`}>
                                    <h3 className={`font-medieval text-xl ${section.type === 'secret' ? 'text-red-400' : 'text-stone-200'}`}>
                                        {section.type === 'secret' && <Icon name="lock" className="w-4 h-4 inline mr-2" />}
                                        {section.title}
                                    </h3>
                                    <span className="text-xs uppercase text-stone-600 font-bold tracking-wider">{section.type}</span>
                                </div>

                                <div className="p-5">
                                    {section.type === 'text' && <p className="whitespace-pre-wrap text-stone-300 leading-relaxed">{section.content}</p>}
                                    {section.type === 'secret' && <p className="whitespace-pre-wrap text-red-200/80 leading-relaxed font-mono text-sm">{section.content}</p>}
                                    {/* ... other sections ... */}
                                    {section.type === 'list' && (
                                        <>
                                            {section.content && <p className="mb-4 text-stone-400 italic">{section.content}</p>}
                                            <ul className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                                                {section.list_items?.map((item, i) => (
                                                    <li key={i} className="flex items-start gap-2 text-stone-300 bg-stone-900/30 p-2 rounded">
                                                        <span className="text-amber-500 mt-1">✦</span>
                                                        <span>{item}</span>
                                                    </li>
                                                ))}
                                            </ul>
                                        </>
                                    )}
                                    {section.type === 'statblock' && (
                                        <>
                                            {section.content && <p className="mb-4 text-stone-400 italic">{section.content}</p>}
                                            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                                                {section.stats?.map((stat, i) => (
                                                    <div key={i} className="bg-stone-900/50 p-3 rounded-lg border border-stone-800 flex flex-col items-center text-center">
                                                        <span className="text-xs uppercase tracking-wider text-amber-600 font-bold mb-1">{stat.label}</span>
                                                        <span className="font-medieval text-xl text-stone-200">{stat.value}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </>
                                    )}
                                    {section.type === 'image' && section.image_url && (
                                        <img src={section.image_url} alt={section.title} className="w-full h-auto rounded-lg shadow-lg" />
                                    )}
                                    {section.type === 'inventory' && (
                                        <div className="overflow-x-auto">
                                            <table className="w-full text-left text-sm">
                                                <thead className="text-stone-500 uppercase text-xs border-b border-stone-700/50">
                                                    <tr>
                                                        <th className="pb-2 pl-2">Item</th>
                                                        <th className="pb-2">Rarity</th>
                                                        <th className="pb-2 text-right pr-2">Qty</th>
                                                    </tr>
                                                </thead>
                                                <tbody className="divide-y divide-stone-700/30">
                                                    {section.items?.map((item, i) => (
                                                        <tr key={i} className="hover:bg-stone-700/20">
                                                            <td className="py-2 pl-2">
                                                                <span className={`font-medium ${item.is_magic ? 'text-amber-400' : 'text-stone-300'}`}>{item.name}</span>
                                                            </td>
                                                            <td className="py-2 text-purple-400 text-xs">{item.rarity || '-'}</td>
                                                            <td className="py-2 text-right pr-2 font-mono text-stone-400">{item.count}</td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        );
    };

    const renderCharacterContent = (char: Character) => {
        return (
            <div className="space-y-8 animate-modal-in max-w-4xl mx-auto pb-20">
                <div className="flex flex-col md:flex-row gap-8 border-b border-stone-700/50 pb-8">
                    <div className="w-48 h-48 rounded-3xl overflow-hidden ring-4 ring-stone-800 shadow-2xl bg-stone-900 flex-shrink-0 mx-auto md:mx-0">
                        {char.image_url ? (
                            <img src={char.image_url} alt={char.name} className="w-full h-full object-cover" />
                        ) : (
                            <div className="w-full h-full flex items-center justify-center text-stone-600 bg-stone-800"><Icon name="user" className="w-16 h-16"/></div>
                        )}
                    </div>
