    const [submitting, setSubmitting] = useState(false);

    // Derived map for picker
    const selectedMap = useMemo(() => maps.find(m => m.id === selectedMapId), [selectedMapId, maps]);

    const resetForm = () => {
        setName(''); setRace(''); setCharClass(''); setLevel(1); setAlignment('');
        setBackstory(''); setGmNotes(''); setIsNpc(true); setIsVisible(false); setImageFile(null); setImageUrl('');
        setRelationships([]); setCurrentPinId(null); setSelectedMapId('');
        setSheetUrl(''); setCharJson(null); setJsonFileName('');
        setEditingChar(null);
        setIsEditing(false);
    };

    const handleEdit = (char: Character) => {
        setEditingChar(char);
        setName(char.name);
        setRace(char.role_details?.race || '');
        setCharClass(char.role_details?.class || '');
        setLevel(char.role_details?.level || 1);
        setAlignment(char.role_details?.alignment || '');
        setBackstory(char.backstory || '');
        setGmNotes(char.gm_notes || '');
        setIsNpc(char.is_npc);
        setIsVisible(char.is_visible);
        setImageUrl(char.image_url || '');
        setRelationships(char.relationships || []);
        setCurrentPinId(char.current_pin_id || null);
        setSheetUrl(char.sheet_url || '');
        setCharJson(char.character_json || null);
        setJsonFileName(char.character_json ? 'Existing File Loaded' : '');

        if (char.current_pin_id) {
            const pin = pins.find(p => p.id === char.current_pin_id);
            if (pin) setSelectedMapId(pin.map_id);
        } else {
            setSelectedMapId('');
        }

        setIsEditing(true);
    };

    const handleJsonUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        try {
            const text = await file.text();
            const json = JSON.parse(text);
            setCharJson(json);
            setJsonFileName(file.name);
        } catch (error) {
            alert("Invalid JSON file");
        }
    };

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user || !name) return;
        setSubmitting(true);

        try {
            let finalImageUrl = imageUrl;
            if (imageFile) {
                 finalImageUrl = await fileToBase64(imageFile);
            }

            const payload = {
                name,
                role_details: { race, class: charClass, level, alignment },
                backstory,
                gm_notes: gmNotes,
                image_url: finalImageUrl,
                is_npc: isNpc,
                is_visible: isVisible,
                relationships: relationships || [],
                current_pin_id: currentPinId || null,
                sheet_url: sheetUrl,
                character_json: charJson,
                created_by: user.id
            };

            let result;
            if (editingChar && editingChar.id) {
                result = await supabase.from('characters').update(payload).eq('id', editingChar.id);
            } else {
                result = await supabase.from('characters').insert(payload);
            }

            if (result.error) throw result.error;

            await refreshData(true);
            resetForm();
        } catch (error: any) {
            console.error("Error saving character:", error);
            alert(`Error saving character: ${error.message || "Unknown error"}. Check if 'characters' table exists.`);
        } finally {
            setSubmitting(false); // CRITICAL: Always reset loading state
        }
    };

    const handleDelete = async (char: Character) => {
        if(!window.confirm(`Delete ${char.name}?`)) return;
        const { error } = await supabase.from('characters').delete().eq('id', char.id);
        if(!error) await refreshData(true);
    };

    const addRelationship = () => setRelationships([...relationships, { targetId: '', type: '', notes: '' }]);
    const updateRelationship = (index: number, field: keyof CharacterRelationship, value: string) => {
        const newRels = [...relationships];
        newRels[index] = { ...newRels[index], [field]: value };
        setRelationships(newRels);
    };
    const removeRelationship = (index: number) => setRelationships(relationships.filter((_, i) => i !== index));

    return (
        <Modal isOpen={isOpen} onClose={onClose} title={isEditing ? (editingChar ? "Edit Character" : "New Character") : "Manage Characters"} maxWidthClass="max-w-4xl">
            {!isEditing ? (
                <div className="space-y-6">
                    <button onClick={() => setIsEditing(true)} className="w-full flex items-center justify-center space-x-2 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-4 rounded-xl shadow-lg transition-all">
                        <Icon name="plus" className="h-5 w-5" />
                        <span>Create New Character</span>
                    </button>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {characters.map(char => (
                             <div key={char.id} className="relative group bg-stone-800/40 border border-stone-700/50 rounded-xl p-4 flex gap-4 hover:bg-stone-800/60 transition-colors">
                                <div className="w-16 h-16 rounded-full bg-stone-900 overflow-hidden flex-shrink-0 border-2 border-stone-600 group-hover:border-amber-500 transition-colors">
                                    {char.image_url ? <img src={char.image_url} alt={char.name} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-stone-600 text-xs">No Img</div>}
                                </div>
                                <div className="min-w-0 flex-1">
                                    <h3 className="font-medieval text-lg text-stone-200 truncate">{char.name}</h3>
                                    <p className="text-xs text-stone-500 uppercase tracking-wider font-bold mb-1">{char.is_npc ? 'NPC' : 'PC'}</p>
                                    <p className="text-xs text-stone-400 truncate">{char.role_details?.race} {char.role_details?.class}</p>
                                    <div className="flex items-center gap-2 mt-1">
                                        {char.current_pin_id && <p className="text-[10px] text-amber-500/80 flex items-center gap-1"><Icon name="pin" className="w-3 h-3" /> On Map</p>}
                                        {!char.is_visible && <p className="text-[10px] text-stone-500 flex items-center gap-1"><Icon name="eye-off" className="w-3 h-3" /> Hidden</p>}
                                    </div>
                                </div>
                                <div className="flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity absolute right-2 top-2">
                                     <button onClick={() => handleEdit(char)} className="p-1.5 rounded-lg bg-stone-900 text-stone-400 hover:text-amber-500"><Icon name="pencil" className="w-4 h-4" /></button>
                                     <button onClick={() => handleDelete(char)} className="p-1.5 rounded-lg bg-stone-900 text-stone-400 hover:text-red-500"><Icon name="trash" className="w-4 h-4" /></button>
                                </div>
                             </div>
                        ))}
                        {characters.length === 0 && <p className="col-span-full text-center text-stone-500 italic py-8">No characters found.</p>}
                    </div>
                </div>
            ) : (
                <form onSubmit={handleSave} className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                    {/* Left Column: Stats & Basic Info */}
                    <div className="space-y-4">
                        <div className="flex items-center gap-4 bg-stone-800/30 p-4 rounded-xl border border-stone-700/30">
                            <label className="w-20 h-20 rounded-full bg-stone-900 border-2 border-dashed border-stone-600 flex items-center justify-center cursor-pointer hover:border-amber-500 overflow-hidden relative">
                                {imageUrl || (imageFile && URL.createObjectURL(imageFile)) ? (
                                    <img src={imageUrl || (imageFile ? URL.createObjectURL(imageFile) : '')} className="w-full h-full object-cover" />
                                ) : <span className="text-xs text-stone-500 text-center">Avatar</span>}
                                <input type="file" className="hidden" accept="image/*" onChange={e => {
                                    if(e.target.files?.[0]) { setImageFile(e.target.files[0]); setImageUrl(''); }
                                }} />
                            </label>
                            <div className="flex-1 space-y-2">
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input type="checkbox" checked={isNpc} onChange={e => setIsNpc(e.target.checked)} className="rounded border-stone-600 bg-stone-800 text-amber-600 focus:ring-amber-500" />
                                    <span className="text-sm font-bold text-stone-300">Is NPC?</span>
                                </label>
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input type="checkbox" checked={isVisible} onChange={e => setIsVisible(e.target.checked)} className="rounded border-stone-600 bg-stone-800 text-amber-600 focus:ring-amber-500" />
                                    <span className="text-sm font-bold text-stone-300">Visible to Players?</span>
                                </label>
                                <input type="text" placeholder="Image URL (optional)" value={imageUrl} onChange={e => { setImageUrl(e.target.value); setImageFile(null); }} className="w-full rounded-lg border border-stone-600/50 bg-stone-900/40 px-3 py-2 text-sm text-stone-200" />
                            </div>
                        </div>

                        <input type="text" placeholder="Name" value={name} onChange={e => setName(e.target.value)} required className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                        <div className="grid grid-cols-2 gap-2">
                             <input type="text" placeholder="Race" value={race} onChange={e => setRace(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                             <input type="text" placeholder="Class" value={charClass} onChange={e => setCharClass(e.target.value)} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                        </div>
                        <div className="flex gap-2">
                            <input type="number" placeholder="Level" min="1" max="20" value={level} onChange={e => setLevel(parseInt(e.target.value))} className="w-24 rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                            <input type="text" placeholder="Alignment" value={alignment} onChange={e => setAlignment(e.target.value)} className="flex-1 rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                        </div>

                         {/* Extra Links */}
                         <div className="space-y-2 bg-stone-800/30 p-4 rounded-xl border border-stone-700/30">
                            <h4 className="text-xs font-bold uppercase text-stone-500 mb-2">Integrations</h4>
                            <div className="flex items-center gap-2">
                                <Icon name="external" className="w-4 h-4 text-stone-500" />
                                <input type="text" placeholder="Link to Character Sheet (URL)" value={sheetUrl} onChange={e => setSheetUrl(e.target.value)} className="flex-1 bg-stone-900/50 rounded border border-stone-700/50 px-3 py-2 text-sm text-stone-200" />
                            </div>
                            <label className="flex items-center gap-2 cursor-pointer bg-stone-900/50 rounded border border-stone-700/50 px-3 py-2 text-sm hover:bg-stone-800/50 transition-colors">
                                <Icon name="upload" className="w-4 h-4 text-stone-500" />
                                <span className="text-stone-300 flex-1 truncate">{jsonFileName || "Upload Tracker JSON (for encounter tools)"}</span>
                                <input type="file" accept=".json" onChange={handleJsonUpload} className="hidden" />
                            </label>
                         </div>

                        <textarea placeholder="Backstory / Bio" value={backstory} onChange={e => setBackstory(e.target.value)} rows={5} className="w-full rounded-xl border border-stone-600/50 bg-stone-800/40 px-4 py-3 text-stone-200 focus:border-amber-500 focus:outline-none" />
                    </div>

                    {/* Right Column: Location & Relationships */}
                    <div className="space-y-4">
                        <div className="bg-stone-800/30 p-4 rounded-xl border border-stone-700/30 space-y-3">
                            <div className="flex justify-between items-center border-b border-stone-700/50 pb-2">
                                <h4 className="text-sm font-bold uppercase text-stone-400 flex items-center gap-2"><Icon name="map" className="w-4 h-4" /> Location</h4>
                                <div className="text-xs text-stone-500 italic">
                                    {currentPinId ? "Pin selected" : "Select a map, then click a pin"}
                                </div>
                            </div>

                            <select 
                                value={selectedMapId} 
                                onChange={e => { setSelectedMapId(e.target.value); setCurrentPinId(null); }} 
                                className="w-full rounded-lg border border-stone-600/50 bg-stone-900/40 px-3 py-2 text-sm text-stone-200 focus:outline-none"
                            >
                                <option value="">(Select Map to Locate Character)</option>
                                {maps.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                            </select>

                            {selectedMap ? (
                                <div className="relative h-64 w-full rounded-xl overflow-hidden border border-stone-700/50 shadow-inner bg-stone-950 group">
                                    <MapViewer 
                                        map={selectedMap}
                                        onSelectPin={(pin) => setCurrentPinId(pin.id)}
                                        onAddPin={() => {}} 
                                        highlightedPinId={currentPinId}
                                    />
                                    {!currentPinId && <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-black/60 px-3 py-1 rounded-full text-xs text-amber-500 pointer-events-none backdrop-blur-sm border border-amber-900/30">Click a pin to place character</div>}
                                    {currentPinId && <div className="absolute top-2 left-1/2 -translate-x-1/2 bg-amber-600/90 px-3 py-1 rounded-full text-xs text-white pointer-events-none shadow-lg">Location Set</div>}
                                </div>
                            ) : (
                                <div className="h-64 flex items-center justify-center bg-stone-900/20 rounded-xl border border-dashed border-stone-700/50 text-stone-600 text-sm italic">
                                    Map preview will appear here
                                </div>
                            )}

                            <div className="flex items-center justify-between text-xs">
                                <span className="text-stone-500">Current ID: <span className="font-mono text-stone-400">{currentPinId ? pins.find(p => p.id === currentPinId)?.title || 'Unknown Pin' : 'None'}</span></span>
                                {currentPinId && <button type="button" onClick={() => setCurrentPinId(null)} className="text-red-500 hover:underline">Clear Location</button>}
                            </div>
                        </div>

                        {/* Relationships */}
                        <div className="bg-stone-800/30 p-4 rounded-xl border border-stone-700/30 space-y-3">
                            <div className="flex justify-between items-center">
                                <h4 className="text-sm font-bold uppercase text-stone-400 flex items-center gap-2"><Icon name="user" className="w-4 h-4" /> Relationships</h4>
                                <button type="button" onClick={addRelationship} className="text-xs text-amber-500 hover:underline">+ Add</button>
                            </div>
                            <div className="space-y-2 max-h-40 overflow-y-auto custom-scrollbar">
                                {relationships.map((rel, idx) => (
                                    <div key={idx} className="flex flex-col gap-2 p-2 bg-stone-900/40 rounded border border-stone-800">
                                        <div className="flex gap-2">
                                            <select 
                                                value={rel.targetId} 
                                                onChange={e => updateRelationship(idx, 'targetId', e.target.value)} 
                                                className="flex-1 rounded border border-stone-600/50 bg-stone-800 text-xs text-stone-200 p-1"
                                            >
                                                <option value="">Select Character...</option>
                                                {characters.filter(c => c.id !== editingChar?.id).map(c => (
                                                    <option key={c.id} value={c.id}>{c.name}</option>
                                                ))}
                                            </select>
                                            <input 
                                                type="text" 
                                                placeholder="Type (e.g. Rival)" 
                                                value={rel.type} 
                                                onChange={e => updateRelationship(idx, 'type', e.target.value)} 
                                                className="w-1/3 rounded border border-stone-600/50 bg-stone-800 text-xs text-stone-200 p-1"
                                            />
                                            <button type="button" onClick={() => removeRelationship(idx)} className="text-stone-500 hover:text-red-500 px-1"><Icon name="trash" className="w-3 h-3" /></button>
                                        </div>
                                        <input 
                                            type="text" 
                                            placeholder="Notes..." 
                                            value={rel.notes || ''} 
                                            onChange={e => updateRelationship(idx, 'notes', e.target.value)} 
                                            className="w-full rounded border border-stone-600/30 bg-stone-800 text-xs text-stone-400 p-1"
                                        />
                                    </div>
                                ))}
                                {relationships.length === 0 && <p className="text-xs text-stone-600 italic text-center">No relationships defined.</p>}
                            </div>
                        </div>

                         <textarea placeholder="GM Notes (Secret)" value={gmNotes} onChange={e => setGmNotes(e.target.value)} rows={2} className="w-full rounded-xl border border-red-900/30 bg-red-950/10 px-4 py-3 text-stone-200 placeholder-red-400/50 focus:border-red-500 focus:outline-none" />
                    </div>

                    <div className="lg:col-span-2 flex gap-3 pt-4 border-t border-stone-700/50">
                        <button type="button" onClick={resetForm} className="flex-1 bg-stone-700 hover:bg-stone-600 text-stone-200 font-bold py-3 px-6 rounded-xl transition-all">Cancel</button>
                        <button type="submit" disabled={submitting} className="flex-1 bg-amber-600 hover:bg-amber-500 text-white font-bold py-3 px-6 rounded-xl shadow-lg transition-all">
                            {submitting ? <Icon name="spinner" className="h-5 w-5 animate-spin mx-auto"/> : "Save Character"}
                        </button>
                    </div>
                </form>
            )}
        </Modal>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { useAppContext } from './Dashboard';
import { useAuth } from '../App';
import { Map as MapType, Pin, Character, Comment } from '../types';
import { Icon } from './Icons';
import { supabase } from '../services/supabase';

interface WikiProps {
    onSelectMap: (map: MapType) => void;
    onLocatePin: (pin: Pin) => void;
}

const Wiki: React.FC<WikiProps> = ({ onSelectMap, onLocatePin }) => {
    const { maps, pins, pinTypes, characters, isPlayerView } = useAppContext();
    const { user } = useAuth();
    const isDM = user?.profile.role === 'DM';
    const canSeeSecrets = isDM && !isPlayerView;

    const [searchQuery, setSearchQuery] = useState('');
    const [selectedMapId, setSelectedMapId] = useState<string | null>(null);
    const [selectedPinId, setSelectedPinId] = useState<string | null>(null);
    const [selectedCharacterId, setSelectedCharacterId] = useState<string | null>(null);
    const [viewMode, setViewMode] = useState<'maps' | 'characters'>('maps'); // Toggle sidebar view

    // Comments State for Characters
    const [characterComments, setCharacterComments] = useState<Comment[]>([]);
    const [newComment, setNewComment] = useState('');
    const [isPrivateComment, setIsPrivateComment] = useState(false);

    // Fetch character comments when a character is selected
    useEffect(() => {
        if (selectedCharacterId) {
            const fetchComments = async () => {
                const { data, error } = await supabase
                    .from('comments')
                    .select('*, users(username)')
                    .eq('character_id', selectedCharacterId)
                    .order('created_at', { ascending: true });
                if (data) setCharacterComments(data as any);
            };
            fetchComments();
        } else {
            setCharacterComments([]);
        }
    }, [selectedCharacterId]);

    const handleAddCharacterComment = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newComment.trim() || !selectedCharacterId || !user) return;

        const { data, error } = await supabase
            .from('comments')
            .insert({
                character_id: selectedCharacterId,
                user_id: user.id,
                text: newComment,
                is_private: isPrivateComment
            })
            .select('*, users(username)')
            .single();

        if (data) setCharacterComments([...characterComments, data as any]);
        setNewComment('');
        setIsPrivateComment(false);
    };

    const handleNavigateToCharacter = (charId: string) => {
        setViewMode('characters');
        setSelectedCharacterId(charId);
        setSelectedMapId(null);
        setSelectedPinId(null);
    };

    // Filter Logic for Maps
    const filteredMaps = useMemo(() => {
        const lowerQ = searchQuery.toLowerCase();

        return maps.map(map => {
            const mapPins = pins.filter(p => p.map_id === map.id);
            let matchesMap = !searchQuery || map.name.toLowerCase().includes(lowerQ);

            const matchingPins = mapPins.filter(pin => {
                if (!searchQuery) return true;
                if (pin.title.toLowerCase().includes(lowerQ)) return true;
                if (pin.data.description?.toLowerCase().includes(lowerQ)) return true;
                return pin.data.sections?.some(s => 
                    s.title.toLowerCase().includes(lowerQ) || 
                    s.content.toLowerCase().includes(lowerQ) ||
                    (s.type === 'list' && s.list_items?.some(i => i.toLowerCase().includes(lowerQ)))
                );
            });

            if (searchQuery && !matchesMap && matchingPins.length === 0) return null;

            return {
                map,
                pins: matchingPins
            };
        }).filter(Boolean) as { map: MapType, pins: Pin[] }[];

    }, [maps, pins, searchQuery]);

    // Filter Logic for Characters
    const filteredCharacters = useMemo(() => {
        const lowerQ = searchQuery.toLowerCase();
        // Determine visibility based on Role and isPlayerView toggle
        const availableChars = (isDM && !isPlayerView) 
            ? characters 
            : characters.filter(c => c.is_visible); // Only show unlocked chars to players

        return availableChars.filter(c => 
            !searchQuery || 
            c.name.toLowerCase().includes(lowerQ) || 
            c.role_details?.race.toLowerCase().includes(lowerQ) ||
            c.role_details?.class.toLowerCase().includes(lowerQ)
        );
    }, [characters, searchQuery, isDM, isPlayerView]);

    const activeMapData = selectedMapId ? filteredMaps.find(c => c.map.id === selectedMapId) : null;
    const activePin = selectedPinId ? pins.find(p => p.id === selectedPinId) : null;
    const activePinMap = activePin ? maps.find(m => m.id === activePin.map_id) : null;
    const activeCharacter = selectedCharacterId ? characters.find(c => c.id === selectedCharacterId) : null;

    // Helper to get character relationships
    const getCharacterName = (id: string) => characters.find(c => c.id === id)?.name || "Unknown";

    // Helper to render a character list (used in Pin and Map views)
    const CharacterPresenceList: React.FC<{ chars: Character[], title: string }> = ({ chars, title }) => {
        if (chars.length === 0) return null;
        return (
            <div className="mb-8 bg-stone-900/40 p-5 rounded-2xl border border-stone-700/50">
                <h3 className="text-xs font-bold uppercase text-stone-500 mb-4 flex items-center gap-2">
                    <Icon name="user" className="w-4 h-4"/> {title}
                </h3>
                <div className="flex flex-wrap gap-4">
                    {chars.map(c => (
                        <button 
                            key={c.id} 
                            onClick={() => handleNavigateToCharacter(c.id)} 
                            className="flex items-center gap-3 bg-stone-800 hover:bg-stone-700 p-2 rounded-xl border border-stone-700 hover:border-amber-500/50 transition-all group min-w-[150px]"
                        >
                            <div className="w-10 h-10 rounded-full bg-stone-900 overflow-hidden ring-2 ring-stone-700 group-hover:ring-amber-500/50 transition-all">
                                {c.image_url ? <img src={c.image_url} className="w-full h-full object-cover" alt={c.name}/> : <div className="w-full h-full flex items-center justify-center text-stone-600"><Icon name="user" className="w-5 h-5"/></div>}
                            </div>
                            <div className="text-left">
                                <p className="text-sm font-bold text-stone-200 group-hover:text-amber-400 truncate max-w-[120px]">{c.name}</p>
                                <p className="text-[10px] text-stone-500 uppercase tracking-wider">{c.role_details?.race}</p>
                            </div>
                        </button>
                    ))}
                </div>
            </div>
        );
    };

    // --- Renderers ---

    const renderPinContent = (pin: Pin) => {
        const type = pinTypes.find(t => t.id === pin.pin_type_id);
        const charactersAtPin = characters.filter(c => c.current_pin_id === pin.id && ((isDM && !isPlayerView) || c.is_visible));

        return (
            <div className="space-y-8 animate-modal-in max-w-4xl mx-auto pb-20">
                {/* Header */}
                <div className="border-b border-stone-700/50 pb-6">
                    <div className="flex items-center gap-4 mb-4">
                        <div className="flex items-center justify-center w-16 h-16 rounded-2xl shadow-xl text-3xl ring-2 ring-stone-700/50" style={{ backgroundColor: type?.color || '#555' }}>
                            {type?.emoji || '📍'}
                        </div>
                        <div>
                            <h1 className="text-4xl font-medieval font-bold text-stone-100">{pin.title}</h1>
                            <div className="flex items-center gap-2 mt-1">
                                <span className="bg-stone-800/50 px-2 py-0.5 rounded text-xs text-stone-400 border border-stone-700 uppercase tracking-wider">{type?.name || 'Unknown'}</span>
                                {activePinMap && <span className="text-stone-500 text-sm flex items-center gap-1"><Icon name="map" className="w-3 h-3"/> {activePinMap.name}</span>}
                            </div>
