            if (isEditing && editingMap?.id) {
                await supabase.from('maps').update(payload).eq('id', editingMap.id);
            } else {
                await supabase.from('maps').insert(payload);
            }

            await refreshData(true);
            resetForm();
        } catch (error) {
            console.error(error);
