                            placeholder="Search everything..." 
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full bg-stone-900/50 border border-stone-700 rounded-lg pl-9 pr-3 py-2 text-sm text-stone-200 focus:border-amber-500 focus:outline-none placeholder-stone-600"
                        />
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar p-2 space-y-4">

                    {/* CHARACTERS SECTION */}
                    {filteredCharacters.length > 0 && (
                        <div>
                             <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2 mt-2">Characters</h3>
                            {filteredCharacters.map(char => (
                                <button
                                    key={char.id}
                                    onClick={() => { setSelectedCharacterId(char.id); setSelectedMapId(null); setSelectedPinId(null); }}
                                    className={`w-full flex items-center gap-3 px-3 py-2 rounded-xl text-left transition-colors mb-1 ${selectedCharacterId === char.id ? 'bg-amber-900/20 text-amber-400 border border-amber-500/30' : 'hover:bg-stone-800/50 text-stone-300 border border-transparent'}`}
                                >
                                    <div className="w-8 h-8 rounded-full bg-stone-800 overflow-hidden flex-shrink-0">
                                        {char.image_url ? <img src={char.image_url} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center"><Icon name="user" className="w-4 h-4"/></div>}
                                    </div>
                                    <div className="min-w-0">
                                        <div className="font-medium truncate text-sm">{char.name}</div>
                                        <div className="text-[10px] text-stone-500 truncate">{char.role_details?.race} {char.role_details?.class}</div>
                                    </div>
                                </button>
                            ))}
                        </div>
                    )}

                    {/* MAPS SECTION */}
                    {filteredMaps.length > 0 && (
                        <div>
                            <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2 mt-2">Locations</h3>
                            {filteredMaps.map(({ map, pins }) => (
                                <div key={map.id} className="rounded-xl overflow-hidden border border-transparent mb-1">
                                    <button 
                                        onClick={() => { setSelectedMapId(map.id); setSelectedPinId(null); setSelectedCharacterId(null); }}
                                        className={`w-full flex items-center gap-3 px-3 py-2 text-left transition-colors ${selectedMapId === map.id && !selectedPinId ? 'bg-amber-900/20 text-amber-400 border-amber-500/30' : 'hover:bg-stone-800/50 text-stone-300'}`}
                                    >
                                        <Icon name="map" className="w-4 h-4 opacity-70"/>
                                        <span className="font-medium truncate">{map.name}</span>
                                    </button>

                                    {(selectedMapId === map.id || searchQuery) && (
                                        <div className="pl-4 border-l border-stone-800 ml-4 mt-1 space-y-0.5">
                                            {pins.map(pin => (
                                                <button 
                                                    key={pin.id}
                                                    onClick={() => { setSelectedMapId(map.id); setSelectedPinId(pin.id); setSelectedCharacterId(null); }}
                                                    className={`w-full flex items-center gap-2 px-3 py-1.5 text-left text-sm rounded-lg transition-colors ${selectedPinId === pin.id ? 'bg-stone-800 text-white' : 'text-stone-500 hover:text-stone-300 hover:bg-stone-800/30'}`}
                                                >
                                                    <span className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: pinTypes.find(t => t.id === pin.pin_type_id)?.color }}></span>
                                                    <span className="truncate">{pin.title}</span>
                                                </button>
                                            ))}
                                            {pins.length === 0 && <p className="px-3 py-1 text-xs text-stone-600 italic">No pins found</p>}
                                        </div>
                                    )}
                                </div>
                            ))}
                        </div>
                    )}

                    {filteredCharacters.length === 0 && filteredMaps.length === 0 && (
                         <div className="text-center text-stone-600 text-sm py-8">
                            <Icon name="search" className="w-8 h-8 mx-auto mb-2 opacity-50"/>
                            <p>No results found.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Right Pane: Content */}
            <div className="flex-1 overflow-y-auto custom-scrollbar bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')]">
                <div className="p-8 md:p-12 min-h-full">
                    {selectedPinId && activePin ? (
                        renderPinContent(activePin)
                    ) : selectedCharacterId && activeCharacter ? (
                        renderCharacterContent(activeCharacter)
                    ) : selectedMapId && activeMapData ? (
                        <div className="max-w-4xl mx-auto space-y-8 animate-modal-in">
                            <div className="flex items-center gap-4 border-b border-stone-700/50 pb-6">
                                <div className="w-20 h-20 rounded-2xl overflow-hidden ring-2 ring-stone-700 shadow-2xl bg-stone-900">
                                    <img src={activeMapData.map.image_url} className="w-full h-full object-cover" alt={activeMapData.map.name} />
                                </div>
                                <div>
                                    <h1 className="text-5xl font-medieval font-bold text-amber-500">{activeMapData.map.name}</h1>
                                    <p className="text-stone-500 mt-1 uppercase tracking-widest text-sm font-bold flex items-center gap-2">
                                        <span className="capitalize">{activeMapData.map.map_type?.replace('_', ' ') || 'Region'} Map</span>
                                    </p>
                                </div>
                                <button 
                                    onClick={() => onSelectMap(activeMapData.map)}
                                    className="ml-auto flex items-center gap-2 bg-amber-600 hover:bg-amber-500 text-white px-6 py-3 rounded-xl shadow-lg transition-all font-bold"
                                >
                                    <Icon name="map" className="w-5 h-5"/>
                                    Open Map
                                </button>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                {activeMapData.pins.map(pin => {
                                    const type = pinTypes.find(t => t.id === pin.pin_type_id);
                                    const charsAtPin = characters.filter(c => c.current_pin_id === pin.id && ((isDM && !isPlayerView) || c.is_visible));

                                    return (
                                        <button 
                                            key={pin.id}
                                            onClick={() => setSelectedPinId(pin.id)}
                                            className="bg-stone-800/40 hover:bg-stone-800 border border-stone-700/30 hover:border-amber-500/50 p-4 rounded-xl text-left transition-all group flex flex-col gap-3"
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className="w-10 h-10 rounded-full flex items-center justify-center text-lg shadow-lg ring-1 ring-white/10" style={{ backgroundColor: type?.color }}>
                                                    {type?.emoji}
                                                </div>
                                                <div className="min-w-0">
                                                    <h3 className="font-bold text-stone-200 truncate group-hover:text-amber-400">{pin.title}</h3>
                                                    <p className="text-xs text-stone-500">{type?.name}</p>
                                                </div>
                                            </div>
                                            {pin.data.description && (
                                                <p className="text-sm text-stone-500 line-clamp-2">{pin.data.description}</p>
                                            )}

                                            {/* Character Portraits Preview */}
                                            {charsAtPin.length > 0 && (
                                                <div className="mt-3 pt-3 border-t border-stone-700/30 flex items-center gap-2">
                                                    <div className="flex -space-x-2">
                                                        {charsAtPin.slice(0, 5).map(c => (
                                                            <div key={c.id} className="w-6 h-6 rounded-full ring-2 ring-stone-800 bg-stone-900 overflow-hidden relative z-0 hover:z-10 transition-all" title={c.name}>
                                                                {c.image_url ? (
                                                                    <img src={c.image_url} className="w-full h-full object-cover" alt={c.name} />
                                                                ) : (
                                                                    <div className="w-full h-full flex items-center justify-center text-stone-500"><Icon name="user" className="w-3 h-3"/></div>
                                                                )}
                                                            </div>
                                                        ))}
                                                        {charsAtPin.length > 5 && (
                                                            <div className="w-6 h-6 rounded-full ring-2 ring-stone-800 bg-stone-800 flex items-center justify-center text-[10px] text-stone-400 font-bold z-0">
                                                                +{charsAtPin.length - 5}
                                                            </div>
                                                        )}
                                                    </div>
                                                    <span className="text-[10px] text-stone-500 font-bold uppercase tracking-wider">
                                                        {charsAtPin.length} Present
                                                    </span>
                                                </div>
                                            )}
                                        </button>
                                    );
                                })}
                            </div>
                        </div>
                    ) : (
                        <div className="h-full flex flex-col items-center justify-center text-stone-600 space-y-6 opacity-50">
                            <Icon name="book" className="w-24 h-24"/>
                            <div className="text-center">
                                <h2 className="text-3xl font-medieval text-stone-400">The Archives</h2>
                                <p className="mt-2">Select a location or character from the left to begin reading.</p>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default Wiki;

import React, { useState, useEffect, createContext, useContext, useCallback } from 'react';
import { useAuth } from '../App';
import { Map as MapType, Pin, PinType, Character } from '../types';
import { supabase } from '../services/supabase';
import Sidebar from './Sidebar';
import MapViewer from './MapViewer';
import PinDetails from './PinDetails';
import Wiki from './Wiki';
import { MapManagerModal, PinEditorModal, PinTypeManagerModal, PlayerManagerModal, CharacterManagerModal, DMToolsModal, UserSettingsModal } from './Modals';
import { Icon } from './Icons';

type AppContextType = {
    maps: MapType[];
    pinTypes: PinType[];
    pins: Pin[];
    characters: Character[];
    isPlayerView: boolean;
    refreshData: (silent?: boolean) => Promise<void>;
    setIsPlayerView: React.Dispatch<React.SetStateAction<boolean>>;
};

const AppContext = createContext<AppContextType | null>(null);
export const useAppContext = () => {
    const context = useContext(AppContext);
    if (!context) throw new Error('useAppContext must be used within an AppContextProvider');
    return context;
};

const Dashboard: React.FC = () => {
    const { user, signOut } = useAuth();
    const [maps, setMaps] = useState<MapType[]>([]);
    const [pinTypes, setPinTypes] = useState<PinType[]>([]);
    const [pins, setPins] = useState<Pin[]>([]);
    const [characters, setCharacters] = useState<Character[]>([]);

    // View State
    const [currentView, setCurrentView] = useState<'map' | 'wiki'>('map');
    const [selectedMap, setSelectedMap] = useState<MapType | null>(null);
    const [selectedPin, setSelectedPin] = useState<Pin | null>(null);

    // Wiki Target State (for deep linking)
    const [wikiTarget, setWikiTarget] = useState<{ type: 'character' | 'map', id: string } | null>(null);

    // Highlight State (for locating pins from Wiki)
    const [highlightedPinId, setHighlightedPinId] = useState<string | null>(null);

    const [isPlayerView, setIsPlayerView] = useState(user?.profile.role === 'Player');
    const [loading, setLoading] = useState(true);

    // Modal states
    const [isDMToolsOpen, setDMToolsOpen] = useState(false);
    const [isMapManagerOpen, setMapManagerOpen] = useState(false);
    const [isPinTypeManagerOpen, setPinTypeManagerOpen] = useState(false);
    const [isPlayerManagerOpen, setPlayerManagerOpen] = useState(false);
    const [isCharacterManagerOpen, setCharacterManagerOpen] = useState(false);
    const [isUserSettingsOpen, setUserSettingsOpen] = useState(false);
    const [editingPin, setEditingPin] = useState<Partial<Pin> | null>(null);

    useEffect(() => {
        if (user) {
            setIsPlayerView(user.profile.role === 'Player');
        }
    }, [user?.id]);

    const refreshData = useCallback(async (silent = false) => {
        if (!user) return;
        if (!silent) setLoading(true);

        const fetchMaps = supabase.from('maps').select('*');
        const { data: mapsData, error: mapsError } = await (user.profile.role === 'DM' ? fetchMaps : fetchMaps.eq('is_visible', true));

        const { data: pinTypesData, error: pinTypesError } = await supabase.from('pin_types').select('*');

        if (mapsData) setMaps(mapsData);
        if (pinTypesData) setPinTypes(pinTypesData);
        if (mapsError) console.error("Error fetching maps", mapsError);
        if (pinTypesError) console.error("Error fetching pin types", pinTypesError);

        // Fetch ALL pins for the wiki search, but map viewer filters by selected map
        const fetchPins = supabase.from('pins').select('*, pin_types(*)');
        const { data: pinsData, error: pinsError } = await (user.profile.role === 'DM' && !isPlayerView ? fetchPins : fetchPins.eq('is_visible', true));
        if (pinsData) setPins(pinsData as Pin[]);

        // Fetch Characters
        const { data: charData, error: charError } = await supabase.from('characters').select('*');
        if (charData) setCharacters(charData as Character[]);
        if (charError) {
             // Swallow error if table doesn't exist yet to prevent app crash on older DBs
             if(charError.code !== '42P01') console.error("Error fetching characters", charError);
        }

        if (!silent) setLoading(false);
    }, [user, isPlayerView]);

    useEffect(() => {
        refreshData();
    }, [refreshData]);

    const handleSelectMap = (map: MapType | null) => {
        setSelectedMap(map);
        setSelectedPin(null);
        setHighlightedPinId(null);
        setCurrentView('map'); // Switch to map view when selecting from sidebar
    };

    const handlePinSave = async () => {
        setEditingPin(null);
        await refreshData(true);
    };

    const handleMovePin = async (pinId: string, x: number, y: number) => {
        // Optimistic update
        setPins(prev => prev.map(p => p.id === pinId ? { ...p, x_coord: x, y_coord: y } : p));

        const { error } = await supabase.from('pins').update({ x_coord: x, y_coord: y }).eq('id', pinId);
        if (error) {
            console.error("Error moving pin:", error);
            // Revert on error
            refreshData(true);
        }
    };

    const handleOpenWikiCharacter = (charId: string) => {
        setWikiTarget({ type: 'character', id: charId });
        setCurrentView('wiki');
        setSelectedPin(null); // Close pin details
    };

    if (loading) {
        return <div className="flex h-screen w-full items-center justify-center bg-stone-950"><Icon name="spinner" className="h-10 w-10 animate-spin text-amber-500" /></div>;
    }

    return (
        <AppContext.Provider value={{ maps, pinTypes, pins, characters, isPlayerView, refreshData, setIsPlayerView }}>
            <div className="flex h-screen w-full flex-col md:flex-row overflow-hidden bg-stone-950 text-stone-200">
                <Sidebar
                    selectedMap={selectedMap}
                    onSelectMap={handleSelectMap}
                    currentView={currentView}
                    onViewChange={setCurrentView}
                    onDMToolsOpen={() => setDMToolsOpen(true)}
                    onUserSettingsOpen={() => setUserSettingsOpen(true)}
                />
                <main className="relative flex-1 bg-stone-950 overflow-hidden">
                    {currentView === 'map' ? (
                        <>
                            {selectedMap ? (
                                <MapViewer
                                    map={selectedMap}
                                    onSelectPin={(pin) => {
                                        setSelectedPin(pin);
                                        setHighlightedPinId(null); // Clear highlight on user interaction
                                    }}
                                    onAddPin={(coords) => {
                                        if (user?.profile.role === 'DM' && !isPlayerView) {
                                            setEditingPin({ x_coord: coords.x, y_coord: coords.y, map_id: selectedMap.id });
                                            setHighlightedPinId(null);
                                        }
                                    }}
                                    onMovePin={handleMovePin}
                                    highlightedPinId={highlightedPinId}
                                />
                            ) : (
                                <div className="flex h-full w-full items-center justify-center text-stone-500">
                                    <div className="text-center">
                                        <Icon name="map" className="mx-auto h-16 w-16 opacity-30 mb-4" />
                                        <p className="text-lg font-medieval">Select a map to begin</p>
                                    </div>
                                </div>
                            )}
                            <PinDetails 
                                pin={selectedPin} 
                                onClose={() => setSelectedPin(null)} 
                                onEdit={(pin) => setEditingPin(pin)}
                                mapId={selectedMap?.id}
                                onOpenWiki={handleOpenWikiCharacter}
                            />
                        </>
                    ) : (
                        <Wiki 
                            target={wikiTarget}
                            onSelectMap={(map) => handleSelectMap(map)}
                            onLocatePin={(pin) => {
                                const map = maps.find(m => m.id === pin.map_id);
                                if(map) {
                                    setSelectedMap(map);
                                    setHighlightedPinId(pin.id); // Set the highlight
                                    setSelectedPin(null); // Ensure detail view is closed
                                    setCurrentView('map');
                                }
                            }}
                        />
                    )}

                    {isDMToolsOpen && (
                        <DMToolsModal 
                            isOpen={isDMToolsOpen}
                            onClose={() => setDMToolsOpen(false)}
                            onMapManagerOpen={() => setMapManagerOpen(true)}
                            onCharacterManagerOpen={() => setCharacterManagerOpen(true)}
                            onPinTypeManagerOpen={() => setPinTypeManagerOpen(true)}
                            onPlayerManagerOpen={() => setPlayerManagerOpen(true)}
                            onSignOut={() => signOut()}
                        />
                    )}

                    {isMapManagerOpen && <MapManagerModal isOpen={isMapManagerOpen} onClose={() => setMapManagerOpen(false)} />}
                    {isPinTypeManagerOpen && <PinTypeManagerModal isOpen={isPinTypeManagerOpen} onClose={() => setPinTypeManagerOpen(false)} />}
                    {isPlayerManagerOpen && <PlayerManagerModal isOpen={isPlayerManagerOpen} onClose={() => setPlayerManagerOpen(false)} />}
                    {isCharacterManagerOpen && <CharacterManagerModal isOpen={isCharacterManagerOpen} onClose={() => setCharacterManagerOpen(false)} />}
                    {isUserSettingsOpen && <UserSettingsModal isOpen={isUserSettingsOpen} onClose={() => setUserSettingsOpen(false)} />}
                    {editingPin && (
                        <PinEditorModal 
                            pinData={editingPin} 
                            onClose={() => setEditingPin(null)} 
                            onSave={handlePinSave} 
                        />
                    )}
                </main>
            </div>
        </AppContext.Provider>
    );
};

export default Dashboard;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Map as MapType, Pin } from '../types';
import { useAppContext } from './Dashboard';
import { useAuth } from '../App';
import { Icon } from './Icons';

interface MapViewerProps {
    map: MapType;
    onSelectPin: (pin: Pin) => void;
    onAddPin: (coords: { x: number; y: number }) => void;
    onMovePin?: (pinId: string, x: number, y: number) => void;
    highlightedPinId?: string | null;
}

type InteractionMode = 'pan' | 'pin';

const MapViewer: React.FC<MapViewerProps> = ({ map, onSelectPin, onAddPin, onMovePin, highlightedPinId }) => {
    const { pins, pinTypes, isPlayerView, characters } = useAppContext();
    const { user } = useAuth();
    const containerRef = useRef<HTMLDivElement>(null);
    const mapRef = useRef<HTMLDivElement>(null);

    const [viewState, setViewState] = useState({ scale: 1, x: 0, y: 0 });
    const [isPanning, setIsPanning] = useState(false);
    const [panStart, setPanStart] = useState({ x: 0, y: 0 });
    const [imgDimensions, setImgDimensions] = useState({ width: 0, height: 0 });
    const [hoveredPinId, setHoveredPinId] = useState<string | null>(null);

    // Dragging Pins State
    const [draggingPinId, setDraggingPinId] = useState<string | null>(null);
    const [dragPosition, setDragPosition] = useState<{ x: number, y: number } | null>(null);

    // Default to 'pan' mode. Only DMs can switch to 'pin'.
    const [interactionMode, setInteractionMode] = useState<InteractionMode>('pan');

    // Defaults if map config is missing
    const gridSize = map.grid_size || 50;
    const pinSize = map.pin_scale || 50;
    const showGrid = map.is_grid_visible || false;

    const isDM = user?.profile.role === 'DM';
    const canEdit = isDM && !isPlayerView;

    const getPinType = (pinTypeId: string) => pinTypes.find(pt => pt.id === pinTypeId);

    const resetView = useCallback(() => {
        if (!containerRef.current || !imgDimensions.width) return;
        const container = containerRef.current;
        const { width: cWidth, height: cHeight } = container.getBoundingClientRect();
        const { width: iWidth, height: iHeight } = imgDimensions;

        const scaleX = cWidth / iWidth;
        const scaleY = cHeight / iHeight;
        const scale = Math.min(scaleX, scaleY, 1);

        const x = (cWidth - iWidth * scale) / 2;
        const y = (cHeight - iHeight * scale) / 2;

        setViewState({ scale, x, y });
    }, [imgDimensions]);

    // Ensure players are always in pan mode
    useEffect(() => {
        if (!canEdit) {
            setInteractionMode('pan');
        }
    }, [canEdit]);

    useEffect(() => {
        const img = new Image();
        img.src = map.image_url;
        img.onload = () => {
            setImgDimensions({ width: img.width, height: img.height });
        };
    }, [map.image_url]);

    // Auto-center on highlighted pin when ID changes
    useEffect(() => {
        if (highlightedPinId && imgDimensions.width > 0 && containerRef.current) {
            const pin = pins.find(p => p.id === highlightedPinId);
            if (pin && pin.map_id === map.id) {
                const container = containerRef.current.getBoundingClientRect();
                const targetScale = Math.max(viewState.scale, 1); // Ensure we are zoomed in at least 1x

                const pinXPx = pin.x_coord * imgDimensions.width;
                const pinYPx = pin.y_coord * imgDimensions.height;

                // Center logic: (ContainerCenter) - (PinPos * Scale)
                const newX = (container.width / 2) - (pinXPx * targetScale);
                const newY = (container.height / 2) - (pinYPx * targetScale);

                setViewState({ scale: targetScale, x: newX, y: newY });
            }
        } else if (!highlightedPinId && imgDimensions.width > 0) {
            // Only reset view on initial load, not when highlight is cleared manually
            if (viewState.scale === 1 && viewState.x === 0) resetView();
        }
    }, [highlightedPinId, imgDimensions, pins, map.id]);

    // Initial reset view on image load
    useEffect(() => {
        if (imgDimensions.width > 0 && !highlightedPinId) {
            resetView();
        }
    }, [imgDimensions, resetView]);

    // Zoom Helpers
    const zoomIn = () => {
        setViewState(prev => ({ ...prev, scale: Math.min(prev.scale * 1.2, 5) }));
    };

    const zoomOut = () => {
        setViewState(prev => ({ ...prev, scale: Math.max(prev.scale / 1.2, 0.1) }));
    };

    const handleWheel = (e: React.WheelEvent) => {
        e.preventDefault();
        const { deltaY, clientX, clientY } = e;
        const scaleAmount = -deltaY * 0.001;
        const newScale = Math.min(Math.max(0.1, viewState.scale + scaleAmount), 5);

        const rect = containerRef.current!.getBoundingClientRect();
        const mouseX = clientX - rect.left;
        const mouseY = clientY - rect.top;

        const newX = mouseX - (mouseX - viewState.x) * (newScale / viewState.scale);
        const newY = mouseY - (mouseY - viewState.y) * (newScale / viewState.scale);

        setViewState({ scale: newScale, x: newX, y: newY });
    };

    const handleMouseDown = (e: React.MouseEvent) => {
        // If we are dragging a pin, do not start pan
        if (draggingPinId) return;

        if (interactionMode === 'pan' || e.button === 1 || e.button === 2) {
            setIsPanning(true);
            setPanStart({ x: e.clientX - viewState.x, y: e.clientY - viewState.y });
        }
    };

    const handleMouseUp = (e: React.MouseEvent) => {
        if (draggingPinId && dragPosition && onMovePin) {
            onMovePin(draggingPinId, dragPosition.x, dragPosition.y);
            setDraggingPinId(null);
            setDragPosition(null);
        }
        setIsPanning(false);
    };

    const handleMouseMove = (e: React.MouseEvent) => {
        if (draggingPinId) {
            if (!containerRef.current || imgDimensions.width === 0) return;
            const rect = containerRef.current.getBoundingClientRect();

            // Calculate mouse position relative to the container
            const mouseX = e.clientX - rect.left;
            const mouseY = e.clientY - rect.top;

            // Inverse transform to get image coordinates
            // screen = image * scale + trans
            // image = (screen - trans) / scale
            let imgX = (mouseX - viewState.x) / viewState.scale;
            let imgY = (mouseY - viewState.y) / viewState.scale;

            // Grid Snapping for Drag
            if (showGrid && gridSize > 0) {
                 const col = Math.floor(imgX / gridSize);
                 const row = Math.floor(imgY / gridSize);
                 const centerX = (col * gridSize) + (gridSize / 2);
                 const centerY = (row * gridSize) + (gridSize / 2);
                 imgX = centerX;
                 imgY = centerY;
            }

            // Convert to percentage
            const pctX = imgX / imgDimensions.width;
            const pctY = imgY / imgDimensions.height;

            setDragPosition({ x: pctX, y: pctY });
            return;
        }

        if (!isPanning) return;
        setViewState(prev => ({ ...prev, x: e.clientX - panStart.x, y: e.clientY - panStart.y }));
    };

    const handleMapClick = (e: React.MouseEvent) => {
        if (!canEdit || isPanning || interactionMode !== 'pin' || draggingPinId) return;

        if (e.target !== mapRef.current && e.target !== (mapRef.current?.querySelector('img') as HTMLElement) && e.target !== (mapRef.current?.querySelector('.grid-overlay') as HTMLElement)) return;

        const rect = mapRef.current!.getBoundingClientRect();

        let x = (e.clientX - rect.left) / rect.width;
        let y = (e.clientY - rect.top) / rect.height;

        if (showGrid && gridSize > 0 && imgDimensions.width > 0 && imgDimensions.height > 0) {
            const originalX = x * imgDimensions.width;
            const originalY = y * imgDimensions.height;
            const col = Math.floor(originalX / gridSize);
            const row = Math.floor(originalY / gridSize);
            const centerX = (col * gridSize) + (gridSize / 2);
            const centerY = (row * gridSize) + (gridSize / 2);
            x = centerX / imgDimensions.width;
            y = centerY / imgDimensions.height;
        }

        onAddPin({ x, y });
    };

    // Start dragging a pin
    const handlePinMouseDown = (e: React.MouseEvent, pinId: string, startX: number, startY: number) => {
        if (!canEdit) return;
        e.stopPropagation(); // Prevent panning
        e.preventDefault();
        setDraggingPinId(pinId);
        setDragPosition({ x: startX, y: startY });
    };

    let cursorStyle = 'default';
    if (draggingPinId) {
        cursorStyle = 'grabbing';
    } else if (isPanning) {
        cursorStyle = 'grabbing';
    } else if (interactionMode === 'pan') {
        cursorStyle = 'grab';
    } else if (interactionMode === 'pin' && canEdit) {
        cursorStyle = 'crosshair';
    }

    return (
        <div 
            ref={containerRef}
            className="h-full w-full overflow-hidden bg-stone-950 relative"
            style={{ cursor: cursorStyle }}
            onWheel={handleWheel}
            onMouseDown={handleMouseDown}
            onMouseUp={handleMouseUp}
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseUp}
        >
            <div
                ref={mapRef}
                className="relative origin-top-left"
                style={{
                    transform: `translate(${viewState.x}px, ${viewState.y}px) scale(${viewState.scale})`,
                    width: `${imgDimensions.width}px`,
                    height: `${imgDimensions.height}px`,
                }}
                onClick={handleMapClick}
            >
                <img src={map.image_url} alt={map.name} className="pointer-events-none w-full h-full absolute top-0 left-0" />

                {showGrid && (
                    <div 
                        className="grid-overlay absolute inset-0 pointer-events-none opacity-30"
                        style={{
                            backgroundSize: `${gridSize}px ${gridSize}px`,
                            backgroundImage: `
                                linear-gradient(to right, rgba(255, 255, 255, 0.5) 1px, transparent 1px),
                                linear-gradient(to bottom, rgba(255, 255, 255, 0.5) 1px, transparent 1px)
                            `
                        }}
                    />
                )}

                {/* Pins */}
                {pins.map(pin => {
                    if (pin.map_id !== map.id) return null;
                    const pinType = getPinType(pin.pin_type_id);
                    const isHighlighted = pin.id === highlightedPinId;

                    const isDragging = pin.id === draggingPinId;
                    const displayX = isDragging && dragPosition ? dragPosition.x : pin.x_coord;
                    const displayY = isDragging && dragPosition ? dragPosition.y : pin.y_coord;

                    return (
                        <div
                            key={pin.id}
                            onMouseDown={(e) => handlePinMouseDown(e, pin.id, pin.x_coord, pin.y_coord)}
                            onClick={(e) => { e.stopPropagation(); if(!isDragging) onSelectPin(pin); }}
                            onMouseEnter={() => setHoveredPinId(pin.id)}
                            onMouseLeave={() => setHoveredPinId(null)}
                            className={`absolute transform -translate-x-1/2 -translate-y-1/2 flex items-center justify-center rounded-full transition-shadow focus:outline-none shadow-lg shadow-black/50 ${isHighlighted ? 'ring-4 ring-amber-500 ring-offset-2 ring-offset-black z-50 animate-pulse' : 'hover:brightness-110 focus:ring-2 focus:ring-white hover:z-50'} ${canEdit ? 'cursor-grab active:cursor-grabbing' : 'cursor-pointer'}`}
                            style={{ 
                                left: `${displayX * 100}%`, 
                                top: `${displayY * 100}%`,
                                backgroundColor: pinType?.color || '#3B82F6',
                                width: `${pinSize}px`,
                                height: `${pinSize}px`,
                                fontSize: `${pinSize * 0.6}px`,
                                transform: isHighlighted ? 'translate(-50%, -50%) scale(1.25)' : 'translate(-50%, -50%)',
                                transition: isDragging ? 'none' : 'transform 0.1s ease-out'
                            }}
                            title={pin.title}
                        >
                            <span className="drop-shadow-md leading-none select-none pointer-events-none">
                                {pinType?.emoji || '📍'}
                            </span>
                        </div>
                    );
                })}

                {/* Hover Preview Tooltip */}
                {hoveredPinId && !draggingPinId && (() => {
                    const pin = pins.find(p => p.id === hoveredPinId);
                    if (!pin || pin.map_id !== map.id) return null;
                    const pinType = getPinType(pin.pin_type_id);
                    const charsHere = characters.filter(c => c.current_pin_id === pin.id && ((isDM && !isPlayerView) || c.is_visible));

                    return (
                        <div
                            className="absolute pointer-events-none z-[100] flex flex-col items-center"
                            style={{
                                left: `${pin.x_coord * 100}%`,
                                top: `${pin.y_coord * 100}%`,
                                // Inverse scaling logic:
                                // 1. Center transform origin (bottom center)
                                // 2. Translate up to clear pin (-pinSize/2 - 10px spacing)
                                // 3. Inverse scale (1/viewState.scale) to keep constant visual size
                                transform: `translate(-50%, -100%) translateY(${-pinSize/2 - 12}px) scale(${1 / viewState.scale})`,
                                transformOrigin: 'bottom center',
                            }}
                        >
                            <div className="bg-stone-900/95 backdrop-blur-xl border border-amber-500/30 p-4 rounded-xl shadow-2xl flex flex-col items-center gap-2 min-w-[160px] animate-modal-in">
                                <div className="text-center">
                                    <h3 className="font-medieval text-amber-500 text-xl leading-none whitespace-nowrap drop-shadow-md">{pin.title}</h3>
                                    <span className="text-[10px] uppercase text-stone-500 font-bold tracking-widest mt-1 block">{pinType?.name}</span>
                                </div>

                                {charsHere.length > 0 && (
                                    <div className="flex items-center justify-center -space-x-2 pt-2 pb-1">
                                        {charsHere.slice(0, 5).map(c => (
                                            <div key={c.id} className="w-8 h-8 rounded-full border-2 border-stone-800 bg-stone-900 overflow-hidden relative z-0 shadow-sm">
                                                {c.image_url ? 
                                                    <img src={c.image_url} className="w-full h-full object-cover" alt={c.name} /> : 
                                                    <div className="w-full h-full flex items-center justify-center text-xs text-stone-500 font-bold">{c.name[0]}</div>
                                                }
                                            </div>
                                        ))}
                                        {charsHere.length > 5 && (
                                            <div className="w-8 h-8 rounded-full border-2 border-stone-800 bg-stone-800 flex items-center justify-center text-[10px] text-stone-400 font-bold z-10 shadow-sm">
                                                +{charsHere.length - 5}
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                            {/* Arrow Pointer */}
                            <div className="w-0 h-0 border-l-[8px] border-l-transparent border-r-[8px] border-r-transparent border-t-[8px] border-t-amber-500/30 translate-y-[-1px]" />
                        </div>
                    );
                })()}
            </div>

            {/* Controls */}
             <div className="absolute bottom-6 right-6 flex flex-col gap-4 z-10">
                {canEdit && (
                    <div className="flex flex-col gap-1 p-1 rounded-xl bg-stone-900/80 backdrop-blur-lg border border-stone-700/50 shadow-xl">
                        <button 
                            onClick={() => setInteractionMode('pan')} 
                            className={`p-2 rounded-lg transition-colors ${interactionMode === 'pan' ? 'bg-amber-600 text-white' : 'text-stone-400 hover:text-stone-200 hover:bg-stone-800'}`}
                            title="Pan Mode"
                        >
                            <Icon name="hand" className="w-5 h-5"/>
                        </button>
                        <button 
                            onClick={() => setInteractionMode('pin')} 
                            className={`p-2 rounded-lg transition-colors ${interactionMode === 'pin' ? 'bg-amber-600 text-white' : 'text-stone-400 hover:text-stone-200 hover:bg-stone-800'}`}
                            title="Add Pin Mode"
                        >
                            <Icon name="pin" className="w-5 h-5"/>
                        </button>
                    </div>
                )}

                <div className="flex flex-col gap-1 p-1 rounded-xl bg-stone-900/80 backdrop-blur-lg border border-stone-700/50 shadow-xl">
                    <button onClick={zoomIn} className="p-2 rounded-lg text-stone-300 hover:text-amber-500 hover:bg-stone-800 transition-colors" title="Zoom In">
                        <Icon name="plus" className="w-5 h-5"/>
                    </button>
                    <button onClick={resetView} className="p-2 rounded-lg text-stone-300 hover:text-amber-500 hover:bg-stone-800 transition-colors" title="Center View">
                        <Icon name="center" className="w-5 h-5"/>
                    </button>
                    <button onClick={zoomOut} className="p-2 rounded-lg text-stone-300 hover:text-amber-500 hover:bg-stone-800 transition-colors" title="Zoom Out">
                        <Icon name="minus" className="w-5 h-5"/>
                    </button>
                </div>
             </div>
        </div>
    );
};

