    useEffect(() => {
        if (user) {
            setUsername(user.profile.username);
            setImageUrl(user.profile.image_url || '');
        }
    }, [user]);

    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!user) return;
