import React, { useState, useEffect, createContext, useContext, useCallback } from 'react';
import { useAuth } from '../App';
import { Map as MapType, Pin, PinType, Character } from '../types';
import { supabase } from '../services/supabase';
import Sidebar from './Sidebar';
import MapViewer from './MapViewer';
import PinDetails from './PinDetails';
import Wiki from './Wiki';
import { MapManagerModal, PinEditorModal, PinTypeManagerModal, PlayerManagerModal, CharacterManagerModal, DMToolsModal, UserSettingsModal } from './Modals';
import { Icon } from './Icons';

type AppContextType = {
    maps: MapType[];
    pinTypes: PinType[];
    pins: Pin[];
    characters: Character[];
    isPlayerView: boolean;
    refreshData: (silent?: boolean) => Promise<void>;
    setIsPlayerView: React.Dispatch<React.SetStateAction<boolean>>;
    // Performance: Local Updaters to avoid full refetch
    updateLocalPin: (pin: Pin) => void;
    updateLocalMap: (map: MapType) => void;
    updateLocalCharacter: (char: Character) => void;
    updateLocalPinType: (pt: PinType) => void;
    removeLocalItem: (type: 'map'|'pin'|'character'|'pintype', id: string) => void;
    reorderMaps: (items: {id: string, sort_order: number}[]) => void;
};

const AppContext = createContext<AppContextType | null>(null);
export const useAppContext = () => {
    const context = useContext(AppContext);
    if (!context) throw new Error('useAppContext must be used within an AppContextProvider');
    return context;
};

const Dashboard: React.FC = () => {
    const { user, signOut } = useAuth();
    const [maps, setMaps] = useState<MapType[]>([]);
    const [pinTypes, setPinTypes] = useState<PinType[]>([]);
    const [pins, setPins] = useState<Pin[]>([]);
    const [characters, setCharacters] = useState<Character[]>([]);

    // View State
    const [currentView, setCurrentView] = useState<'map' | 'wiki'>('map');

    // Unified Selection State
    const [selectedMap, setSelectedMap] = useState<MapType | null>(null);
    const [selectedPin, setSelectedPin] = useState<Pin | null>(null);
    const [selectedCharacter, setSelectedCharacter] = useState<Character | null>(null);

    // Highlight State (for locating pins from Wiki)
    const [highlightedPinId, setHighlightedPinId] = useState<string | null>(null);

    const [isPlayerView, setIsPlayerView] = useState(user?.profile.role === 'Player');
    const [loading, setLoading] = useState(true);

    // Modal states
    const [isDMToolsOpen, setDMToolsOpen] = useState(false);
    const [isMapManagerOpen, setMapManagerOpen] = useState(false);
    const [isPinTypeManagerOpen, setPinTypeManagerOpen] = useState(false);
    const [isPlayerManagerOpen, setPlayerManagerOpen] = useState(false);
    const [isCharacterManagerOpen, setCharacterManagerOpen] = useState(false);
    const [isUserSettingsOpen, setUserSettingsOpen] = useState(false);
    const [editingPin, setEditingPin] = useState<Partial<Pin> | null>(null);

    useEffect(() => {
        if (user) {
            setIsPlayerView(user.profile.role === 'Player');
        }
    }, [user?.id]);

    const refreshData = useCallback(async (silent = false) => {
        if (!user) return;
        if (!silent) setLoading(true);

        const isDM = user.profile.role === 'DM';

        // Parallel Fetching for Performance
        const promises = [
            // 1. Maps (Sorted Alphabetically by name)
            isDM 
                ? supabase.from('maps').select('*').order('name', {ascending: true}) 
                : supabase.from('maps').select('*').eq('is_visible', true).order('name', {ascending: true}),
            // 2. Pin Types
            supabase.from('pin_types').select('*').order('name', {ascending: true}),
            // 3. Pins (Sorted Alphabetically by title)
            (isDM && !isPlayerView) 
                ? supabase.from('pins').select('*, pin_types(*)').order('title', {ascending: true}) 
                : supabase.from('pins').select('*, pin_types(*)').eq('is_visible', true).order('title', {ascending: true}),
            // 4. Characters (Sorted Alphabetically by name)
            supabase.from('characters').select('*').order('name', {ascending: true})
        ];

        const [mapsRes, pinTypesRes, pinsRes, charsRes] = await Promise.all(promises);

        if (mapsRes.data) setMaps(mapsRes.data);
        if (pinTypesRes.data) setPinTypes(pinTypesRes.data);
        if (pinsRes.data) setPins(pinsRes.data as Pin[]);
        if (charsRes.data) setCharacters(charsRes.data as Character[]);

        // Errors
        if (mapsRes.error) console.error("Maps error", mapsRes.error);
        if (pinsRes.error) console.error("Pins error", pinsRes.error);

        if (!silent) setLoading(false);
    }, [user, isPlayerView]);

    useEffect(() => {
        refreshData();
    }, [refreshData]);

    // --- Performance: Local Updaters ---
    const updateLocalPin = (pin: Pin) => {
        setPins(prev => {
            const idx = prev.findIndex(p => p.id === pin.id);
            let newPins = [...prev];
            if (idx >= 0) {
                newPins[idx] = pin;
            } else {
                newPins.push(pin);
            }
            // Maintain alphabetical sort
            return newPins.sort((a, b) => a.title.localeCompare(b.title));
        });
        // Also update selected pin if it matches
        if (selectedPin?.id === pin.id) setSelectedPin(pin);
    };

    const updateLocalMap = (map: MapType) => {
        setMaps(prev => {
            const idx = prev.findIndex(m => m.id === map.id);
            let newMaps = [...prev];
            if (idx >= 0) {
                newMaps[idx] = map;
            } else {
                newMaps.push(map);
            }
            // Maintain alphabetical sort
            return newMaps.sort((a, b) => a.name.localeCompare(b.name));
        });
        if (selectedMap?.id === map.id) setSelectedMap(map);
    };

    const updateLocalCharacter = (char: Character) => {
        setCharacters(prev => {
            const idx = prev.findIndex(c => c.id === char.id);
            let newChars = [...prev];
            if (idx >= 0) {
                newChars[idx] = char;
            } else {
                newChars.push(char);
            }
            // Maintain alphabetical sort
            return newChars.sort((a, b) => a.name.localeCompare(b.name));
        });
    };

    const updateLocalPinType = (pt: PinType) => {
        setPinTypes(prev => {
            const idx = prev.findIndex(p => p.id === pt.id);
            if (idx >= 0) {
                const newPt = [...prev];
                newPt[idx] = pt;
                return newPt;
            }
            return [...prev, pt];
        });
    };

    const removeLocalItem = (type: 'map'|'pin'|'character'|'pintype', id: string) => {
        if(type === 'map') setMaps(prev => prev.filter(m => m.id !== id));
        if(type === 'pin') setPins(prev => prev.filter(p => p.id !== id));
        if(type === 'character') setCharacters(prev => prev.filter(c => c.id !== id));
        if(type === 'pintype') setPinTypes(prev => prev.filter(p => p.id !== id));
    };

    const reorderMaps = async (updates: {id: string, sort_order: number}[]) => {
        // Optimistic update
        setMaps(prev => {
            const mapMap = new Map<string, MapType>(prev.map(m => [m.id, m]));
            updates.forEach(u => {
                const m = mapMap.get(u.id);
                if (m) m.sort_order = u.sort_order;
            });
            return Array.from(mapMap.values()).sort((a, b) => a.name.localeCompare(b.name));
        });

        const { error } = await supabase.from('maps').upsert(updates.map(u => ({
            id: u.id,
            sort_order: u.sort_order,
            updated_at: new Date().toISOString()
        })));

        if (error) {
            console.error("Error reordering maps:", error);
        }
    };
    // ------------------------------------

    const handleSelectMap = (map: MapType | null) => {
        setSelectedMap(map);
        setSelectedPin(null);
        setSelectedCharacter(null);
        setHighlightedPinId(null);
    };

    const handleSelectPin = (pin: Pin | null) => {
        setSelectedPin(pin);
        setSelectedCharacter(null);
        // If selecting a pin, we implicitly keep the map selected or select the parent map
        if (pin) {
            const parentMap = maps.find(m => m.id === pin.map_id);
            if(parentMap) setSelectedMap(parentMap);
        }
        setHighlightedPinId(null);
    };

    const handleSelectCharacter = (char: Character | null) => {
        setSelectedCharacter(char);
        setSelectedPin(null);
        setSelectedMap(null);
    };

    const handlePinSave = async (savedPin?: Pin) => {
        setEditingPin(null);
        if (savedPin) {
            updateLocalPin(savedPin);
        } else {
            await refreshData(true);
        }
    };

    const handleMovePin = async (pinId: string, x: number, y: number) => {
        // Optimistic update
        setPins(prev => prev.map(p => p.id === pinId ? { ...p, x_coord: x, y_coord: y } : p));

        const { error } = await supabase.from('pins').update({ x_coord: x, y_coord: y }).eq('id', pinId);
        if (error) {
            console.error("Error moving pin:", error);
            refreshData(true); // Only fetch on error
        }
    };

    // Called when clicking "Open in Wiki" from a character modal
    const handleOpenWikiCharacter = (charId: string) => {
        const char = characters.find(c => c.id === charId);
        if (char) {
            setSelectedCharacter(char);
            setSelectedMap(null);
            setSelectedPin(null);
            setCurrentView('wiki');
        }
    };

    if (loading) {
        return <div className="flex h-screen w-full items-center justify-center bg-stone-950"><Icon name="spinner" className="h-10 w-10 animate-spin text-amber-500" /></div>;
    }

    return (
        <AppContext.Provider value={{ 
            maps, pinTypes, pins, characters, isPlayerView, refreshData, setIsPlayerView,
            updateLocalPin, updateLocalMap, updateLocalCharacter, updateLocalPinType, removeLocalItem, reorderMaps
        }}>
            <div className="flex h-screen w-full flex-col md:flex-row overflow-hidden bg-stone-950 text-stone-200">
                <Sidebar
                    selectedMap={selectedMap}
                    selectedPin={selectedPin}
                    selectedCharacter={selectedCharacter}
                    onSelectMap={handleSelectMap}
                    onSelectPin={handleSelectPin}
                    onSelectCharacter={handleSelectCharacter}
                    currentView={currentView}
                    onViewChange={setCurrentView}
                    onDMToolsOpen={() => setDMToolsOpen(true)}
                    onUserSettingsOpen={() => setUserSettingsOpen(true)}
                />
                <main className="relative flex-1 bg-stone-950 overflow-hidden">
                    {currentView === 'map' ? (
                        <>
                            {selectedMap ? (
                                <MapViewer
                                    map={selectedMap}
                                    onSelectPin={(pin) => {
                                        setSelectedPin(pin);
                                        setHighlightedPinId(null); 
                                    }}
                                    onAddPin={(coords) => {
                                        if (user?.profile.role === 'DM' && !isPlayerView) {
                                            setEditingPin({ x_coord: coords.x, y_coord: coords.y, map_id: selectedMap.id });
                                            setHighlightedPinId(null);
                                        }
                                    }}
                                    onMovePin={handleMovePin}
                                    highlightedPinId={highlightedPinId}
                                />
                            ) : (
                                <div className="flex h-full w-full items-center justify-center text-stone-500">
                                    <div className="text-center">
                                        <Icon name="map" className="mx-auto h-16 w-16 opacity-30 mb-4" />
                                        <p className="text-lg font-medieval">Select a map to begin</p>
                                    </div>
                                </div>
                            )}
                            <PinDetails 
                                pin={selectedPin} 
                                onClose={() => setSelectedPin(null)} 
                                onEdit={(pin) => setEditingPin(pin)}
                                mapId={selectedMap?.id}
                                onOpenWiki={handleOpenWikiCharacter}
                            />
                        </>
                    ) : (
                        <Wiki 
                            selectedMap={selectedMap}
                            selectedPin={selectedPin}
                            selectedCharacter={selectedCharacter}
                            onSelectMap={(map) => {
                                setSelectedMap(map);
                                setCurrentView('map');
                            }}
                            onLocatePin={(pin) => {
                                const map = maps.find(m => m.id === pin.map_id);
                                if(map) {
                                    setSelectedMap(map);
                                    setHighlightedPinId(pin.id); 
                                    setSelectedPin(null); 
                                    setCurrentView('map');
                                }
                            }}
                        />
                    )}

                    {isDMToolsOpen && (
                        <DMToolsModal 
                            isOpen={isDMToolsOpen}
                            onClose={() => setDMToolsOpen(false)}
                            onMapManagerOpen={() => setMapManagerOpen(true)}
                            onCharacterManagerOpen={() => setCharacterManagerOpen(true)}
                            onPinTypeManagerOpen={() => setPinTypeManagerOpen(true)}
                            onPlayerManagerOpen={() => setPlayerManagerOpen(true)}
                            onSignOut={() => signOut()}
                        />
                    )}

                    {isMapManagerOpen && <MapManagerModal isOpen={isMapManagerOpen} onClose={() => setMapManagerOpen(false)} />}
                    {isPinTypeManagerOpen && <PinTypeManagerModal isOpen={isPinTypeManagerOpen} onClose={() => setPinTypeManagerOpen(false)} />}
                    {isPlayerManagerOpen && <PlayerManagerModal isOpen={isPlayerManagerOpen} onClose={() => setPlayerManagerOpen(false)} />}
                    {isCharacterManagerOpen && <CharacterManagerModal isOpen={isCharacterManagerOpen} onClose={() => setCharacterManagerOpen(false)} />}
                    {isUserSettingsOpen && <UserSettingsModal isOpen={isUserSettingsOpen} onClose={() => setUserSettingsOpen(false)} />}
                    {editingPin && (
                        <PinEditorModal 
                            pinData={editingPin} 
                            onClose={() => setEditingPin(null)} 
                            onSave={handlePinSave} 
                        />
                    )}
                </main>
            </div>
        </AppContext.Provider>
    );
};

export default Dashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { useAuth } from '../App';
import { useAppContext } from './Dashboard';
import { Map as MapType, MapTypeEnum, Pin, Character } from '../types';
import { Icon } from './Icons';

interface SidebarProps {
    selectedMap: MapType | null;
    selectedPin: Pin | null;
    selectedCharacter: Character | null;
    onSelectMap: (map: MapType | null) => void;
    onSelectPin: (pin: Pin | null) => void;
    onSelectCharacter: (char: Character | null) => void;
    currentView: 'map' | 'wiki';
    onViewChange: (view: 'map' | 'wiki') => void;
    onDMToolsOpen: () => void;
    onUserSettingsOpen: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
    selectedMap, selectedPin, selectedCharacter, 
    onSelectMap, onSelectPin, onSelectCharacter,
    currentView, onViewChange, onDMToolsOpen, onUserSettingsOpen 
}) => {
    const { user, signOut } = useAuth();
    const { maps, pins, pinTypes, characters, isPlayerView, setIsPlayerView, reorderMaps } = useAppContext();
    const [expandedMapIds, setExpandedMapIds] = useState<Set<string>>(new Set());

    // Wiki State
    const [wikiSearchQuery, setWikiSearchQuery] = useState('');

    // D&D State
    const [draggedMapId, setDraggedMapId] = useState<string | null>(null);
    const [dragOverMapId, setDragOverMapId] = useState<string | null>(null);

    const isDM = user?.profile.role === 'DM';
    const canReorder = isDM && !isPlayerView && currentView === 'map';

    // Filter data based on view mode
    const displayMaps = useMemo(() => {
        const list = (isPlayerView) ? maps.filter(m => m.is_visible) : maps;
        // Standard alphabetical sort
        return list.sort((a, b) => a.name.localeCompare(b.name));
    }, [maps, isPlayerView]);

    const displayCharacters = useMemo(() => {
        const list = (isPlayerView) ? characters.filter(c => c.is_visible) : characters;
        return list.sort((a, b) => a.name.localeCompare(b.name));
    }, [characters, isPlayerView]);

    // Wiki Filter Logic
    const filteredWikiData = useMemo(() => {
        if (currentView !== 'wiki') return { maps: [], characters: [] };

        const lowerQ = wikiSearchQuery.toLowerCase();

        // Filter Characters
        const fChars = displayCharacters.filter(c => 
            !wikiSearchQuery || 
            c.name.toLowerCase().includes(lowerQ) || 
            c.role_details?.race.toLowerCase().includes(lowerQ) ||
            c.role_details?.class.toLowerCase().includes(lowerQ)
        );

        // Filter Maps (Search flat list logic)
        // If Searching, flat list. If not, tree structure (handled by rendering logic).
        const fMaps = displayMaps.map(map => {
            const mapPins = pins.filter(p => p.map_id === map.id);
            const matchingPins = mapPins.filter(pin => 
                pin.title.toLowerCase().includes(lowerQ) || 
                pin.data.description?.toLowerCase().includes(lowerQ)
            ).sort((a, b) => a.title.localeCompare(b.title));

            const matchesMap = map.name.toLowerCase().includes(lowerQ);
            if (!matchesMap && matchingPins.length === 0) return null;

            return { map, pins: matchingPins };
        }).filter(Boolean) as { map: MapType, pins: Pin[] }[];

        return { maps: fMaps, characters: fChars };
    }, [currentView, wikiSearchQuery, displayMaps, displayCharacters, pins]);


    // Auto-expand logic for current selection
    useEffect(() => {
        if (selectedMap) {
            let current = selectedMap;
            const newExpanded = new Set(expandedMapIds);
            let changed = false;

            // Only expand through visible parents
            while (current && current.parent_map_id) {
                if (!newExpanded.has(current.parent_map_id)) {
                    newExpanded.add(current.parent_map_id);
                    changed = true;
                }
                const parent = displayMaps.find(m => m.id === current!.parent_map_id);
                if (!parent || parent.id === current.id) break;
                current = parent;
            }

            if (changed) {
                setExpandedMapIds(newExpanded);
            }
        }
    }, [selectedMap, displayMaps]);

    const toggleExpand = (mapId: string, e: React.MouseEvent) => {
        e.stopPropagation();
        const newSet = new Set(expandedMapIds);
        if (newSet.has(mapId)) newSet.delete(mapId);
        else newSet.add(mapId);
        setExpandedMapIds(newSet);
    };

    // --- D&D Handlers (Map View Only) ---
    const handleDragStart = (e: React.DragEvent, map: MapType) => {
        if (!canReorder) return;
        setDraggedMapId(map.id);
        e.dataTransfer.effectAllowed = 'move';
    };

    const handleDragOver = (e: React.DragEvent, map: MapType) => {
        if (!canReorder || !draggedMapId || draggedMapId === map.id) return;
        const draggedMap = maps.find(m => m.id === draggedMapId);
        if (!draggedMap || draggedMap.parent_map_id !== map.parent_map_id) return;
        e.preventDefault(); 
        setDragOverMapId(map.id);
    };

    const handleDrop = (e: React.DragEvent, targetMap: MapType) => {
        e.preventDefault();
        setDragOverMapId(null);
        if (!draggedMapId || draggedMapId === targetMap.id) return;
        const draggedMap = maps.find(m => m.id === draggedMapId);
        if (!draggedMap || draggedMap.parent_map_id !== targetMap.parent_map_id) return;
        const siblings = maps.filter(m => m.parent_map_id === draggedMap.parent_map_id).sort((a, b) => a.name.localeCompare(b.name));
        const oldIndex = siblings.findIndex(m => m.id === draggedMapId);
        const newIndex = siblings.findIndex(m => m.id === targetMap.id);
        if (oldIndex === -1 || newIndex === -1) return;
        const newSiblings = [...siblings];
        newSiblings.splice(oldIndex, 1);
        newSiblings.splice(newIndex, 0, draggedMap);
        const updates = newSiblings.map((m, index) => ({ id: m.id, sort_order: index }));
        reorderMaps(updates);
        setDraggedMapId(null);
    };

    const getMapIconName = (type?: MapTypeEnum) => {
        switch (type) {
            case 'world': return 'globe';
            case 'city': return 'castle';
            case 'dungeon': return 'skull';
            case 'battlemap': return 'compass';
            default: return 'map';
        }
    };

    // --- Tree Items ---

    const MapModeTreeItem: React.FC<{ map: MapType, level: number, visited?: Set<string> }> = ({ map, level, visited = new Set() }) => {
        if (visited.has(map.id)) return null;
        const newVisited = new Set(visited).add(map.id);

        const children = displayMaps.filter(m => m.parent_map_id === map.id).sort((a, b) => a.name.localeCompare(b.name));
        const hasChildren = children.length > 0;
        const isExpanded = expandedMapIds.has(map.id);
        const isSelected = selectedMap?.id === map.id;
        const iconName = getMapIconName(map.map_type);
        const isDragging = draggedMapId === map.id;
        const isDragOver = dragOverMapId === map.id;

        return (
            <div 
                className={`select-none transition-all duration-200 ${isDragging ? 'opacity-50' : ''}`}
                draggable={canReorder}
                onDragStart={(e) => handleDragStart(e, map)}
                onDragOver={(e) => handleDragOver(e, map)}
                onDrop={(e) => handleDrop(e, map)}
            >
                <div 
                    onClick={() => onSelectMap(map)}
                    className={`flex items-center space-x-2 rounded-xl py-2 pr-3 text-sm font-medium transition-all duration-200 group cursor-pointer relative
                        ${isSelected 
                            ? 'bg-amber-900/30 text-amber-400 border border-amber-500/20 shadow-[0_0_10px_rgba(245,158,11,0.1)]' 
                            : 'text-stone-400 hover:bg-stone-800/50 hover:text-stone-100'
                        }
                        ${isDragOver ? 'ring-2 ring-amber-500 bg-stone-800' : ''}
                    `}
                    style={{ paddingLeft: `${level * 12 + 8}px` }}
                >
                    <div className="flex-shrink-0 flex items-center justify-center w-6 h-6">
                        {hasChildren ? (
                            <button onClick={(e) => toggleExpand(map.id, e)} className="p-1 hover:text-amber-500 transition-colors focus:outline-none">
                                <Icon name={isExpanded ? "chevron-down" : "chevron-right"} className="w-4 h-4 opacity-70" />
                            </button>
                        ) : (
                            <Icon name={iconName} className={`h-4 w-4 opacity-50 ${isSelected ? 'text-amber-500' : ''}`} />
                        )}
                    </div>
                    <span className="truncate flex-1">{map.name}</span>
                    {!isPlayerView && !map.is_visible && <Icon name="eye-off" className="w-3 h-3 text-stone-600" title="Hidden" />}
                </div>
                {hasChildren && isExpanded && (
                    <div className="mt-1 space-y-1">
                        {children.map(child => (
                            <MapModeTreeItem key={child.id} map={child} level={level + 1} visited={newVisited} />
                        ))}
                    </div>
                )}
            </div>
        );
    };

    const WikiModeTreeItem: React.FC<{ map: MapType, level: number }> = ({ map, level }) => {
        const children = displayMaps.filter(m => m.parent_map_id === map.id).sort((a, b) => a.name.localeCompare(b.name));
        const hasChildren = children.length > 0;
        const isExpanded = expandedMapIds.has(map.id);
        const isMapSelected = selectedMap?.id === map.id;

        // Requirement: Only show pins if this specific map is selected
        const mapPins = isMapSelected 
            ? pins.filter(p => p.map_id === map.id).sort((a, b) => a.title.localeCompare(b.title))
            : [];

        return (
            <div className="select-none">
                <div 
                    onClick={() => onSelectMap(map)}
                    className={`flex items-center space-x-2 px-3 py-2 text-sm transition-all cursor-pointer rounded-lg mb-0.5
                        ${isMapSelected 
                            ? 'bg-amber-900/20 text-amber-400 border border-amber-500/30' 
                            : 'text-stone-300 hover:bg-stone-800/50 hover:text-white border border-transparent'
                        }
                    `}
                    style={{ paddingLeft: `${level * 12 + 12}px` }}
                >
                    <div className="flex-shrink-0 w-4 h-4 flex items-center justify-center">
                        {hasChildren ? (
                            <button onClick={(e) => toggleExpand(map.id, e)} className="hover:text-amber-500 focus:outline-none">
                                <Icon name={isExpanded ? "chevron-down" : "chevron-right"} className="w-3 h-3 opacity-70" />
                            </button>
                        ) : <Icon name="map" className="w-3 h-3 opacity-50"/>}
                    </div>
                    <span className="truncate flex-1">{map.name}</span>
                </div>

                {isMapSelected && mapPins.length > 0 && (
                    <div className="mb-1">
                        {mapPins.map(pin => (
                            <button 
                                key={pin.id}
                                onClick={() => onSelectPin(pin)}
                                className={`w-full flex items-center gap-2 py-1 text-xs text-left rounded-md transition-colors pl-2
                                    ${selectedPin?.id === pin.id ? 'bg-stone-800 text-white font-bold' : 'text-stone-500 hover:text-stone-300 hover:bg-stone-800/20'}
                                `}
                                style={{ paddingLeft: `${level * 12 + 32}px` }}
                            >
                                <span className="w-1.5 h-1.5 rounded-full flex-shrink-0" style={{ backgroundColor: pinTypes.find(t => t.id === pin.pin_type_id)?.color }}></span>
                                <span className="truncate">{pin.title}</span>
                            </button>
                        ))}
                    </div>
                )}

                {hasChildren && isExpanded && (
                    <div>
                        {children.map(child => (
                            <WikiModeTreeItem key={child.id} map={child} level={level + 1} />
                        ))}
                    </div>
                )}
            </div>
        );
    };

    // --- Render ---

    const rootMaps = displayMaps.filter(m => !m.parent_map_id || !displayMaps.find(p => p.id === m.parent_map_id)).sort((a, b) => a.name.localeCompare(b.name));

    return (
        <aside className="flex h-full w-full flex-col md:w-80 bg-stone-900/80 backdrop-blur-xl border-r border-stone-700/50 p-4 shadow-2xl z-20">
            <div className="flex items-center justify-between mb-4">
                <h1 className="text-2xl font-medieval font-bold text-amber-500 drop-shadow-sm">D&D World Map</h1>
            </div>

            {/* Mode Switcher */}
            <div className="grid grid-cols-2 gap-2 bg-stone-800/50 p-1 rounded-xl mb-4">
                <button 
                    onClick={() => onViewChange('map')}
                    className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-bold transition-all ${currentView === 'map' ? 'bg-amber-600 text-white shadow-lg' : 'text-stone-400 hover:text-stone-200'}`}
                >
                    <Icon name="map" className="w-4 h-4" />
                    Map
                </button>
                <button 
                    onClick={() => onViewChange('wiki')}
                    className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-bold transition-all ${currentView === 'wiki' ? 'bg-amber-600 text-white shadow-lg' : 'text-stone-400 hover:text-stone-200'}`}
                >
                    <Icon name="book" className="w-4 h-4" />
                    Wiki
                </button>
            </div>

            <button 
                onClick={onUserSettingsOpen}
                className="w-full flex items-center space-x-3 rounded-xl bg-stone-800/40 hover:bg-stone-800/80 border border-stone-700/30 hover:border-amber-500/50 p-3 shadow-inner transition-all group text-left"
                title="Profile Settings"
            >
                <div className="flex h-10 w-10 items-center justify-center rounded-full bg-stone-900 border border-stone-700 overflow-hidden text-amber-500 group-hover:border-amber-500/50 transition-colors">
                    {user?.profile.image_url ? (
                        <img src={user.profile.image_url} alt="Profile" className="w-full h-full object-cover" />
                    ) : (
                        <span className="font-medieval font-bold text-lg">{user?.profile.username.charAt(0).toUpperCase()}</span>
                    )}
                </div>
                <div className="min-w-0 flex-1">
                    <p className="font-semibold truncate text-stone-200 group-hover:text-amber-500 transition-colors">{user?.profile.username}</p>
                    <p className="text-xs text-stone-500 uppercase tracking-wider font-bold">{user?.profile.role}</p>
                </div>
                <Icon name="settings" className="w-4 h-4 text-stone-600 group-hover:text-amber-500 opacity-0 group-hover:opacity-100 transition-all" />
            </button>

            {/* Wiki Search Bar */}
            {currentView === 'wiki' && (
                <div className="mt-4 relative">
                    <Icon name="search" className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-stone-500" />
                    <input 
                        type="text" 
                        placeholder="Search wiki..." 
                        value={wikiSearchQuery}
                        onChange={(e) => setWikiSearchQuery(e.target.value)}
                        className="w-full bg-stone-900/50 border border-stone-700 rounded-lg pl-9 pr-3 py-2 text-sm text-stone-200 focus:border-amber-500 focus:outline-none placeholder-stone-600"
                    />
                </div>
            )}

            <nav className="mt-8 flex-1 overflow-y-auto custom-scrollbar pr-2">

                {currentView === 'map' ? (
                    // --- MAP VIEW SIDEBAR CONTENT ---
                    <>
                        <div className="flex items-center justify-between mb-2 px-2">
                            <h2 className="text-xs font-medieval tracking-widest text-stone-500 uppercase">Maps</h2>
                            {canReorder && <span className="text-[10px] text-stone-600 italic">Drag to reorder</span>}
                        </div>
                        {rootMaps.length > 0 ? (
                            <div className="space-y-1">
                                {rootMaps.map((map) => (
                                    <MapModeTreeItem key={map.id} map={map} level={0} />
                                ))}
                            </div>
                        ) : (
                            <p className="px-3 text-sm text-stone-600 italic">No maps found.</p>
                        )}
                    </>
                ) : (
                    // --- WIKI VIEW SIDEBAR CONTENT ---
                    <>
                         {wikiSearchQuery && (
                             <div className="mb-4">
                                <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2">Search Results</h3>
                                {filteredWikiData.characters.length === 0 && filteredWikiData.maps.length === 0 && (
                                     <p className="px-3 text-sm text-stone-600 italic">No results found.</p>
                                )}
                             </div>
                         )}

                         {/* Characters Section (Show if query matches or no query) */}
                         {(filteredWikiData.characters.length > 0) && (
                            <div className="mb-6">
                                <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2">Characters</h3>
                                {filteredWikiData.characters.map(char => (
                                    <button
                                        key={char.id}
                                        onClick={() => onSelectCharacter(char)}
                                        className={`w-full flex items-center gap-3 px-3 py-2 rounded-xl text-left transition-colors mb-1 ${selectedCharacter?.id === char.id ? 'bg-amber-900/20 text-amber-400 border border-amber-500/30' : 'hover:bg-stone-800/50 text-stone-300 border border-transparent'}`}
                                    >
                                        <div className="w-8 h-8 rounded-full bg-stone-800 overflow-hidden flex-shrink-0">
                                            {char.image_url ? <img src={char.image_url} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center"><Icon name="user" className="w-4 h-4"/></div>}
                                        </div>
                                        <div className="min-w-0">
                                            <div className="font-medium truncate text-sm">{char.name}</div>
                                            <div className="text-[10px] text-stone-500 truncate">{char.role_details?.race} {char.role_details?.class}</div>
                                        </div>
                                    </button>
                                ))}
                            </div>
                         )}

                         {/* Locations Section */}
                         {/* If Search Active: Flat List. If Not: Tree */}
                         {(wikiSearchQuery ? filteredWikiData.maps.length > 0 : rootMaps.length > 0) && (
                             <div>
                                <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2">Locations</h3>
                                {wikiSearchQuery ? (
                                    <div>
                                        {filteredWikiData.maps.map(({ map, pins }) => (
                                            <div key={map.id} className="mb-2">
                                                <button 
                                                    onClick={() => onSelectMap(map)}
                                                    className={`w-full flex items-center gap-3 px-3 py-2 text-left transition-colors rounded-lg ${selectedMap?.id === map.id ? 'text-amber-400 bg-amber-900/20' : 'text-stone-300 hover:bg-stone-800/50'}`}
                                                >
                                                    <Icon name="map" className="w-4 h-4 opacity-70"/>
                                                    <span className="font-medium truncate">{map.name}</span>
                                                </button>
                                                <div className="pl-4 border-l border-stone-800 ml-4 mt-1 space-y-0.5">
                                                    {pins.map(pin => (
                                                        <button 
                                                            key={pin.id}
                                                            onClick={() => onSelectPin(pin)}
                                                            className="w-full flex items-center gap-2 px-3 py-1.5 text-left text-xs rounded-lg text-stone-400 hover:text-stone-200"
                                                        >
                                                            <span className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: pinTypes.find(t => t.id === pin.pin_type_id)?.color }}></span>
                                                            <span className="truncate">{pin.title}</span>
                                                        </button>
                                                    ))}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                ) : (
                                    <div>
                                        {rootMaps.map(map => (
                                            <WikiModeTreeItem key={map.id} map={map} level={0} />
                                        ))}
                                    </div>
                                )}
                             </div>
                         )}
                    </>
                )}
            </nav>

            {user?.profile.role === 'DM' && (
                <div className="mt-4 pt-4 border-t border-stone-800">
                    <h2 className="text-[10px] font-medieval tracking-widest text-stone-600 uppercase px-2 mb-2">DM Controls</h2>
                    <div className="flex gap-2">
                        <button 
                            onClick={onDMToolsOpen}
                            className="flex-1 flex items-center justify-center p-3 rounded-xl bg-stone-800/40 hover:bg-stone-700 border border-stone-700/50 hover:border-amber-500/50 text-stone-400 hover:text-amber-500 transition-all group"
                            title="DM Tools & Settings"
                        >
                            <Icon name="view_apps" className="w-7 h-7" />
                        </button>

                        <button 
                            onClick={() => setIsPlayerView(!isPlayerView)}
                            className={`flex-1 flex items-center justify-center p-3 rounded-xl border transition-all ${
                                isPlayerView 
                                ? 'bg-amber-900/20 border-amber-600/50 text-amber-500 shadow-[inset_0_0_10px_rgba(245,158,11,0.1)]' 
                                : 'bg-stone-800/40 border-stone-700/50 text-stone-400 hover:bg-stone-700 hover:text-stone-200'
                            }`}
                            title={isPlayerView ? "Switch to DM View" : "Switch to Player View"}
                        >
                            <Icon name={isPlayerView ? "visibility" : "visibility_off"} className="w-7 h-7" />
                        </button>
                    </div>
                </div>
            )}

            {user?.profile.role === 'Player' && (
                <div className="mt-4 border-t border-stone-800 pt-4">
                    <button onClick={signOut} className="flex w-full items-center space-x-3 rounded-xl px-3 py-2 text-left text-sm font-medium text-stone-500 hover:bg-red-900/20 hover:text-red-400 transition-colors">
                        <Icon name="logout" className="h-5 w-5" />
                        <span>Sign Out</span>
                    </button>
                </div>
            )}
        </aside>
    );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import { useAppContext } from './Dashboard';
import { useAuth } from '../App';
import { Map as MapType, Pin, Character, Comment } from '../types';
import { Icon } from './Icons';
import { supabase } from '../services/supabase';

interface WikiProps {
    selectedMap: MapType | null;
    selectedPin: Pin | null;
    selectedCharacter: Character | null;
    onSelectMap: (map: MapType) => void;
    onLocatePin: (pin: Pin) => void;
}

const Wiki: React.FC<WikiProps> = ({ selectedMap, selectedPin, selectedCharacter, onSelectMap, onLocatePin }) => {
    const { maps, pins, pinTypes, characters, isPlayerView } = useAppContext();
    const { user } = useAuth();
    const isDM = user?.profile.role === 'DM';
    const canSeeSecrets = isDM && !isPlayerView;

    // Comments State for Characters
    const [characterComments, setCharacterComments] = useState<Comment[]>([]);
    const [newComment, setNewComment] = useState('');
    const [isPrivateComment, setIsPrivateComment] = useState(false);

    // Fetch character comments when a character is selected
    useEffect(() => {
        if (selectedCharacter) {
            const fetchComments = async () => {
                const { data, error } = await supabase
                    .from('comments')
                    .select('*, users(username)')
                    .eq('character_id', selectedCharacter.id)
                    .order('created_at', { ascending: true });
                if (data) setCharacterComments(data as any);
            };
            fetchComments();
        } else {
            setCharacterComments([]);
        }
    }, [selectedCharacter?.id]);

    const handleAddCharacterComment = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newComment.trim() || !selectedCharacter || !user) return;

        const { data, error } = await supabase
            .from('comments')
            .insert({
                character_id: selectedCharacter.id,
                user_id: user.id,
                text: newComment,
                is_private: isPrivateComment
            })
            .select('*, users(username)')
            .single();

        if (data) setCharacterComments([...characterComments, data as any]);
        setNewComment('');
        setIsPrivateComment(false);
    };

    // Get pins for the currently active map (to display in content area)
    const activeMapPins = selectedMap 
        ? pins.filter(p => p.map_id === selectedMap.id).sort((a,b) => a.title.localeCompare(b.title))
        : [];

    const getCharacterName = (id: string) => characters.find(c => c.id === id)?.name || "Unknown";

    const CharacterPresenceList: React.FC<{ chars: Character[], title: string }> = ({ chars, title }) => {
        if (chars.length === 0) return null;
        return (
            <div className="mb-8 bg-stone-900/40 p-5 rounded-2xl border border-stone-700/50">
                <h3 className="text-xs font-bold uppercase text-stone-500 mb-4 flex items-center gap-2">
                    <Icon name="user" className="w-4 h-4"/> {title}
                </h3>
                <div className="flex flex-wrap gap-4">
                    {chars.map(c => (
                        <div key={c.id} className="flex items-center gap-3 bg-stone-800 p-2 rounded-xl border border-stone-700 min-w-[150px]">
                            <div className="w-10 h-10 rounded-full bg-stone-900 overflow-hidden ring-2 ring-stone-700">
                                {c.image_url ? <img src={c.image_url} className="w-full h-full object-cover" alt={c.name}/> : <div className="w-full h-full flex items-center justify-center text-stone-600"><Icon name="user" className="w-5 h-5"/></div>}
                            </div>
                            <div className="text-left">
                                <p className="text-sm font-bold text-stone-200 truncate max-w-[120px]">{c.name}</p>
                                <p className="text-[10px] text-stone-500 uppercase tracking-wider">{c.role_details?.race}</p>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        );
    };

    // --- Renderers ---

    const renderPinContent = (pin: Pin) => {
        const type = pinTypes.find(t => t.id === pin.pin_type_id);
        const charactersAtPin = characters.filter(c => c.current_pin_id === pin.id && ((isDM && !isPlayerView) || c.is_visible));
        const pinMap = maps.find(m => m.id === pin.map_id);

        return (
            <div className="space-y-8 animate-modal-in max-w-4xl mx-auto pb-20">
                {/* Header */}
                <div className="border-b border-stone-700/50 pb-6">
                    <div className="flex items-center gap-4 mb-4">
                        <div className="flex items-center justify-center w-16 h-16 rounded-2xl shadow-xl text-3xl ring-2 ring-stone-700/50" style={{ backgroundColor: type?.color || '#555' }}>
                            {type?.emoji || '📍'}
                        </div>
                        <div>
                            <h1 className="text-4xl font-medieval font-bold text-stone-100">{pin.title}</h1>
                            <div className="flex items-center gap-2 mt-1">
                                <span className="bg-stone-800/50 px-2 py-0.5 rounded text-xs text-stone-400 border border-stone-700 uppercase tracking-wider">{type?.name || 'Unknown'}</span>
                                {pinMap && <span className="text-stone-500 text-sm flex items-center gap-1"><Icon name="map" className="w-3 h-3"/> {pinMap.name}</span>}
                            </div>
                        </div>
                        <button 
                            onClick={() => onLocatePin(pin)}
                            className="ml-auto flex items-center gap-2 bg-stone-800 hover:bg-amber-700/20 hover:text-amber-500 border border-stone-700 px-4 py-2 rounded-xl transition-all text-sm font-medium group"
                        >
                            <Icon name="compass" className="w-4 h-4 group-hover:rotate-45 transition-transform"/>
                            Locate on Map
                        </button>
                    </div>

                    {pin.data.description && (
                         <div className="prose prose-invert max-w-none text-stone-300 text-lg leading-relaxed bg-stone-900/20 p-6 rounded-2xl border border-stone-800/50">
                            {pin.data.description}
                         </div>
                    )}
                </div>

                <CharacterPresenceList chars={charactersAtPin} title="Present Here" />

                {/* Sections */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {pin.data.sections?.map((section, idx) => {
                        if (section.type === 'secret' && !canSeeSecrets) return null;

                        const isFullWidth = section.type === 'text' || section.type === 'list' || section.type === 'inventory';

                        return (
                            <div key={idx} className={`bg-stone-800/20 rounded-2xl border border-stone-700/30 overflow-hidden ${isFullWidth ? 'md:col-span-2' : ''} ${section.type === 'secret' ? 'border-red-900/50 bg-red-950/10' : ''}`}>
                                <div className={`px-5 py-3 border-b border-stone-700/30 flex items-center justify-between ${section.type === 'secret' ? 'bg-red-950/30' : 'bg-stone-800/40'}`}>
                                    <h3 className={`font-medieval text-xl ${section.type === 'secret' ? 'text-red-400' : 'text-stone-200'}`}>
                                        {section.type === 'secret' && <Icon name="lock" className="w-4 h-4 inline mr-2" />}
                                        {section.title}
                                    </h3>
                                    <span className="text-xs uppercase text-stone-600 font-bold tracking-wider">{section.type}</span>
                                </div>

                                <div className="p-5">
                                    {section.type === 'text' && <p className="whitespace-pre-wrap text-stone-300 leading-relaxed">{section.content}</p>}
                                    {section.type === 'secret' && <p className="whitespace-pre-wrap text-red-200/80 leading-relaxed font-mono text-sm">{section.content}</p>}
                                    {/* ... other sections ... */}
                                    {section.type === 'list' && (
                                        <>
                                            {section.content && <p className="mb-4 text-stone-400 italic">{section.content}</p>}
                                            <ul className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                                                {section.list_items?.map((item, i) => (
                                                    <li key={i} className="flex items-start gap-2 text-stone-300 bg-stone-900/30 p-2 rounded">
                                                        <span className="text-amber-500 mt-1">✦</span>
                                                        <span>{item}</span>
                                                    </li>
                                                ))}
                                            </ul>
                                        </>
                                    )}
                                    {section.type === 'statblock' && (
                                        <>
                                            {section.content && <p className="mb-4 text-stone-400 italic">{section.content}</p>}
                                            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                                                {section.stats?.map((stat, i) => (
                                                    <div key={i} className="bg-stone-900/50 p-3 rounded-lg border border-stone-800 flex flex-col items-center text-center">
                                                        <span className="text-xs uppercase tracking-wider text-amber-600 font-bold mb-1">{stat.label}</span>
                                                        <span className="font-medieval text-xl text-stone-200">{stat.value}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </>
                                    )}
                                    {section.type === 'image' && section.image_url && (
                                        <img src={section.image_url} alt={section.title} className="w-full h-auto rounded-lg shadow-lg" />
                                    )}
                                    {section.type === 'inventory' && (
                                        <div className="overflow-x-auto">
                                            <table className="w-full text-left text-sm">
                                                <thead className="text-stone-500 uppercase text-xs border-b border-stone-700/50">
                                                    <tr>
                                                        <th className="pb-2 pl-2">Item</th>
                                                        <th className="pb-2">Rarity</th>
                                                        <th className="pb-2 text-right pr-2">Qty</th>
                                                    </tr>
                                                </thead>
                                                <tbody className="divide-y divide-stone-700/30">
                                                    {section.items?.map((item, i) => (
                                                        <tr key={i} className="hover:bg-stone-700/20">
                                                            <td className="py-2 pl-2">
                                                                <span className={`font-medium ${item.is_magic ? 'text-amber-400' : 'text-stone-300'}`}>{item.name}</span>
                                                            </td>
                                                            <td className="py-2 text-purple-400 text-xs">{item.rarity || '-'}</td>
                                                            <td className="py-2 text-right pr-2 font-mono text-stone-400">{item.count}</td>
                                                        </tr>
                                                    ))}
                                                </tbody>
                                            </table>
                                        </div>
                                    )}
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>
        );
    };

    const renderCharacterContent = (char: Character) => {
        return (
            <div className="space-y-8 animate-modal-in max-w-4xl mx-auto pb-20">
                <div className="flex flex-col md:flex-row gap-8 border-b border-stone-700/50 pb-8">
                    <div className="w-48 h-48 rounded-3xl overflow-hidden ring-4 ring-stone-800 shadow-2xl bg-stone-900 flex-shrink-0 mx-auto md:mx-0">
                        {char.image_url ? (
                            <img src={char.image_url} alt={char.name} className="w-full h-full object-cover" />
                        ) : (
                            <div className="w-full h-full flex items-center justify-center text-stone-600 bg-stone-800"><Icon name="user" className="w-16 h-16"/></div>
                        )}
                    </div>
                    <div className="flex-1 text-center md:text-left">
                        <h1 className="text-5xl font-medieval font-bold text-amber-500 mb-2">{char.name}</h1>
                        <div className="flex flex-wrap items-center justify-center md:justify-start gap-3 text-sm text-stone-400 mb-4">
                            <span className="bg-stone-800 px-3 py-1 rounded-full border border-stone-700">{char.role_details?.race}</span>

                            {!isPlayerView && (
                                <>
                                    <span className="bg-stone-800 px-3 py-1 rounded-full border border-stone-700">{char.role_details?.class}</span>
                                    <span className="bg-amber-900/30 px-3 py-1 rounded-full border border-amber-800/30 text-amber-500">Lvl {char.role_details?.level}</span>
                                    <span className="text-stone-500">{char.role_details?.alignment}</span>
                                </>
                            )}
                        </div>
                        {char.current_pin_id && (() => {
                            const currentPin = pins.find(p => p.id === char.current_pin_id);
                            const currentMap = currentPin ? maps.find(m => m.id === currentPin.map_id) : null;

                            if (!currentPin || !currentMap) return null;

                            return (
                                <button 
                                    onClick={() => onLocatePin(currentPin)}
                                    className="inline-flex items-center gap-2 text-amber-500 bg-amber-900/10 hover:bg-amber-900/20 px-3 py-1.5 rounded-lg border border-amber-900/30 hover:border-amber-500/50 mb-4 transition-all cursor-pointer group"
                                >
                                    <Icon name="map" className="w-4 h-4 group-hover:scale-110 transition-transform"/>
                                    <span>Currently in <span className="font-bold border-b border-transparent group-hover:border-amber-500 transition-colors">{currentMap.name}</span></span>
                                    <Icon name="chevron-right" className="w-3 h-3 opacity-0 group-hover:opacity-100 transition-opacity -ml-1" />
                                </button>
                            );
                        })()}

                        {!isPlayerView && char.sheet_url && (
                            <div className="flex gap-2 justify-center md:justify-start">
                                <a href={char.sheet_url} target="_blank" rel="noopener noreferrer" className="flex items-center gap-2 bg-stone-800 hover:bg-stone-700 px-4 py-2 rounded-xl text-sm font-medium transition-colors">
                                    <Icon name="external" className="w-4 h-4"/> Character Sheet
                                </a>
                            </div>
                        )}
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                    <div className="md:col-span-2 space-y-6">
                        <div className="bg-stone-800/20 p-6 rounded-2xl border border-stone-700/30">
                            <h3 className="font-medieval text-xl text-stone-300 mb-4 border-b border-stone-700/50 pb-2">Biography</h3>
                            <p className="whitespace-pre-wrap text-stone-400 leading-relaxed">{char.backstory || "No biography available."}</p>
                        </div>

                        {/* Comments Section */}
                        <div className="bg-stone-800/20 p-6 rounded-2xl border border-stone-700/30">
                            <h3 className="font-medieval text-xl text-stone-300 mb-4 border-b border-stone-700/50 pb-2">Journal & Notes</h3>
                            <div className="space-y-4 mb-6">
                                {characterComments.length === 0 && <p className="text-stone-600 italic text-sm">No notes yet.</p>}
                                {characterComments.map(comment => (
                                    <div key={comment.id} className="bg-stone-900/40 p-4 rounded-xl border border-stone-800">
                                        <div className="flex justify-between items-start mb-2">
                                            <span className="font-bold text-amber-600 text-sm">{comment.users.username}</span>
                                            <span className="text-xs text-stone-600">{new Date(comment.created_at).toLocaleDateString()}</span>
                                        </div>
                                        <p className="text-stone-300 text-sm">{comment.text}</p>
                                    </div>
                                ))}
                            </div>
                            <form onSubmit={handleAddCharacterComment} className="space-y-3">
                                <textarea 
                                    value={newComment} 
                                    onChange={e => setNewComment(e.target.value)} 
                                    placeholder="Add a note..." 
                                    className="w-full bg-stone-900/50 border border-stone-700/50 rounded-xl p-3 text-sm text-stone-200 focus:outline-none focus:border-amber-500"
                                    rows={2}
                                />
                                <div className="flex justify-end">
                                    <button type="submit" className="bg-amber-600 hover:bg-amber-500 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-lg transition-all">Post Note</button>
                                </div>
                            </form>
                        </div>
                    </div>

                    <div className="space-y-6">
                        {canSeeSecrets && char.gm_notes && (
                            <div className="bg-red-950/20 p-5 rounded-2xl border border-red-900/40">
                                <h3 className="font-medieval text-lg text-red-400 mb-2 flex items-center gap-2"><Icon name="lock" className="w-4 h-4"/> GM Notes</h3>
                                <p className="text-sm text-red-300/70 whitespace-pre-wrap">{char.gm_notes}</p>
                            </div>
                        )}

                        <div className="bg-stone-800/20 p-5 rounded-2xl border border-stone-700/30">
                            <h3 className="font-medieval text-lg text-stone-300 mb-3">Relationships</h3>
                            {char.relationships.length > 0 ? (
                                <ul className="space-y-3">
                                    {char.relationships.map((rel, i) => (
                                        <li key={i} className="text-sm">
                                            <div className="font-bold text-stone-200">{getCharacterName(rel.targetId)}</div>
                                            <div className="text-amber-600 text-xs uppercase tracking-wide font-bold">{rel.type}</div>
                                            {rel.notes && <div className="text-stone-500 italic mt-1">"{rel.notes}"</div>}
                                        </li>
                                    ))}
                                </ul>
                            ) : <p className="text-stone-600 italic text-sm">No known connections.</p>}
                        </div>
                    </div>
                </div>
            </div>
        );
    };

    // --- Main Layout ---
    return (
        <div className="flex h-full w-full bg-stone-950 text-stone-200">
            {/* Right Pane: Content */}
            <div className="flex-1 overflow-y-auto custom-scrollbar bg-[url('https://www.transparenttextures.com/patterns/dark-matter.png')]">
                <div className="p-8 md:p-12 min-h-full">
                    {selectedPin ? (
                        renderPinContent(selectedPin)
                    ) : selectedCharacter ? (
                        renderCharacterContent(selectedCharacter)
                    ) : selectedMap ? (
                        <div className="max-w-4xl mx-auto space-y-8 animate-modal-in">
                            <div className="flex items-center gap-4 border-b border-stone-700/50 pb-6">
                                <div className="w-20 h-20 rounded-2xl overflow-hidden ring-2 ring-stone-700 shadow-2xl bg-stone-900">
                                    <img src={selectedMap.image_url} className="w-full h-full object-cover" alt={selectedMap.name} />
                                </div>
                                <div>
                                    <h1 className="text-5xl font-medieval font-bold text-amber-500">{selectedMap.name}</h1>
                                    <p className="text-stone-500 mt-1 uppercase tracking-widest text-sm font-bold flex items-center gap-2">
                                        <span className="capitalize">{selectedMap.map_type?.replace('_', ' ') || 'Region'} Map</span>
                                    </p>
                                </div>
                                <button 
                                    onClick={() => onSelectMap(selectedMap)}
                                    className="ml-auto flex items-center gap-2 bg-amber-600 hover:bg-amber-500 text-white px-6 py-3 rounded-xl shadow-lg transition-all font-bold"
                                >
                                    <Icon name="map" className="w-5 h-5"/>
                                    Open Map
                                </button>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                                {activeMapPins.map(pin => {
                                    const type = pinTypes.find(t => t.id === pin.pin_type_id);
                                    const charsAtPin = characters.filter(c => c.current_pin_id === pin.id && ((isDM && !isPlayerView) || c.is_visible));

                                    return (
                                        <button 
                                            key={pin.id}
                                            onClick={() => onLocatePin(pin)} // Since we are in wiki, locate simply selects the pin to view
                                            className="bg-stone-800/40 hover:bg-stone-800 border border-stone-700/30 hover:border-amber-500/50 p-4 rounded-xl text-left transition-all group flex flex-col gap-3"
                                        >
                                            <div className="flex items-center gap-3">
                                                <div className="w-10 h-10 rounded-full flex items-center justify-center text-lg shadow-lg ring-1 ring-white/10" style={{ backgroundColor: type?.color }}>
                                                    {type?.emoji}
                                                </div>
                                                <div className="min-w-0">
                                                    <h3 className="font-bold text-stone-200 truncate group-hover:text-amber-400">{pin.title}</h3>
                                                    <p className="text-xs text-stone-500">{type?.name}</p>
                                                </div>
                                            </div>
                                            {pin.data.description && (
                                                <p className="text-sm text-stone-500 line-clamp-2">{pin.data.description}</p>
                                            )}

                                            {/* Character Portraits Preview */}
                                            {charsAtPin.length > 0 && (
                                                <div className="mt-3 pt-3 border-t border-stone-700/30 flex items-center gap-2">
                                                    <div className="flex -space-x-2">
                                                        {charsAtPin.slice(0, 5).map(c => (
                                                            <div key={c.id} className="w-6 h-6 rounded-full ring-2 ring-stone-800 bg-stone-900 overflow-hidden relative z-0 hover:z-10 transition-all" title={c.name}>
                                                                {c.image_url ? (
                                                                    <img src={c.image_url} className="w-full h-full object-cover" alt={c.name} />
                                                                ) : (
                                                                    <div className="w-full h-full flex items-center justify-center text-stone-500"><Icon name="user" className="w-3 h-3"/></div>
                                                                )}
                                                            </div>
                                                        ))}
                                                        {charsAtPin.length > 5 && (
                                                            <div className="w-6 h-6 rounded-full ring-2 ring-stone-800 bg-stone-800 flex items-center justify-center text-[10px] text-stone-400 font-bold z-0">
                                                                +{charsAtPin.length - 5}
                                                            </div>
                                                        )}
                                                    </div>
                                                    <span className="text-[10px] text-stone-500 font-bold uppercase tracking-wider">
                                                        {charsAtPin.length} Present
                                                    </span>
                                                </div>
                                            )}
                                        </button>
                                    );
                                })}
                                {activeMapPins.length === 0 && <p className="col-span-full text-stone-600 italic text-center py-10">No pins on this map yet.</p>}
                            </div>
                        </div>
                    ) : (
                        <div className="h-full flex flex-col items-center justify-center text-stone-600 space-y-6 opacity-50">
                            <Icon name="book" className="w-24 h-24"/>
                            <div className="text-center">
                                <h2 className="text-3xl font-medieval text-stone-400">The Archives</h2>
                                <p className="mt-2">Select a location or character from the sidebar to begin reading.</p>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
};

export default Wiki;

import React, { useState, useEffect, createContext, useContext, useCallback } from 'react';
import { useAuth } from '../App';
import { Map as MapType, Pin, PinType, Character } from '../types';
import { supabase } from '../services/supabase';
import Sidebar from './Sidebar';
import MapViewer from './MapViewer';
import PinDetails from './PinDetails';
import Wiki from './Wiki';
import { MapManagerModal, PinEditorModal, PinTypeManagerModal, PlayerManagerModal, CharacterManagerModal, DMToolsModal, UserSettingsModal } from './Modals';
import { Icon } from './Icons';

type AppContextType = {
    maps: MapType[];
    pinTypes: PinType[];
    pins: Pin[];
    characters: Character[];
    isPlayerView: boolean;
    refreshData: (silent?: boolean) => Promise<void>;
    setIsPlayerView: React.Dispatch<React.SetStateAction<boolean>>;
    // Performance: Local Updaters to avoid full refetch
    updateLocalPin: (pin: Pin) => void;
    updateLocalMap: (map: MapType) => void;
    updateLocalCharacter: (char: Character) => void;
    updateLocalPinType: (pt: PinType) => void;
    removeLocalItem: (type: 'map'|'pin'|'character'|'pintype', id: string) => void;
};

const AppContext = createContext<AppContextType | null>(null);
export const useAppContext = () => {
    const context = useContext(AppContext);
    if (!context) throw new Error('useAppContext must be used within an AppContextProvider');
    return context;
};

const Dashboard: React.FC = () => {
    const { user, signOut } = useAuth();
    const [maps, setMaps] = useState<MapType[]>([]);
    const [pinTypes, setPinTypes] = useState<PinType[]>([]);
    const [pins, setPins] = useState<Pin[]>([]);
    const [characters, setCharacters] = useState<Character[]>([]);

    // View State
    const [currentView, setCurrentView] = useState<'map' | 'wiki'>('map');

    // Unified Selection State
    const [selectedMap, setSelectedMap] = useState<MapType | null>(null);
    const [selectedPin, setSelectedPin] = useState<Pin | null>(null);
    const [selectedCharacter, setSelectedCharacter] = useState<Character | null>(null);

    // Highlight State (for locating pins from Wiki)
    const [highlightedPinId, setHighlightedPinId] = useState<string | null>(null);

    const [isPlayerView, setIsPlayerView] = useState(user?.profile.role === 'Player');
    const [loading, setLoading] = useState(true);

    // Modal states
    const [isDMToolsOpen, setDMToolsOpen] = useState(false);
    const [isMapManagerOpen, setMapManagerOpen] = useState(false);
    const [isPinTypeManagerOpen, setPinTypeManagerOpen] = useState(false);
    const [isPlayerManagerOpen, setPlayerManagerOpen] = useState(false);
    const [isCharacterManagerOpen, setCharacterManagerOpen] = useState(false);
    const [isUserSettingsOpen, setUserSettingsOpen] = useState(false);
    const [editingPin, setEditingPin] = useState<Partial<Pin> | null>(null);

    useEffect(() => {
        if (user) {
            setIsPlayerView(user.profile.role === 'Player');
        }
    }, [user?.id]);

    const refreshData = useCallback(async (silent = false) => {
        if (!user) return;
        if (!silent) setLoading(true);

        const isDM = user.profile.role === 'DM';

        // Parallel Fetching for Performance
        const promises = [
            // 1. Maps (Sorted Alphabetically by name)
            isDM 
                ? supabase.from('maps').select('*').order('name', {ascending: true}) 
                : supabase.from('maps').select('*').eq('is_visible', true).order('name', {ascending: true}),
            // 2. Pin Types
            supabase.from('pin_types').select('*').order('name', {ascending: true}),
            // 3. Pins (Sorted Alphabetically by title)
            (isDM && !isPlayerView) 
                ? supabase.from('pins').select('*, pin_types(*)').order('title', {ascending: true}) 
                : supabase.from('pins').select('*, pin_types(*)').eq('is_visible', true).order('title', {ascending: true}),
            // 4. Characters (Sorted Alphabetically by name)
            supabase.from('characters').select('*').order('name', {ascending: true})
        ];

        const [mapsRes, pinTypesRes, pinsRes, charsRes] = await Promise.all(promises);

        if (mapsRes.data) setMaps(mapsRes.data);
        if (pinTypesRes.data) setPinTypes(pinTypesRes.data);
        if (pinsRes.data) setPins(pinsRes.data as Pin[]);
        if (charsRes.data) setCharacters(charsRes.data as Character[]);

        // Errors
        if (mapsRes.error) console.error("Maps error", mapsRes.error);
        if (pinsRes.error) console.error("Pins error", pinsRes.error);

        if (!silent) setLoading(false);
    }, [user, isPlayerView]);

    useEffect(() => {
        refreshData();
    }, [refreshData]);

    // --- Performance: Local Updaters ---
    const updateLocalPin = (pin: Pin) => {
        setPins(prev => {
            const idx = prev.findIndex(p => p.id === pin.id);
            let newPins = [...prev];
            if (idx >= 0) {
                newPins[idx] = pin;
            } else {
                newPins.push(pin);
            }
            // Maintain alphabetical sort
            return newPins.sort((a, b) => a.title.localeCompare(b.title));
        });
        // Also update selected pin if it matches
        if (selectedPin?.id === pin.id) setSelectedPin(pin);
    };

    const updateLocalMap = (map: MapType) => {
        setMaps(prev => {
            const idx = prev.findIndex(m => m.id === map.id);
            let newMaps = [...prev];
            if (idx >= 0) {
                newMaps[idx] = map;
            } else {
                newMaps.push(map);
            }
            // Maintain alphabetical sort
            return newMaps.sort((a, b) => a.name.localeCompare(b.name));
        });
        if (selectedMap?.id === map.id) setSelectedMap(map);
    };

    const updateLocalCharacter = (char: Character) => {
        setCharacters(prev => {
            const idx = prev.findIndex(c => c.id === char.id);
            let newChars = [...prev];
            if (idx >= 0) {
                newChars[idx] = char;
            } else {
                newChars.push(char);
            }
            // Maintain alphabetical sort
            return newChars.sort((a, b) => a.name.localeCompare(b.name));
        });
    };

    const updateLocalPinType = (pt: PinType) => {
        setPinTypes(prev => {
            const idx = prev.findIndex(p => p.id === pt.id);
            if (idx >= 0) {
                const newPt = [...prev];
                newPt[idx] = pt;
                return newPt;
            }
            return [...prev, pt];
        });
    };

    const removeLocalItem = (type: 'map'|'pin'|'character'|'pintype', id: string) => {
        if(type === 'map') setMaps(prev => prev.filter(m => m.id !== id));
        if(type === 'pin') setPins(prev => prev.filter(p => p.id !== id));
        if(type === 'character') setCharacters(prev => prev.filter(c => c.id !== id));
        if(type === 'pintype') setPinTypes(prev => prev.filter(p => p.id !== id));
    };

    // ------------------------------------

    const handleSelectMap = (map: MapType | null) => {
        setSelectedMap(map);
        setSelectedPin(null);
        setSelectedCharacter(null);
        setHighlightedPinId(null);
    };

    const handleSelectPin = (pin: Pin | null) => {
        setSelectedPin(pin);
        setSelectedCharacter(null);
        // If selecting a pin, we implicitly keep the map selected or select the parent map
        if (pin) {
            const parentMap = maps.find(m => m.id === pin.map_id);
            if(parentMap) setSelectedMap(parentMap);
        }
        setHighlightedPinId(null);
    };

    const handleSelectCharacter = (char: Character | null) => {
        setSelectedCharacter(char);
        setSelectedPin(null);
        setSelectedMap(null);
    };

    const handlePinSave = async (savedPin?: Pin) => {
        setEditingPin(null);
        if (savedPin) {
            updateLocalPin(savedPin);
        } else {
            await refreshData(true);
        }
    };

    const handleMovePin = async (pinId: string, x: number, y: number) => {
        // Optimistic update
        setPins(prev => prev.map(p => p.id === pinId ? { ...p, x_coord: x, y_coord: y } : p));

        const { error } = await supabase.from('pins').update({ x_coord: x, y_coord: y }).eq('id', pinId);
        if (error) {
            console.error("Error moving pin:", error);
            refreshData(true); // Only fetch on error
        }
    };

    // Called when clicking "Open in Wiki" from a character modal
    const handleOpenWikiCharacter = (charId: string) => {
        const char = characters.find(c => c.id === charId);
        if (char) {
            setSelectedCharacter(char);
            setSelectedMap(null);
            setSelectedPin(null);
            setCurrentView('wiki');
        }
    };

    if (loading) {
        return <div className="flex h-screen w-full items-center justify-center bg-stone-950"><Icon name="spinner" className="h-10 w-10 animate-spin text-amber-500" /></div>;
    }

    return (
        <AppContext.Provider value={{ 
            maps, pinTypes, pins, characters, isPlayerView, refreshData, setIsPlayerView,
            updateLocalPin, updateLocalMap, updateLocalCharacter, updateLocalPinType, removeLocalItem
        }}>
            <div className="flex h-screen w-full flex-col md:flex-row overflow-hidden bg-stone-950 text-stone-200">
                <Sidebar
                    selectedMap={selectedMap}
                    selectedPin={selectedPin}
                    selectedCharacter={selectedCharacter}
                    onSelectMap={handleSelectMap}
                    onSelectPin={handleSelectPin}
                    onSelectCharacter={handleSelectCharacter}
                    currentView={currentView}
                    onViewChange={setCurrentView}
                    onDMToolsOpen={() => setDMToolsOpen(true)}
                    onUserSettingsOpen={() => setUserSettingsOpen(true)}
                />
                <main className="relative flex-1 bg-stone-950 overflow-hidden">
                    {currentView === 'map' ? (
                        <>
                            {selectedMap ? (
                                <MapViewer
                                    map={selectedMap}
                                    onSelectPin={(pin) => {
                                        setSelectedPin(pin);
                                        setHighlightedPinId(null); 
                                    }}
                                    onAddPin={(coords) => {
                                        if (user?.profile.role === 'DM' && !isPlayerView) {
                                            setEditingPin({ x_coord: coords.x, y_coord: coords.y, map_id: selectedMap.id });
                                            setHighlightedPinId(null);
                                        }
                                    }}
                                    onMovePin={handleMovePin}
                                    highlightedPinId={highlightedPinId}
                                />
                            ) : (
                                <div className="flex h-full w-full items-center justify-center text-stone-500">
                                    <div className="text-center">
                                        <Icon name="map" className="mx-auto h-16 w-16 opacity-30 mb-4" />
                                        <p className="text-lg font-medieval">Select a map to begin</p>
                                    </div>
                                </div>
                            )}
                            <PinDetails 
                                pin={selectedPin} 
                                onClose={() => setSelectedPin(null)} 
                                onEdit={(pin) => setEditingPin(pin)}
                                mapId={selectedMap?.id}
                                onOpenWiki={handleOpenWikiCharacter}
                            />
                        </>
                    ) : (
                        <Wiki 
                            selectedMap={selectedMap}
                            selectedPin={selectedPin}
                            selectedCharacter={selectedCharacter}
                            onSelectMap={(map) => {
                                setSelectedMap(map);
                                setCurrentView('map');
                            }}
                            onLocatePin={(pin) => {
                                const map = maps.find(m => m.id === pin.map_id);
                                if(map) {
                                    setSelectedMap(map);
                                    setHighlightedPinId(pin.id); 
                                    setSelectedPin(null); 
                                    setCurrentView('map');
                                }
                            }}
                        />
                    )}

                    {isDMToolsOpen && (
                        <DMToolsModal 
                            isOpen={isDMToolsOpen}
                            onClose={() => setDMToolsOpen(false)}
                            onMapManagerOpen={() => setMapManagerOpen(true)}
                            onCharacterManagerOpen={() => setCharacterManagerOpen(true)}
                            onPinTypeManagerOpen={() => setPinTypeManagerOpen(true)}
                            onPlayerManagerOpen={() => setPlayerManagerOpen(true)}
                            onSignOut={() => signOut()}
                        />
                    )}

                    {isMapManagerOpen && <MapManagerModal isOpen={isMapManagerOpen} onClose={() => setMapManagerOpen(false)} />}
                    {isPinTypeManagerOpen && <PinTypeManagerModal isOpen={isPinTypeManagerOpen} onClose={() => setPinTypeManagerOpen(false)} />}
                    {isPlayerManagerOpen && <PlayerManagerModal isOpen={isPlayerManagerOpen} onClose={() => setPlayerManagerOpen(false)} />}
                    {isCharacterManagerOpen && <CharacterManagerModal isOpen={isCharacterManagerOpen} onClose={() => setCharacterManagerOpen(false)} />}
                    {isUserSettingsOpen && <UserSettingsModal isOpen={isUserSettingsOpen} onClose={() => setUserSettingsOpen(false)} />}
                    {editingPin && (
                        <PinEditorModal 
                            pinData={editingPin} 
                            onClose={() => setEditingPin(null)} 
                            onSave={handlePinSave} 
                        />
                    )}
                </main>
            </div>
        </AppContext.Provider>
    );
};

export default Dashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { useAuth } from '../App';
import { useAppContext } from './Dashboard';
import { Map as MapType, MapTypeEnum, Pin, Character } from '../types';
import { Icon } from './Icons';

interface SidebarProps {
    selectedMap: MapType | null;
    selectedPin: Pin | null;
    selectedCharacter: Character | null;
    onSelectMap: (map: MapType | null) => void;
    onSelectPin: (pin: Pin | null) => void;
    onSelectCharacter: (char: Character | null) => void;
    currentView: 'map' | 'wiki';
    onViewChange: (view: 'map' | 'wiki') => void;
    onDMToolsOpen: () => void;
    onUserSettingsOpen: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
    selectedMap, selectedPin, selectedCharacter, 
    onSelectMap, onSelectPin, onSelectCharacter,
    currentView, onViewChange, onDMToolsOpen, onUserSettingsOpen 
}) => {
    const { user, signOut } = useAuth();
    const { maps, pins, pinTypes, characters, isPlayerView, setIsPlayerView } = useAppContext();
    const [expandedMapIds, setExpandedMapIds] = useState<Set<string>>(new Set());

    // Wiki State
    const [wikiSearchQuery, setWikiSearchQuery] = useState('');

    // Filter data based on view mode
    const displayMaps = useMemo(() => {
        const list = (isPlayerView) ? maps.filter(m => m.is_visible) : maps;
        // Standard alphabetical sort
        return list.sort((a, b) => a.name.localeCompare(b.name));
    }, [maps, isPlayerView]);

    const displayCharacters = useMemo(() => {
        const list = (isPlayerView) ? characters.filter(c => c.is_visible) : characters;
        return list.sort((a, b) => a.name.localeCompare(b.name));
    }, [characters, isPlayerView]);

    // Wiki Filter Logic
    const filteredWikiData = useMemo(() => {
        if (currentView !== 'wiki') return { maps: [], characters: [] };

        const lowerQ = wikiSearchQuery.toLowerCase();

        // Filter Characters
        const fChars = displayCharacters.filter(c => 
            !wikiSearchQuery || 
            c.name.toLowerCase().includes(lowerQ) || 
            c.role_details?.race.toLowerCase().includes(lowerQ) ||
            c.role_details?.class.toLowerCase().includes(lowerQ)
        );

        // Filter Maps (Search flat list logic)
        // If Searching, flat list. If not, tree structure (handled by rendering logic).
        const fMaps = displayMaps.map(map => {
            const mapPins = pins.filter(p => p.map_id === map.id);
            const matchingPins = mapPins.filter(pin => 
                pin.title.toLowerCase().includes(lowerQ) || 
                pin.data.description?.toLowerCase().includes(lowerQ)
            ).sort((a, b) => a.title.localeCompare(b.title));

            const matchesMap = map.name.toLowerCase().includes(lowerQ);
            if (!matchesMap && matchingPins.length === 0) return null;

            return { map, pins: matchingPins };
        }).filter(Boolean) as { map: MapType, pins: Pin[] }[];

        return { maps: fMaps, characters: fChars };
    }, [currentView, wikiSearchQuery, displayMaps, displayCharacters, pins]);


    // Auto-expand logic for current selection
    useEffect(() => {
        if (selectedMap) {
            let current = selectedMap;
            const newExpanded = new Set(expandedMapIds);
            let changed = false;

            // Only expand through visible parents
            while (current && current.parent_map_id) {
                if (!newExpanded.has(current.parent_map_id)) {
                    newExpanded.add(current.parent_map_id);
                    changed = true;
                }
                const parent = displayMaps.find(m => m.id === current!.parent_map_id);
                if (!parent || parent.id === current.id) break;
                current = parent;
            }

            if (changed) {
                setExpandedMapIds(newExpanded);
            }
        }
    }, [selectedMap, displayMaps]);

    const toggleExpand = (mapId: string, e: React.MouseEvent) => {
        e.stopPropagation();
        const newSet = new Set(expandedMapIds);
        if (newSet.has(mapId)) newSet.delete(mapId);
        else newSet.add(mapId);
        setExpandedMapIds(newSet);
    };

    const getMapIconName = (type?: MapTypeEnum) => {
        switch (type) {
            case 'world': return 'globe';
            case 'city': return 'castle';
            case 'dungeon': return 'skull';
            case 'battlemap': return 'compass';
            default: return 'map';
        }
    };

    // --- Tree Items ---

    const MapModeTreeItem: React.FC<{ map: MapType, level: number, visited?: Set<string> }> = ({ map, level, visited = new Set() }) => {
        if (visited.has(map.id)) return null;
        const newVisited = new Set(visited).add(map.id);

        const children = displayMaps.filter(m => m.parent_map_id === map.id).sort((a, b) => a.name.localeCompare(b.name));
        const hasChildren = children.length > 0;
        const isExpanded = expandedMapIds.has(map.id);
        const isSelected = selectedMap?.id === map.id;
        const iconName = getMapIconName(map.map_type);

        return (
            <div className="select-none transition-all duration-200">
                <div 
                    onClick={() => onSelectMap(map)}
                    className={`flex items-center space-x-2 rounded-xl py-2 pr-3 text-sm font-medium transition-all duration-200 group cursor-pointer relative
                        ${isSelected 
                            ? 'bg-amber-900/30 text-amber-400 border border-amber-500/20 shadow-[0_0_10px_rgba(245,158,11,0.1)]' 
                            : 'text-stone-400 hover:bg-stone-800/50 hover:text-stone-100'
                        }
                    `}
                    style={{ paddingLeft: `${level * 12 + 8}px` }}
                >
                    <div className="flex-shrink-0 flex items-center justify-center w-6 h-6">
                        {hasChildren ? (
                            <button onClick={(e) => toggleExpand(map.id, e)} className="p-1 hover:text-amber-500 transition-colors focus:outline-none">
                                <Icon name={isExpanded ? "chevron-down" : "chevron-right"} className="w-4 h-4 opacity-70" />
                            </button>
                        ) : (
                            <Icon name={iconName} className={`h-4 w-4 opacity-50 ${isSelected ? 'text-amber-500' : ''}`} />
                        )}
                    </div>
                    <span className="truncate flex-1">{map.name}</span>
                    {!isPlayerView && !map.is_visible && <Icon name="eye-off" className="w-3 h-3 text-stone-600" title="Hidden" />}
                </div>
                {hasChildren && isExpanded && (
                    <div className="mt-1 space-y-1">
                        {children.map(child => (
                            <MapModeTreeItem key={child.id} map={child} level={level + 1} visited={newVisited} />
                        ))}
                    </div>
                )}
            </div>
        );
    };

    const WikiModeTreeItem: React.FC<{ map: MapType, level: number }> = ({ map, level }) => {
        const children = displayMaps.filter(m => m.parent_map_id === map.id).sort((a, b) => a.name.localeCompare(b.name));
        const hasChildren = children.length > 0;
        const isExpanded = expandedMapIds.has(map.id);
        const isMapSelected = selectedMap?.id === map.id;
        const iconName = getMapIconName(map.map_type); // Unified icon logic

        // Requirement: Only show pins if this specific map is selected
        const mapPins = isMapSelected 
            ? pins.filter(p => p.map_id === map.id).sort((a, b) => a.title.localeCompare(b.title))
            : [];

        return (
            <div className="select-none transition-all duration-200">
                <div 
                    onClick={() => onSelectMap(map)}
                    // MATCHED STYLING FROM MAP MODE
                    className={`flex items-center space-x-2 rounded-xl py-2 pr-3 text-sm font-medium transition-all duration-200 group cursor-pointer relative
                        ${isMapSelected 
                            ? 'bg-amber-900/30 text-amber-400 border border-amber-500/20 shadow-[0_0_10px_rgba(245,158,11,0.1)]' 
                            : 'text-stone-400 hover:bg-stone-800/50 hover:text-stone-100'
                        }
                    `}
                    style={{ paddingLeft: `${level * 12 + 8}px` }}
                >
                    <div className="flex-shrink-0 flex items-center justify-center w-6 h-6">
                        {hasChildren ? (
                            <button onClick={(e) => toggleExpand(map.id, e)} className="p-1 hover:text-amber-500 transition-colors focus:outline-none">
                                <Icon name={isExpanded ? "chevron-down" : "chevron-right"} className="w-4 h-4 opacity-70" />
                            </button>
                        ) : (
                             // MATCHED ICON SIZE AND OPACITY
                             <Icon name={iconName} className={`h-4 w-4 opacity-50 ${isMapSelected ? 'text-amber-500' : ''}`} />
                        )}
                    </div>
                    <span className="truncate flex-1">{map.name}</span>
                </div>

                {isMapSelected && mapPins.length > 0 && (
                    <div className="mb-1 mt-1 space-y-0.5">
                        {mapPins.map(pin => (
                            <button 
                                key={pin.id}
                                onClick={() => onSelectPin(pin)}
                                className={`w-full flex items-center gap-2 py-1.5 text-xs text-left rounded-lg transition-colors pl-2
                                    ${selectedPin?.id === pin.id ? 'bg-stone-800 text-amber-500 font-bold' : 'text-stone-500 hover:text-stone-300 hover:bg-stone-800/30'}
                                `}
                                style={{ paddingLeft: `${level * 12 + 36}px` }}
                            >
                                <span className="w-1.5 h-1.5 rounded-full flex-shrink-0" style={{ backgroundColor: pinTypes.find(t => t.id === pin.pin_type_id)?.color }}></span>
                                <span className="truncate">{pin.title}</span>
                            </button>
                        ))}
                    </div>
                )}

                {hasChildren && isExpanded && (
                    <div className="mt-1 space-y-1">
                        {children.map(child => (
                            <WikiModeTreeItem key={child.id} map={child} level={level + 1} />
                        ))}
                    </div>
                )}
            </div>
        );
    };

    // --- Render ---

    const rootMaps = displayMaps.filter(m => !m.parent_map_id || !displayMaps.find(p => p.id === m.parent_map_id)).sort((a, b) => a.name.localeCompare(b.name));

    return (
        <aside className="flex h-full w-full flex-col md:w-80 bg-stone-900/80 backdrop-blur-xl border-r border-stone-700/50 p-4 shadow-2xl z-20">
            <div className="flex items-center justify-between mb-4">
                <h1 className="text-2xl font-medieval font-bold text-amber-500 drop-shadow-sm">D&D World Map</h1>
            </div>

            {/* Mode Switcher */}
            <div className="grid grid-cols-2 gap-2 bg-stone-800/50 p-1 rounded-xl mb-4">
                <button 
                    onClick={() => onViewChange('map')}
                    className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-bold transition-all ${currentView === 'map' ? 'bg-amber-600 text-white shadow-lg' : 'text-stone-400 hover:text-stone-200'}`}
                >
                    <Icon name="map" className="w-4 h-4" />
                    Map
                </button>
                <button 
                    onClick={() => onViewChange('wiki')}
                    className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-bold transition-all ${currentView === 'wiki' ? 'bg-amber-600 text-white shadow-lg' : 'text-stone-400 hover:text-stone-200'}`}
                >
                    <Icon name="book" className="w-4 h-4" />
                    Wiki
                </button>
            </div>

            <button 
                onClick={onUserSettingsOpen}
                className="w-full flex items-center space-x-3 rounded-xl bg-stone-800/40 hover:bg-stone-800/80 border border-stone-700/30 hover:border-amber-500/50 p-3 shadow-inner transition-all group text-left"
                title="Profile Settings"
            >
                <div className="flex h-10 w-10 items-center justify-center rounded-full bg-stone-900 border border-stone-700 overflow-hidden text-amber-500 group-hover:border-amber-500/50 transition-colors">
                    {user?.profile.image_url ? (
                        <img src={user.profile.image_url} alt="Profile" className="w-full h-full object-cover" />
                    ) : (
                        <span className="font-medieval font-bold text-lg">{user?.profile.username.charAt(0).toUpperCase()}</span>
                    )}
                </div>
                <div className="min-w-0 flex-1">
                    <p className="font-semibold truncate text-stone-200 group-hover:text-amber-500 transition-colors">{user?.profile.username}</p>
                    <p className="text-xs text-stone-500 uppercase tracking-wider font-bold">{user?.profile.role}</p>
                </div>
                <Icon name="settings" className="w-4 h-4 text-stone-600 group-hover:text-amber-500 opacity-0 group-hover:opacity-100 transition-all" />
            </button>

            {/* Wiki Search Bar */}
            {currentView === 'wiki' && (
                <div className="mt-4 relative">
                    <Icon name="search" className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-stone-500" />
                    <input 
                        type="text" 
                        placeholder="Search wiki..." 
                        value={wikiSearchQuery}
                        onChange={(e) => setWikiSearchQuery(e.target.value)}
                        className="w-full bg-stone-900/50 border border-stone-700 rounded-lg pl-9 pr-3 py-2 text-sm text-stone-200 focus:border-amber-500 focus:outline-none placeholder-stone-600"
                    />
                </div>
            )}

            <nav className="mt-8 flex-1 overflow-y-auto custom-scrollbar pr-2">

                {currentView === 'map' ? (
                    // --- MAP VIEW SIDEBAR CONTENT ---
                    <>
                        <div className="flex items-center justify-between mb-2 px-2">
                            <h2 className="text-xs font-medieval tracking-widest text-stone-500 uppercase">Maps</h2>
                        </div>
                        {rootMaps.length > 0 ? (
                            <div className="space-y-1">
                                {rootMaps.map((map) => (
                                    <MapModeTreeItem key={map.id} map={map} level={0} />
                                ))}
                            </div>
                        ) : (
                            <p className="px-3 text-sm text-stone-600 italic">No maps found.</p>
                        )}
                    </>
                ) : (
                    // --- WIKI VIEW SIDEBAR CONTENT ---
                    <>
                         {wikiSearchQuery && (
                             <div className="mb-4">
                                <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2">Search Results</h3>
                                {filteredWikiData.characters.length === 0 && filteredWikiData.maps.length === 0 && (
                                     <p className="px-3 text-sm text-stone-600 italic">No results found.</p>
                                )}
                             </div>
                         )}

                         {/* Characters Section (Show if query matches or no query) */}
                         {(filteredWikiData.characters.length > 0) && (
                            <div className="mb-6">
                                <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2">Characters</h3>
                                {filteredWikiData.characters.map(char => (
                                    <button
                                        key={char.id}
                                        onClick={() => onSelectCharacter(char)}
                                        className={`w-full flex items-center gap-3 px-3 py-2 rounded-xl text-left transition-colors mb-1 ${selectedCharacter?.id === char.id ? 'bg-amber-900/20 text-amber-400 border border-amber-500/30' : 'hover:bg-stone-800/50 text-stone-300 border border-transparent'}`}
                                    >
                                        <div className="w-8 h-8 rounded-full bg-stone-800 overflow-hidden flex-shrink-0">
                                            {char.image_url ? <img src={char.image_url} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center"><Icon name="user" className="w-4 h-4"/></div>}
                                        </div>
                                        <div className="min-w-0">
                                            <div className="font-medium truncate text-sm">{char.name}</div>
                                            <div className="text-[10px] text-stone-500 truncate">{char.role_details?.race} {char.role_details?.class}</div>
                                        </div>
                                    </button>
                                ))}
                            </div>
                         )}

                         {/* Locations Section */}
                         {/* If Search Active: Flat List. If Not: Tree */}
                         {(wikiSearchQuery ? filteredWikiData.maps.length > 0 : rootMaps.length > 0) && (
                             <div>
                                <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2">Locations</h3>
                                {wikiSearchQuery ? (
                                    <div>
                                        {filteredWikiData.maps.map(({ map, pins }) => (
                                            <div key={map.id} className="mb-2">
                                                <button 
                                                    onClick={() => onSelectMap(map)}
                                                    className={`w-full flex items-center gap-3 px-3 py-2 text-left transition-colors rounded-lg ${selectedMap?.id === map.id ? 'text-amber-400 bg-amber-900/20' : 'text-stone-300 hover:bg-stone-800/50'}`}
                                                >
                                                    <Icon name="map" className="w-4 h-4 opacity-70"/>
                                                    <span className="font-medium truncate">{map.name}</span>
                                                </button>
                                                <div className="pl-4 border-l border-stone-800 ml-4 mt-1 space-y-0.5">
                                                    {pins.map(pin => (
                                                        <button 
                                                            key={pin.id}
                                                            onClick={() => onSelectPin(pin)}
                                                            className="w-full flex items-center gap-2 px-3 py-1.5 text-left text-xs rounded-lg text-stone-400 hover:text-stone-200"
                                                        >
                                                            <span className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: pinTypes.find(t => t.id === pin.pin_type_id)?.color }}></span>
                                                            <span className="truncate">{pin.title}</span>
                                                        </button>
                                                    ))}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                ) : (
                                    <div>
                                        {rootMaps.map(map => (
                                            <WikiModeTreeItem key={map.id} map={map} level={0} />
                                        ))}
                                    </div>
                                )}
                             </div>
                         )}
                    </>
                )}
            </nav>

            {user?.profile.role === 'DM' && (
                <div className="mt-4 pt-4 border-t border-stone-800">
                    <h2 className="text-[10px] font-medieval tracking-widest text-stone-600 uppercase px-2 mb-2">DM Controls</h2>
                    <div className="flex gap-2">
                        <button 
                            onClick={onDMToolsOpen}
                            className="flex-1 flex items-center justify-center p-3 rounded-xl bg-stone-800/40 hover:bg-stone-700 border border-stone-700/50 hover:border-amber-500/50 text-stone-400 hover:text-amber-500 transition-all group"
                            title="DM Tools & Settings"
                        >
                            <Icon name="view_apps" className="w-7 h-7" />
                        </button>

                        <button 
                            onClick={() => setIsPlayerView(!isPlayerView)}
                            className={`flex-1 flex items-center justify-center p-3 rounded-xl border transition-all ${
                                isPlayerView 
                                ? 'bg-amber-900/20 border-amber-600/50 text-amber-500 shadow-[inset_0_0_10px_rgba(245,158,11,0.1)]' 
                                : 'bg-stone-800/40 border-stone-700/50 text-stone-400 hover:bg-stone-700 hover:text-stone-200'
                            }`}
                            title={isPlayerView ? "Switch to DM View" : "Switch to Player View"}
                        >
                            <Icon name={isPlayerView ? "visibility" : "visibility_off"} className="w-7 h-7" />
                        </button>
                    </div>
                </div>
            )}

            {user?.profile.role === 'Player' && (
                <div className="mt-4 border-t border-stone-800 pt-4">
                    <button onClick={signOut} className="flex w-full items-center space-x-3 rounded-xl px-3 py-2 text-left text-sm font-medium text-stone-500 hover:bg-red-900/20 hover:text-red-400 transition-colors">
                        <Icon name="logout" className="h-5 w-5" />
                        <span>Sign Out</span>
                    </button>
                </div>
            )}
        </aside>
    );
};

export default Sidebar;

import React, { useState } from 'react';
import { supabase } from '../services/supabase';
import { Icon } from './Icons';

interface AuthScreenProps {
  authError: string | null;
  onAuthAttempt: () => void;
}

const AuthScreen: React.FC<AuthScreenProps> = ({ authError, onAuthAttempt }) => {
  const [username, setUsername] = useState('');
  const [internalError, setInternalError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const displayError = authError || internalError;

  const handleLogin = async () => {
    onAuthAttempt();
    setInternalError(null);
    setLoading(true);

    const trimmedUsername = username.trim();
    if (!trimmedUsername) {
        setInternalError("Username is required.");
        setLoading(false);
        return;
    }
    const lowerCaseUsername = trimmedUsername.toLowerCase();

    // Replicate the deterministic password generation
    const dummyEmail = `${lowerCaseUsername}@dnd-map-login.local`;
    const dummyPassword = `DUMMY_PASSWORD_FOR_${lowerCaseUsername}`;

    const { error } = await supabase.auth.signInWithPassword({
      email: dummyEmail,
      password: dummyPassword,
    });

    if (error) {
      if (error.message === 'Invalid login credentials') {
         setInternalError("User not found or incorrect credentials. Please contact your DM to create an account.");
      } else {
         setInternalError(error.message);
      }
    }

    setLoading(false);
  };

  const handleKeyPress = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && username) {
      handleLogin();
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-stone-950">
      <div className="w-full max-w-md bg-stone-900/60 backdrop-blur-2xl border border-stone-700/50 shadow-2xl rounded-3xl p-8 animate-modal-in">
        <div className="text-center mb-8 flex flex-col items-center">
          <img 
            src="https://nielskrikke.com/wp-content/uploads/2025/12/maps-app-icon.png" 
            alt="World Atlas Logo" 
            className="w-20 h-20 mb-4 rounded-2xl shadow-lg border-2 border-amber-600/30"
          />
          <h1 className="text-4xl font-medieval font-bold mb-2 text-amber-500 drop-shadow-md">
            World Atlas
          </h1>
          <p className="text-stone-400">
            Enter your username to log in
          </p>
        </div>

        {displayError && (
          <div className="mb-6 p-4 bg-red-900/30 border border-red-800/50 rounded-xl">
            <p className="text-red-300 text-sm">{displayError}</p>
          </div>
        )}

        <div className="space-y-4 mb-6">
          <div>
            <label className="block text-sm font-medium mb-2 text-stone-300">
              Username
            </label>
            <div className="relative group">
              <Icon name="user" className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-stone-500 group-focus-within:text-amber-500 transition-colors" />
              <input
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                onKeyPress={handleKeyPress}
                className="bg-stone-800/40 border border-stone-600/50 rounded-xl w-full pl-10 pr-4 py-3 text-stone-200 placeholder-stone-500 focus:outline-none focus:border-amber-500 focus:ring-1 focus:ring-amber-500 transition-all"
                placeholder="Enter username"
                disabled={loading}
              />
            </div>
          </div>
        </div>

        <div className="space-y-3">
          <button
            onClick={handleLogin}
            disabled={loading || !username}
            className="w-full py-3 px-4 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded-xl shadow-lg shadow-amber-900/20 transition-all hover:scale-[1.02] active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center disabled:hover:scale-100"
          >
            {loading && !displayError ? <Icon name="spinner" className="animate-spin h-5 w-5" /> : 'Log In'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default AuthScreen;

import React, { useState, useEffect, useMemo } from 'react';
import { useAuth } from '../App';
import { useAppContext } from './Dashboard';
import { Map as MapType, MapTypeEnum, Pin, Character } from '../types';
import { Icon } from './Icons';

interface SidebarProps {
    selectedMap: MapType | null;
    selectedPin: Pin | null;
    selectedCharacter: Character | null;
    onSelectMap: (map: MapType | null) => void;
    onSelectPin: (pin: Pin | null) => void;
    onSelectCharacter: (char: Character | null) => void;
    currentView: 'map' | 'wiki';
    onViewChange: (view: 'map' | 'wiki') => void;
    onDMToolsOpen: () => void;
    onUserSettingsOpen: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
    selectedMap, selectedPin, selectedCharacter, 
    onSelectMap, onSelectPin, onSelectCharacter,
    currentView, onViewChange, onDMToolsOpen, onUserSettingsOpen 
}) => {
    const { user, signOut } = useAuth();
    const { maps, pins, pinTypes, characters, isPlayerView, setIsPlayerView } = useAppContext();
    const [expandedMapIds, setExpandedMapIds] = useState<Set<string>>(new Set());

    // Wiki State
    const [wikiSearchQuery, setWikiSearchQuery] = useState('');

    // Filter data based on view mode
    const displayMaps = useMemo(() => {
        const list = (isPlayerView) ? maps.filter(m => m.is_visible) : maps;
        // Standard alphabetical sort
        return list.sort((a, b) => a.name.localeCompare(b.name));
    }, [maps, isPlayerView]);

    const displayCharacters = useMemo(() => {
        const list = (isPlayerView) ? characters.filter(c => c.is_visible) : characters;
        return list.sort((a, b) => a.name.localeCompare(b.name));
    }, [characters, isPlayerView]);

    // Wiki Filter Logic
    const filteredWikiData = useMemo(() => {
        if (currentView !== 'wiki') return { maps: [], characters: [] };

        const lowerQ = wikiSearchQuery.toLowerCase();

        // Filter Characters
        const fChars = displayCharacters.filter(c => 
            !wikiSearchQuery || 
            c.name.toLowerCase().includes(lowerQ) || 
            c.role_details?.race.toLowerCase().includes(lowerQ) ||
            c.role_details?.class.toLowerCase().includes(lowerQ)
        );

        // Filter Maps (Search flat list logic)
        // If Searching, flat list. If not, tree structure (handled by rendering logic).
        const fMaps = displayMaps.map(map => {
            const mapPins = pins.filter(p => p.map_id === map.id);
            const matchingPins = mapPins.filter(pin => 
                pin.title.toLowerCase().includes(lowerQ) || 
                pin.data.description?.toLowerCase().includes(lowerQ)
            ).sort((a, b) => a.title.localeCompare(b.title));

            const matchesMap = map.name.toLowerCase().includes(lowerQ);
            if (!matchesMap && matchingPins.length === 0) return null;

            return { map, pins: matchingPins };
        }).filter(Boolean) as { map: MapType, pins: Pin[] }[];

        return { maps: fMaps, characters: fChars };
    }, [currentView, wikiSearchQuery, displayMaps, displayCharacters, pins]);


    // Auto-expand logic for current selection
    useEffect(() => {
        if (selectedMap) {
            let current = selectedMap;
            const newExpanded = new Set(expandedMapIds);
            let changed = false;

            // Only expand through visible parents
            while (current && current.parent_map_id) {
                if (!newExpanded.has(current.parent_map_id)) {
                    newExpanded.add(current.parent_map_id);
                    changed = true;
                }
                const parent = displayMaps.find(m => m.id === current!.parent_map_id);
                if (!parent || parent.id === current.id) break;
                current = parent;
            }

            if (changed) {
                setExpandedMapIds(newExpanded);
            }
        }
    }, [selectedMap, displayMaps]);

    const toggleExpand = (mapId: string, e: React.MouseEvent) => {
        e.stopPropagation();
        const newSet = new Set(expandedMapIds);
        if (newSet.has(mapId)) newSet.delete(mapId);
        else newSet.add(mapId);
        setExpandedMapIds(newSet);
    };

    const getMapIconName = (type?: MapTypeEnum) => {
        switch (type) {
            case 'world': return 'globe';
            case 'city': return 'castle';
            case 'dungeon': return 'skull';
            case 'battlemap': return 'compass';
            default: return 'map';
        }
    };

    // --- Tree Items ---

    const MapModeTreeItem: React.FC<{ map: MapType, level: number, visited?: Set<string> }> = ({ map, level, visited = new Set() }) => {
        if (visited.has(map.id)) return null;
        const newVisited = new Set(visited).add(map.id);

        const children = displayMaps.filter(m => m.parent_map_id === map.id).sort((a, b) => a.name.localeCompare(b.name));
        const hasChildren = children.length > 0;
        const isExpanded = expandedMapIds.has(map.id);
        const isSelected = selectedMap?.id === map.id;
        const iconName = getMapIconName(map.map_type);

        return (
            <div className="select-none transition-all duration-200">
                <div 
                    onClick={() => onSelectMap(map)}
                    className={`flex items-center space-x-2 rounded-xl py-2 pr-3 text-sm font-medium transition-all duration-200 group cursor-pointer relative
                        ${isSelected 
                            ? 'bg-amber-900/30 text-amber-400 border border-amber-500/20 shadow-[0_0_10px_rgba(245,158,11,0.1)]' 
                            : 'text-stone-400 hover:bg-stone-800/50 hover:text-stone-100'
                        }
                    `}
                    style={{ paddingLeft: `${level * 12 + 8}px` }}
                >
                    <div className="flex-shrink-0 flex items-center justify-center w-6 h-6">
                        {hasChildren ? (
                            <button onClick={(e) => toggleExpand(map.id, e)} className="p-1 hover:text-amber-500 transition-colors focus:outline-none">
                                <Icon name={isExpanded ? "chevron-down" : "chevron-right"} className="w-4 h-4 opacity-70" />
                            </button>
                        ) : (
                            <Icon name={iconName} className={`h-4 w-4 opacity-50 ${isSelected ? 'text-amber-500' : ''}`} />
                        )}
                    </div>
                    <span className="truncate flex-1">{map.name}</span>
                    {!isPlayerView && !map.is_visible && <Icon name="eye-off" className="w-3 h-3 text-stone-600" title="Hidden" />}
                </div>
                {hasChildren && isExpanded && (
                    <div className="mt-1 space-y-1">
                        {children.map(child => (
                            <MapModeTreeItem key={child.id} map={child} level={level + 1} visited={newVisited} />
                        ))}
                    </div>
                )}
            </div>
        );
    };

    const WikiModeTreeItem: React.FC<{ map: MapType, level: number }> = ({ map, level }) => {
        const children = displayMaps.filter(m => m.parent_map_id === map.id).sort((a, b) => a.name.localeCompare(b.name));
        const hasChildren = children.length > 0;
        const isExpanded = expandedMapIds.has(map.id);
        const isMapSelected = selectedMap?.id === map.id;
        const iconName = getMapIconName(map.map_type); // Unified icon logic

        // Requirement: Only show pins if this specific map is selected
        const mapPins = isMapSelected 
            ? pins.filter(p => p.map_id === map.id).sort((a, b) => a.title.localeCompare(b.title))
            : [];

        return (
            <div className="select-none transition-all duration-200">
                <div 
                    onClick={() => onSelectMap(map)}
                    // MATCHED STYLING FROM MAP MODE
                    className={`flex items-center space-x-2 rounded-xl py-2 pr-3 text-sm font-medium transition-all duration-200 group cursor-pointer relative
                        ${isMapSelected 
                            ? 'bg-amber-900/30 text-amber-400 border border-amber-500/20 shadow-[0_0_10px_rgba(245,158,11,0.1)]' 
                            : 'text-stone-400 hover:bg-stone-800/50 hover:text-stone-100'
                        }
                    `}
                    style={{ paddingLeft: `${level * 12 + 8}px` }}
                >
                    <div className="flex-shrink-0 flex items-center justify-center w-6 h-6">
                        {hasChildren ? (
                            <button onClick={(e) => toggleExpand(map.id, e)} className="p-1 hover:text-amber-500 transition-colors focus:outline-none">
                                <Icon name={isExpanded ? "chevron-down" : "chevron-right"} className="w-4 h-4 opacity-70" />
                            </button>
                        ) : (
                             // MATCHED ICON SIZE AND OPACITY
                             <Icon name={iconName} className={`h-4 w-4 opacity-50 ${isMapSelected ? 'text-amber-500' : ''}`} />
                        )}
                    </div>
                    <span className="truncate flex-1">{map.name}</span>
                </div>

                {isMapSelected && mapPins.length > 0 && (
                    <div className="mb-1 mt-1 space-y-0.5">
                        {mapPins.map(pin => (
                            <button 
                                key={pin.id}
                                onClick={() => onSelectPin(pin)}
                                className={`w-full flex items-center gap-2 py-1.5 text-xs text-left rounded-lg transition-colors pl-2
                                    ${selectedPin?.id === pin.id ? 'bg-stone-800 text-amber-500 font-bold' : 'text-stone-500 hover:text-stone-300 hover:bg-stone-800/30'}
                                `}
                                style={{ paddingLeft: `${level * 12 + 36}px` }}
                            >
                                <span className="w-1.5 h-1.5 rounded-full flex-shrink-0" style={{ backgroundColor: pinTypes.find(t => t.id === pin.pin_type_id)?.color }}></span>
                                <span className="truncate">{pin.title}</span>
                            </button>
                        ))}
                    </div>
                )}

                {hasChildren && isExpanded && (
                    <div className="mt-1 space-y-1">
                        {children.map(child => (
                            <WikiModeTreeItem key={child.id} map={child} level={level + 1} />
                        ))}
                    </div>
                )}
            </div>
        );
    };

    // --- Render ---

    const rootMaps = displayMaps.filter(m => !m.parent_map_id || !displayMaps.find(p => p.id === m.parent_map_id)).sort((a, b) => a.name.localeCompare(b.name));

    return (
        <aside className="flex h-full w-full flex-col md:w-80 bg-stone-900/80 backdrop-blur-xl border-r border-stone-700/50 p-4 shadow-2xl z-20">
            <div className="flex items-center gap-3 mb-6 px-1">
                <img src="https://nielskrikke.com/wp-content/uploads/2025/12/maps-app-icon.png" alt="World Atlas" className="w-10 h-10 rounded-xl shadow-lg border border-stone-600/50" />
                <h1 className="text-2xl font-medieval font-bold text-amber-500 drop-shadow-sm">World Atlas</h1>
            </div>

            {/* Mode Switcher */}
            <div className="grid grid-cols-2 gap-2 bg-stone-800/50 p-1 rounded-xl mb-4">
                <button 
                    onClick={() => onViewChange('map')}
                    className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-bold transition-all ${currentView === 'map' ? 'bg-amber-600 text-white shadow-lg' : 'text-stone-400 hover:text-stone-200'}`}
                >
                    <Icon name="map" className="w-4 h-4" />
                    Map
                </button>
                <button 
                    onClick={() => onViewChange('wiki')}
                    className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-bold transition-all ${currentView === 'wiki' ? 'bg-amber-600 text-white shadow-lg' : 'text-stone-400 hover:text-stone-200'}`}
                >
                    <Icon name="book" className="w-4 h-4" />
                    Wiki
                </button>
            </div>

            <button 
                onClick={onUserSettingsOpen}
                className="w-full flex items-center space-x-3 rounded-xl bg-stone-800/40 hover:bg-stone-800/80 border border-stone-700/30 hover:border-amber-500/50 p-3 shadow-inner transition-all group text-left"
                title="Profile Settings"
            >
                <div className="flex h-10 w-10 items-center justify-center rounded-full bg-stone-900 border border-stone-700 overflow-hidden text-amber-500 group-hover:border-amber-500/50 transition-colors">
                    {user?.profile.image_url ? (
                        <img src={user.profile.image_url} alt="Profile" className="w-full h-full object-cover" />
                    ) : (
                        <span className="font-medieval font-bold text-lg">{user?.profile.username.charAt(0).toUpperCase()}</span>
                    )}
                </div>
                <div className="min-w-0 flex-1">
                    <p className="font-semibold truncate text-stone-200 group-hover:text-amber-500 transition-colors">{user?.profile.username}</p>
                    <p className="text-xs text-stone-500 uppercase tracking-wider font-bold">{user?.profile.role}</p>
                </div>
                <Icon name="settings" className="w-4 h-4 text-stone-600 group-hover:text-amber-500 opacity-0 group-hover:opacity-100 transition-all" />
            </button>

            {/* Wiki Search Bar */}
            {currentView === 'wiki' && (
                <div className="mt-4 relative">
                    <Icon name="search" className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-stone-500" />
                    <input 
                        type="text" 
                        placeholder="Search wiki..." 
                        value={wikiSearchQuery}
                        onChange={(e) => setWikiSearchQuery(e.target.value)}
                        className="w-full bg-stone-900/50 border border-stone-700 rounded-lg pl-9 pr-3 py-2 text-sm text-stone-200 focus:border-amber-500 focus:outline-none placeholder-stone-600"
                    />
                </div>
            )}

            <nav className="mt-8 flex-1 overflow-y-auto custom-scrollbar pr-2">

                {currentView === 'map' ? (
                    // --- MAP VIEW SIDEBAR CONTENT ---
                    <>
                        <div className="flex items-center justify-between mb-2 px-2">
                            <h2 className="text-xs font-medieval tracking-widest text-stone-500 uppercase">Maps</h2>
                        </div>
                        {rootMaps.length > 0 ? (
                            <div className="space-y-1">
                                {rootMaps.map((map) => (
                                    <MapModeTreeItem key={map.id} map={map} level={0} />
                                ))}
                            </div>
                        ) : (
                            <p className="px-3 text-sm text-stone-600 italic">No maps found.</p>
                        )}
                    </>
                ) : (
                    // --- WIKI VIEW SIDEBAR CONTENT ---
                    <>
                         {wikiSearchQuery && (
                             <div className="mb-4">
                                <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2">Search Results</h3>
                                {filteredWikiData.characters.length === 0 && filteredWikiData.maps.length === 0 && (
                                     <p className="px-3 text-sm text-stone-600 italic">No results found.</p>
                                )}
                             </div>
                         )}

                         {/* Characters Section (Show if query matches or no query) */}
                         {(filteredWikiData.characters.length > 0) && (
                            <div className="mb-6">
                                <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2">Characters</h3>
                                {filteredWikiData.characters.map(char => (
                                    <button
                                        key={char.id}
                                        onClick={() => onSelectCharacter(char)}
                                        className={`w-full flex items-center gap-3 px-3 py-2 rounded-xl text-left transition-colors mb-1 ${selectedCharacter?.id === char.id ? 'bg-amber-900/20 text-amber-400 border border-amber-500/30' : 'hover:bg-stone-800/50 text-stone-300 border border-transparent'}`}
                                    >
                                        <div className="w-8 h-8 rounded-full bg-stone-800 overflow-hidden flex-shrink-0">
                                            {char.image_url ? <img src={char.image_url} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center"><Icon name="user" className="w-4 h-4"/></div>}
                                        </div>
                                        <div className="min-w-0">
                                            <div className="font-medium truncate text-sm">{char.name}</div>
                                            <div className="text-[10px] text-stone-500 truncate">{char.role_details?.race} {char.role_details?.class}</div>
                                        </div>
                                    </button>
                                ))}
                            </div>
                         )}

                         {/* Locations Section */}
                         {/* If Search Active: Flat List. If Not: Tree */}
                         {(wikiSearchQuery ? filteredWikiData.maps.length > 0 : rootMaps.length > 0) && (
                             <div>
                                <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2">Locations</h3>
                                {wikiSearchQuery ? (
                                    <div>
                                        {filteredWikiData.maps.map(({ map, pins }) => (
                                            <div key={map.id} className="mb-2">
                                                <button 
                                                    onClick={() => onSelectMap(map)}
                                                    className={`w-full flex items-center gap-3 px-3 py-2 text-left transition-colors rounded-lg ${selectedMap?.id === map.id ? 'text-amber-400 bg-amber-900/20' : 'text-stone-300 hover:bg-stone-800/50'}`}
                                                >
                                                    <Icon name="map" className="w-4 h-4 opacity-70"/>
                                                    <span className="font-medium truncate">{map.name}</span>
                                                </button>
                                                <div className="pl-4 border-l border-stone-800 ml-4 mt-1 space-y-0.5">
                                                    {pins.map(pin => (
                                                        <button 
                                                            key={pin.id}
                                                            onClick={() => onSelectPin(pin)}
                                                            className="w-full flex items-center gap-2 px-3 py-1.5 text-left text-xs rounded-lg text-stone-400 hover:text-stone-200"
                                                        >
                                                            <span className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: pinTypes.find(t => t.id === pin.pin_type_id)?.color }}></span>
                                                            <span className="truncate">{pin.title}</span>
                                                        </button>
                                                    ))}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                ) : (
                                    <div>
                                        {rootMaps.map(map => (
                                            <WikiModeTreeItem key={map.id} map={map} level={0} />
                                        ))}
                                    </div>
                                )}
                             </div>
                         )}
                    </>
                )}
            </nav>

            {user?.profile.role === 'DM' && (
                <div className="mt-4 pt-4 border-t border-stone-800">
                    <h2 className="text-[10px] font-medieval tracking-widest text-stone-600 uppercase px-2 mb-2">DM Controls</h2>
                    <div className="flex gap-2">
                        <button 
                            onClick={onDMToolsOpen}
                            className="flex-1 flex items-center justify-center p-3 rounded-xl bg-stone-800/40 hover:bg-stone-700 border border-stone-700/50 hover:border-amber-500/50 text-stone-400 hover:text-amber-500 transition-all group"
                            title="DM Tools & Settings"
                        >
                            <Icon name="view_apps" className="w-7 h-7" />
                        </button>

                        <button 
                            onClick={() => setIsPlayerView(!isPlayerView)}
                            className={`flex-1 flex items-center justify-center p-3 rounded-xl border transition-all ${
                                isPlayerView 
                                ? 'bg-amber-900/20 border-amber-600/50 text-amber-500 shadow-[inset_0_0_10px_rgba(245,158,11,0.1)]' 
                                : 'bg-stone-800/40 border-stone-700/50 text-stone-400 hover:bg-stone-700 hover:text-stone-200'
                            }`}
                            title={isPlayerView ? "Switch to DM View" : "Switch to Player View"}
                        >
                            <Icon name={isPlayerView ? "visibility" : "visibility_off"} className="w-7 h-7" />
                        </button>
                    </div>
                </div>
            )}

            {user?.profile.role === 'Player' && (
                <div className="mt-4 border-t border-stone-800 pt-4">
                    <button onClick={signOut} className="flex w-full items-center space-x-3 rounded-xl px-3 py-2 text-left text-sm font-medium text-stone-500 hover:bg-red-900/20 hover:text-red-400 transition-colors">
                        <Icon name="logout" className="h-5 w-5" />
                        <span>Sign Out</span>
                    </button>
                </div>
            )}
        </aside>
    );
};

export default Sidebar;

import React, { useState } from 'react';
import { supabase } from '../services/supabase';
import { Icon } from './Icons';

interface AuthScreenProps {
  authError: string | null;
  onAuthAttempt: () => void;
}

const AuthScreen: React.FC<AuthScreenProps> = ({ authError, onAuthAttempt }) => {
  const [username, setUsername] = useState('');
  const [internalError, setInternalError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const displayError = authError || internalError;

  const handleLogin = async () => {
    onAuthAttempt();
    setInternalError(null);
    setLoading(true);

    const trimmedUsername = username.trim();
    if (!trimmedUsername) {
        setInternalError("Username is required.");
        setLoading(false);
        return;
    }
    const lowerCaseUsername = trimmedUsername.toLowerCase();

    // Replicate the deterministic password generation
    const dummyEmail = `${lowerCaseUsername}@dnd-map-login.local`;
    const dummyPassword = `DUMMY_PASSWORD_FOR_${lowerCaseUsername}`;

    const { error } = await supabase.auth.signInWithPassword({
      email: dummyEmail,
      password: dummyPassword,
    });

    if (error) {
      if (error.message === 'Invalid login credentials') {
         setInternalError("User not found or incorrect credentials. Please contact your DM to create an account.");
      } else {
         setInternalError(error.message);
      }
    }

    setLoading(false);
  };

  const handleKeyPress = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && username) {
      handleLogin();
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-stone-950">
      <div className="w-full max-w-md bg-stone-900/60 backdrop-blur-2xl border border-stone-700/50 shadow-2xl rounded-3xl p-8 animate-modal-in">
        <div className="text-center mb-8 flex flex-col items-center">
          <img 
            src="https://nielskrikke.com/wp-content/uploads/2025/12/maps-app-icon-v2.png" 
            alt="World Atlas Logo" 
            className="w-20 h-20 mb-4 rounded-2xl shadow-lg border-2 border-amber-600/30"
          />
          <h1 className="text-4xl font-medieval font-bold mb-2 text-amber-500 drop-shadow-md">
            World Atlas
          </h1>
          <p className="text-stone-400">
            Enter your username to log in
          </p>
        </div>

        {displayError && (
          <div className="mb-6 p-4 bg-red-900/30 border border-red-800/50 rounded-xl">
            <p className="text-red-300 text-sm">{displayError}</p>
          </div>
        )}

        <div className="space-y-4 mb-6">
          <div>
            <label className="block text-sm font-medium mb-2 text-stone-300">
              Username
            </label>
            <div className="relative group">
              <Icon name="user" className="absolute left-3 top-1/2 transform -translate-y-1/2 w-5 h-5 text-stone-500 group-focus-within:text-amber-500 transition-colors" />
              <input
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                onKeyPress={handleKeyPress}
                className="bg-stone-800/40 border border-stone-600/50 rounded-xl w-full pl-10 pr-4 py-3 text-stone-200 placeholder-stone-500 focus:outline-none focus:border-amber-500 focus:ring-1 focus:ring-amber-500 transition-all"
                placeholder="Enter username"
                disabled={loading}
              />
            </div>
          </div>
        </div>

        <div className="space-y-3">
          <button
            onClick={handleLogin}
            disabled={loading || !username}
            className="w-full py-3 px-4 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded-xl shadow-lg shadow-amber-900/20 transition-all hover:scale-[1.02] active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center disabled:hover:scale-100"
          >
            {loading && !displayError ? <Icon name="spinner" className="animate-spin h-5 w-5" /> : 'Log In'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default AuthScreen;

import React, { useState, useEffect, useMemo } from 'react';
import { useAuth } from '../App';
import { useAppContext } from './Dashboard';
import { Map as MapType, MapTypeEnum, Pin, Character } from '../types';
import { Icon } from './Icons';

interface SidebarProps {
    selectedMap: MapType | null;
    selectedPin: Pin | null;
    selectedCharacter: Character | null;
    onSelectMap: (map: MapType | null) => void;
    onSelectPin: (pin: Pin | null) => void;
    onSelectCharacter: (char: Character | null) => void;
    currentView: 'map' | 'wiki';
    onViewChange: (view: 'map' | 'wiki') => void;
    onDMToolsOpen: () => void;
    onUserSettingsOpen: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ 
    selectedMap, selectedPin, selectedCharacter, 
    onSelectMap, onSelectPin, onSelectCharacter,
    currentView, onViewChange, onDMToolsOpen, onUserSettingsOpen 
}) => {
    const { user, signOut } = useAuth();
    const { maps, pins, pinTypes, characters, isPlayerView, setIsPlayerView } = useAppContext();
    const [expandedMapIds, setExpandedMapIds] = useState<Set<string>>(new Set());

    // Wiki State
    const [wikiSearchQuery, setWikiSearchQuery] = useState('');

    // Filter data based on view mode
    const displayMaps = useMemo(() => {
        const list = (isPlayerView) ? maps.filter(m => m.is_visible) : maps;
        // Standard alphabetical sort
        return list.sort((a, b) => a.name.localeCompare(b.name));
    }, [maps, isPlayerView]);

    const displayCharacters = useMemo(() => {
        const list = (isPlayerView) ? characters.filter(c => c.is_visible) : characters;
        return list.sort((a, b) => a.name.localeCompare(b.name));
    }, [characters, isPlayerView]);

    // Wiki Filter Logic
    const filteredWikiData = useMemo(() => {
        if (currentView !== 'wiki') return { maps: [], characters: [] };

        const lowerQ = wikiSearchQuery.toLowerCase();

        // Filter Characters
        const fChars = displayCharacters.filter(c => 
            !wikiSearchQuery || 
            c.name.toLowerCase().includes(lowerQ) || 
            c.role_details?.race.toLowerCase().includes(lowerQ) ||
            c.role_details?.class.toLowerCase().includes(lowerQ)
        );

        // Filter Maps (Search flat list logic)
        // If Searching, flat list. If not, tree structure (handled by rendering logic).
        const fMaps = displayMaps.map(map => {
            const mapPins = pins.filter(p => p.map_id === map.id);
            const matchingPins = mapPins.filter(pin => 
                pin.title.toLowerCase().includes(lowerQ) || 
                pin.data.description?.toLowerCase().includes(lowerQ)
            ).sort((a, b) => a.title.localeCompare(b.title));

            const matchesMap = map.name.toLowerCase().includes(lowerQ);
            if (!matchesMap && matchingPins.length === 0) return null;

            return { map, pins: matchingPins };
        }).filter(Boolean) as { map: MapType, pins: Pin[] }[];

        return { maps: fMaps, characters: fChars };
    }, [currentView, wikiSearchQuery, displayMaps, displayCharacters, pins]);


    // Auto-expand logic for current selection
    useEffect(() => {
        if (selectedMap) {
            let current = selectedMap;
            const newExpanded = new Set(expandedMapIds);
            let changed = false;

            // Only expand through visible parents
            while (current && current.parent_map_id) {
                if (!newExpanded.has(current.parent_map_id)) {
                    newExpanded.add(current.parent_map_id);
                    changed = true;
                }
                const parent = displayMaps.find(m => m.id === current!.parent_map_id);
                if (!parent || parent.id === current.id) break;
                current = parent;
            }

            if (changed) {
                setExpandedMapIds(newExpanded);
            }
        }
    }, [selectedMap, displayMaps]);

    const toggleExpand = (mapId: string, e: React.MouseEvent) => {
        e.stopPropagation();
        const newSet = new Set(expandedMapIds);
        if (newSet.has(mapId)) newSet.delete(mapId);
        else newSet.add(mapId);
        setExpandedMapIds(newSet);
    };

    const getMapIconName = (type?: MapTypeEnum) => {
        switch (type) {
            case 'world': return 'globe';
            case 'city': return 'castle';
            case 'dungeon': return 'skull';
            case 'battlemap': return 'compass';
            default: return 'map';
        }
    };

    // --- Tree Items ---

    const MapModeTreeItem: React.FC<{ map: MapType, level: number, visited?: Set<string> }> = ({ map, level, visited = new Set() }) => {
        if (visited.has(map.id)) return null;
        const newVisited = new Set(visited).add(map.id);

        const children = displayMaps.filter(m => m.parent_map_id === map.id).sort((a, b) => a.name.localeCompare(b.name));
        const hasChildren = children.length > 0;
        const isExpanded = expandedMapIds.has(map.id);
        const isSelected = selectedMap?.id === map.id;
        const iconName = getMapIconName(map.map_type);

        return (
            <div className="select-none transition-all duration-200">
                <div 
                    onClick={() => onSelectMap(map)}
                    className={`flex items-center space-x-2 rounded-xl py-2 pr-3 text-sm font-medium transition-all duration-200 group cursor-pointer relative
                        ${isSelected 
                            ? 'bg-amber-900/30 text-amber-400 border border-amber-500/20 shadow-[0_0_10px_rgba(245,158,11,0.1)]' 
                            : 'text-stone-400 hover:bg-stone-800/50 hover:text-stone-100'
                        }
                    `}
                    style={{ paddingLeft: `${level * 12 + 8}px` }}
                >
                    <div className="flex-shrink-0 flex items-center justify-center w-6 h-6">
                        {hasChildren ? (
                            <button onClick={(e) => toggleExpand(map.id, e)} className="p-1 hover:text-amber-500 transition-colors focus:outline-none">
                                <Icon name={isExpanded ? "chevron-down" : "chevron-right"} className="w-4 h-4 opacity-70" />
                            </button>
                        ) : (
                            <Icon name={iconName} className={`h-4 w-4 opacity-50 ${isSelected ? 'text-amber-500' : ''}`} />
                        )}
                    </div>
                    <span className="truncate flex-1">{map.name}</span>
                    {!isPlayerView && !map.is_visible && <Icon name="eye-off" className="w-3 h-3 text-stone-600" title="Hidden" />}
                </div>
                {hasChildren && isExpanded && (
                    <div className="mt-1 space-y-1">
                        {children.map(child => (
                            <MapModeTreeItem key={child.id} map={child} level={level + 1} visited={newVisited} />
                        ))}
                    </div>
                )}
            </div>
        );
    };

    const WikiModeTreeItem: React.FC<{ map: MapType, level: number }> = ({ map, level }) => {
        const children = displayMaps.filter(m => m.parent_map_id === map.id).sort((a, b) => a.name.localeCompare(b.name));
        const hasChildren = children.length > 0;
        const isExpanded = expandedMapIds.has(map.id);
        const isMapSelected = selectedMap?.id === map.id;
        const iconName = getMapIconName(map.map_type); // Unified icon logic

        // Requirement: Only show pins if this specific map is selected
        const mapPins = isMapSelected 
            ? pins.filter(p => p.map_id === map.id).sort((a, b) => a.title.localeCompare(b.title))
            : [];

        return (
            <div className="select-none transition-all duration-200">
                <div 
                    onClick={() => onSelectMap(map)}
                    // MATCHED STYLING FROM MAP MODE
                    className={`flex items-center space-x-2 rounded-xl py-2 pr-3 text-sm font-medium transition-all duration-200 group cursor-pointer relative
                        ${isMapSelected 
                            ? 'bg-amber-900/30 text-amber-400 border border-amber-500/20 shadow-[0_0_10px_rgba(245,158,11,0.1)]' 
                            : 'text-stone-400 hover:bg-stone-800/50 hover:text-stone-100'
                        }
                    `}
                    style={{ paddingLeft: `${level * 12 + 8}px` }}
                >
                    <div className="flex-shrink-0 flex items-center justify-center w-6 h-6">
                        {hasChildren ? (
                            <button onClick={(e) => toggleExpand(map.id, e)} className="p-1 hover:text-amber-500 transition-colors focus:outline-none">
                                <Icon name={isExpanded ? "chevron-down" : "chevron-right"} className="w-4 h-4 opacity-70" />
                            </button>
                        ) : (
                             // MATCHED ICON SIZE AND OPACITY
                             <Icon name={iconName} className={`h-4 w-4 opacity-50 ${isMapSelected ? 'text-amber-500' : ''}`} />
                        )}
                    </div>
                    <span className="truncate flex-1">{map.name}</span>
                </div>

                {isMapSelected && mapPins.length > 0 && (
                    <div className="mb-1 mt-1 space-y-0.5">
                        {mapPins.map(pin => (
                            <button 
                                key={pin.id}
                                onClick={() => onSelectPin(pin)}
                                className={`w-full flex items-center gap-2 py-1.5 text-xs text-left rounded-lg transition-colors pl-2
                                    ${selectedPin?.id === pin.id ? 'bg-stone-800 text-amber-500 font-bold' : 'text-stone-500 hover:text-stone-300 hover:bg-stone-800/30'}
                                `}
                                style={{ paddingLeft: `${level * 12 + 36}px` }}
                            >
                                <span className="w-1.5 h-1.5 rounded-full flex-shrink-0" style={{ backgroundColor: pinTypes.find(t => t.id === pin.pin_type_id)?.color }}></span>
                                <span className="truncate">{pin.title}</span>
                            </button>
                        ))}
                    </div>
                )}

                {hasChildren && isExpanded && (
                    <div className="mt-1 space-y-1">
                        {children.map(child => (
                            <WikiModeTreeItem key={child.id} map={child} level={level + 1} />
                        ))}
                    </div>
                )}
            </div>
        );
    };

    // --- Render ---

    const rootMaps = displayMaps.filter(m => !m.parent_map_id || !displayMaps.find(p => p.id === m.parent_map_id)).sort((a, b) => a.name.localeCompare(b.name));

    return (
        <aside className="flex h-full w-full flex-col md:w-80 bg-stone-900/80 backdrop-blur-xl border-r border-stone-700/50 p-4 shadow-2xl z-20">
            <div className="flex items-center gap-3 mb-6 px-1">
                <img src="https://nielskrikke.com/wp-content/uploads/2025/12/maps-app-icon-v2.png" alt="World Atlas" className="w-10 h-10 rounded-xl shadow-lg border border-stone-600/50" />
                <h1 className="text-2xl font-medieval font-bold text-amber-500 drop-shadow-sm">World Atlas</h1>
            </div>

            {/* Mode Switcher */}
            <div className="grid grid-cols-2 gap-2 bg-stone-800/50 p-1 rounded-xl mb-4">
                <button 
                    onClick={() => onViewChange('map')}
                    className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-bold transition-all ${currentView === 'map' ? 'bg-amber-600 text-white shadow-lg' : 'text-stone-400 hover:text-stone-200'}`}
                >
                    <Icon name="map" className="w-4 h-4" />
                    Map
                </button>
                <button 
                    onClick={() => onViewChange('wiki')}
                    className={`flex items-center justify-center gap-2 py-2 rounded-lg text-sm font-bold transition-all ${currentView === 'wiki' ? 'bg-amber-600 text-white shadow-lg' : 'text-stone-400 hover:text-stone-200'}`}
                >
                    <Icon name="book" className="w-4 h-4" />
                    Wiki
                </button>
            </div>

            <button 
                onClick={onUserSettingsOpen}
                className="w-full flex items-center space-x-3 rounded-xl bg-stone-800/40 hover:bg-stone-800/80 border border-stone-700/30 hover:border-amber-500/50 p-3 shadow-inner transition-all group text-left"
                title="Profile Settings"
            >
                <div className="flex h-10 w-10 items-center justify-center rounded-full bg-stone-900 border border-stone-700 overflow-hidden text-amber-500 group-hover:border-amber-500/50 transition-colors">
                    {user?.profile.image_url ? (
                        <img src={user.profile.image_url} alt="Profile" className="w-full h-full object-cover" />
                    ) : (
                        <span className="font-medieval font-bold text-lg">{user?.profile.username.charAt(0).toUpperCase()}</span>
                    )}
                </div>
                <div className="min-w-0 flex-1">
                    <p className="font-semibold truncate text-stone-200 group-hover:text-amber-500 transition-colors">{user?.profile.username}</p>
                    <p className="text-xs text-stone-500 uppercase tracking-wider font-bold">{user?.profile.role}</p>
                </div>
                <Icon name="settings" className="w-4 h-4 text-stone-600 group-hover:text-amber-500 opacity-0 group-hover:opacity-100 transition-all" />
            </button>

            {/* Wiki Search Bar */}
            {currentView === 'wiki' && (
                <div className="mt-4 relative">
                    <Icon name="search" className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-stone-500" />
                    <input 
                        type="text" 
                        placeholder="Search wiki..." 
                        value={wikiSearchQuery}
                        onChange={(e) => setWikiSearchQuery(e.target.value)}
                        className="w-full bg-stone-900/50 border border-stone-700 rounded-lg pl-9 pr-3 py-2 text-sm text-stone-200 focus:border-amber-500 focus:outline-none placeholder-stone-600"
                    />
                </div>
            )}

            <nav className="mt-8 flex-1 overflow-y-auto custom-scrollbar pr-2">

                {currentView === 'map' ? (
                    // --- MAP VIEW SIDEBAR CONTENT ---
                    <>
                        <div className="flex items-center justify-between mb-2 px-2">
                            <h2 className="text-xs font-medieval tracking-widest text-stone-500 uppercase">Maps</h2>
                        </div>
                        {rootMaps.length > 0 ? (
                            <div className="space-y-1">
                                {rootMaps.map((map) => (
                                    <MapModeTreeItem key={map.id} map={map} level={0} />
                                ))}
                            </div>
                        ) : (
                            <p className="px-3 text-sm text-stone-600 italic">No maps found.</p>
                        )}
                    </>
                ) : (
                    // --- WIKI VIEW SIDEBAR CONTENT ---
                    <>
                         {wikiSearchQuery && (
                             <div className="mb-4">
                                <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2">Search Results</h3>
                                {filteredWikiData.characters.length === 0 && filteredWikiData.maps.length === 0 && (
                                     <p className="px-3 text-sm text-stone-600 italic">No results found.</p>
                                )}
                             </div>
                         )}

                         {/* Characters Section (Show if query matches or no query) */}
                         {(filteredWikiData.characters.length > 0) && (
                            <div className="mb-6">
                                <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2">Characters</h3>
                                {filteredWikiData.characters.map(char => (
                                    <button
                                        key={char.id}
                                        onClick={() => onSelectCharacter(char)}
                                        className={`w-full flex items-center gap-3 px-3 py-2 rounded-xl text-left transition-colors mb-1 ${selectedCharacter?.id === char.id ? 'bg-amber-900/20 text-amber-400 border border-amber-500/30' : 'hover:bg-stone-800/50 text-stone-300 border border-transparent'}`}
                                    >
                                        <div className="w-8 h-8 rounded-full bg-stone-800 overflow-hidden flex-shrink-0">
                                            {char.image_url ? <img src={char.image_url} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center"><Icon name="user" className="w-4 h-4"/></div>}
                                        </div>
                                        <div className="min-w-0">
                                            <div className="font-medium truncate text-sm">{char.name}</div>
                                            <div className="text-[10px] text-stone-500 truncate">{char.role_details?.race} {char.role_details?.class}</div>
                                        </div>
                                    </button>
                                ))}
                            </div>
                         )}

                         {/* Locations Section */}
                         {/* If Search Active: Flat List. If Not: Tree */}
                         {(wikiSearchQuery ? filteredWikiData.maps.length > 0 : rootMaps.length > 0) && (
                             <div>
                                <h3 className="px-3 text-xs font-bold uppercase text-stone-500 mb-2">Locations</h3>
                                {wikiSearchQuery ? (
                                    <div>
                                        {filteredWikiData.maps.map(({ map, pins }) => (
                                            <div key={map.id} className="mb-2">
                                                <button 
                                                    onClick={() => onSelectMap(map)}
                                                    className={`w-full flex items-center gap-3 px-3 py-2 text-left transition-colors rounded-lg ${selectedMap?.id === map.id ? 'text-amber-400 bg-amber-900/20' : 'text-stone-300 hover:bg-stone-800/50'}`}
                                                >
                                                    <Icon name="map" className="w-4 h-4 opacity-70"/>
                                                    <span className="font-medium truncate">{map.name}</span>
                                                </button>
                                                <div className="pl-4 border-l border-stone-800 ml-4 mt-1 space-y-0.5">
                                                    {pins.map(pin => (
                                                        <button 
                                                            key={pin.id}
                                                            onClick={() => onSelectPin(pin)}
                                                            className="w-full flex items-center gap-2 px-3 py-1.5 text-left text-xs rounded-lg text-stone-400 hover:text-stone-200"
                                                        >
                                                            <span className="w-1.5 h-1.5 rounded-full" style={{ backgroundColor: pinTypes.find(t => t.id === pin.pin_type_id)?.color }}></span>
                                                            <span className="truncate">{pin.title}</span>
                                                        </button>
                                                    ))}
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                ) : (
                                    <div>
                                        {rootMaps.map(map => (
                                            <WikiModeTreeItem key={map.id} map={map} level={0} />
                                        ))}
                                    </div>
                                )}
                             </div>
                         )}
                    </>
                )}
            </nav>

            {user?.profile.role === 'DM' && (
                <div className="mt-4 pt-4 border-t border-stone-800">
                    <h2 className="text-[10px] font-medieval tracking-widest text-stone-600 uppercase px-2 mb-2">DM Controls</h2>
                    <div className="flex gap-2">
                        <button 
                            onClick={onDMToolsOpen}
                            className="flex-1 flex items-center justify-center p-3 rounded-xl bg-stone-800/40 hover:bg-stone-700 border border-stone-700/50 hover:border-amber-500/50 text-stone-400 hover:text-amber-500 transition-all group"
                            title="DM Tools & Settings"
                        >
                            <Icon name="view_apps" className="w-7 h-7" />
                        </button>

                        <button 
                            onClick={() => setIsPlayerView(!isPlayerView)}
                            className={`flex-1 flex items-center justify-center p-3 rounded-xl border transition-all ${
                                isPlayerView 
                                ? 'bg-amber-900/20 border-amber-600/50 text-amber-500 shadow-[inset_0_0_10px_rgba(245,158,11,0.1)]' 
                                : 'bg-stone-800/40 border-stone-700/50 text-stone-400 hover:bg-stone-700 hover:text-stone-200'
                            }`}
                            title={isPlayerView ? "Switch to DM View" : "Switch to Player View"}
                        >
                            <Icon name={isPlayerView ? "visibility" : "visibility_off"} className="w-7 h-7" />
                        </button>
                    </div>
                </div>
            )}

            {user?.profile.role === 'Player' && (
                <div className="mt-4 border-t border-stone-800 pt-4">
                    <button onClick={signOut} className="flex w-full items-center space-x-3 rounded-xl px-3 py-2 text-left text-sm font-medium text-stone-500 hover:bg-red-900/20 hover:text-red-400 transition-colors">
                        <Icon name="logout" className="h-5 w-5" />
                        <span>Sign Out</span>
                    </button>
                </div>
            )}
        </aside>
    );
};

export default Sidebar;
